CREATE TABLE steam_description(
   steam_appid          INTEGER  NOT NULL PRIMARY KEY 
  ,detailed_description VARCHAR(62517) NOT NULL
  ,about_the_game       VARCHAR(27961) NOT NULL
  ,short_description    VARCHAR(342) NOT NULL
);
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (10,'Play the world''s number 1 online action game. Engage in an incredibly realistic brand of terrorist warfare in this wildly popular team-based game. Ally with teammates to complete strategic missions. Take out enemy sites. Rescue hostages. Your role affects your team''s success. Your team''s success affects your role.','Play the world''s number 1 online action game. Engage in an incredibly realistic brand of terrorist warfare in this wildly popular team-based game. Ally with teammates to complete strategic missions. Take out enemy sites. Rescue hostages. Your role affects your team''s success. Your team''s success affects your role.','Play the world''s number 1 online action game. Engage in an incredibly realistic brand of terrorist warfare in this wildly popular team-based game. Ally with teammates to complete strategic missions. Take out enemy sites. Rescue hostages. Your role affects your team''s success. Your team''s success affects your role.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (20,'One of the most popular online action games of all time, Team Fortress Classic features over nine character classes -- from Medic to Spy to Demolition Man -- enlisted in a unique style of online team warfare. Each character class possesses unique weapons, items, and abilities, as teams compete online in a variety of game play modes.','One of the most popular online action games of all time, Team Fortress Classic features over nine character classes -- from Medic to Spy to Demolition Man -- enlisted in a unique style of online team warfare. Each character class possesses unique weapons, items, and abilities, as teams compete online in a variety of game play modes.','One of the most popular online action games of all time, Team Fortress Classic features over nine character classes -- from Medic to Spy to Demolition Man -- enlisted in a unique style of online team warfare. Each character class possesses unique weapons, items, and abilities, as teams compete online in a variety of game play modes.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (30,'Enlist in an intense brand of Axis vs. Allied teamplay set in the WWII European Theatre of Operations. Players assume the role of light/assault/heavy infantry, sniper or machine-gunner class, each with a unique arsenal of historical weaponry at their disposal. Missions are based on key historical operations. And, as war rages, players must work together with their squad to accomplish a variety of mission-specific objectives.','Enlist in an intense brand of Axis vs. Allied teamplay set in the WWII European Theatre of Operations. Players assume the role of light/assault/heavy infantry, sniper or machine-gunner class, each with a unique arsenal of historical weaponry at their disposal. Missions are based on key historical operations. And, as war rages, players must work together with their squad to accomplish a variety of mission-specific objectives.','Enlist in an intense brand of Axis vs. Allied teamplay set in the WWII European Theatre of Operations. Players assume the role of light/assault/heavy infantry, sniper or machine-gunner class, each with a unique arsenal of historical weaponry at their disposal. Missions are based on key historical operations.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (40,'Enjoy fast-paced multiplayer gaming with Deathmatch Classic (a.k.a. DMC). Valve''s tribute to the work of id software, DMC invites players to grab their rocket launchers and put their reflexes to the test in a collection of futuristic settings.','Enjoy fast-paced multiplayer gaming with Deathmatch Classic (a.k.a. DMC). Valve''s tribute to the work of id software, DMC invites players to grab their rocket launchers and put their reflexes to the test in a collection of futuristic settings.','Enjoy fast-paced multiplayer gaming with Deathmatch Classic (a.k.a. DMC). Valve''s tribute to the work of id software, DMC invites players to grab their rocket launchers and put their reflexes to the test in a collection of futuristic settings.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (50,'Return to the Black Mesa Research Facility as one of the military specialists assigned to eliminate Gordon Freeman. Experience an entirely new episode of single player action. Meet fierce alien opponents, and experiment with new weaponry. Named ''Game of the Year'' by the Academy of Interactive Arts and Sciences.','Return to the Black Mesa Research Facility as one of the military specialists assigned to eliminate Gordon Freeman. Experience an entirely new episode of single player action. Meet fierce alien opponents, and experiment with new weaponry. Named ''Game of the Year'' by the Academy of Interactive Arts and Sciences.','Return to the Black Mesa Research Facility as one of the military specialists assigned to eliminate Gordon Freeman. Experience an entirely new episode of single player action. Meet fierce alien opponents, and experiment with new weaponry. Named ''Game of the Year'' by the Academy of Interactive Arts and Sciences.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (60,'A futuristic action game that challenges your agility as well as your aim, Ricochet features one-on-one and team matches played in a variety of futuristic battle arenas.','A futuristic action game that challenges your agility as well as your aim, Ricochet features one-on-one and team matches played in a variety of futuristic battle arenas.','A futuristic action game that challenges your agility as well as your aim, Ricochet features one-on-one and team matches played in a variety of futuristic battle arenas.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (70,'Named Game of the Year by over 50 publications, Valve''s debut title blends action and adventure with award-winning technology to create a frighteningly realistic world where players must think to survive. Also includes an exciting multiplayer mode that allows you to play against friends and enemies around the world.','Named Game of the Year by over 50 publications, Valve''s debut title blends action and adventure with award-winning technology to create a frighteningly realistic world where players must think to survive. Also includes an exciting multiplayer mode that allows you to play against friends and enemies around the world.','Named Game of the Year by over 50 publications, Valve''s debut title blends action and adventure with award-winning technology to create a frighteningly realistic world where players must think to survive. Also includes an exciting multiplayer mode that allows you to play against friends and enemies around the world.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (80,'With its extensive Tour of Duty campaign, a near-limitless number of skirmish modes, updates and new content for Counter-Strike''s award-winning multiplayer game play, plus over 12 bonus single player missions, Counter-Strike: Condition Zero is a tremendous offering of single and multiplayer content.','With its extensive Tour of Duty campaign, a near-limitless number of skirmish modes, updates and new content for Counter-Strike''s award-winning multiplayer game play, plus over 12 bonus single player missions, Counter-Strike: Condition Zero is a tremendous offering of single and multiplayer content.','With its extensive Tour of Duty campaign, a near-limitless number of skirmish modes, updates and new content for Counter-Strike''s award-winning multiplayer game play, plus over 12 bonus single player missions, Counter-Strike: Condition Zero is a tremendous offering of single and multiplayer content.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (130,'Made by Gearbox Software and originally released in 2001 as an add-on to Half-Life, Blue Shift is a return to the Black Mesa Research Facility in which you play as Barney Calhoun, the security guard sidekick who helped Gordon out of so many sticky situations.','Made by Gearbox Software and originally released in 2001 as an add-on to Half-Life, Blue Shift is a return to the Black Mesa Research Facility in which you play as Barney Calhoun, the security guard sidekick who helped Gordon out of so many sticky situations.','Made by Gearbox Software and originally released in 2001 as an add-on to Half-Life, Blue Shift is a return to the Black Mesa Research Facility in which you play as Barney Calhoun, the security guard sidekick who helped Gordon out of so many sticky situations.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (220,'1998. HALF-LIFE sends a shock through the game industry with its combination of pounding action and continuous, immersive storytelling. Valve''s debut title wins more than 50 game-of-the-year awards on its way to being named "Best PC Game Ever" by PC Gamer, and launches a franchise with more than eight million retail units sold worldwide.<br><br>
		NOW. By taking the suspense, challenge and visceral charge of the original, and adding startling new realism and responsiveness, Half-Life 2 opens the door to a world where the player''s presence affects everything around him, from the physical environment to the behaviors even the emotions of both friends and enemies.<br><br>
		The player again picks up the crowbar of research scientist Gordon Freeman, who finds himself on an alien-infested Earth being picked to the bone, its resources depleted, its populace dwindling. Freeman is thrust into the unenviable role of rescuing the world from the wrong he unleashed back at Black Mesa. And a lot of people he cares about are counting on him.<br><br>
		The intense, real-time gameplay of Half-Life 2 is made possible only by Source&reg;, Valve''s new proprietary engine technology. Source provides major enhancements in:<br><br>
		<ul>
		<li><span class="copyHead">Characters:</span> Advanced facial animation system delivers the most sophisticated in-game characters ever seen. With 40 distinct facial "muscles," human characters convey the full array of human emotion, and respond to the player with fluidity and intelligence.</li>
		<li><span class="copyHead">Physics:</span> From pebbles to water to 2-ton trucks respond as expected, as they obey the laws of mass, friction, gravity, and buoyancy.</li>
		<li><span class="copyHead">Graphics:</span> Source''s shader-based renderer, like the one used at Pixar to create movies such as Toy Story&reg; and Monster''s, Inc.&reg;, creates the most beautiful and realistic environments ever seen in a video game.</li>
		<li><span class="copyHead">AI:</span> Neither friends nor enemies charge blindly into the fray. They can assess threats, navigate tricky terrain, and fashion weapons from whatever is at hand.</li>
		</ul>','1998. HALF-LIFE sends a shock through the game industry with its combination of pounding action and continuous, immersive storytelling. Valve''s debut title wins more than 50 game-of-the-year awards on its way to being named "Best PC Game Ever" by PC Gamer, and launches a franchise with more than eight million retail units sold worldwide.<br><br>
		NOW. By taking the suspense, challenge and visceral charge of the original, and adding startling new realism and responsiveness, Half-Life 2 opens the door to a world where the player''s presence affects everything around him, from the physical environment to the behaviors even the emotions of both friends and enemies.<br><br>
		The player again picks up the crowbar of research scientist Gordon Freeman, who finds himself on an alien-infested Earth being picked to the bone, its resources depleted, its populace dwindling. Freeman is thrust into the unenviable role of rescuing the world from the wrong he unleashed back at Black Mesa. And a lot of people he cares about are counting on him.<br><br>
		The intense, real-time gameplay of Half-Life 2 is made possible only by Source&reg;, Valve''s new proprietary engine technology. Source provides major enhancements in:<br><br>
		<ul>
		<li><span class="copyHead">Characters:</span> Advanced facial animation system delivers the most sophisticated in-game characters ever seen. With 40 distinct facial "muscles," human characters convey the full array of human emotion, and respond to the player with fluidity and intelligence.</li>
		<li><span class="copyHead">Physics:</span> From pebbles to water to 2-ton trucks respond as expected, as they obey the laws of mass, friction, gravity, and buoyancy.</li>
		<li><span class="copyHead">Graphics:</span> Source''s shader-based renderer, like the one used at Pixar to create movies such as Toy Story&reg; and Monster''s, Inc.&reg;, creates the most beautiful and realistic environments ever seen in a video game.</li>
		<li><span class="copyHead">AI:</span> Neither friends nor enemies charge blindly into the fray. They can assess threats, navigate tricky terrain, and fashion weapons from whatever is at hand.</li>
		</ul>','1998. HALF-LIFE sends a shock through the game industry with its combination of pounding action and continuous, immersive storytelling. Valve''s debut title wins more than 50 game-of-the-year awards on its way to being named "Best PC Game Ever" by PC Gamer, and launches a franchise with more than eight million retail units sold worldwide.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (240,'THE NEXT INSTALLMENT OF THE WORLD''S # 1 ONLINE ACTION GAME <br>Counter-Strike: Source blends Counter-Strike''s award-winning teamplay action with the advanced technology of Source&trade; technology. Featuring state of the art graphics, all new sounds, and introducing physics, Counter-Strike: Source is a must-have for every action gamer.','THE NEXT INSTALLMENT OF THE WORLD''S # 1 ONLINE ACTION GAME <br>Counter-Strike: Source blends Counter-Strike''s award-winning teamplay action with the advanced technology of Source&trade; technology. Featuring state of the art graphics, all new sounds, and introducing physics, Counter-Strike: Source is a must-have for every action gamer.','Just updated to include player stats, achievements, new scoreboards and more!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (280,'Winner of over 50 Game of the Year awards, Half-Life set new standards for action games when it was released in 1998. Half-Life: Source is a digitally remastered version of the critically acclaimed and best selling PC game, enhanced via Source technology to include physics simulation, enhanced effects, and more.','Winner of over 50 Game of the Year awards, Half-Life set new standards for action games when it was released in 1998. Half-Life: Source is a digitally remastered version of the critically acclaimed and best selling PC game, enhanced via Source technology to include physics simulation, enhanced effects, and more.','Winner of over 50 Game of the Year awards, Half-Life set new standards for action games when it was released in 1998. Half-Life: Source is a digitally remastered version of the critically acclaimed and best selling PC game, enhanced via Source technology to include physics simulation, enhanced effects, and more.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (300,'Day of Defeat offers intense online action gameplay set in Europe during WWII. Assume the role of infantry, sniper or machine-gunner classes, and more. DoD:S features enhanced graphics and sounds design to leverage the power of Source, Valve''s new engine technology.','Day of Defeat offers intense online action gameplay set in Europe during WWII. Assume the role of infantry, sniper or machine-gunner classes, and more. DoD:S features enhanced graphics and sounds design to leverage the power of Source, Valve''s new engine technology.','Valve''s WWII Multiplayer Classic - Now available for Mac.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (320,'Fast multiplayer action set in the Half-Life 2 universe! HL2''s physics adds a new dimension to deathmatch play. Play straight deathmatch or try Combine vs. Resistance teamplay. Toss a toilet at your friend today!','Fast multiplayer action set in the Half-Life 2 universe! HL2''s physics adds a new dimension to deathmatch play. Play straight deathmatch or try Combine vs. Resistance teamplay. Toss a toilet at your friend today!','Fast multiplayer action set in the Half-Life 2 universe! HL2''s physics adds a new dimension to deathmatch play. Play straight deathmatch or try Combine vs. Resistance teamplay. Toss a toilet at your friend today!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (340,'Originally planned as a section of the Highway 17 chapter of Half-Life 2, Lost Coast is a playable technology showcase that introduces High Dynamic Range lighting to the Source engine.','Originally planned as a section of the Highway 17 chapter of Half-Life 2, Lost Coast is a playable technology showcase that introduces High Dynamic Range lighting to the Source engine.','Originally planned as a section of the Highway 17 chapter of Half-Life 2, Lost Coast is a playable technology showcase that introduces High Dynamic Range lighting to the Source engine.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (360,'Half-Life Deathmatch: Source is a recreation of the first multiplayer game set in the Half-Life universe. Features all the classic weapons and most-played maps, now running on the Source engine.','Half-Life Deathmatch: Source is a recreation of the first multiplayer game set in the Half-Life universe. Features all the classic weapons and most-played maps, now running on the Source engine.','Half-Life Deathmatch: Source is a recreation of the first multiplayer game set in the Half-Life universe. Features all the classic weapons and most-played maps, now running on the Source engine.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (380,'Half-Life 2 has sold over 4 million copies worldwide, and earned over 35 Game of the Year Awards. Episode One is the first in a series of games that reveal the aftermath of Half-Life 2 and launch a journey beyond City 17. Also features two multiplayer games. Half-Life 2 not required.','Half-Life 2 has sold over 4 million copies worldwide, and earned over 35 Game of the Year Awards. Episode One is the first in a series of games that reveal the aftermath of Half-Life 2 and launch a journey beyond City 17. Also features two multiplayer games. Half-Life 2 not required.','Half-Life 2 has sold over 4 million copies worldwide, and earned over 35 Game of the Year Awards. Episode One is the first in a series of games that reveal the aftermath of Half-Life 2 and launch a journey beyond City 17. Also features two multiplayer games. Half-Life 2 not required.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (400,'<p>Portal&trade; is a new single player game from Valve. Set in the mysterious Aperture Science Laboratories, Portal has been called one of the most innovative new games on the horizon and will offer gamers hours of unique gameplay.</p>
					<p>The game is designed to change the way players approach, manipulate, and surmise the possibilities in a given environment; similar to how Half-Life&reg; 2''s Gravity Gun innovated new ways to leverage an object in any given situation.</p>
					<p>Players must solve physical puzzles and challenges by opening portals to maneuvering objects, and themselves, through space.</p>','<p>Portal&trade; is a new single player game from Valve. Set in the mysterious Aperture Science Laboratories, Portal has been called one of the most innovative new games on the horizon and will offer gamers hours of unique gameplay.</p>
					<p>The game is designed to change the way players approach, manipulate, and surmise the possibilities in a given environment; similar to how Half-Life&reg; 2''s Gravity Gun innovated new ways to leverage an object in any given situation.</p>
					<p>Players must solve physical puzzles and challenges by opening portals to maneuvering objects, and themselves, through space.</p>','Portal&trade; is a new single player game from Valve. Set in the mysterious Aperture Science Laboratories, Portal has been called one of the most innovative new games on the horizon and will offer gamers hours of unique gameplay.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (420,'<p>Half-Life&reg; 2: Episode Two is the second in a trilogy of new games created by Valve that extends the award-winning and best-selling Half-Life&reg; adventure.</p>
					<p>As Dr. Gordon Freeman, you were last seen exiting City 17 with Alyx Vance as the Citadel erupted amidst a storm of unknown proportions. In Episode Two, you must battle and race against Combine forces as you traverse the White Forest to deliver a crucial information packet stolen from the Citadel to an enclave of fellow resistance scientists.</p>
					<p>Episode Two extends the award-winning Half-Life gameplay with unique weapons, vehicles, and newly-spawned creatures.</p>','<p>Half-Life&reg; 2: Episode Two is the second in a trilogy of new games created by Valve that extends the award-winning and best-selling Half-Life&reg; adventure.</p>
					<p>As Dr. Gordon Freeman, you were last seen exiting City 17 with Alyx Vance as the Citadel erupted amidst a storm of unknown proportions. In Episode Two, you must battle and race against Combine forces as you traverse the White Forest to deliver a crucial information packet stolen from the Citadel to an enclave of fellow resistance scientists.</p>
					<p>Episode Two extends the award-winning Half-Life gameplay with unique weapons, vehicles, and newly-spawned creatures.</p>','Half-Life&reg; 2: Episode Two is the second in a trilogy of new games created by Valve that extends the award-winning and best-selling Half-Life&reg; adventure. As Dr. Gordon Freeman, you were last seen exiting City 17 with Alyx Vance as the Citadel erupted amidst a storm of unknown proportions.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (440,'<h1>The Jungle Inferno Update</h1><p><a href="https://steamcommunity.com/linkfilter/?url=http://www.teamfortress.com/jungleinferno/" target="_blank" rel="noopener"  >Play the all-new Jungle Inferno Campaign! </a><br><ul class="bb_ul"><li> 1 new official map: Mercenary Park<br></li><li> 5 featured community maps: Mossrock, Lazarus, Brazil, Enclosure, and Banana Bay<br></li><li> 2 new official taunts: Yeti Punch and Yeti Smash<br></li><li> 5 new community taunts: The Dueling Banjo, The Jumping Jack, The Soviet Strongarm, The Russian Arms Race, and The Headcase<br></li><li> 2 community cosmetic cases with 20 items each<br></li><li> 2 new War Paint collections made up of community-made War Paints and official War Paints<br></li><li> 2 new War Paint collections filled with classic weapon skins being brought back for another tour<br></li><li> 4 new Pyro items: The Dragon''s Fury, The Thermal Thruster (with a new kill taunt: The Gas Blast), The Gas Passer, and the Hot Hand<br></li><li> 1 new Heavy item: The Second Banana<br></li><li> Free contracts to earn the new Pyro and Heavy items<br></li><li> 36 campaign contracts</li></ul><a href="https://steamcommunity.com/linkfilter/?url=http://www.teamfortress.com/jungleinferno/" target="_blank" rel="noopener"  ><img src="https://steamcdn-a.akamaihd.net/steam/apps/440/extras/jungle_inferno_blog.jpg?t=1539304875" ></a></p><br><h1>About the Game</h1><p><strong>"The most fun you can have online"</strong> - PC Gamer<br><br>									 <strong>Is now FREE!</strong><br><br>									 There’s no catch! Play as much as you want, as long as you like!</p><br>									 <p><strong>The most highly-rated free game of all time!</strong><br><br>									 One of the most popular online action games of all time, Team Fortress 2 delivers constant free updates—new game modes, maps, equipment and, most importantly, hats. Nine distinct classes provide a broad range of tactical abilities and personalities, and lend themselves to a variety of player skills.</p><br>									 <p><strong>New to TF? Don’t sweat it!</strong><br><br>									 No matter what your style and experience, we’ve got a character for you. Detailed training and offline practice modes will help you hone your skills before jumping into one of TF2’s many game modes, including Capture the Flag, Control Point, Payload, Arena, King of the Hill and more.</p><br>									 <p><strong>Make a character your own!</strong><br><br>									 There are hundreds of weapons, hats and more to collect, craft, buy and trade. Tweak your favorite class to suit your gameplay style and personal taste. You don’t need to pay to win—virtually all of the items in the Mann Co. Store can also be found in-game.</p><br>									<a href="<a href="https://steamcommunity.com/linkfilter/?url=http://www.teamfortress.com/freetoplay" target="_blank" rel="noopener"  >http://www.teamfortress.com/freetoplay</a>"><img src="<a href="http://storefront.steampowered.com/v/gfx/apps/440/extras/page_banner_english1.jpg" target="_blank" rel="noreferrer"  >http://storefront.steampowered.com/v/gfx/apps/440/extras/page_banner_english1.jpg</a>"></a><br>','<p><strong>"The most fun you can have online"</strong> - PC Gamer<br>
									 <strong>Is now FREE!</strong><br>
									 There’s no catch! Play as much as you want, as long as you like!</p>
									 <p><strong>The most highly-rated free game of all time!</strong><br>
									 One of the most popular online action games of all time, Team Fortress 2 delivers constant free updates—new game modes, maps, equipment and, most importantly, hats. Nine distinct classes provide a broad range of tactical abilities and personalities, and lend themselves to a variety of player skills.</p>
									 <p><strong>New to TF? Don’t sweat it!</strong><br>
									 No matter what your style and experience, we’ve got a character for you. Detailed training and offline practice modes will help you hone your skills before jumping into one of TF2’s many game modes, including Capture the Flag, Control Point, Payload, Arena, King of the Hill and more.</p>
									 <p><strong>Make a character your own!</strong><br>
									 There are hundreds of weapons, hats and more to collect, craft, buy and trade. Tweak your favorite class to suit your gameplay style and personal taste. You don’t need to pay to win—virtually all of the items in the Mann Co. Store can also be found in-game.</p>
									<a href="http://www.teamfortress.com/freetoplay"><img src="http://storefront.steampowered.com/v/gfx/apps/440/extras/page_banner_english1.jpg"></a>','Nine distinct classes provide a broad range of tactical abilities and personalities. Constantly updated with new game modes, maps, equipment and, most importantly, hats!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (500,'From Valve (the creators of Counter-Strike, Half-Life and more) comes Left 4 Dead, a co-op action horror game for the PC and Xbox 360 that casts up to four players in an epic struggle for survival against swarming zombie hordes and terrifying mutant monsters.                    <br>					Set in the immediate aftermath of the zombie apocalypse, L4D''s survival co-op mode lets you blast a path through the infected in four unique “movies,” guiding your survivors across the rooftops of an abandoned metropolis, through rural ghost towns and pitch-black forests in your quest to escape a devastated Ground Zero crawling with infected enemies. Each &quot;movie&quot; is comprised of five large maps, and can be played by one to four human players, with an emphasis on team-based strategy and objectives.                     <br>					New technology dubbed &quot;the AI Director&quot; is used to generate a unique gameplay experience every time you play. The Director tailors the frequency and ferocity of the zombie attacks to your performance, putting you in the middle of a fast-paced, but not overwhelming, Hollywood horror movie.                    <br>					<ul class="bb_ul"><li>Addictive single player, co-op, and multiplayer action gameplay from the makers of Counter-Strike and Half-Life                    <br>					</li><li>Versus Mode lets you compete four-on-four with friends, playing as a human trying to get rescued, or as a zombie boss monster that will stop at nothing to destroy them.<br>					</li><li>See how long you and your friends can hold out against the infected horde in the new Survival Mode<br>					</li><li>An advanced AI director dynamically creates intense and unique experiences every time the game is played                     <br>					</li><li>20 maps, 10 weapons and unlimited possibilities in four sprawling &quot;movies&quot;                     <br>					</li><li>Matchmaking, stats, rankings, and awards system drive collaborative play                     <br>					</li><li>Designer''s Commentary allows gamers to go &quot;behind the scenes&quot; of the game                     <br>					</li><li>Powered by Source and Steam                     </li></ul><h2 class="bb_tag">THE SACRIFICE</h2><img src="https://steamcdn-a.akamaihd.net/steam/apps/550/extras/pageRibbon.jpg" >&quot;The Sacrifice” is  the new add-on for Left 4 Dead.<br><br>&quot;The Sacrifice&quot; is the prequel to &quot;The Passing,&quot; and takes place from the L4D Survivors'' perspective as they make their way South. In addition to advancing the story, &quot;The Sacrifice&quot; introduces a new style finale featuring &quot;Sacrificial Gameplay&quot; where players get to decide who will give their life so the others may live.<br><br>In The Sacrifice for Left 4 Dead owners receive &quot;The Sacrifice&quot; campaign playable in Campaign, Versus,  and Survival modes.','From Valve (the creators of Counter-Strike, Half-Life and more) comes Left 4 Dead, a co-op action horror game for the PC and Xbox 360 that casts up to four players in an epic struggle for survival against swarming zombie hordes and terrifying mutant monsters.                    <br>					Set in the immediate aftermath of the zombie apocalypse, L4D''s survival co-op mode lets you blast a path through the infected in four unique “movies,” guiding your survivors across the rooftops of an abandoned metropolis, through rural ghost towns and pitch-black forests in your quest to escape a devastated Ground Zero crawling with infected enemies. Each &quot;movie&quot; is comprised of five large maps, and can be played by one to four human players, with an emphasis on team-based strategy and objectives.                     <br>					New technology dubbed &quot;the AI Director&quot; is used to generate a unique gameplay experience every time you play. The Director tailors the frequency and ferocity of the zombie attacks to your performance, putting you in the middle of a fast-paced, but not overwhelming, Hollywood horror movie.                    <br>					<ul class="bb_ul"><li>Addictive single player, co-op, and multiplayer action gameplay from the makers of Counter-Strike and Half-Life                    <br>					</li><li>Versus Mode lets you compete four-on-four with friends, playing as a human trying to get rescued, or as a zombie boss monster that will stop at nothing to destroy them.<br>					</li><li>See how long you and your friends can hold out against the infected horde in the new Survival Mode<br>					</li><li>An advanced AI director dynamically creates intense and unique experiences every time the game is played                     <br>					</li><li>20 maps, 10 weapons and unlimited possibilities in four sprawling &quot;movies&quot;                     <br>					</li><li>Matchmaking, stats, rankings, and awards system drive collaborative play                     <br>					</li><li>Designer''s Commentary allows gamers to go &quot;behind the scenes&quot; of the game                     <br>					</li><li>Powered by Source and Steam                     </li></ul><h2 class="bb_tag">THE SACRIFICE</h2><img src="https://steamcdn-a.akamaihd.net/steam/apps/550/extras/pageRibbon.jpg" >&quot;The Sacrifice” is  the new add-on for Left 4 Dead.<br><br>&quot;The Sacrifice&quot; is the prequel to &quot;The Passing,&quot; and takes place from the L4D Survivors'' perspective as they make their way South. In addition to advancing the story, &quot;The Sacrifice&quot; introduces a new style finale featuring &quot;Sacrificial Gameplay&quot; where players get to decide who will give their life so the others may live.<br><br>In The Sacrifice for Left 4 Dead owners receive &quot;The Sacrifice&quot; campaign playable in Campaign, Versus,  and Survival modes.','From Valve (the creators of Counter-Strike, Half-Life and more) comes Left 4 Dead, a co-op action horror game for the PC and Xbox 360 that casts up to four players in an epic struggle for survival against swarming zombie hordes and terrifying mutant monsters.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (550,'Set in the zombie apocalypse, Left 4 Dead 2 (L4D2) is the highly anticipated sequel to the award-winning Left 4 Dead, the #1 co-op game of 2008.<br>                    This co-operative action horror FPS takes you and your friends through the cities, swamps and cemeteries of the Deep South, from Savannah to New Orleans across five expansive campaigns.<br>                    You''ll play as one of four new survivors armed with a wide and devastating array of classic and upgraded weapons. In addition to firearms, you''ll also get a chance to take out some aggression on infected with a variety of carnage-creating melee weapons, from chainsaws to axes and even the deadly frying pan.<br>                    You''ll be putting these weapons to the test against (or playing as in Versus) three horrific and formidable new Special Infected. You''ll also encounter five new uncommon common infected, including the terrifying Mudmen.<br>                    Helping to take L4D''s frantic, action-packed gameplay to the next level is AI Director 2.0. This improved Director has the ability to procedurally change the weather you''ll fight through and the pathways you''ll take, in addition to tailoring the enemy population, effects, and sounds to match your performance. L4D2 promises a satisfying and uniquely challenging experience every time the game is played, custom-fitted to your style of play.<br>                    <ul class="bb_ul"><li>Next generation co-op action gaming from the makers of Half-Life, Portal, Team Fortress and Counter-Strike.<br>                    </li><li>Over 20 new weapons &amp; items headlined by over 10 melee weapons – axe, chainsaw, frying pan, baseball bat – allow you to get up close with the zombies<br>                    </li><li>New survivors. New Story. New dialogue. <br>                    </li><li>Five expansive campaigns for co-operative, Versus and Survival game modes.<br>                    </li><li>An all new multiplayer mode.<br>                    </li><li>Uncommon common infected. Each of the five new campaigns contains at least one new uncommon common zombies which are exclusive to that campaign. <br>                    </li><li>AI Director 2.0: Advanced technology dubbed The AI Director drove L4D''s unique gameplay – customizing enemy population, effects, and music, based upon the players’ performance. L4D 2 features The AI Director 2.0 which expands the Director’s ability to customize level layout, world objects, weather, and lighting to reflect different times of day.<br>                    </li><li>Stats, rankings, and awards system drives collaborative play<br>                    </li></ul>','Set in the zombie apocalypse, Left 4 Dead 2 (L4D2) is the highly anticipated sequel to the award-winning Left 4 Dead, the #1 co-op game of 2008.<br>                    This co-operative action horror FPS takes you and your friends through the cities, swamps and cemeteries of the Deep South, from Savannah to New Orleans across five expansive campaigns.<br>                    You''ll play as one of four new survivors armed with a wide and devastating array of classic and upgraded weapons. In addition to firearms, you''ll also get a chance to take out some aggression on infected with a variety of carnage-creating melee weapons, from chainsaws to axes and even the deadly frying pan.<br>                    You''ll be putting these weapons to the test against (or playing as in Versus) three horrific and formidable new Special Infected. You''ll also encounter five new uncommon common infected, including the terrifying Mudmen.<br>                    Helping to take L4D''s frantic, action-packed gameplay to the next level is AI Director 2.0. This improved Director has the ability to procedurally change the weather you''ll fight through and the pathways you''ll take, in addition to tailoring the enemy population, effects, and sounds to match your performance. L4D2 promises a satisfying and uniquely challenging experience every time the game is played, custom-fitted to your style of play.<br>                    <ul class="bb_ul"><li>Next generation co-op action gaming from the makers of Half-Life, Portal, Team Fortress and Counter-Strike.<br>                    </li><li>Over 20 new weapons &amp; items headlined by over 10 melee weapons – axe, chainsaw, frying pan, baseball bat – allow you to get up close with the zombies<br>                    </li><li>New survivors. New Story. New dialogue. <br>                    </li><li>Five expansive campaigns for co-operative, Versus and Survival game modes.<br>                    </li><li>An all new multiplayer mode.<br>                    </li><li>Uncommon common infected. Each of the five new campaigns contains at least one new uncommon common zombies which are exclusive to that campaign. <br>                    </li><li>AI Director 2.0: Advanced technology dubbed The AI Director drove L4D''s unique gameplay – customizing enemy population, effects, and music, based upon the players’ performance. L4D 2 features The AI Director 2.0 which expands the Director’s ability to customize level layout, world objects, weather, and lighting to reflect different times of day.<br>                    </li><li>Stats, rankings, and awards system drives collaborative play<br>                    </li></ul>','Set in the zombie apocalypse, Left 4 Dead 2 (L4D2) is the highly anticipated sequel to the award-winning Left 4 Dead, the #1 co-op game of 2008. This co-operative action horror FPS takes you and your friends through the cities, swamps and cemeteries of the Deep South, from Savannah to New Orleans across five expansive campaigns.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (570,'<strong>The most-played game on Steam.</strong><br>Every day, millions of players worldwide enter battle as one of over a hundred Dota heroes. And no matter if it''s their 10th hour of play or 1,000th, there''s always something new to discover. With regular updates that ensure a constant evolution of gameplay, features, and heroes, Dota 2 has truly taken on a life of its own.<br><br><strong>One Battlefield. Infinite Possibilities.</strong><br>When it comes to diversity of heroes, abilities, and powerful items, Dota boasts an endless array—no two games are the same. Any hero can fill multiple roles, and there''s an abundance of items to help meet the needs of each game. Dota doesn''t provide limitations on how to play, it empowers you to express your own style.<br><br><strong>All heroes are free.</strong><br>Competitive balance is Dota''s crown jewel, and to ensure everyone is playing on an even field, the core content of the game—like the vast pool of heroes—is available to all players. Fans can collect cosmetics for heroes and fun add-ons for the world they inhabit, but everything you need to play is already included before you join your first match.<br><br><strong>Bring your friends and party up.</strong><br>Dota is deep, and constantly evolving, but it''s never too late to join. <br>Learn the ropes playing co-op vs. bots. Sharpen your skills in the hero demo mode. Jump into the behavior- and skill-based matchmaking system that ensures you''ll <br>be matched with the right players each game.','<strong>The most-played game on Steam.</strong><br>Every day, millions of players worldwide enter battle as one of over a hundred Dota heroes. And no matter if it''s their 10th hour of play or 1,000th, there''s always something new to discover. With regular updates that ensure a constant evolution of gameplay, features, and heroes, Dota 2 has truly taken on a life of its own.<br><br><strong>One Battlefield. Infinite Possibilities.</strong><br>When it comes to diversity of heroes, abilities, and powerful items, Dota boasts an endless array—no two games are the same. Any hero can fill multiple roles, and there''s an abundance of items to help meet the needs of each game. Dota doesn''t provide limitations on how to play, it empowers you to express your own style.<br><br><strong>All heroes are free.</strong><br>Competitive balance is Dota''s crown jewel, and to ensure everyone is playing on an even field, the core content of the game—like the vast pool of heroes—is available to all players. Fans can collect cosmetics for heroes and fun add-ons for the world they inhabit, but everything you need to play is already included before you join your first match.<br><br><strong>Bring your friends and party up.</strong><br>Dota is deep, and constantly evolving, but it''s never too late to join. <br>Learn the ropes playing co-op vs. bots. Sharpen your skills in the hero demo mode. Jump into the behavior- and skill-based matchmaking system that ensures you''ll <br>be matched with the right players each game.','Every day, millions of players worldwide enter battle as one of over a hundred Dota heroes. And no matter if it''s their 10th hour of play or 1,000th, there''s always something new to discover. With regular updates that ensure a constant evolution of gameplay, features, and heroes, Dota 2 has taken on a life of its own.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (620,'Portal 2 draws from the award-winning formula of innovative gameplay, story, and music that earned the original Portal over 70 industry accolades and created a cult following.<br><br>										The single-player portion of Portal 2 introduces a cast of dynamic new characters, a host of fresh puzzle elements, and a much larger set of devious test chambers. Players will explore never-before-seen areas of the Aperture Science Labs and be reunited with GLaDOS, the occasionally murderous computer companion who guided them through the original game.<br>										<br>										The game’s two-player cooperative mode features its own entirely separate campaign with a unique story, test chambers, and two new player characters. This new mode forces players to reconsider everything they thought they knew about portals. Success will require them to not just act cooperatively, but to think cooperatively.<br>										<br>										<strong>Product Features</strong><br>										<ul class="bb_ul"><li><strong>Extensive single player:</strong> Featuring next generation gameplay and a wildly-engrossing story.<br>										</li><li><strong>Complete two-person co-op:</strong> Multiplayer game featuring its own dedicated story, characters, and gameplay.<br>										</li><li><strong>Advanced physics:</strong> Allows for the creation of a whole new range of interesting challenges, producing a much larger but not harder game.<br>										</li><li><strong>Original music.</strong><br>										</li><li><strong>Massive sequel:</strong> The original Portal was named 2007''s Game of the Year by over 30 publications worldwide. <br>										</li><li><strong>Editing Tools:</strong> Portal 2 editing tools will be included.<br>										</li></ul>','Portal 2 draws from the award-winning formula of innovative gameplay, story, and music that earned the original Portal over 70 industry accolades and created a cult following.<br><br>										The single-player portion of Portal 2 introduces a cast of dynamic new characters, a host of fresh puzzle elements, and a much larger set of devious test chambers. Players will explore never-before-seen areas of the Aperture Science Labs and be reunited with GLaDOS, the occasionally murderous computer companion who guided them through the original game.<br>										<br>										The game’s two-player cooperative mode features its own entirely separate campaign with a unique story, test chambers, and two new player characters. This new mode forces players to reconsider everything they thought they knew about portals. Success will require them to not just act cooperatively, but to think cooperatively.<br>										<br>										<strong>Product Features</strong><br>										<ul class="bb_ul"><li><strong>Extensive single player:</strong> Featuring next generation gameplay and a wildly-engrossing story.<br>										</li><li><strong>Complete two-person co-op:</strong> Multiplayer game featuring its own dedicated story, characters, and gameplay.<br>										</li><li><strong>Advanced physics:</strong> Allows for the creation of a whole new range of interesting challenges, producing a much larger but not harder game.<br>										</li><li><strong>Original music.</strong><br>										</li><li><strong>Massive sequel:</strong> The original Portal was named 2007''s Game of the Year by over 30 publications worldwide. <br>										</li><li><strong>Editing Tools:</strong> Portal 2 editing tools will be included.<br>										</li></ul>','The &quot;Perpetual Testing Initiative&quot; has been expanded to allow you to design co-op puzzles for you and your friends!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (630,'Alien Swarm is a game and Source SDK release from a group of talented designers at Valve who were hired from the Mod community.<br>					Available free of charge, the game thrusts players into an epic bug hunt featuring a unique blend of co-op play and squad-level tactics. With your friends, form a squad of four distinct IAF Marine classes. Plan your attack using an unlockable arsenal of weapons with countless loadout configurations against a wide variety of aliens. Blaze your way through an overrun, off-world colony, eradicating the alien infestation in environments ranging from the icy planet''s surface, to a subterranean lava-flooded mining facility.<br>					Along with the game get the complete code base for Alien Swarm that features updates to the Source engine as well as the SDK. Alien Swarm adds 3rd person camera, depth of field, improved dynamic shadows and a wide variety of gameplay additions to the Source engine.<br>					<ul class="bb_ul"><li>Tactical, 4 player co-op action game with a top-down perspective <br>					</li><li>Complete game code and mod tools <br>					</li><li>Unlock persistent items by gaining levels <br>					</li><li>Over 40 weapons and equipment with countless loadout configurations <br>					</li><li>4 unique classes and 8 unique characters <br>					</li><li>Matchmaking, Steam Cloud, Steam Stats <br>					</li><li>64 achievements <br>					</li><li>Tile-based map generation tool <br>					</li><li>Powered by Source and Steam <br>					</li></ul>','Alien Swarm is a game and Source SDK release from a group of talented designers at Valve who were hired from the Mod community.<br>					Available free of charge, the game thrusts players into an epic bug hunt featuring a unique blend of co-op play and squad-level tactics. With your friends, form a squad of four distinct IAF Marine classes. Plan your attack using an unlockable arsenal of weapons with countless loadout configurations against a wide variety of aliens. Blaze your way through an overrun, off-world colony, eradicating the alien infestation in environments ranging from the icy planet''s surface, to a subterranean lava-flooded mining facility.<br>					Along with the game get the complete code base for Alien Swarm that features updates to the Source engine as well as the SDK. Alien Swarm adds 3rd person camera, depth of field, improved dynamic shadows and a wide variety of gameplay additions to the Source engine.<br>					<ul class="bb_ul"><li>Tactical, 4 player co-op action game with a top-down perspective <br>					</li><li>Complete game code and mod tools <br>					</li><li>Unlock persistent items by gaining levels <br>					</li><li>Over 40 weapons and equipment with countless loadout configurations <br>					</li><li>4 unique classes and 8 unique characters <br>					</li><li>Matchmaking, Steam Cloud, Steam Stats <br>					</li><li>64 achievements <br>					</li><li>Tile-based map generation tool <br>					</li><li>Powered by Source and Steam <br>					</li></ul>','Co-operative multiplayer game and complete code base available for free.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (730,'Counter-Strike: Global Offensive (CS: GO) expands upon the team-based action gameplay that it pioneered when it was launched 19 years ago.<br />
<br />
CS: GO features new maps, characters, weapons, and game modes, and delivers updated versions of the classic CS content (de_dust2, etc.).<br />
<br />
&quot;Counter-Strike took the gaming industry by surprise when the unlikely MOD became the most played online PC action game in the world almost immediately after its release in August 1999,&quot; said Doug Lombardi at Valve. &quot;For the past 12 years, it has continued to be one of the most-played games in the world, headline competitive gaming tournaments and selling over 25 million units worldwide across the franchise. CS: GO promises to expand on CS'' award-winning gameplay and deliver it to gamers on the PC as well as the next gen consoles and the Mac.&quot;','Counter-Strike: Global Offensive (CS: GO) expands upon the team-based action gameplay that it pioneered when it was launched 19 years ago.<br />
<br />
CS: GO features new maps, characters, weapons, and game modes, and delivers updated versions of the classic CS content (de_dust2, etc.).<br />
<br />
&quot;Counter-Strike took the gaming industry by surprise when the unlikely MOD became the most played online PC action game in the world almost immediately after its release in August 1999,&quot; said Doug Lombardi at Valve. &quot;For the past 12 years, it has continued to be one of the most-played games in the world, headline competitive gaming tournaments and selling over 25 million units worldwide across the franchise. CS: GO promises to expand on CS'' award-winning gameplay and deliver it to gamers on the PC as well as the next gen consoles and the Mac.&quot;','Counter-Strike: Global Offensive (CS: GO) expands upon the team-based action gameplay that it pioneered when it was launched 19 years ago. CS: GO features new maps, characters, weapons, and game modes, and delivers updated versions of the classic CS content (de_dust2, etc.).');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1002,'Featuring a wide collection of single and multiplayer games, either online or with multiple mice, Rag Doll Kung Fu provides players with one of the most creative and unique game experiences delivered in years. Additionally, between those game rounds, the challenges of an aspiring Kung Fu master are revealed via outlandish cut scenes inspired by classic Kung Fu cinema.','Featuring a wide collection of single and multiplayer games, either online or with multiple mice, Rag Doll Kung Fu provides players with one of the most creative and unique game experiences delivered in years. Additionally, between those game rounds, the challenges of an aspiring Kung Fu master are revealed via outlandish cut scenes inspired by classic Kung Fu cinema.','Featuring a wide collection of single and multiplayer games, either online or with multiple mice, Rag Doll Kung Fu provides players with one of the most creative and unique game experiences delivered in years.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1200,'<h1>D-Day Anniversary 2016 Update for Darkest Hour</h1><p>To commemorate the 72nd anniversary of the D-Day landings in Normandy, we have added a total of five new official maps for the Darkest Hour mod!<br><br><ul class="bb_ul"><li>La Cambe (50+ players)<br></li><li>St-Clement (32+ players)<br></li><li>Dead Man’s Corner (8-16 players)<br></li><li>Vierville (16-32 players)<br></li><li>Foucarville (8-16 players)</li></ul><br>If you own RO:Ostfront the mod is completely free to you. To get your copy, simply head for the store page: <a href="http://store.steampowered.com/app/1280/" target="_blank" rel="noreferrer"  >HERE</a></p><br><h1>About the Game</h1>Fight in the theatre of war that changed the world forever. Battle alongside your compatriots on some of the most inhospitable environments of the Eastern Front in Red Orchestra: Ostfront 41-45. Red Orchestra places you in the most realistic WWII first-person multi-player combat to date on the PC, allowing the player to fight through some of the most intense combat of the war. You can play as infantry, using a wide range of infantry weapons, or crew one of the many armored combat vehicles available in the game, from half-tracks to the most famous German and Soviet heavy tanks. Engage the enemy with everything in your arsenal, from your bayonet at close quarters up to the massive 122mm cannon on the Soviet IS-2. And if that isn''t enough, find an officer and a radio to call in thunderous artillery strikes to shake the enemy loose.<br>					<ul class="bb_ul"><li>Crew 16 fully realized vehicles with highly detailed exterior and interior models <br>					</li><li>Choose from 30 authentic infantry weapons <br>					</li><li>Full 50+ player online Multiplayer Support<br>					</li><li>Unique Setting - the only FPS to focus on the WWII Russian Front<br>					</li><li>Engage enemy tanks at 800 metres and more with the Simulation-level armored vehicle combat<br>					</li><li>Fight the full range of combined arms infantry and vehicle combat in detailed environments based on real-world data, from city-centre to deeply rural settings <br>					</li><li>Realistic bullet and projectile ballistics will make you duck for cover <br>					</li><li>Coordinate strategies with your team-mates via Voice Over IP <br>					</li><li>Authentic Immersive Sound FX and 3d Positional Sound System <br>					</li><li>3D ''Iron Sights'' and unique 3D scope system <br>					</li><li>True weapon deployment system including resting rifles on support<br>					</li><li>Historically accurate artillery system <br>					</li><li>Distance-based sound system dynamically creates the battle ambiance<br>					</li><li>Advanced player movement system featuring diving over obstacles and leaning <br>					</li><li>Custom 8 way animation system for highly realistic player animations </li></ul>New for Summer ''07<br>					This update includes a new map, a new vehicle and some major graphical enhancements to the game and is available to owners of the game for free through Steam. The new map - Krivoi Rog - gives players the largest tank slugfest to date, with 16 square kilometers of terrain, 3000 meter viewable range and up to 50 players. This map also features the new vehicle - the German Panzer IV G, providing the German players with some additional fire-power for the mid-war period.<br>					In addition to the new map and vehicle, an all-new adaptive bloom system has been added for the game''s graphics, making the bloom crystal-clear even at low resolutions. For further eye-candy, Anti-Aliasing and Anisotropic Filtering settings are now configurable in-game.<br>					New for Spring ''07<br>					<ul class="bb_ul"><li>Ten new maps, the winning entries in Tripwire''s Custom Map Competition. Tripwire worked with the developers of each of these maps to ensure the maps are optimized, polished, and gameplay balanced. Highlights in the new map-pack include:<br>					</li><li><strong>&quot;Smolensk Stalemate&quot;:</strong> the contest winning map features perfectly balanced to-and-fro infantry combat through ruined villages and trenches in August 1943.<br><strong>&quot;Leningrad&quot;:</strong> features close-quarters infantry fighting in the ruined streets of the city, above them in the bombed-out buildings and deep beneath them in the sewers, all with close-in armor support.<br><strong>&quot;Berezina&quot;:</strong> the After-Hourz team surpass themselves on this rural/village map, introducing not just a new vehicle (the Russian BT-7 light tank), but also the first functional anti-tank gun in the game. To cap it off, the BT-7 even carries tank-riders.<br><strong>&quot;Black Day July&quot;:</strong> one of the very best for tank combat fans, set in the rolling countryside around Prokhorovka as German and Russian armor clash en masse during the Battle of Kursk.<br>					</li><li>Increased player limits. A new level of intensity with 50+ player multiplayer battles (up from the previous limit of 32).<br>					</li><li>New community made content, including the Russian BT-7 light tank with infantry tank riders and the first player controllable anti-tank gun in the game.<br>					</li><li>New soundtrack: The &quot;Orchestra&quot; comes to the Ostfront - the game now features a complete in-game soundtrack from composer Matthew Burns.<br>					</li><li>Gameplay enhancements. The addition of several features requested by the clan/ladder/league community to enhance competitive play.</li></ul>','Fight in the theatre of war that changed the world forever. Battle alongside your compatriots on some of the most inhospitable environments of the Eastern Front in Red Orchestra: Ostfront 41-45. Red Orchestra places you in the most realistic WWII first-person multi-player combat to date on the PC, allowing the player to fight through some of the most intense combat of the war. You can play as infantry, using a wide range of infantry weapons, or crew one of the many armored combat vehicles available in the game, from half-tracks to the most famous German and Soviet heavy tanks. Engage the enemy with everything in your arsenal, from your bayonet at close quarters up to the massive 122mm cannon on the Soviet IS-2. And if that isn''t enough, find an officer and a radio to call in thunderous artillery strikes to shake the enemy loose.<br>					<ul class="bb_ul"><li>Crew 16 fully realized vehicles with highly detailed exterior and interior models <br>					</li><li>Choose from 30 authentic infantry weapons <br>					</li><li>Full 50+ player online Multiplayer Support<br>					</li><li>Unique Setting - the only FPS to focus on the WWII Russian Front<br>					</li><li>Engage enemy tanks at 800 metres and more with the Simulation-level armored vehicle combat<br>					</li><li>Fight the full range of combined arms infantry and vehicle combat in detailed environments based on real-world data, from city-centre to deeply rural settings <br>					</li><li>Realistic bullet and projectile ballistics will make you duck for cover <br>					</li><li>Coordinate strategies with your team-mates via Voice Over IP <br>					</li><li>Authentic Immersive Sound FX and 3d Positional Sound System <br>					</li><li>3D ''Iron Sights'' and unique 3D scope system <br>					</li><li>True weapon deployment system including resting rifles on support<br>					</li><li>Historically accurate artillery system <br>					</li><li>Distance-based sound system dynamically creates the battle ambiance<br>					</li><li>Advanced player movement system featuring diving over obstacles and leaning <br>					</li><li>Custom 8 way animation system for highly realistic player animations </li></ul>New for Summer ''07<br>					This update includes a new map, a new vehicle and some major graphical enhancements to the game and is available to owners of the game for free through Steam. The new map - Krivoi Rog - gives players the largest tank slugfest to date, with 16 square kilometers of terrain, 3000 meter viewable range and up to 50 players. This map also features the new vehicle - the German Panzer IV G, providing the German players with some additional fire-power for the mid-war period.<br>					In addition to the new map and vehicle, an all-new adaptive bloom system has been added for the game''s graphics, making the bloom crystal-clear even at low resolutions. For further eye-candy, Anti-Aliasing and Anisotropic Filtering settings are now configurable in-game.<br>					New for Spring ''07<br>					<ul class="bb_ul"><li>Ten new maps, the winning entries in Tripwire''s Custom Map Competition. Tripwire worked with the developers of each of these maps to ensure the maps are optimized, polished, and gameplay balanced. Highlights in the new map-pack include:<br>					</li><li><strong>&quot;Smolensk Stalemate&quot;:</strong> the contest winning map features perfectly balanced to-and-fro infantry combat through ruined villages and trenches in August 1943.<br><strong>&quot;Leningrad&quot;:</strong> features close-quarters infantry fighting in the ruined streets of the city, above them in the bombed-out buildings and deep beneath them in the sewers, all with close-in armor support.<br><strong>&quot;Berezina&quot;:</strong> the After-Hourz team surpass themselves on this rural/village map, introducing not just a new vehicle (the Russian BT-7 light tank), but also the first functional anti-tank gun in the game. To cap it off, the BT-7 even carries tank-riders.<br><strong>&quot;Black Day July&quot;:</strong> one of the very best for tank combat fans, set in the rolling countryside around Prokhorovka as German and Russian armor clash en masse during the Battle of Kursk.<br>					</li><li>Increased player limits. A new level of intensity with 50+ player multiplayer battles (up from the previous limit of 32).<br>					</li><li>New community made content, including the Russian BT-7 light tank with infantry tank riders and the first player controllable anti-tank gun in the game.<br>					</li><li>New soundtrack: The &quot;Orchestra&quot; comes to the Ostfront - the game now features a complete in-game soundtrack from composer Matthew Burns.<br>					</li><li>Gameplay enhancements. The addition of several features requested by the clan/ladder/league community to enhance competitive play.</li></ul>','Fight in the theatre of war that changed the world forever. Battle alongside your compatriots on some of the most inhospitable environments of the Eastern Front in Red Orchestra: Ostfront 41-45. Red Orchestra places you in the most realistic WWII first-person multi-player combat to date on the PC, allowing the player to fight through...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1250,'Killing Floor is a Co-op Survival Horror FPS set in the devastated cities and countryside of England after a series of cloning experiments for the military goes horribly wrong. You and your friends are members of the military dropped into these locations with a simple mission: Survive long enough to cleanse the area of the failed experiments!<br>					<ul class="bb_ul"><li>Cooperative gameplay for up to six players against multiple waves of specimens<br>					</li><li>Persistent Perks system, allowing players to convert their in-game achievements into permanent improvements to their character''s skills and abilities <br>					</li><li>Over 170 Steam Achievements, including “Dignity for the dead” for killing 10 enemies feeding on dead teammates'' corpses and “Hot Cross Fun” for finishing off 25 burning enemies with a Crossbow<br>					</li><li>Slow-motion “ZEDtime” to better watch those crucial and violent creature deaths, even in multiplayer <br>					</li><li>Solo game mode for offline play <br>					</li><li>Ten different monster types trying to eat your face off, armed with everything from teeth and claws, to chainsaws, chain-guns and rocket-launchers <br>					</li><li>33+ weapons for the players to chose from, ranging from knives and fire-axes to pump shotguns, rifles and a flamethrower <br>					</li><li>Equip your team with welders, medical tools and body armor to help your odds of survival <br>					</li><li>Choose which Perks to play with to best balance out your co-op team against the horrors <br>					</li><li>Open, non-linear play areas: choose when and where to fight — or run; weld doors closed to direct the monster horde down alternate corridors<br>					</li><li>Fully-configurable, allowing players to change the difficulty level, number of creature waves, or even set up their own favorite waves of monsters <br>					</li><li>Support for Steam Friends and other Steamworks features<br>					</li><li>Includes Windows-only SDK for the creation of new levels and mods<br>					</li></ul>','Killing Floor is a Co-op Survival Horror FPS set in the devastated cities and countryside of England after a series of cloning experiments for the military goes horribly wrong. You and your friends are members of the military dropped into these locations with a simple mission: Survive long enough to cleanse the area of the failed experiments!<br>					<ul class="bb_ul"><li>Cooperative gameplay for up to six players against multiple waves of specimens<br>					</li><li>Persistent Perks system, allowing players to convert their in-game achievements into permanent improvements to their character''s skills and abilities <br>					</li><li>Over 170 Steam Achievements, including “Dignity for the dead” for killing 10 enemies feeding on dead teammates'' corpses and “Hot Cross Fun” for finishing off 25 burning enemies with a Crossbow<br>					</li><li>Slow-motion “ZEDtime” to better watch those crucial and violent creature deaths, even in multiplayer <br>					</li><li>Solo game mode for offline play <br>					</li><li>Ten different monster types trying to eat your face off, armed with everything from teeth and claws, to chainsaws, chain-guns and rocket-launchers <br>					</li><li>33+ weapons for the players to chose from, ranging from knives and fire-axes to pump shotguns, rifles and a flamethrower <br>					</li><li>Equip your team with welders, medical tools and body armor to help your odds of survival <br>					</li><li>Choose which Perks to play with to best balance out your co-op team against the horrors <br>					</li><li>Open, non-linear play areas: choose when and where to fight — or run; weld doors closed to direct the monster horde down alternate corridors<br>					</li><li>Fully-configurable, allowing players to change the difficulty level, number of creature waves, or even set up their own favorite waves of monsters <br>					</li><li>Support for Steam Friends and other Steamworks features<br>					</li><li>Includes Windows-only SDK for the creation of new levels and mods<br>					</li></ul>','6-player co-op survival horror at its finest! Free updates, free special events and a ridiculous amount of fun!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1300,'You are John Blade, commander of HardCorps, an elite security force dedicated to protecting the people of Freeport City. Four years have passed since your first battle with Elexis Sinclaire, a beautiful, brilliant, and ruthless scientist who is out to remake humanity according to her own twisted vision. The law has failed to bring Elexis and her multi-billion dollar empire, SiNTEK, to justice, so Blade is determined to take matters into his own hands. Joining Blade on his mission are JC - a hacker with a secret to keep - and Jessica Cannon, a fiery rookie who can find her way into any secure facility.<br>					Enter the living, breathing world of Freeport City, a futuristic collision of New York, San Francisco and Tokyo. As Freeport continues to suffer from mutant attacks, you must now bring down Sinclaire before she can set her deadly plan in motion and alter the shape of humanity forever.<br>					SiN Episodes™: Emergence launches the new era of episodic gaming. A first person shooter powered by Valve''s award-winning Source™ technology, SiN Episodes offers unprecedented interactivity, an engrossing story, and a revolutionary dynamic difficulty system that provides a custom experience based on your skill level and play style.<br>					<ul class="bb_ul"><li>Intense Combat: Face off against ruthless enemies, like jetpack soldiers and mutants that evolve as you fight them. Witness enemies that adapt to your actions and truly work as a team, as they cover each other and help fallen comrades to get back on their feet.<br>Outsmart your opponents by using your surroundings to your advantage as you set up traps using lethal elements of the environment. Location-based damage rewards accuracy while melee combat moves enable you to get up-close and personal.<br>					</li><li>Unprecedented Interactivity: Blast your way through highly interactive environments powered by an enhanced version of the Source engine. Characters dynamically react to what you''re looking at and the environment. Target and shoot off specific vehicle parts and literally blow cars to pieces. Experience the next level of vehicle combat with a flexible positioning system enabling you to move around the interior with an unprecedented degree of freedom, allowing you to pick the ideal position to attack that enemy position up ahead.<br>					</li><li>Personal Challenge System™: Driven by one of the most elaborate statistics systems ever created, SiN Episodes will constantly adapt to your playing style and offers a challenge that is custom-tailored to your skill level.<br>					</li><li>Episodic Delivery: Buy as little or as much of the game as you want, with each installment offering 3 - 6 hours of action-packed gameplay. But tread lightly, as the choices you make may influence future episodes in unforeseen ways.<br>					</li><li>Source Powered: Utilizing the same engine that powered Half-life® 2, Emergence gives you stunningly gorgeous graphics and intense physics-based gameplay.</li></ul>','You are John Blade, commander of HardCorps, an elite security force dedicated to protecting the people of Freeport City. Four years have passed since your first battle with Elexis Sinclaire, a beautiful, brilliant, and ruthless scientist who is out to remake humanity according to her own twisted vision. The law has failed to bring Elexis and her multi-billion dollar empire, SiNTEK, to justice, so Blade is determined to take matters into his own hands. Joining Blade on his mission are JC - a hacker with a secret to keep - and Jessica Cannon, a fiery rookie who can find her way into any secure facility.<br>					Enter the living, breathing world of Freeport City, a futuristic collision of New York, San Francisco and Tokyo. As Freeport continues to suffer from mutant attacks, you must now bring down Sinclaire before she can set her deadly plan in motion and alter the shape of humanity forever.<br>					SiN Episodes™: Emergence launches the new era of episodic gaming. A first person shooter powered by Valve''s award-winning Source™ technology, SiN Episodes offers unprecedented interactivity, an engrossing story, and a revolutionary dynamic difficulty system that provides a custom experience based on your skill level and play style.<br>					<ul class="bb_ul"><li>Intense Combat: Face off against ruthless enemies, like jetpack soldiers and mutants that evolve as you fight them. Witness enemies that adapt to your actions and truly work as a team, as they cover each other and help fallen comrades to get back on their feet.<br>Outsmart your opponents by using your surroundings to your advantage as you set up traps using lethal elements of the environment. Location-based damage rewards accuracy while melee combat moves enable you to get up-close and personal.<br>					</li><li>Unprecedented Interactivity: Blast your way through highly interactive environments powered by an enhanced version of the Source engine. Characters dynamically react to what you''re looking at and the environment. Target and shoot off specific vehicle parts and literally blow cars to pieces. Experience the next level of vehicle combat with a flexible positioning system enabling you to move around the interior with an unprecedented degree of freedom, allowing you to pick the ideal position to attack that enemy position up ahead.<br>					</li><li>Personal Challenge System™: Driven by one of the most elaborate statistics systems ever created, SiN Episodes will constantly adapt to your playing style and offers a challenge that is custom-tailored to your skill level.<br>					</li><li>Episodic Delivery: Buy as little or as much of the game as you want, with each installment offering 3 - 6 hours of action-packed gameplay. But tread lightly, as the choices you make may influence future episodes in unforeseen ways.<br>					</li><li>Source Powered: Utilizing the same engine that powered Half-life® 2, Emergence gives you stunningly gorgeous graphics and intense physics-based gameplay.</li></ul>','You are John Blade, commander of HardCorps, an elite security force dedicated to protecting the people of Freeport City. Four years have passed since your first battle with Elexis Sinclaire, a beautiful, brilliant, and ruthless scientist who is out to remake humanity according to her own twisted vision.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1500,'Combining fast-paced action with strategic battle planning, Darwinia features a novel and intuitive control mechanism, a graphical style ripped from 80''s retro classics like Tron and Defender, and a story concerning a tribe of nomadic sprites trapped in a modern 3D world.','Combining fast-paced action with strategic battle planning, Darwinia features a novel and intuitive control mechanism, a graphical style ripped from 80''s retro classics like Tron and Defender, and a story concerning a tribe of nomadic sprites trapped in a modern 3D world.','Combining fast-paced action with strategic battle planning, Darwinia features a novel and intuitive control mechanism, a graphical style ripped from 80''s retro classics like Tron and Defender, and a story concerning a tribe of nomadic sprites trapped in a modern 3D world.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1510,'You play an Uplink Agent who makes a living by performing jobs for major corporations. Your tasks involve hacking into rival computer systems, stealing research data, sabotaging other companies, laundering money, erasing evidence, or framing innocent people.<br />
<br />
You use the money you earn to upgrade your computer systems, and to buy new software and tools. As your experience level increases you find more dangerous and profitable missions become available. You can speculate on a fully working stock market (and even influence its outcome). You can modify peoples academic or criminal records. You can divert money from bank transfers into your own accounts. You can even take part in the construction of the most deadly computer virus ever designed.','You play an Uplink Agent who makes a living by performing jobs for major corporations. Your tasks involve hacking into rival computer systems, stealing research data, sabotaging other companies, laundering money, erasing evidence, or framing innocent people.<br />
<br />
You use the money you earn to upgrade your computer systems, and to buy new software and tools. As your experience level increases you find more dangerous and profitable missions become available. You can speculate on a fully working stock market (and even influence its outcome). You can modify peoples academic or criminal records. You can divert money from bank transfers into your own accounts. You can even take part in the construction of the most deadly computer virus ever designed.','You play an Uplink Agent who makes a living by performing jobs for major corporations. Your tasks involve hacking into rival computer systems, stealing research data, sabotaging other companies, laundering money, erasing evidence, or framing innocent people.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1520,'Inspired by the 1983 cult classic film, Wargames, DEFCON superbly evokes the tension, paranoia and suspicion of the Cold War era, playing on the fascinating aspects of psychological gameplay that occur during strategic nuclear warfare.<br />
					You play a General hidden deep within an underground bunker. Your mission is to successfully exterminate your enemy''s civilian population whilst saving your own. Points are awarded or lost depending on both the efficacy and thoroughness of your nuclear vendetta and the number of your own civilian deaths.  In order to win you must wipe out the enemy population and simultaneously disable the enemy''s ability to retaliate against you. This is an extremely difficult task since launching an attack on the enemy exposes the positions of your own Ground Silos, Subs and Bombers the moment they launch nuclear weapons, making you extremely vulnerable and exposed to a crushing counter-attack. <br />
					Desperate attempts must be made to form fast, tactical alliances, alliances that may at any moment break-down to become the treacherous and most deadly of betrayals. Everyone looks to each other in a state of nervous suspense and paranoid accusation. In all-out nuclear Armageddon, everybody dies, everybody loses, you just have to make sure you lose the least!','Inspired by the 1983 cult classic film, Wargames, DEFCON superbly evokes the tension, paranoia and suspicion of the Cold War era, playing on the fascinating aspects of psychological gameplay that occur during strategic nuclear warfare.<br />
					You play a General hidden deep within an underground bunker. Your mission is to successfully exterminate your enemy''s civilian population whilst saving your own. Points are awarded or lost depending on both the efficacy and thoroughness of your nuclear vendetta and the number of your own civilian deaths.  In order to win you must wipe out the enemy population and simultaneously disable the enemy''s ability to retaliate against you. This is an extremely difficult task since launching an attack on the enemy exposes the positions of your own Ground Silos, Subs and Bombers the moment they launch nuclear weapons, making you extremely vulnerable and exposed to a crushing counter-attack. <br />
					Desperate attempts must be made to form fast, tactical alliances, alliances that may at any moment break-down to become the treacherous and most deadly of betrayals. Everyone looks to each other in a state of nervous suspense and paranoid accusation. In all-out nuclear Armageddon, everybody dies, everybody loses, you just have to make sure you lose the least!','Inspired by the 1983 cult classic film, Wargames, DEFCON superbly evokes the tension, paranoia and suspicion of the Cold War era, playing on the fascinating aspects of psychological gameplay that occur during strategic nuclear warfare. You play a General hidden deep within an underground bunker.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1530,'&quot;Long ago a computer scientist called Dr Sepulveda created a beautiful digital world existing entirely within a computer network of his own invention. This world was called Darwinia and it was inhabited by a peaceful, law-abiding digital life-form called the Darwinians.                    <br />
					As the years wore on however the Darwinians became ever more aggressive and autonomous. They divided into factions, squabbling over Darwinia''s limited natural resources. Tribes began to roam the fractal voids hell bent on each others destruction, drunk on power and unswerving in the pursuit of world supremacy.                    <br />
					Far and wide, they became known as the Multiwinians...&quot;                    <br />
					Welcome to Multiwinia: Survival of the Flattest  the ultimate retro-arcade multiplayer experience! Choose from a selection of six spectacular action-packed game modes, set in one of the most beautiful game environs you will ever set eyes on.                    <br />
					Challenge your opponent to a game of stick-man slaughter, and watch digital-war unfold, as your Multiwinian army struggles to complete a chosen task faster and better than your rival''s. It''s fast, it''s furious, and only the flattest will survive!','&quot;Long ago a computer scientist called Dr Sepulveda created a beautiful digital world existing entirely within a computer network of his own invention. This world was called Darwinia and it was inhabited by a peaceful, law-abiding digital life-form called the Darwinians.                    <br />
					As the years wore on however the Darwinians became ever more aggressive and autonomous. They divided into factions, squabbling over Darwinia''s limited natural resources. Tribes began to roam the fractal voids hell bent on each others destruction, drunk on power and unswerving in the pursuit of world supremacy.                    <br />
					Far and wide, they became known as the Multiwinians...&quot;                    <br />
					Welcome to Multiwinia: Survival of the Flattest  the ultimate retro-arcade multiplayer experience! Choose from a selection of six spectacular action-packed game modes, set in one of the most beautiful game environs you will ever set eyes on.                    <br />
					Challenge your opponent to a game of stick-man slaughter, and watch digital-war unfold, as your Multiwinian army struggles to complete a chosen task faster and better than your rival''s. It''s fast, it''s furious, and only the flattest will survive!','&quot;Long ago a computer scientist called Dr Sepulveda created a beautiful digital world existing entirely within a computer network of his own invention. This world was called Darwinia and it was inhabited by a peaceful, law-abiding digital life-form called the Darwinians.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1600,'S.C.S. - Dangerous Waters allows you total control over multiple air, surface, and submarine platforms in a modern-day naval environment. Take direct control of individual crew stations and also plan and execute combined arms naval strategies from a top-down ''Commanders Eye'' perspective.','S.C.S. - Dangerous Waters allows you total control over multiple air, surface, and submarine platforms in a modern-day naval environment. Take direct control of individual crew stations and also plan and execute combined arms naval strategies from a top-down ''Commanders Eye'' perspective.','S.C.S. - Dangerous Waters allows you total control over multiple air, surface, and submarine platforms in a modern-day naval environment. Take direct control of individual crew stations and also plan and execute combined arms naval strategies from a top-down ''Commanders Eye'' perspective.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1610,'The award-winning Space Empires IV Deluxe is the latest edition in the Space Empires series. A grand strategy title in the space 4X (explore, expand, exploit, and exterminate) genre, Space Empires has already found a place in the heart of strategy gamers everywhere.<br />
			Research technology, design new ships, wage war on a tactical level, put down rebellions, meet and greet new species, and much more. All the level and campaign design tools are included, allowing anyone to become a part of the expansive Space Empires Mod community.','The award-winning Space Empires IV Deluxe is the latest edition in the Space Empires series. A grand strategy title in the space 4X (explore, expand, exploit, and exterminate) genre, Space Empires has already found a place in the heart of strategy gamers everywhere.<br />
			Research technology, design new ships, wage war on a tactical level, put down rebellions, meet and greet new species, and much more. All the level and campaign design tools are included, allowing anyone to become a part of the expansive Space Empires Mod community.','The award-winning Space Empires IV Deluxe is the latest edition in the Space Empires series. A grand strategy title in the space 4X (explore, expand, exploit, and exterminate) genre, Space Empires has already found a place in the heart of strategy gamers everywhere.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1630,'<p>The award-winning series Disciples introduced a milestone in the game''s very successful history; the introduction of a new race: The Elves. The Elven Race added a new dimension to the game and added countless hours of gameplay.</p>
					   <p>Now that series has expanded further with Disciples II: Rise Of The Elves. This version features all of the campaigns found in the original and a brand new campaign that continues the storyline of the Elven Race. It also includes 14 new skirmish maps to test hone your skills.</p>
					   <h2>Key features</h2>
					   <ul>
						    <li>New campaign that continues the Elven Storyline 
						    <li>14 new skirmish maps to test gamer''s skills 
						    <li>5 playable races to choose from; the Empire; the Undead Hordes, the Mountain Clans, the Legions of the Damned, and the Elven Alliance 
						    <li>The Elven tech tree allows players to choose between Noble or Wild Elves increasing replayability 
						    <li>Over 200 individually animated unit types and over 100 different spells 
						    <li>Scenario editor to create your own adventures 
						    <li>Battle friends and enemies in multiplayer over LAN, Internet or Hot-Seat play 
					   </ul>','<p>The award-winning series Disciples introduced a milestone in the game''s very successful history; the introduction of a new race: The Elves. The Elven Race added a new dimension to the game and added countless hours of gameplay.</p>
					   <p>Now that series has expanded further with Disciples II: Rise Of The Elves. This version features all of the campaigns found in the original and a brand new campaign that continues the storyline of the Elven Race. It also includes 14 new skirmish maps to test hone your skills.</p>
					   <h2>Key features</h2>
					   <ul>
						    <li>New campaign that continues the Elven Storyline 
						    <li>14 new skirmish maps to test gamer''s skills 
						    <li>5 playable races to choose from; the Empire; the Undead Hordes, the Mountain Clans, the Legions of the Damned, and the Elven Alliance 
						    <li>The Elven tech tree allows players to choose between Noble or Wild Elves increasing replayability 
						    <li>Over 200 individually animated unit types and over 100 different spells 
						    <li>Scenario editor to create your own adventures 
						    <li>Battle friends and enemies in multiplayer over LAN, Internet or Hot-Seat play 
					   </ul>','The award-winning series Disciples introduced a milestone in the game''s very successful history; the introduction of a new race: The Elves. The Elven Race added a new dimension to the game and added countless hours of gameplay. Now that series has expanded further with Disciples II: Rise Of The Elves.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1640,'<strong>Disciples II: Gallean''s Return</strong> is a compilation edition that includes the base game, Disciples II: Dark Prophecy, plus the two standalone expansions Disciples II: Guardians of the Light and Disciples II: Servants of the Dark.<br>					 <br><strong>Disciples II: Guardians of the Light</strong> is a stand-alone expansion that lets you dive into the fantastical world of Disciples II as either the Empire or the Mountain Clans.<br>					 The Empire is decaying from within as self-proclaimed rulers struggle for control of the now vacant throne while a cruel Inquisition sweeps across the human lands, causing rebellion and misery. Meanwhile the Clans, recovering from their near-destruction, begin to reunite their tribes. They have received divine instructions and now seek to uncover an ancient ritual that will let them communicate with their god, Wotan.<br>					 <strong>Disciples II: Servants of the Dark</strong> is a stand-alone expansion that brings you into the never-ending quest for supremacy as either the Undead Hordes or the Legions of the Damned.<br>					 On the dark side, the Legions of the Damned enact a plan to spread Bethrezen’s plague across Nevendaar. They sense the threat brought about by the rebirth of the Elven god and will stop at nothing to steal this power for their own purposes. Perhaps most pivotal to the conflict, however, is Mortis and her army of Undead Hordes. After all, the rebirth of her husband Gallean was her doing. He had rejected her for what she had become, a twisted, heartless beast. Now she would teach her mate a lesson... one that would scar his people for eternity...<br>					 <h2 class="bb_tag">Features</h2>					 <ul class="bb_ul"><li>Random map generator<br>						 </li><li>Multiple resolution support<br>						 </li><li>High level unit AI support<br>						 </li><li>Improved computer AI<br>						 </li><li>Improved editor<br>						 </li><li>Improved UI<br>						 </li><li>Auto-Resolve Combat mode<br>						 </li><li>Player can capture capitals<br>						 </li><li>Direct 3D support for improved performance<br>						 </li><li>Enhanced chat interface<br>						 </li><li>Support for large maps, 120x120 and 144x144<br>						 </li><li>All the updates for Disciples II: Dark Prophecy<br>						 </li><li>2 new high-level mini campaigns and original Disciples II campaigns<br>						 </li><li>16 skirmish/multiplayer maps including 10 never-before-seen maps<br>						 </li><li>3 new special characters<br>						 </li><li>New capital backgrounds<br>						 </li><li>New battle backgrounds<br>						 </li><li>Four new music tracks<br>						 </li><li>Exclusive portfolio containing original concept art and sketches<br>					 </li></ul>','<strong>Disciples II: Gallean''s Return</strong> is a compilation edition that includes the base game, Disciples II: Dark Prophecy, plus the two standalone expansions Disciples II: Guardians of the Light and Disciples II: Servants of the Dark.<br>					 <br><strong>Disciples II: Guardians of the Light</strong> is a stand-alone expansion that lets you dive into the fantastical world of Disciples II as either the Empire or the Mountain Clans.<br>					 The Empire is decaying from within as self-proclaimed rulers struggle for control of the now vacant throne while a cruel Inquisition sweeps across the human lands, causing rebellion and misery. Meanwhile the Clans, recovering from their near-destruction, begin to reunite their tribes. They have received divine instructions and now seek to uncover an ancient ritual that will let them communicate with their god, Wotan.<br>					 <strong>Disciples II: Servants of the Dark</strong> is a stand-alone expansion that brings you into the never-ending quest for supremacy as either the Undead Hordes or the Legions of the Damned.<br>					 On the dark side, the Legions of the Damned enact a plan to spread Bethrezen’s plague across Nevendaar. They sense the threat brought about by the rebirth of the Elven god and will stop at nothing to steal this power for their own purposes. Perhaps most pivotal to the conflict, however, is Mortis and her army of Undead Hordes. After all, the rebirth of her husband Gallean was her doing. He had rejected her for what she had become, a twisted, heartless beast. Now she would teach her mate a lesson... one that would scar his people for eternity...<br>					 <h2 class="bb_tag">Features</h2>					 <ul class="bb_ul"><li>Random map generator<br>						 </li><li>Multiple resolution support<br>						 </li><li>High level unit AI support<br>						 </li><li>Improved computer AI<br>						 </li><li>Improved editor<br>						 </li><li>Improved UI<br>						 </li><li>Auto-Resolve Combat mode<br>						 </li><li>Player can capture capitals<br>						 </li><li>Direct 3D support for improved performance<br>						 </li><li>Enhanced chat interface<br>						 </li><li>Support for large maps, 120x120 and 144x144<br>						 </li><li>All the updates for Disciples II: Dark Prophecy<br>						 </li><li>2 new high-level mini campaigns and original Disciples II campaigns<br>						 </li><li>16 skirmish/multiplayer maps including 10 never-before-seen maps<br>						 </li><li>3 new special characters<br>						 </li><li>New capital backgrounds<br>						 </li><li>New battle backgrounds<br>						 </li><li>Four new music tracks<br>						 </li><li>Exclusive portfolio containing original concept art and sketches<br>					 </li></ul>','Disciples II: Gallean''s Return is a compilation edition that includes the base game, Disciples II: Dark Prophecy, plus the two standalone expansions Disciples II: Guardians of the Light and Disciples II: Servants of the Dark.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1670,'The most devastating mechanized armor to ever roll onto a battlefield is brought to life in Iron Warriors: T72-Tank Command. This epic combat simulator allows the player to command an entire platoon of tanks and ALL associated support units, or assume the role of ANY member in a complete tank crew!<br><br>The realism of both the physics and 3D engine creates game environments where real life armored tactic become the only way to survive on the today''s modern battlefield!
					<ul>
					<li>Three of Russia''s most devastating and powerful tanks ever produced are  yours to control; the T - 34-85, T-55A and T-72B!</li>
					<li>Roll these mechanized monsters through 18 campaigns, 2 training missions, 5 single player missions and 3 multiplayer (LAN) missions. </li>
					<li>Master your tank and crew and you will soon take command of other units that round out your mechanized platoon.</li>
					<li>Cooperative multi-player support allows gamers to team up as a tank crew and play different positions within the same tank! </li>
					<li>Roll into battle on some of the most realistic terrain maps ever modeled; real weather, destructible terrain and detailed models. </li>
					<li>Ballistics models take into effect: wind, shell, aerodynamic flight characteristics, barrel wear and droop!</li>
					<li>Powerful mission editor, map editor, and structure editor included; modify existing content or create your own. </li></ul>','The most devastating mechanized armor to ever roll onto a battlefield is brought to life in Iron Warriors: T72-Tank Command. This epic combat simulator allows the player to command an entire platoon of tanks and ALL associated support units, or assume the role of ANY member in a complete tank crew!<br><br>The realism of both the physics and 3D engine creates game environments where real life armored tactic become the only way to survive on the today''s modern battlefield!
					<ul>
					<li>Three of Russia''s most devastating and powerful tanks ever produced are  yours to control; the T - 34-85, T-55A and T-72B!</li>
					<li>Roll these mechanized monsters through 18 campaigns, 2 training missions, 5 single player missions and 3 multiplayer (LAN) missions. </li>
					<li>Master your tank and crew and you will soon take command of other units that round out your mechanized platoon.</li>
					<li>Cooperative multi-player support allows gamers to team up as a tank crew and play different positions within the same tank! </li>
					<li>Roll into battle on some of the most realistic terrain maps ever modeled; real weather, destructible terrain and detailed models. </li>
					<li>Ballistics models take into effect: wind, shell, aerodynamic flight characteristics, barrel wear and droop!</li>
					<li>Powerful mission editor, map editor, and structure editor included; modify existing content or create your own. </li></ul>','The most devastating mechanized armor to ever roll onto a battlefield is brought to life in Iron Warriors: T72-Tank Command. This epic combat simulator allows the player to command an entire platoon of tanks and ALL associated support units, or assume the role of ANY member in a complete tank crew!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1690,'Space Empires V is the latest edition in the Space Empires series. This new chapter completely updates the UI and takes the player into a real-time rendered 3D universe. Watch space battles played out in glorious detail and realistic effects. Expand, Explore, Exploit, and Exterminate in a huge living breathing galaxy. New features abound with political alliances between multiple empires, a top-down ship design system, a hexagonal movement grid, and many more. Due to player demand, the game is completely ''moddable'' and even adds a scriptable AI system to the mix. Space Empires V boldly takes the next step in the genre of space strategy<br>					<ul class="bb_ul"><li>24 bit 3D real-time rendered graphics. <br>					</li><li>Detailed Tactical Combat (and a combat simulator to test your designs!). <br>					</li><li>New vehicle types and sizes: Ships, Bases, Freighters, Fighters, Mines, Satellites, Troops, Drones, and Weapons Platforms. <br>					</li><li>Ability to completely design and customize all of your vehicles. <br>					</li><li>Large Galaxy: 100 solar systems with 15 planets each. <br>					</li><li>Huge Technology Tree: Thousands of tech levels with hundreds of components and facilities. <br>					</li><li>Completely customizable game graphics: Create your own planets, stars, vehicles, etc. <br>					</li><li>Completely customizable AI players: Create your own AI players with unique traits, styles, and speech. <br>					</li><li>14 unique races to play or customize (or just create your own!) <br>					</li><li>Randomly generated map for every game (or load an existing map). <br>					</li><li>Complete game customization allowed by players (&quot;mods&quot;). </li></ul>','Space Empires V is the latest edition in the Space Empires series. This new chapter completely updates the UI and takes the player into a real-time rendered 3D universe. Watch space battles played out in glorious detail and realistic effects. Expand, Explore, Exploit, and Exterminate in a huge living breathing galaxy. New features abound with political alliances between multiple empires, a top-down ship design system, a hexagonal movement grid, and many more. Due to player demand, the game is completely ''moddable'' and even adds a scriptable AI system to the mix. Space Empires V boldly takes the next step in the genre of space strategy<br>					<ul class="bb_ul"><li>24 bit 3D real-time rendered graphics. <br>					</li><li>Detailed Tactical Combat (and a combat simulator to test your designs!). <br>					</li><li>New vehicle types and sizes: Ships, Bases, Freighters, Fighters, Mines, Satellites, Troops, Drones, and Weapons Platforms. <br>					</li><li>Ability to completely design and customize all of your vehicles. <br>					</li><li>Large Galaxy: 100 solar systems with 15 planets each. <br>					</li><li>Huge Technology Tree: Thousands of tech levels with hundreds of components and facilities. <br>					</li><li>Completely customizable game graphics: Create your own planets, stars, vehicles, etc. <br>					</li><li>Completely customizable AI players: Create your own AI players with unique traits, styles, and speech. <br>					</li><li>14 unique races to play or customize (or just create your own!) <br>					</li><li>Randomly generated map for every game (or load an existing map). <br>					</li><li>Complete game customization allowed by players (&quot;mods&quot;). </li></ul>','Space Empires V is the latest edition in the Space Empires series. This new chapter completely updates the UI and takes the player into a real-time rendered 3D universe. Watch space battles played out in glorious detail and realistic effects. Expand, Explore, Exploit, and Exterminate in a huge living breathing galaxy.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1700,'This critically acclaimed first-person RPG takes the player on an amazing journey into the fantasy world of Arx. The game mixes intelligent story with immersive and actual medieval surroundings. Arx Fatalis allows the player to feel that all his actions have a direct consequence on those around him.<br />
					The goal of the game is to destroy the secret cult of Akbaa, the god of destruction. As a player, you must prevent the return of such a cruel creature to the physical world. Should you fail, Akbaa is bound to impose its terror upon the world of Arx.<br />
					You will become the hero of an underground world - with weapons, spells and magical items to defend against goblins, trolls, rat-men and other vicious opponents.<br />
					Besides brute force, stealth and the &quot;onscreen gesture based magic system&quot; are the three alternative ways to succeed.   Using the mouse, flaming runes can be drawn in mid-air.  A combination of these gestures can create powerful magic spells that will protect you or empower you to defeat opponents and pursue the quest.','This critically acclaimed first-person RPG takes the player on an amazing journey into the fantasy world of Arx. The game mixes intelligent story with immersive and actual medieval surroundings. Arx Fatalis allows the player to feel that all his actions have a direct consequence on those around him.<br />
					The goal of the game is to destroy the secret cult of Akbaa, the god of destruction. As a player, you must prevent the return of such a cruel creature to the physical world. Should you fail, Akbaa is bound to impose its terror upon the world of Arx.<br />
					You will become the hero of an underground world - with weapons, spells and magical items to defend against goblins, trolls, rat-men and other vicious opponents.<br />
					Besides brute force, stealth and the &quot;onscreen gesture based magic system&quot; are the three alternative ways to succeed.   Using the mouse, flaming runes can be drawn in mid-air.  A combination of these gestures can create powerful magic spells that will protect you or empower you to defeat opponents and pursue the quest.','This critically acclaimed first-person RPG takes the player on an amazing journey into the fantasy world of Arx. The game mixes intelligent story with immersive and actual medieval surroundings. Arx Fatalis allows the player to feel that all his actions have a direct consequence on those around him.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1840,'The Source Filmmaker (SFM) is the movie-making tool built and used by us here at Valve to make movies inside the Source game engine. Because the SFM uses the same assets as the game, anything that exists in the game can be used in the movie, and vice versa. By utilizing the hardware rendering power of a modern gaming PC, the SFM allows storytellers to work in a what-you-see-is-what-you-get environment so they can iterate in the context of what it will feel like for the final audience.<br><br>To get started, just click the button above to install. The SFM includes all the base game assets from Team Fortress 2 along with assets from some of the first “Meet the Team” short films.<h2 class="bb_tag">Resources</h2>Once you''re up and running, here are some general resources for finding help and learning how to get the most out of the Source Filmmaker.<br><ul class="bb_ul"><li><a href="https://developer.valvesoftware.com/wiki/Source_Filmmaker" target="_blank" rel="noreferrer"  >Official Wiki Documentation</a><br></li><li><a href="https://steamcommunity.com/linkfilter/?url=http://www.sourcefilmmaker.com/faq/" target="_blank" rel="noopener"  >Frequently Asked Questions</a><br></li><li><a href="http://www.youtube.com/playlist?list=PL2B46DEB4157E67C4&amp;feature=plcp" target="_blank" rel="noreferrer"  >Video Tutorials</a><br></li><li><a href="http://steamcommunity.com/sfm/discussions/?appid=1840" target="_blank" rel="noreferrer"  >Community Discussions</a><br></li><li><a href="https://developer.valvesoftware.com/wiki/SFM/Bug_reports" target="_blank" rel="noreferrer"  >How to file bug reports</a></li></ul>','The Source Filmmaker (SFM) is the movie-making tool built and used by us here at Valve to make movies inside the Source game engine. Because the SFM uses the same assets as the game, anything that exists in the game can be used in the movie, and vice versa. By utilizing the hardware rendering power of a modern gaming PC, the SFM allows storytellers to work in a what-you-see-is-what-you-get environment so they can iterate in the context of what it will feel like for the final audience.<br><br>To get started, just click the button above to install. The SFM includes all the base game assets from Team Fortress 2 along with assets from some of the first “Meet the Team” short films.<h2 class="bb_tag">Resources</h2>Once you''re up and running, here are some general resources for finding help and learning how to get the most out of the Source Filmmaker.<br><ul class="bb_ul"><li><a href="https://developer.valvesoftware.com/wiki/Source_Filmmaker" target="_blank" rel="noreferrer"  >Official Wiki Documentation</a><br></li><li><a href="https://steamcommunity.com/linkfilter/?url=http://www.sourcefilmmaker.com/faq/" target="_blank" rel="noopener"  >Frequently Asked Questions</a><br></li><li><a href="http://www.youtube.com/playlist?list=PL2B46DEB4157E67C4&amp;feature=plcp" target="_blank" rel="noreferrer"  >Video Tutorials</a><br></li><li><a href="http://steamcommunity.com/sfm/discussions/?appid=1840" target="_blank" rel="noreferrer"  >Community Discussions</a><br></li><li><a href="https://developer.valvesoftware.com/wiki/SFM/Bug_reports" target="_blank" rel="noreferrer"  >How to file bug reports</a></li></ul>','The Source Filmmaker (SFM) is the movie-making tool built and used by us here at Valve to make movies inside the Source game engine. Because the SFM uses the same assets as the game, anything that exists in the game can be used in the movie, and vice versa.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1900,'After the destruction of the EARTH in 2150, the leaders of the Eurasian Dynasty escaped on board an evacuation fleet. Now they are fighting for the survival of the human species. Their base is one large building comprising of smaller variable parts. The Lunar Corporation is already on the Red Planet and has to fight to find a new base and home after the destruction of the Earth. LC buildings are built one on top of the other, similar to a skyscraper, but with one big difference - they have the ability to defy all the laws of gravity to move quickly to a new location.<br><br>The UCS (United Civilized States) machines evolved from the UCS battle machines. During the long flight to Mars, the computer decided to kill all human survivors and then initiated a plan to conquer the solar system with its own mechanical army. The Aliens - alien renegades were imprisoned a long ago, deep in the unknown history of Mars. <br><br>In 2160 the landing of the UCS ships awoke them from their long sleep...<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/1900/extras/E2160_awards2.png?t=1478034392" ><br><strong><h2 class="bb_tag">GAME FEATURES:</h2></strong><br><ul class="bb_ul"><li>4 playable parties with different basic technologies and abilities<br></li><li>Each party consists of more than 13 basic buildings and more than 13 basic units<br></li><li>4 single player campaigns, each with 7 missions<br></li><li>Skirmish mode with 10 maps<br></li><li>4 Multiplayer modes with 10 maps<br></li><li>Realistic, formable and multi-textured terrain<br></li><li>12 virtual agents with special abilities<br></li><li>Multiplayer matches for up to 8 players per match<br></li><li>EarthC (programming language) SDK for Mod teams<br></li><li>Rich musical score consists of 29 dynamically varyied tracks<br></li><li>Includes Superstorm, Platinum and Titanium Map Pack</li></ul>','After the destruction of the EARTH in 2150, the leaders of the Eurasian Dynasty escaped on board an evacuation fleet. Now they are fighting for the survival of the human species. Their base is one large building comprising of smaller variable parts. The Lunar Corporation is already on the Red Planet and has to fight to find a new base and home after the destruction of the Earth. LC buildings are built one on top of the other, similar to a skyscraper, but with one big difference - they have the ability to defy all the laws of gravity to move quickly to a new location.<br><br>The UCS (United Civilized States) machines evolved from the UCS battle machines. During the long flight to Mars, the computer decided to kill all human survivors and then initiated a plan to conquer the solar system with its own mechanical army. The Aliens - alien renegades were imprisoned a long ago, deep in the unknown history of Mars. <br><br>In 2160 the landing of the UCS ships awoke them from their long sleep...<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/1900/extras/E2160_awards2.png?t=1478034392" ><br><strong><h2 class="bb_tag">GAME FEATURES:</h2></strong><br><ul class="bb_ul"><li>4 playable parties with different basic technologies and abilities<br></li><li>Each party consists of more than 13 basic buildings and more than 13 basic units<br></li><li>4 single player campaigns, each with 7 missions<br></li><li>Skirmish mode with 10 maps<br></li><li>4 Multiplayer modes with 10 maps<br></li><li>Realistic, formable and multi-textured terrain<br></li><li>12 virtual agents with special abilities<br></li><li>Multiplayer matches for up to 8 players per match<br></li><li>EarthC (programming language) SDK for Mod teams<br></li><li>Rich musical score consists of 29 dynamically varyied tracks<br></li><li>Includes Superstorm, Platinum and Titanium Map Pack</li></ul>','After the destruction of the EARTH in 2150, the leaders of the Eurasian Dynasty escaped on board an evacuation fleet. Now they are fighting for the survival of the human species. Their base is one large building comprising of smaller variable parts.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (1930,'... 300 years after Aziraal has been banished, a brother and sister are drawn into the conflict which has flared up between the Orcs and the free world. Kyra, the hero''s younger sister, suddenly disappears in mysterious circumstances.<br><br>«<i>...If my family really belongs to the chosen ones, why then have we always been as poor as church mice? I have never given much credence to all the old stories about a relict in our family''s possession - one which supposedly bannedAziraal, the god of the Orcs - they say that only those ofmy bloodwere chosen to safeguard the secret.<br>''Tis nothing but nonsense methinks – however, my sister Kyra always listened eagerly to the stories of the old ones... but she vanished several months ago... </i>»<br><br><strong>To all intents and purposes you''re an unscrupulous bounty hunter and mercenary - but the search for your sister takes you back to your roots. </strong><br><br>At the beginning of your epic adventure, a mercenary task takes you to the far north - but you''re also following up a mysterious lead at the same time - the first clue you''ve been given since Kyra''s disappearance. You get a shock during a meeting with the delegates of a dark Brotherhood - your sister''s kidnappers are indeed after your family''s relict. Whether there''s any truth in your family being chosen ones or not, the others obviously believe it - and if you ever want to see Kyra alive again, you''ll have to act swiftly...<br><br><ul class="bb_ul"><li><strong>Includes the original Two Worlds, plus the add-on Tainted Blood</strong><br></li><li><strong>OVER 90 NEW QUESTS:</strong> Journey even deeper into the world of Antaloor with over 90 new quests and eight new multiplayer maps<br></li><li>Soundtrack by Grammy Award Winner <strong>Harold Faltermeyer</strong></li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/1930/extras/TW_Awards_quer.png?t=1548695249" ><h2 class="bb_tag"><strong>FEATURES:</strong></h2><ul class="bb_ul"><li><strong>STUPENDOUS LANDSCAPES:</strong> in a fantasy world where every inhabitant leads a separate dynamic life with realistic daily routines, your deeds will determine the fate of the strife-torn land of Antaloor. <br></li><li><strong>PLAYING FREEDOM:</strong> Two Worlds is not for those who don''t like making decisions, because you''ll often have to take one side or the other  an intelligent, networked reputation system for guilds and secret societies makes sure of that.<br></li><li><strong>KNIGHT, THIEF, MAGE OR ALCHEMIST:</strong> spectacular, dynamically-choreographed fights on foot or at full gallop. An absorbing alchemy system for creating individual potions and power-ups provides diversification - and carrying out break-ins in Sneak mode will have your nerves jangling! If this still isn''t enough, try the sophisticated magic system...<br></li><li><strong>INTUITIVE INTERFACE AND INDIVIDUAL DEVELOPMENT OF ATTRIBUTES:</strong> you can experiment with all the character attributes and develop your skills as and when you like. An elaborate inventory system ensures that you always have a clear overview  no matter how hot the action gets. <br></li><li><strong>MASSIVE MULTIPLAYER INCLUDED:</strong> bustling towns are the trading centers and meeting points for several hundred players. Self-created characters fight gripping PvsP duels in Arena mode  or solve a series of exciting quests as allies.<br></li><li><strong>UPDATED GAME ENGINE:</strong> The brand new 1.6 engine update now included!</li></ul>','... 300 years after Aziraal has been banished, a brother and sister are drawn into the conflict which has flared up between the Orcs and the free world. Kyra, the hero''s younger sister, suddenly disappears in mysterious circumstances.<br><br>«<i>...If my family really belongs to the chosen ones, why then have we always been as poor as church mice? I have never given much credence to all the old stories about a relict in our family''s possession - one which supposedly bannedAziraal, the god of the Orcs - they say that only those ofmy bloodwere chosen to safeguard the secret.<br>''Tis nothing but nonsense methinks – however, my sister Kyra always listened eagerly to the stories of the old ones... but she vanished several months ago... </i>»<br><br><strong>To all intents and purposes you''re an unscrupulous bounty hunter and mercenary - but the search for your sister takes you back to your roots. </strong><br><br>At the beginning of your epic adventure, a mercenary task takes you to the far north - but you''re also following up a mysterious lead at the same time - the first clue you''ve been given since Kyra''s disappearance. You get a shock during a meeting with the delegates of a dark Brotherhood - your sister''s kidnappers are indeed after your family''s relict. Whether there''s any truth in your family being chosen ones or not, the others obviously believe it - and if you ever want to see Kyra alive again, you''ll have to act swiftly...<br><br><ul class="bb_ul"><li><strong>Includes the original Two Worlds, plus the add-on Tainted Blood</strong><br></li><li><strong>OVER 90 NEW QUESTS:</strong> Journey even deeper into the world of Antaloor with over 90 new quests and eight new multiplayer maps<br></li><li>Soundtrack by Grammy Award Winner <strong>Harold Faltermeyer</strong></li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/1930/extras/TW_Awards_quer.png?t=1548695249" ><h2 class="bb_tag"><strong>FEATURES:</strong></h2><ul class="bb_ul"><li><strong>STUPENDOUS LANDSCAPES:</strong> in a fantasy world where every inhabitant leads a separate dynamic life with realistic daily routines, your deeds will determine the fate of the strife-torn land of Antaloor. <br></li><li><strong>PLAYING FREEDOM:</strong> Two Worlds is not for those who don''t like making decisions, because you''ll often have to take one side or the other  an intelligent, networked reputation system for guilds and secret societies makes sure of that.<br></li><li><strong>KNIGHT, THIEF, MAGE OR ALCHEMIST:</strong> spectacular, dynamically-choreographed fights on foot or at full gallop. An absorbing alchemy system for creating individual potions and power-ups provides diversification - and carrying out break-ins in Sneak mode will have your nerves jangling! If this still isn''t enough, try the sophisticated magic system...<br></li><li><strong>INTUITIVE INTERFACE AND INDIVIDUAL DEVELOPMENT OF ATTRIBUTES:</strong> you can experiment with all the character attributes and develop your skills as and when you like. An elaborate inventory system ensures that you always have a clear overview  no matter how hot the action gets. <br></li><li><strong>MASSIVE MULTIPLAYER INCLUDED:</strong> bustling towns are the trading centers and meeting points for several hundred players. Self-created characters fight gripping PvsP duels in Arena mode  or solve a series of exciting quests as allies.<br></li><li><strong>UPDATED GAME ENGINE:</strong> The brand new 1.6 engine update now included!</li></ul>','... 300 years after Aziraal has been banished, a brother and sister are drawn into the conflict which has flared up between the Orcs and the free world. Kyra, the hero''s younger sister, suddenly disappears in mysterious circumstances.«...If my family really belongs to the chosen ones, why then have we always been as poor as church mice?');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2100,'Discover a new breed of Action-RPG game powered by an enhanced version of the Source™ Engine by Valve. Set in the Might &amp; Magic® universe, players will experience ferocious combat in a dark and immersive fantasy environment.  Swords, Stealth, Sorcery. Choose your way to kill.<br>					<ul class="bb_ul"><li>Cutting-edge technology: Experience an enhanced version of the famous Source™ Engine created by Valve. Discover the fresh perspective of a view with complete body awareness, realistic movements, physics rendering, and a complete first-person melee combat system in a fantasy setting. <br>					</li><li>Never-ending action: Challenge the forces of evil in 12 huge levels and learn to master over 30 weapons and an arsenal of devastating spells.<br>					</li><li>Evolve your character: Extend your gameplay experience without being limited to a single discipline. Learn powerful new spells and attacks using Dark Messiah''s unique Skill Evolution System as you progress through the game.<br>					</li><li>Revolutionary multiplayer mode: Get ready to battle with up to 32 players in the revolutionary Crusade mode, which will enable players to gain experience and new skills across dynamic online campaigns. Enlist with the humans or the undead and choose among five complementary character classes. </li></ul>© 2006 Ubisoft Entertainment.  All Rights Reserved.  Dark Messiah, Might and Magic, Ubisoft and the Ubisoft logo are trademarks of Ubisoft Entertainment in the U.S. and/or other countries.  Developed by Arkane Studios.','Discover a new breed of Action-RPG game powered by an enhanced version of the Source™ Engine by Valve. Set in the Might &amp; Magic® universe, players will experience ferocious combat in a dark and immersive fantasy environment.  Swords, Stealth, Sorcery. Choose your way to kill.<br>					<ul class="bb_ul"><li>Cutting-edge technology: Experience an enhanced version of the famous Source™ Engine created by Valve. Discover the fresh perspective of a view with complete body awareness, realistic movements, physics rendering, and a complete first-person melee combat system in a fantasy setting. <br>					</li><li>Never-ending action: Challenge the forces of evil in 12 huge levels and learn to master over 30 weapons and an arsenal of devastating spells.<br>					</li><li>Evolve your character: Extend your gameplay experience without being limited to a single discipline. Learn powerful new spells and attacks using Dark Messiah''s unique Skill Evolution System as you progress through the game.<br>					</li><li>Revolutionary multiplayer mode: Get ready to battle with up to 32 players in the revolutionary Crusade mode, which will enable players to gain experience and new skills across dynamic online campaigns. Enlist with the humans or the undead and choose among five complementary character classes. </li></ul>© 2006 Ubisoft Entertainment.  All Rights Reserved.  Dark Messiah, Might and Magic, Ubisoft and the Ubisoft logo are trademarks of Ubisoft Entertainment in the U.S. and/or other countries.  Developed by Arkane Studios.','Discover a new breed of Action-RPG game powered by an enhanced version of the Source™ Engine by Valve. Set in the Might &amp; Magic® universe, players will experience ferocious combat in a dark and immersive fantasy environment. Swords, Stealth, Sorcery. Choose your way to kill.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2200,'Welcome to the Arena, where high-ranking warriors are transformed into spineless mush. Abandoning every ounce of common sense and any trace of doubt, you lunge onto a stage of harrowing landscapes and veiled abysses. Your new environment rejects you with lava pits and atmospheric hazards as legions of foes surround you, testing the gut reaction that brought you here in the first place. Your new mantra: Fight or be finished.','Welcome to the Arena, where high-ranking warriors are transformed into spineless mush. Abandoning every ounce of common sense and any trace of doubt, you lunge onto a stage of harrowing landscapes and veiled abysses. Your new environment rejects you with lava pits and atmospheric hazards as legions of foes surround you, testing the gut reaction that brought you here in the first place. Your new mantra: Fight or be finished.','Welcome to the Arena, where high-ranking warriors are transformed into spineless mush. Abandoning every ounce of common sense and any trace of doubt, you lunge onto a stage of harrowing landscapes and veiled abysses.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2210,'In a desperate war for Earth’s survival, against an unrelenting enemy, the only way to defeat them is to become one of them. Armed with advanced weaponry and vehicles and aided by an elite squad of marines, you take the battle to the heart of the Strogg home planet and become earth’s only hope for victory.<br>						<h2 class="bb_tag">Key features:</h2>						<ul class="bb_ul"><li>Built on id Tech 4 (the Doom 3 engine)<br>						</li><li>Sequel to the Quake 2 storyline<br>						</li><li>Battle outdoors using tanks and walkers<br>						</li><li>Fight with the support of an elite squad<br>						</li><li>Compete online in fast action, arena-style multiplayer<br>						</li></ul>','In a desperate war for Earth’s survival, against an unrelenting enemy, the only way to defeat them is to become one of them. Armed with advanced weaponry and vehicles and aided by an elite squad of marines, you take the battle to the heart of the Strogg home planet and become earth’s only hope for victory.<br>						<h2 class="bb_tag">Key features:</h2>						<ul class="bb_ul"><li>Built on id Tech 4 (the Doom 3 engine)<br>						</li><li>Sequel to the Quake 2 storyline<br>						</li><li>Battle outdoors using tanks and walkers<br>						</li><li>Fight with the support of an elite squad<br>						</li><li>Compete online in fast action, arena-style multiplayer<br>						</li></ul>','The latest chapter in the Quake series is now on Steam!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2270,'Maybe it was the fact that people got to blow away Nazis. Maybe it was the sheer challenge of it all. For whatever reason, Wolfenstein 3D and Spear of Destiny, pioneered the first-person shooter genre and brought its legendary creators, id Software, worldwide notoriety and numerous awards. In fact, The Computer Gaming World Hall of Fame recognized Wolfenstein 3D as helping to shape the overall direction of the computer gaming industry.','Maybe it was the fact that people got to blow away Nazis. Maybe it was the sheer challenge of it all. For whatever reason, Wolfenstein 3D and Spear of Destiny, pioneered the first-person shooter genre and brought its legendary creators, id Software, worldwide notoriety and numerous awards. In fact, The Computer Gaming World Hall of Fame recognized Wolfenstein 3D as helping to shape the overall direction of the computer gaming industry.','Maybe it was the fact that people got to blow away Nazis. Maybe it was the sheer challenge of it all. For whatever reason, Wolfenstein 3D and Spear of Destiny, pioneered the first-person shooter genre and brought its legendary creators, id Software, worldwide notoriety and numerous awards.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2280,'The complete megahit game that set the world afire. Plus All-New Episode IV: Thy Flesh Consumed.<br />
					The demons came and the marines died. Except one. You are the last defense against these hell-spawned hordes. Prepare for the most intense mutant-laden, blood-splattered action ever! The texture-mapped virtual world is so real, you don''t just play DOOM - you live it.<br />
					The Ultimate DOOM takes you beyond anything you''ve ever experienced. First, you get all three original episodes - that''s 27 levels of awesome, explosive excitement. Then it really blows you away with an all-new episode: Thy Flesh Consumed.<br />
					Now you''re dead meat. Just when you think you''re getting pretty good at DOOM, you get hit with Perfect Hatred, Sever the Wicked and seven other expert levels never seen before! They''re so incredibly tough, the first 27 levels will seem like a walk in the park!','The complete megahit game that set the world afire. Plus All-New Episode IV: Thy Flesh Consumed.<br />
					The demons came and the marines died. Except one. You are the last defense against these hell-spawned hordes. Prepare for the most intense mutant-laden, blood-splattered action ever! The texture-mapped virtual world is so real, you don''t just play DOOM - you live it.<br />
					The Ultimate DOOM takes you beyond anything you''ve ever experienced. First, you get all three original episodes - that''s 27 levels of awesome, explosive excitement. Then it really blows you away with an all-new episode: Thy Flesh Consumed.<br />
					Now you''re dead meat. Just when you think you''re getting pretty good at DOOM, you get hit with Perfect Hatred, Sever the Wicked and seven other expert levels never seen before! They''re so incredibly tough, the first 27 levels will seem like a walk in the park!','The complete megahit game that set the world afire. Plus All-New Episode IV: Thy Flesh Consumed. The demons came and the marines died. Except one. You are the last defense against these hell-spawned hordes. Prepare for the most intense mutant-laden, blood-splattered action ever!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2290,'<strong>Two New, 32-Level DOOM II Episodes.</strong><br>					Evilution:<br>					Far from earth, the UAC recommenced their experiments on on of the moons of Jupiter. A spaceship, mistaken for a supply vexxel on radar, hovered above the base. Hideous demons poured out, blanketing the base with death. All your comrades were quickly slaughtered or zombified. This time, it''s not about survival. It''s about revenge.<br>					The Plutonia Experiment:<br>					Every effort has been made by the nation''s top scientists to close the seven interdimensional Gates of Hell, but one portal remains open. Alone, you must infiltrate the ravaged complex, defeat the demon Gatekeeper and seal the last Hell-hole before the undead are prepared to, once again, take over the world.','<strong>Two New, 32-Level DOOM II Episodes.</strong><br>					Evilution:<br>					Far from earth, the UAC recommenced their experiments on on of the moons of Jupiter. A spaceship, mistaken for a supply vexxel on radar, hovered above the base. Hideous demons poured out, blanketing the base with death. All your comrades were quickly slaughtered or zombified. This time, it''s not about survival. It''s about revenge.<br>					The Plutonia Experiment:<br>					Every effort has been made by the nation''s top scientists to close the seven interdimensional Gates of Hell, but one portal remains open. Alone, you must infiltrate the ravaged complex, defeat the demon Gatekeeper and seal the last Hell-hole before the undead are prepared to, once again, take over the world.','Two New, 32-Level DOOM II Episodes. Evilution: Far from earth, the UAC recommenced their experiments on on of the moons of Jupiter. A spaceship, mistaken for a supply vexxel on radar, hovered above the base. Hideous demons poured out, blanketing the base with death. All your comrades were quickly slaughtered or zombified.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2300,'Let the Obsession begin. Again.<br />
					This time, the entire forces of the netherworld have overrun Earth. To save her, you must descend into the stygian depths of Hell itself!<br />
					Battle mightier, nastier, deadlier demons and monsters. Use more powerful weapons. Survive more mind-blowing explosions and more of the bloodiest, fiercest, most awesome blastfest ever!<br />
					Play DOOM II solo, with two people over a modem, or with up to four players over a LAN (supporting IPX protocol). No matter which way you choose, get ready for adrenaline-pumping, action-packed excitement that''s sure to give your heart a real workout.','Let the Obsession begin. Again.<br />
					This time, the entire forces of the netherworld have overrun Earth. To save her, you must descend into the stygian depths of Hell itself!<br />
					Battle mightier, nastier, deadlier demons and monsters. Use more powerful weapons. Survive more mind-blowing explosions and more of the bloodiest, fiercest, most awesome blastfest ever!<br />
					Play DOOM II solo, with two people over a modem, or with up to four players over a LAN (supporting IPX protocol). No matter which way you choose, get ready for adrenaline-pumping, action-packed excitement that''s sure to give your heart a real workout.','Let the Obsession begin. Again. This time, the entire forces of the netherworld have overrun Earth. To save her, you must descend into the stygian depths of Hell itself! Battle mightier, nastier, deadlier demons and monsters. Use more powerful weapons.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2310,'Rage through 32 single player levels and 6 deathmatch levels of sheer terror and fully immersive sound and lighting. Arm yourself against the cannibalistic Ogre, fiendish Vore and indestructible Schambler using lethal nails, fierce Thunderbolts and abominable Rocket and Grenade Launchers.','Rage through 32 single player levels and 6 deathmatch levels of sheer terror and fully immersive sound and lighting. Arm yourself against the cannibalistic Ogre, fiendish Vore and indestructible Schambler using lethal nails, fierce Thunderbolts and abominable Rocket and Grenade Launchers.','Rage through 32 single player levels and 6 deathmatch levels of sheer terror and fully immersive sound and lighting. Arm yourself against the cannibalistic Ogre, fiendish Vore and indestructible Schambler using lethal nails, fierce Thunderbolts and abominable Rocket and Grenade Launchers.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2320,'Shortly after landing on an alien surface, you learn that hundreds of your men have been reduced to just a few. Now you must fight your way through heavily fortified military installations, lower the city''s defenses and shut down the enemy''s war machine. Only then will the fate of humanity be known.','Shortly after landing on an alien surface, you learn that hundreds of your men have been reduced to just a few. Now you must fight your way through heavily fortified military installations, lower the city''s defenses and shut down the enemy''s war machine. Only then will the fate of humanity be known.','Shortly after landing on an alien surface, you learn that hundreds of your men have been reduced to just a few. Now you must fight your way through heavily fortified military installations, lower the city''s defenses and shut down the enemy''s war machine. Only then will the fate of humanity be known.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2330,'You are part of an elite commando force that must infiltrate a hostile alien cite. Once inside, you must scour industrial landscapes, crawl through waterways and air ducts, navigate treacherous canyons teeming with vicious mutants, stow away on an alien spacecraft, and destroy the enemy''s secret moon base.','You are part of an elite commando force that must infiltrate a hostile alien cite. Once inside, you must scour industrial landscapes, crawl through waterways and air ducts, navigate treacherous canyons teeming with vicious mutants, stow away on an alien spacecraft, and destroy the enemy''s secret moon base.','You are part of an elite commando force that must infiltrate a hostile alien cite. Once inside, you must scour industrial landscapes, crawl through waterways and air ducts, navigate treacherous canyons teeming with vicious mutants, stow away on an alien spacecraft, and destroy the enemy''s secret moon base.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2340,'Take out the Big Gun sounded simple enough, except the Strogg were waiting. You, and a few marines like you, are the lucky ones. You''ve made it down in one piece and are still able to contact the fleet. The Gravity Well, the Strogg''s newest weapon in its arsenal against mankind, is operational. With the fleet around Stroggos, 5% of ground forces surviving, and that number dwindling by the second, your orders have changed: free your comrades. Destroy the Gravity Well.<br>					<ul class="bb_ul"><li>New Enemies - The Stalker, Turrets, Daedalus, Medic Commander, Carrier, and the Black Widow.<br>					</li><li>14 Entirely new levels and 10 new deathmatch levels.<br>					</li><li>New Power-Ups - Deathmatch specific power-ups: Vengeance Sphere, Hunter Sphere, and Anti-matter bomb.<br>					</li><li>New Weapons - The Chainsaw, ETF Rifle and Plasma Beam.</li></ul>','Take out the Big Gun sounded simple enough, except the Strogg were waiting. You, and a few marines like you, are the lucky ones. You''ve made it down in one piece and are still able to contact the fleet. The Gravity Well, the Strogg''s newest weapon in its arsenal against mankind, is operational. With the fleet around Stroggos, 5% of ground forces surviving, and that number dwindling by the second, your orders have changed: free your comrades. Destroy the Gravity Well.<br>					<ul class="bb_ul"><li>New Enemies - The Stalker, Turrets, Daedalus, Medic Commander, Carrier, and the Black Widow.<br>					</li><li>14 Entirely new levels and 10 new deathmatch levels.<br>					</li><li>New Power-Ups - Deathmatch specific power-ups: Vengeance Sphere, Hunter Sphere, and Anti-matter bomb.<br>					</li><li>New Weapons - The Chainsaw, ETF Rifle and Plasma Beam.</li></ul>','Take out the Big Gun sounded simple enough, except the Strogg were waiting. You, and a few marines like you, are the lucky ones. You''ve made it down in one piece and are still able to contact the fleet. The Gravity Well, the Strogg''s newest weapon in its arsenal against mankind, is operational.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2350,'Never before have the forces aligned. United by name and by cause, The Fallen, Pagans, Crusaders, Intruders, and Stroggs must channel their power into an allied operation where teamwork is the only method of mass destruction. Four distinct games test each troop''s synthesis and strength to exacting degrees. Cooperation is the only course of action, and war, the only alternative. Soldiers once alone in their struggle, now face the Arena as one.','Never before have the forces aligned. United by name and by cause, The Fallen, Pagans, Crusaders, Intruders, and Stroggs must channel their power into an allied operation where teamwork is the only method of mass destruction. Four distinct games test each troop''s synthesis and strength to exacting degrees. Cooperation is the only course of action, and war, the only alternative. Soldiers once alone in their struggle, now face the Arena as one.','Never before have the forces aligned. United by name and by cause, The Fallen, Pagans, Crusaders, Intruders, and Stroggs must channel their power into an allied operation where teamwork is the only method of mass destruction. Four distinct games test each troop''s synthesis and strength to exacting degrees.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2360,'<p>While you were battling the evil forces of D''Sparil, the other Serpent Riders were busy sowing the seeds of destruction in other dimensions. One such dimension is the decaying world where Hexen takes place. A world littered with the mangled corpses of nonbelievers and inhabited by the undead followers that executed them. Only three humans &endash; a warrior, a mage and a cleric &endash; have escaped the leaders'' vicious spell. Now these brave souls have sworn to crush the evil regime that threatens to destroy the world forever. Separated upon entering the mystical portal, the three are forced to attempt on their own what they had hoped to do together: find Korax''s stronghold, destroy him and restore order in the physical world.</p>
					<ul>
					<li>Become one of 3 heroes. Wield superhuman powers and lethal weapons.</li>
					<li>Walk. Run. Fly. Look all around. Inflict serious pain.</li>
					<li>Pillage your way through earthquakes, crumbling bridges and fog.</li>
					<li>Track down powerful artifacts and cast wicked spells.</li>
					<li>Four sick individuals can wreak havoc via network, two by modem.</li></ul>','<p>While you were battling the evil forces of D''Sparil, the other Serpent Riders were busy sowing the seeds of destruction in other dimensions. One such dimension is the decaying world where Hexen takes place. A world littered with the mangled corpses of nonbelievers and inhabited by the undead followers that executed them. Only three humans &endash; a warrior, a mage and a cleric &endash; have escaped the leaders'' vicious spell. Now these brave souls have sworn to crush the evil regime that threatens to destroy the world forever. Separated upon entering the mystical portal, the three are forced to attempt on their own what they had hoped to do together: find Korax''s stronghold, destroy him and restore order in the physical world.</p>
					<ul>
					<li>Become one of 3 heroes. Wield superhuman powers and lethal weapons.</li>
					<li>Walk. Run. Fly. Look all around. Inflict serious pain.</li>
					<li>Pillage your way through earthquakes, crumbling bridges and fog.</li>
					<li>Track down powerful artifacts and cast wicked spells.</li>
					<li>Four sick individuals can wreak havoc via network, two by modem.</li></ul>','While you were battling the evil forces of D''Sparil, the other Serpent Riders were busy sowing the seeds of destruction in other dimensions. One such dimension is the decaying world where Hexen takes place. A world littered with the mangled corpses of nonbelievers and inhabited by the undead followers that executed them.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2370,'<p>Where HeXen Ends, the True Nightmare Begins. Deathkings of the Dark Citadel is the only official expansion of the original HeXen game. This add-on pack features 20 new single player levels from the original HeXen team as well as a host of new multiplayer options.</p>
					<p>Deathkings of the Dark Citadel was the first true game expansion that Raven Software ever produced. In addition to providing three new hubs for the original HeXen, the Deathkings expansion was the first multiplayer game that allowed eight players to connect to a LAN simultaneously.</p>','<p>Where HeXen Ends, the True Nightmare Begins. Deathkings of the Dark Citadel is the only official expansion of the original HeXen game. This add-on pack features 20 new single player levels from the original HeXen team as well as a host of new multiplayer options.</p>
					<p>Deathkings of the Dark Citadel was the first true game expansion that Raven Software ever produced. In addition to providing three new hubs for the original HeXen, the Deathkings expansion was the first multiplayer game that allowed eight players to connect to a LAN simultaneously.</p>','Where HeXen Ends, the True Nightmare Begins. Deathkings of the Dark Citadel is the only official expansion of the original HeXen game. This add-on pack features 20 new single player levels from the original HeXen team as well as a host of new multiplayer options.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2390,'<p>In a twisted medieval dimension, undead creatures and bestial horrors have done the unthinkable--callously slaughtering your entire race. Your friends. Your family. Eliminated. But the nightmare has just begun. Wielding ungodly weapons such as the Firemace and Hellstaff and casting spells from the Tomes of Power, you must seek your vengeance. Or die trying.</p>
					<ul>
					<li>Supports up to four players via network, two by modem. Adventure through the game with a friend or crack their skull in a bloody deathmatch.</li>
					<li>Walk. Run. Fly. Look all around you, even up and down.</li>
					<li>Choose from among 7 weapons (from the simple staff to the awesome Phoenix Rod).</li>
					<li>Use arcane artifacts to unleash unearthly power on unsuspecting foes.</li></ul>','<p>In a twisted medieval dimension, undead creatures and bestial horrors have done the unthinkable--callously slaughtering your entire race. Your friends. Your family. Eliminated. But the nightmare has just begun. Wielding ungodly weapons such as the Firemace and Hellstaff and casting spells from the Tomes of Power, you must seek your vengeance. Or die trying.</p>
					<ul>
					<li>Supports up to four players via network, two by modem. Adventure through the game with a friend or crack their skull in a bloody deathmatch.</li>
					<li>Walk. Run. Fly. Look all around you, even up and down.</li>
					<li>Choose from among 7 weapons (from the simple staff to the awesome Phoenix Rod).</li>
					<li>Use arcane artifacts to unleash unearthly power on unsuspecting foes.</li></ul>','In a twisted medieval dimension, undead creatures and bestial horrors have done the unthinkable--callously slaughtering your entire race. Your friends. Your family. Eliminated. But the nightmare has just begun.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2400,'<h1>Finding a Server</h1><p><strong>Ahoy Shipmates!</strong><br><br>Unfortunately the in-game server browser is no longer working.  However, players can connect to servers via the Steam Client &gt; View &gt; Servers (if you don''t see The Ship you may have to restart the client).  Feel free to drop by the forums to chat about this and you can find a more detail explanation of the issues in our announcement:  <a href="http://steamcommunity.com/games/theship/announcements/detail/194000194554609687" target="_blank" rel="noreferrer"  >http://steamcommunity.com/games/theship/announcements/detail/194000194554609687</a></p><br><h1>About the Game</h1><strong>This package includes a tutorial, The Ship Single Player, which introduces you to some gameplay mechanics and storyline, and The Ship Multiplayer where you can hunt and be hunted by other players.</strong><br><br>Please read our State of the Game announcement:  <a href="http://steamcommunity.com/gid/103582791430084264/announcements/detail/194000194554609687" target="_blank" rel="noreferrer"  >http://steamcommunity.com/gid/103582791430084264/announcements/detail/194000194554609687</a><br><br>For PC gamers who enjoy multiplayer games with a bit of intelligence, intrigue and ingenuity, <strong>The Ship</strong> is a murder mystery alternative to traditional FPS multiplayer games.  Each player is given a Quarry to kill - and must evade their own Hunter in the process, all set on board a series of 1920s art deco cruise ships.<br><br>The Ship is owned by the mysterious Mr X and as one of many ''lucky'' recipients of a free ticket you arrive on board The Ship to find there''s a catch to your luxury cruise.  You are coerced into a brutal Hunt to indulge Mr. X''s fantasies, under threat of death for not only yourself, but also your family. Your only chance to save yourself and your family is to play the Hunt and win.<br><br>Combining stealthy multiplayer action and a needs system, The Ship is a truly unique gaming experience.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/2400/extras/The-Ship---Mr-X.jpg?t=1521044912" >','<strong>This package includes a tutorial, The Ship Single Player, which introduces you to some gameplay mechanics and storyline, and The Ship Multiplayer where you can hunt and be hunted by other players.</strong><br><br>Please read our State of the Game announcement:  <a href="http://steamcommunity.com/gid/103582791430084264/announcements/detail/194000194554609687" target="_blank" rel="noreferrer"  >http://steamcommunity.com/gid/103582791430084264/announcements/detail/194000194554609687</a><br><br>For PC gamers who enjoy multiplayer games with a bit of intelligence, intrigue and ingenuity, <strong>The Ship</strong> is a murder mystery alternative to traditional FPS multiplayer games.  Each player is given a Quarry to kill - and must evade their own Hunter in the process, all set on board a series of 1920s art deco cruise ships.<br><br>The Ship is owned by the mysterious Mr X and as one of many ''lucky'' recipients of a free ticket you arrive on board The Ship to find there''s a catch to your luxury cruise.  You are coerced into a brutal Hunt to indulge Mr. X''s fantasies, under threat of death for not only yourself, but also your family. Your only chance to save yourself and your family is to play the Hunt and win.<br><br>Combining stealthy multiplayer action and a needs system, The Ship is a truly unique gaming experience.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/2400/extras/The-Ship---Mr-X.jpg?t=1521044912" >','The Ship is a murder mystery multiplayer.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2450,'<p>Congratulations, you’ve just been cast in your first slasher movie!  You’ve been given your big break by the notorious Director X. His methods have produced some of the finest grindhouse films ever committed to celluloid. Famous faces and big names are not what this director is looking for. Fresh faces are all Director X casts, and with your embarrassingly empty resume you’re as fresh as they come!</p>
					<p>But seven other hopefuls are also in the running, so you’re going to need to prove your worth if you’re to hit the leading credits. You’re going to have to scratch, claw and strike to slash your way to the top. This job’s going to be murder!</p>
					<p>Developed by Outerlight, Bloody Good Time takes a new and irreverent approach to multiplayer shooters. The game runs on the Valve’s Source engine, known for classic multiplayer shooters such as Half-Life and Team Fortress.</p>
					<h2>Key Features:</h2>
					<ul>
						  <li><strong>Be a deceitful bastard!</strong> Flush your enemies in the toilet, crash their heads on their plates when they eat, do whatever it takes to maim and <strong>kill other competitors in nasty and unexpected ways!</strong>
						  <li>Use a <strong>full arsenal of wacky weapons</strong> including guns, a baseball bat, a frying pan, and even an exploding remote-controlled rat to <strong>transform the movie set into real mayhem!</strong>
						  <li>Clash with up to 8 players online in a zany, first-person shooter, <strong>multiplayer experience like no other</strong>. 
						  <li>Choose from a variety of <strong>stereotypical B- movie characters</strong>, including the bikini beach babe, the stoner, the creepy clown and the super jock.
						  <li>From Spring Break Beach to the Horror House to the Vegas Hotel, discover <strong>what’s behind the Hollywood set in these unique multiplayer maps</strong>.
						  <li><strong>Developed by Outerlight</strong>, best known for their work on The Ship and the Half-Life mod of the Ship. This Scottish-based developer brings a great combination of humor and quality game play to Bloody Good Time.
						  <li>Running on the <strong>Valve’s Source engine</strong>, Bloody Good Time comes from the same pedigree of classic, online multiplayer shooters such as Half-Life, Team Fortress and Counter-Strike.
					</ul>','<p>Congratulations, you’ve just been cast in your first slasher movie!  You’ve been given your big break by the notorious Director X. His methods have produced some of the finest grindhouse films ever committed to celluloid. Famous faces and big names are not what this director is looking for. Fresh faces are all Director X casts, and with your embarrassingly empty resume you’re as fresh as they come!</p>
					<p>But seven other hopefuls are also in the running, so you’re going to need to prove your worth if you’re to hit the leading credits. You’re going to have to scratch, claw and strike to slash your way to the top. This job’s going to be murder!</p>
					<p>Developed by Outerlight, Bloody Good Time takes a new and irreverent approach to multiplayer shooters. The game runs on the Valve’s Source engine, known for classic multiplayer shooters such as Half-Life and Team Fortress.</p>
					<h2>Key Features:</h2>
					<ul>
						  <li><strong>Be a deceitful bastard!</strong> Flush your enemies in the toilet, crash their heads on their plates when they eat, do whatever it takes to maim and <strong>kill other competitors in nasty and unexpected ways!</strong>
						  <li>Use a <strong>full arsenal of wacky weapons</strong> including guns, a baseball bat, a frying pan, and even an exploding remote-controlled rat to <strong>transform the movie set into real mayhem!</strong>
						  <li>Clash with up to 8 players online in a zany, first-person shooter, <strong>multiplayer experience like no other</strong>. 
						  <li>Choose from a variety of <strong>stereotypical B- movie characters</strong>, including the bikini beach babe, the stoner, the creepy clown and the super jock.
						  <li>From Spring Break Beach to the Horror House to the Vegas Hotel, discover <strong>what’s behind the Hollywood set in these unique multiplayer maps</strong>.
						  <li><strong>Developed by Outerlight</strong>, best known for their work on The Ship and the Half-Life mod of the Ship. This Scottish-based developer brings a great combination of humor and quality game play to Bloody Good Time.
						  <li>Running on the <strong>Valve’s Source engine</strong>, Bloody Good Time comes from the same pedigree of classic, online multiplayer shooters such as Half-Life, Team Fortress and Counter-Strike.
					</ul>','Congratulations, you’ve just been cast in your first slasher movie by the notorious Director X!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2500,'Shadowgrounds breathes fresh air into the action genre with explosive combat sequences, an innovative weapon upgrade system, and an intriguing storyline. The adrenaline-pumping, top-down gameplay and audiovisual fireworks set the scene for this new action experience which also includes single computer (split keyboard or joystick) co-op play.<br>					<strong>UPGRADE THOSE WEAPONS!</strong> Use a devastating arsenal of high-tech weaponry to dispose of the alien threat. Each weapon has multiple upgrades that maximize the carnage. Unleash the flames of the Flamethrower''s Fuel Trap, cause mayhem with the Grenade Launcher''s Poison Grenades, slash and dice the monsters with the Laser Rifle''s Pinpoint Laser - and many more!<br>					<strong>WHAT LURKS IN THE SHADOWS?</strong> Shadowgrounds uses cutting-edge realistic lighting and glow technology to light up the battlefield and create detailed shadows producing an atmosphere of fear. But the lighting and the flashlight also affect some aliens'' behavior - take advantage of that and you can turn the tide in the game of fear by using your flashlight effectively.<br>					<strong>DESTRUCTIBLE ENVIRONMENT!</strong> What good are weapons and special effects if you can''t wreak havoc on the environment? Shadowgrounds lets you go all-out - glass shatters, ground shakes, trees fall, barrels explode and furniture blows to smithereens. You can use the environment to your advantage.<br>					<strong>THEY''RE BIG AND NASTY!</strong> Big, brutal monsters await you. Prepare to face many different bosses who will do anything to stop your journey. They''re nasty, blood-thirsty beasts, but don''t give in to fear - remember to use the environment and the lighting to your advantage!<br>					<ul class="bb_ul"><li>Upgrade weaponry with powerful modifications.<br>					</li><li>Face enormous monsters in boss battles.<br>					</li><li>Destructible environment allows you to wreak havoc with your arsenal.<br>					</li><li>Visit many exciting locations, including a secret military base and the alien-infested colony New Atlantis.<br>					</li><li>Fight side-by-side with NPC allies against the massive alien hordes.<br>					</li><li>Check security cameras and computer logs to investigate alien origins.<br>					</li><li>Realistic lighting with gameplay effects bring the aliens out of the shadows.<br>					</li><li>Enjoy horrifying sound effects and a thrilling music soundtrack made exclusively for Shadowgrounds.</li></ul>','Shadowgrounds breathes fresh air into the action genre with explosive combat sequences, an innovative weapon upgrade system, and an intriguing storyline. The adrenaline-pumping, top-down gameplay and audiovisual fireworks set the scene for this new action experience which also includes single computer (split keyboard or joystick) co-op play.<br>					<strong>UPGRADE THOSE WEAPONS!</strong> Use a devastating arsenal of high-tech weaponry to dispose of the alien threat. Each weapon has multiple upgrades that maximize the carnage. Unleash the flames of the Flamethrower''s Fuel Trap, cause mayhem with the Grenade Launcher''s Poison Grenades, slash and dice the monsters with the Laser Rifle''s Pinpoint Laser - and many more!<br>					<strong>WHAT LURKS IN THE SHADOWS?</strong> Shadowgrounds uses cutting-edge realistic lighting and glow technology to light up the battlefield and create detailed shadows producing an atmosphere of fear. But the lighting and the flashlight also affect some aliens'' behavior - take advantage of that and you can turn the tide in the game of fear by using your flashlight effectively.<br>					<strong>DESTRUCTIBLE ENVIRONMENT!</strong> What good are weapons and special effects if you can''t wreak havoc on the environment? Shadowgrounds lets you go all-out - glass shatters, ground shakes, trees fall, barrels explode and furniture blows to smithereens. You can use the environment to your advantage.<br>					<strong>THEY''RE BIG AND NASTY!</strong> Big, brutal monsters await you. Prepare to face many different bosses who will do anything to stop your journey. They''re nasty, blood-thirsty beasts, but don''t give in to fear - remember to use the environment and the lighting to your advantage!<br>					<ul class="bb_ul"><li>Upgrade weaponry with powerful modifications.<br>					</li><li>Face enormous monsters in boss battles.<br>					</li><li>Destructible environment allows you to wreak havoc with your arsenal.<br>					</li><li>Visit many exciting locations, including a secret military base and the alien-infested colony New Atlantis.<br>					</li><li>Fight side-by-side with NPC allies against the massive alien hordes.<br>					</li><li>Check security cameras and computer logs to investigate alien origins.<br>					</li><li>Realistic lighting with gameplay effects bring the aliens out of the shadows.<br>					</li><li>Enjoy horrifying sound effects and a thrilling music soundtrack made exclusively for Shadowgrounds.</li></ul>','Shadowgrounds breathes fresh air into the action genre with explosive combat sequences, an innovative weapon upgrade system, and an intriguing storyline. The adrenaline-pumping, top-down gameplay and audiovisual fireworks set the scene for this new action experience which also includes single computer (split keyboard or joystick) co-op...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2520,'Gumboy has fun and novel gameplay set in a richly imagined world.   With simple game controls, Gumboy lets the player bounce, roll, float, and fly through the world.  Additionally, Gumboy can change size, shape and material.  Moving through the world with different physical properties and gameplay:  spheres, cubes or stars filled with rubber, air or water...  Combine these elements with objectives centered on particle effects and control and Gumboy is refreshing, challenging, and original fun for everyone for all types of gamers.<br>					<ul class="bb_ul"><li>Innovative game based on ball physics in various environments<br>					</li><li>Over 50 levels within a fairy-tale atmosphere<br>					</li><li>Interactive environments: water, wind, rain, teleports, boosts, sticky and slippery surfaces<br>					</li><li>Original artistic depiction of 6 various worlds (forest, field, cave, magical world...)<br>					</li><li>Fantastic lighting and dynamic effects<br>					</li><li>Detailed graphics with acceleration and fascinating particle effects<br>					</li><li>Various ball shapes: sphere, cube, star<br>					</li><li>Various ball fillings with an influence on its characteristics: rubber, air, water<br>					</li><li>Saves games in progress and the results achieved for several players<br>					</li><li>Game supports widescreen displays (16:9)</li></ul>','Gumboy has fun and novel gameplay set in a richly imagined world.   With simple game controls, Gumboy lets the player bounce, roll, float, and fly through the world.  Additionally, Gumboy can change size, shape and material.  Moving through the world with different physical properties and gameplay:  spheres, cubes or stars filled with rubber, air or water...  Combine these elements with objectives centered on particle effects and control and Gumboy is refreshing, challenging, and original fun for everyone for all types of gamers.<br>					<ul class="bb_ul"><li>Innovative game based on ball physics in various environments<br>					</li><li>Over 50 levels within a fairy-tale atmosphere<br>					</li><li>Interactive environments: water, wind, rain, teleports, boosts, sticky and slippery surfaces<br>					</li><li>Original artistic depiction of 6 various worlds (forest, field, cave, magical world...)<br>					</li><li>Fantastic lighting and dynamic effects<br>					</li><li>Detailed graphics with acceleration and fascinating particle effects<br>					</li><li>Various ball shapes: sphere, cube, star<br>					</li><li>Various ball fillings with an influence on its characteristics: rubber, air, water<br>					</li><li>Saves games in progress and the results achieved for several players<br>					</li><li>Game supports widescreen displays (16:9)</li></ul>','Gumboy has fun and novel gameplay set in a richly imagined world. With simple game controls, Gumboy lets the player bounce, roll, float, and fly through the world. Additionally, Gumboy can change size, shape and material.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2590,'Somewhere in deep space, at an apparently abandoned mining base on the asteriod Alpha Prime, something has gone terribly wrong. Miners were warned that the hubbardium they were mining was too dangerous, but the lure of unimaginable wealth was too strong. Now, something has happened to them and it''s up to you to save them and face an unknown threat.<br>					Equipped with a surplus of advanced weapons and devices--including a variety of robots and manipulators, surveillance cameras and security systems that can be hacked, controlled and used to complete your task--your mission is simple: Get in, get ''em, and get out!<br>					<ul class="bb_ul"><li>10 levels of fast-paced, unrelenting action including mining station, spaceship hangar, magnetic railway or asteroid surface<br>					</li><li>Non-playable characters aid you in your mission to save the miners and get off the asteroid<br>					</li><li>Countless enemies including Special Forces soldiers, robots and deranged miners<br>					</li><li>8 futuristic weapons including pistols, shotguns, machine guns, grenades…<br>					</li><li>Vehicles can be used to move to different locations quickly<br>					</li><li>Hack into devices including robots, surveillance cameras, security systems, doors, etc.<br>					</li><li>Bullet time allows players to temporarily slow down the action and get the upper hand<br>					</li><li>Compatible with Matrox TripleHead2Go™, enabling gamers to connect 3 screens</li></ul>','Somewhere in deep space, at an apparently abandoned mining base on the asteriod Alpha Prime, something has gone terribly wrong. Miners were warned that the hubbardium they were mining was too dangerous, but the lure of unimaginable wealth was too strong. Now, something has happened to them and it''s up to you to save them and face an unknown threat.<br>					Equipped with a surplus of advanced weapons and devices--including a variety of robots and manipulators, surveillance cameras and security systems that can be hacked, controlled and used to complete your task--your mission is simple: Get in, get ''em, and get out!<br>					<ul class="bb_ul"><li>10 levels of fast-paced, unrelenting action including mining station, spaceship hangar, magnetic railway or asteroid surface<br>					</li><li>Non-playable characters aid you in your mission to save the miners and get off the asteroid<br>					</li><li>Countless enemies including Special Forces soldiers, robots and deranged miners<br>					</li><li>8 futuristic weapons including pistols, shotguns, machine guns, grenades…<br>					</li><li>Vehicles can be used to move to different locations quickly<br>					</li><li>Hack into devices including robots, surveillance cameras, security systems, doors, etc.<br>					</li><li>Bullet time allows players to temporarily slow down the action and get the upper hand<br>					</li><li>Compatible with Matrox TripleHead2Go™, enabling gamers to connect 3 screens</li></ul>','Somewhere in deep space, at an apparently abandoned mining base on the asteriod Alpha Prime, something has gone terribly wrong. Miners were warned that the hubbardium they were mining was too dangerous, but the lure of unimaginable wealth was too strong.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2600,'Vampire®: The Masquerade-Bloodlines™ delivers a new type of RPG experience-one that blends all the core elements of a traditional RPG with the graphical richness, immediacy and brutal combat of a first-person action game. The game plunges players into the dark and gritty vampire underworld of modern-day L.A. as a creature of the night. Players will develop their character''s powers, interact with other characters and embark on story-driven quests as they battle mortals and other vampires with an incredible array of vampire powers and weapons. Powered by Valve''s Source Technology, the game is based on White Wolf''s popular Vampire: The Masquerade pen-and-paper RPG series and its official clans.','Vampire®: The Masquerade-Bloodlines™ delivers a new type of RPG experience-one that blends all the core elements of a traditional RPG with the graphical richness, immediacy and brutal combat of a first-person action game. The game plunges players into the dark and gritty vampire underworld of modern-day L.A. as a creature of the night. Players will develop their character''s powers, interact with other characters and embark on story-driven quests as they battle mortals and other vampires with an incredible array of vampire powers and weapons. Powered by Valve''s Source Technology, the game is based on White Wolf''s popular Vampire: The Masquerade pen-and-paper RPG series and its official clans.','Vampire®: The Masquerade-Bloodlines™ delivers a new type of RPG experience-one that blends all the core elements of a traditional RPG with the graphical richness, immediacy and brutal combat of a first-person action game. The game plunges players into the dark and gritty vampire underworld of modern-day L.A. as a creature of the night.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2610,'When life robs Colton White of all that matters, the only thing left he can trust is his GUN. From award-winning developer, Neversoft, and accomplished screenwriter, Randall Jahnson (The Mask of Zorro, The Doors), GUN follows Colton on his quest for discovery as he seeks to exact vengeful justice on those who have wronged him. GUN is a realistic epic action/adventure that lets gamers experience the brutality of the lawless West.<br>					<ul class="bb_ul"><li>New and savage ways to punish: Stealthily sneak up and attack your enemies, use them as cover, stab and shoot them. Blast away and watch the aftermath, shoot guns out of enemy hands, or destroy with dynamite. <br>					</li><li>Extensive variety of missions and game play: Wage war on horseback, commandeer trains, protect prostitutes, collect bounties, play poker, hunt buffalo, and more. Multiple game play styles include: precision shooting, stealth tactics, and use of explosives. Embark on numerous side missions that allow you to master gun slinging and horse riding. Unlock secret weapons and upgrade your skills and abilities to improve your weapon and equipment performance.<br>					</li><li>Brutal realism: Act as a gunslinger protecting righteousness, or seek retribution as you face corrupt lawmen, warring tribes, cold-blooded outlaws, and ruthless renegades. Encounter legendary gunfighters such as JJ Webb. Employ a multitude of authentic weapons including: Six shooters, shotguns, Gatling guns, flaming arrows, hatchets, dynamite, and more.<br>					</li><li>Expansive interactive world: Play an extensive variety of exciting missions as you journey west across the new frontier. Ride on horseback through the scenic, yet dangerous Western terrain of canyons, mountains, plains, forests, gold mines and towns.</li></ul><br>© 2006 Activision Publishing, Inc.  Activision is a registered trademark and GUN is a trademark of Activision Publishing, Inc.  All rights reserved.  All other trademarks and trade names are the properties of their respective owners.','When life robs Colton White of all that matters, the only thing left he can trust is his GUN. From award-winning developer, Neversoft, and accomplished screenwriter, Randall Jahnson (The Mask of Zorro, The Doors), GUN follows Colton on his quest for discovery as he seeks to exact vengeful justice on those who have wronged him. GUN is a realistic epic action/adventure that lets gamers experience the brutality of the lawless West.<br>					<ul class="bb_ul"><li>New and savage ways to punish: Stealthily sneak up and attack your enemies, use them as cover, stab and shoot them. Blast away and watch the aftermath, shoot guns out of enemy hands, or destroy with dynamite. <br>					</li><li>Extensive variety of missions and game play: Wage war on horseback, commandeer trains, protect prostitutes, collect bounties, play poker, hunt buffalo, and more. Multiple game play styles include: precision shooting, stealth tactics, and use of explosives. Embark on numerous side missions that allow you to master gun slinging and horse riding. Unlock secret weapons and upgrade your skills and abilities to improve your weapon and equipment performance.<br>					</li><li>Brutal realism: Act as a gunslinger protecting righteousness, or seek retribution as you face corrupt lawmen, warring tribes, cold-blooded outlaws, and ruthless renegades. Encounter legendary gunfighters such as JJ Webb. Employ a multitude of authentic weapons including: Six shooters, shotguns, Gatling guns, flaming arrows, hatchets, dynamite, and more.<br>					</li><li>Expansive interactive world: Play an extensive variety of exciting missions as you journey west across the new frontier. Ride on horseback through the scenic, yet dangerous Western terrain of canyons, mountains, plains, forests, gold mines and towns.</li></ul><br>© 2006 Activision Publishing, Inc.  Activision is a registered trademark and GUN is a trademark of Activision Publishing, Inc.  All rights reserved.  All other trademarks and trade names are the properties of their respective owners.','When life robs Colton White of all that matters, the only thing left he can trust is his GUN. From award-winning developer, Neversoft, and accomplished screenwriter, Randall Jahnson (The Mask of Zorro, The Doors), GUN follows Colton on his quest for discovery as he seeks to exact vengeful justice on those who have wronged him.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2620,'<strong><i>Call of Duty®</i></strong> delivers the gritty realism and cinematic intensity of World War II''s epic battlefield moments like never before - through the eyes of citizen soldiers and unsung heroes from an alliance of countries who together helped shape the course of modern history.<br><br>Play through the chaos of battle as part of a well-trained squad, that lays down covering fire and pulls its wounded to safety. In addition to authentic squad movements and tactics, each soldier''s distinct personality and training comes out on the battlefield.<br><br>No one soldier or nation single-handedly won the war. For the first time, <strong><i>Call of Duty®</i></strong> captures the war from multiple perspectives, through the eyes of American, British and Russian soldiers. Battle through 24 missions spanning 4 interconnected historical campaigns. Take on mission objectives ranging from sabotage and all-out assault to stealth, vehicle combat and rescue. Authentic weapons, locations, vehicles and sounds of war all contribute to the realism, immersing you in the most intense World War II experience yet.<br><br>© 2003 Activision Publishing, Inc.  Activision and Call of Duty are registered trademarks of Activision Publishing, Inc.  All rights reserved.  All other trademarks and trade names are the properties of their respective owners.','<strong><i>Call of Duty®</i></strong> delivers the gritty realism and cinematic intensity of World War II''s epic battlefield moments like never before - through the eyes of citizen soldiers and unsung heroes from an alliance of countries who together helped shape the course of modern history.<br><br>Play through the chaos of battle as part of a well-trained squad, that lays down covering fire and pulls its wounded to safety. In addition to authentic squad movements and tactics, each soldier''s distinct personality and training comes out on the battlefield.<br><br>No one soldier or nation single-handedly won the war. For the first time, <strong><i>Call of Duty®</i></strong> captures the war from multiple perspectives, through the eyes of American, British and Russian soldiers. Battle through 24 missions spanning 4 interconnected historical campaigns. Take on mission objectives ranging from sabotage and all-out assault to stealth, vehicle combat and rescue. Authentic weapons, locations, vehicles and sounds of war all contribute to the realism, immersing you in the most intense World War II experience yet.<br><br>© 2003 Activision Publishing, Inc.  Activision and Call of Duty are registered trademarks of Activision Publishing, Inc.  All rights reserved.  All other trademarks and trade names are the properties of their respective owners.','Call of Duty® delivers the gritty realism and cinematic intensity of World War II''s epic battlefield moments like never before - through the eyes of citizen soldiers and unsung heroes from an alliance of countries who together helped shape the course of modern history.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2630,'Call of Duty® 2 redefines the cinematic intensity and chaos of battle as seen through the eyes of ordinary soldiers fighting together in epic WWII conflicts. The sequel to 2003''s Call of Duty, winner of over 80 Game of the Year awards, Call of Duty 2 offers more immense, more intense, more realistic battles than ever before, thanks to the stunning visuals of the new COD™2 engine.<br>					<ul class="bb_ul"><li>The #1 WWII shooter development team returns with an amazing new experience: Developed by Infinity Ward, creators of the award-winning Call of Duty. All-new, unprecedented enhancements from stunningly realistic graphics to seamless gameplay, thanks to the revolutionary COD2 engine, groundbreaking AI, and choice-based gameplay innovations. Beautifully rendered snow, rain, fog, and smoke, combined with dynamic lighting and shadows, make this the most intense WWII shooter yet.<br>					</li><li>New conflicts and enemies to face: Call of Duty 2 brings you bigger battles, with more tanks, troops, and explosions on-screen, and bigger scope, with a wide range of locales and environments across the European Theater. Fight &quot;The Desert Fox&quot; across the scorching sands of North Africa as wave upon wave of tanks clash in the desert. Use rocket-propelled grappling hooks alongside your Army Ranger squad to storm and scale the cliffs of Pointe du Hoc against a relentless German counterassault, and slog through urban chaos as a tank hunter in war-torn Russia. <br>					</li><li>Rely on your squad as never before: The dozens of Allied soldiers surrounding you are fully aware of the changing situations around them, and will let you know using an all-new, context-sensitive battle chatter system. They will draw enemy fire, lay down cover for you, use foxholes and moving tanks for cover, and warn you of incoming enemy troops and hostile fire.<br>					</li><li>Choice-based gameplay: Play through missions in the order you see fit. Will you decide to play first as a sniper or as a tank commander? It''s your call. Open-ended battlefields allow you to individualize your tactics and choose the order in which you complete your objectives. <br>					</li><li>Multiplayer Mayhem: Go online for intense Axis vs. Allies team-based multiplayer action, building on the hugely popular Call of Duty multiplayer modes.</li></ul>','Call of Duty® 2 redefines the cinematic intensity and chaos of battle as seen through the eyes of ordinary soldiers fighting together in epic WWII conflicts. The sequel to 2003''s Call of Duty, winner of over 80 Game of the Year awards, Call of Duty 2 offers more immense, more intense, more realistic battles than ever before, thanks to the stunning visuals of the new COD™2 engine.<br>					<ul class="bb_ul"><li>The #1 WWII shooter development team returns with an amazing new experience: Developed by Infinity Ward, creators of the award-winning Call of Duty. All-new, unprecedented enhancements from stunningly realistic graphics to seamless gameplay, thanks to the revolutionary COD2 engine, groundbreaking AI, and choice-based gameplay innovations. Beautifully rendered snow, rain, fog, and smoke, combined with dynamic lighting and shadows, make this the most intense WWII shooter yet.<br>					</li><li>New conflicts and enemies to face: Call of Duty 2 brings you bigger battles, with more tanks, troops, and explosions on-screen, and bigger scope, with a wide range of locales and environments across the European Theater. Fight &quot;The Desert Fox&quot; across the scorching sands of North Africa as wave upon wave of tanks clash in the desert. Use rocket-propelled grappling hooks alongside your Army Ranger squad to storm and scale the cliffs of Pointe du Hoc against a relentless German counterassault, and slog through urban chaos as a tank hunter in war-torn Russia. <br>					</li><li>Rely on your squad as never before: The dozens of Allied soldiers surrounding you are fully aware of the changing situations around them, and will let you know using an all-new, context-sensitive battle chatter system. They will draw enemy fire, lay down cover for you, use foxholes and moving tanks for cover, and warn you of incoming enemy troops and hostile fire.<br>					</li><li>Choice-based gameplay: Play through missions in the order you see fit. Will you decide to play first as a sniper or as a tank commander? It''s your call. Open-ended battlefields allow you to individualize your tactics and choose the order in which you complete your objectives. <br>					</li><li>Multiplayer Mayhem: Go online for intense Axis vs. Allies team-based multiplayer action, building on the hugely popular Call of Duty multiplayer modes.</li></ul>','Call of Duty® 2 redefines the cinematic intensity and chaos of battle as seen through the eyes of ordinary soldiers fighting together in epic WWII conflicts. The sequel to 2003''s Call of Duty, winner of over 80 Game of the Year awards, Call of Duty 2 offers more immense, more intense, more realistic battles than ever before, thanks to...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2640,'Award-winning developer Gray Matter Interactive follows up on the success of Infinity Ward''s Call of Duty™ - winner of over 80 Game of the Year and 50 Editors'' Choice awards worldwide - with Call of Duty™: United Offensive™. Take the role of American, British, and Russian soldiers in some of the most climactic battles of World War II, including the Battle of the Bulge, the invasion of Sicily, and the Battle of Kursk.<br />
					Fight in tanks, jeeps, motorcycles, even a bomber. Work with your squad through snow and rain, using new weapons including flamethrowers and deployable machine guns, or by calling in artillery strikes. 13 All-New Single Player missions spanning three campaigns. 11 exciting new Multiplayer maps and 3 new multiplayer modes including Domination, Capture the Flag, and Base Assault.<br />
<br />
© 2006 Activision Publishing, Inc.  Activision and Call of Duty are registered trademarks of Activision Publishing, Inc.  All rights reserved.  All other trademarks and trade names are the properties of their respective owners.','Award-winning developer Gray Matter Interactive follows up on the success of Infinity Ward''s Call of Duty™ - winner of over 80 Game of the Year and 50 Editors'' Choice awards worldwide - with Call of Duty™: United Offensive™. Take the role of American, British, and Russian soldiers in some of the most climactic battles of World War II, including the Battle of the Bulge, the invasion of Sicily, and the Battle of Kursk.<br />
					Fight in tanks, jeeps, motorcycles, even a bomber. Work with your squad through snow and rain, using new weapons including flamethrowers and deployable machine guns, or by calling in artillery strikes. 13 All-New Single Player missions spanning three campaigns. 11 exciting new Multiplayer maps and 3 new multiplayer modes including Domination, Capture the Flag, and Base Assault.<br />
<br />
© 2006 Activision Publishing, Inc.  Activision and Call of Duty are registered trademarks of Activision Publishing, Inc.  All rights reserved.  All other trademarks and trade names are the properties of their respective owners.','Award-winning developer Gray Matter Interactive follows up on the success of Infinity Ward''s Call of Duty™ - winner of over 80 Game of the Year and 50 Editors'' Choice awards worldwide - with Call of Duty™: United Offensive™.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2710,'<strong>Tomorrow''s War Is NOW</strong><br>					Ripped from today''s headlines, Act of War: Direct Action™ is a frightening tale of suspense, international intrigue and geopolitical military conflict. This real-time strategy experience puts you squarely in control of counterterrorist forces and delivers a first look at tomorrow''s war.<br>					The Situation:<br>					A crippling energy crisis. Terrorist attacks. Massive strikes. Global instability.<br>					<br>					The Enemy:<br>					A shadowy Consortium of back-room conspirators determined to throw the world into utter chaos using widespread terror tactics. <br>					<br>					The Heroes:<br>					A new &quot;direct action&quot; operation known as Task Force TALON to counter massive military assaults, rescue hostages, conduct classified spy missions, take prisoners and stop an unpredictable enemy bent on toppling the world''s governments.<br>					<ul class="bb_ul"><li>Command ultra-realistic modern military units<br>					</li><li>Power-packed combination of high-end cinema, video effects and live action<br>					</li><li>Intense multiplayer operations for up to eight players<br>					</li><li>Real urban combat, including POW captures and landscape destruction<br>					</li><li>Gripping storyline by NY Times bestselling author, Dale Brown</li></ul>','<strong>Tomorrow''s War Is NOW</strong><br>					Ripped from today''s headlines, Act of War: Direct Action™ is a frightening tale of suspense, international intrigue and geopolitical military conflict. This real-time strategy experience puts you squarely in control of counterterrorist forces and delivers a first look at tomorrow''s war.<br>					The Situation:<br>					A crippling energy crisis. Terrorist attacks. Massive strikes. Global instability.<br>					<br>					The Enemy:<br>					A shadowy Consortium of back-room conspirators determined to throw the world into utter chaos using widespread terror tactics. <br>					<br>					The Heroes:<br>					A new &quot;direct action&quot; operation known as Task Force TALON to counter massive military assaults, rescue hostages, conduct classified spy missions, take prisoners and stop an unpredictable enemy bent on toppling the world''s governments.<br>					<ul class="bb_ul"><li>Command ultra-realistic modern military units<br>					</li><li>Power-packed combination of high-end cinema, video effects and live action<br>					</li><li>Intense multiplayer operations for up to eight players<br>					</li><li>Real urban combat, including POW captures and landscape destruction<br>					</li><li>Gripping storyline by NY Times bestselling author, Dale Brown</li></ul>','Tomorrow''s War Is NOW Ripped from today''s headlines, Act of War: Direct Action™ is a frightening tale of suspense, international intrigue and geopolitical military conflict. This real-time strategy experience puts you squarely in control of counterterrorist forces and delivers a first look at tomorrow''s war.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2720,'ThreadSpace: Hyperbol is an action-strategy game set in the distant future. Players battle each other on roads in space as they pilot massive ships capable of firing a wide variety of weapons.  Create defenses, coordinate with your team, and launch an assault against your opponents to achieve victory!<br>					<ul class="bb_ul"><li>Countless strategies: Over 30 unique projectiles are at your disposal to attack the enemy, fortify your defenses, and assist your allies.<br>					</li><li>Tactical team play: Coordinate with a team of players to defeat your opponents where every player can have unique strengths and weaknesses.  Up to 16 players online.<br>					</li><li>Customizable ships: Acquire ships to control and customize their design by selecting different parts and colors.  Customize the way your ship behaves by installing new components that alter its attributes.<br>					</li><li>Persistent universe: Play as a character you create that can gain levels and credits. Purchase new ships and components with the credits you earn to truly distinguish your character in the universe.<br>					</li><li>Online ladder system: Compete against other players online and see who the best pilots are.  Earn rewards for being on top.<br>					</li><li>Awards: Demonstrate your skill by earning in-game awards like &quot;Bounty Hunter&quot; and &quot;Combat Mastery&quot;.<br>					</li><li>Voice communication: Talk to your team to plan your attacks and coordinate your abilities.<br>					</li><li>Create custom maps: Make your own maps with the Map Editor to play them online and with your friends.</li></ul>','ThreadSpace: Hyperbol is an action-strategy game set in the distant future. Players battle each other on roads in space as they pilot massive ships capable of firing a wide variety of weapons.  Create defenses, coordinate with your team, and launch an assault against your opponents to achieve victory!<br>					<ul class="bb_ul"><li>Countless strategies: Over 30 unique projectiles are at your disposal to attack the enemy, fortify your defenses, and assist your allies.<br>					</li><li>Tactical team play: Coordinate with a team of players to defeat your opponents where every player can have unique strengths and weaknesses.  Up to 16 players online.<br>					</li><li>Customizable ships: Acquire ships to control and customize their design by selecting different parts and colors.  Customize the way your ship behaves by installing new components that alter its attributes.<br>					</li><li>Persistent universe: Play as a character you create that can gain levels and credits. Purchase new ships and components with the credits you earn to truly distinguish your character in the universe.<br>					</li><li>Online ladder system: Compete against other players online and see who the best pilots are.  Earn rewards for being on top.<br>					</li><li>Awards: Demonstrate your skill by earning in-game awards like &quot;Bounty Hunter&quot; and &quot;Combat Mastery&quot;.<br>					</li><li>Voice communication: Talk to your team to plan your attacks and coordinate your abilities.<br>					</li><li>Create custom maps: Make your own maps with the Map Editor to play them online and with your friends.</li></ul>','ThreadSpace: Hyperbol is an action-strategy game set in the distant future. Players battle each other on roads in space as they pilot massive ships capable of firing a wide variety of weapons. Create defenses, coordinate with your team, and launch an assault against your opponents to achieve victory!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2780,'Sequel to the highly successful Operation Flashpoint, ARMA: Combat Operations is a first person tactical military shooter on the PC with large elements of realism and simulation. This game features a blend of large-scale military conflict spread across large areas alongside the more close quartered battles. You''ll be thrust into the midst of an engaging and expanding storyline, fighting against smart, aggressive enemies who will continually provide a challenge over a massive landscape.<br>					<ul class="bb_ul"><li><strong>Story driven single player campaign:</strong> Write your own campaign storyline by choosing the right mission order when playing the 20+ missions. Play it differently next time and find new ways to victory!<br>					</li><li><strong>Large scale multiplayer:</strong> Use ARMA Combat Operations'' strong multiplayer mode and play battles where tanks supported by infantry and helicopters take control of an enemy city. The engine supports 50+ live opponents in a role of both friendly and enemy forces.<br>					</li><li><strong>More than 30 weapons:</strong> Every weapon has unique firing characteristics featuring the new and improved recoil system.<br>					</li><li><strong>Vast environment to explore:</strong> Explore Sahrani, an area over 400 square kilometers in size, full of flora and fauna.<br>					</li><li><strong>More than 30 modern vehicles:</strong> All vehicles in the game can be controlled - tanks, armored vehicles, helicopters, airplanes, civilian cars or even boats.<br>					</li><li><strong>Multiple gunners:</strong> Utilize the multiple gunner positions on tanks and helicopters to rain death on your enemies both in multiplayer missions and single player campaign.<br>					</li><li><strong>HDR Lighting effects:</strong> Ambushing an enemy with the sun in your eyes leaves you at the disadvantage. Think smart, fight better!<br>					</li><li><strong>Real constellations and tides:</strong> ARMA''s great depth even includes such features as fully simulated star maps, lunar cycles and tides. Watch where you park your vehicle, soldier!<br>					</li><li><strong>Built-in mission editor:</strong> Create you own scenarios using the easy-to-use mission wizard, advanced built-in mission editor, scripting language or BI tools available online and share your creation with the game.</li></ul>','Sequel to the highly successful Operation Flashpoint, ARMA: Combat Operations is a first person tactical military shooter on the PC with large elements of realism and simulation. This game features a blend of large-scale military conflict spread across large areas alongside the more close quartered battles. You''ll be thrust into the midst of an engaging and expanding storyline, fighting against smart, aggressive enemies who will continually provide a challenge over a massive landscape.<br>					<ul class="bb_ul"><li><strong>Story driven single player campaign:</strong> Write your own campaign storyline by choosing the right mission order when playing the 20+ missions. Play it differently next time and find new ways to victory!<br>					</li><li><strong>Large scale multiplayer:</strong> Use ARMA Combat Operations'' strong multiplayer mode and play battles where tanks supported by infantry and helicopters take control of an enemy city. The engine supports 50+ live opponents in a role of both friendly and enemy forces.<br>					</li><li><strong>More than 30 weapons:</strong> Every weapon has unique firing characteristics featuring the new and improved recoil system.<br>					</li><li><strong>Vast environment to explore:</strong> Explore Sahrani, an area over 400 square kilometers in size, full of flora and fauna.<br>					</li><li><strong>More than 30 modern vehicles:</strong> All vehicles in the game can be controlled - tanks, armored vehicles, helicopters, airplanes, civilian cars or even boats.<br>					</li><li><strong>Multiple gunners:</strong> Utilize the multiple gunner positions on tanks and helicopters to rain death on your enemies both in multiplayer missions and single player campaign.<br>					</li><li><strong>HDR Lighting effects:</strong> Ambushing an enemy with the sun in your eyes leaves you at the disadvantage. Think smart, fight better!<br>					</li><li><strong>Real constellations and tides:</strong> ARMA''s great depth even includes such features as fully simulated star maps, lunar cycles and tides. Watch where you park your vehicle, soldier!<br>					</li><li><strong>Built-in mission editor:</strong> Create you own scenarios using the easy-to-use mission wizard, advanced built-in mission editor, scripting language or BI tools available online and share your creation with the game.</li></ul>','Sequel to the highly successful Operation Flashpoint, ARMA: Combat Operations is a first person tactical military shooter on the PC with large elements of realism and simulation. This game features a blend of large-scale military conflict spread across large areas alongside the more close quartered battles.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2800,'X²: The Threat is of a new generation of space simulator games, you play the role of Julian Gardna who continues the story set by X: Beyond The Frontier. The updated graphics engine gives the universe a fresher feel with newly designed ships and stations adding to the complexity of the universe.<br>					<ul class="bb_ul"><li>Explore: You can explore over 130 beautifully designed sectors occupied by nebulas that affect your ships and stations, asteroids you can mine for materials you can later sell on for profit.<br>					</li><li>New Ships: Explore in over 60 ships of varying sizes from scout class ships to the much larger carrier class battleships.<br>					</li><li>New Upgrades:  Upgrade your ships systems with many more upgrades, and download new upgrades that make use of the new scripting engine designed specially for X².<br>					</li><li>New Weapons: Add new weapons to your ship including the Ion Disruptor and Mass Driver, but also build factories that will develop these weapons and sell them to make a profit, expanding your own empire among the universe.<br>					</li><li>New Missions:  Take part in missions offered to you on each stations bulletin board, make money by defending convoys and destroy incoming Xenon fleets intent on destroying everything in their path.<br>But above all else, help to defend the universe from the Khaak, before they kill everyone and everything they come across.</li></ul>','X²: The Threat is of a new generation of space simulator games, you play the role of Julian Gardna who continues the story set by X: Beyond The Frontier. The updated graphics engine gives the universe a fresher feel with newly designed ships and stations adding to the complexity of the universe.<br>					<ul class="bb_ul"><li>Explore: You can explore over 130 beautifully designed sectors occupied by nebulas that affect your ships and stations, asteroids you can mine for materials you can later sell on for profit.<br>					</li><li>New Ships: Explore in over 60 ships of varying sizes from scout class ships to the much larger carrier class battleships.<br>					</li><li>New Upgrades:  Upgrade your ships systems with many more upgrades, and download new upgrades that make use of the new scripting engine designed specially for X².<br>					</li><li>New Weapons: Add new weapons to your ship including the Ion Disruptor and Mass Driver, but also build factories that will develop these weapons and sell them to make a profit, expanding your own empire among the universe.<br>					</li><li>New Missions:  Take part in missions offered to you on each stations bulletin board, make money by defending convoys and destroy incoming Xenon fleets intent on destroying everything in their path.<br>But above all else, help to defend the universe from the Khaak, before they kill everyone and everything they come across.</li></ul>','X²: The Threat is of a new generation of space simulator games, you play the role of Julian Gardna who continues the story set by X: Beyond The Frontier. The updated graphics engine gives the universe a fresher feel with newly designed ships and stations adding to the complexity of the universe.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2810,'The Sequel to the award winning X²: The Threat introduces a new 3D engine as well as a new story, new ships and a new gameplay to greatly increase the variety in the X-universe. The economy of X³: Reunion is more complex than anything seen in the X-universe before. Factories are being built by NPCs, wars can affect the global economy, NPCs can trade freely and pirates behave far more realistically.<br />
					The Technology: Extensive development has gone into the X³ engine, making full use of DirectX 9 technology, to create dramatic visual effects and stunningly realistic starships. Coupled with the massively enhanced A.L. (Artificial Life) system, X³: REUNION presents players with an ever changing, evolving universe; where a player''s actions really can shape the future of the universe.<br />
					The new X³ 2.0: Bala Gi Research Missions: The X³ 2.0: Bala Gi Research Missions offers a host of new features and missions, allowing the player to delve deeper than ever before into the X universe.<br />
					Space just got a whole lot bigger with the addition of two new sectors and the introduction of the gargantuan Player HQ which allows many exciting new features including the ability to build your own ships and even give them customized space paint finishes.  In addition to the new M7 battleship, there is an assortment of new weapons and onboard ship devices to use and explore.','The Sequel to the award winning X²: The Threat introduces a new 3D engine as well as a new story, new ships and a new gameplay to greatly increase the variety in the X-universe. The economy of X³: Reunion is more complex than anything seen in the X-universe before. Factories are being built by NPCs, wars can affect the global economy, NPCs can trade freely and pirates behave far more realistically.<br />
					The Technology: Extensive development has gone into the X³ engine, making full use of DirectX 9 technology, to create dramatic visual effects and stunningly realistic starships. Coupled with the massively enhanced A.L. (Artificial Life) system, X³: REUNION presents players with an ever changing, evolving universe; where a player''s actions really can shape the future of the universe.<br />
					The new X³ 2.0: Bala Gi Research Missions: The X³ 2.0: Bala Gi Research Missions offers a host of new features and missions, allowing the player to delve deeper than ever before into the X universe.<br />
					Space just got a whole lot bigger with the addition of two new sectors and the introduction of the gargantuan Player HQ which allows many exciting new features including the ability to build your own ships and even give them customized space paint finishes.  In addition to the new M7 battleship, there is an assortment of new weapons and onboard ship devices to use and explore.','The Sequel to the award winning X²: The Threat introduces a new 3D engine as well as a new story, new ships and a new gameplay to greatly increase the variety in the X-universe. The economy of X³: Reunion is more complex than anything seen in the X-universe before.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2820,'It is the year 2938. The long wished-for encounter of the X Universe and the Earth holds both joy and sorrow for the people. Despite flourishing trade, the clash of the diverse races, cultures and life forms creates new tensions, mistrust and open conflict that need to be overcome!<br>					Experience the brilliant climax of the legendary X-Trilogy , and take your place in the history of the X Universe.<br>					<ul class="bb_ul"><li>Largest X Universe ever.<br>					</li><li>New faction: the Terrans – inhabitants of the Earth.<br>					</li><li>More jobs and non-linear missions than ever before.<br>					</li><li>More than 100 new spaceships, new ship classes and weapon systems.<br>					</li><li>Re-designed user interface for comfortable control by mouse, keyboard and joystick.<br>					</li><li>New group management tool.<br>					</li><li>Large battleships can be boarded by an outside team.</li></ul>','It is the year 2938. The long wished-for encounter of the X Universe and the Earth holds both joy and sorrow for the people. Despite flourishing trade, the clash of the diverse races, cultures and life forms creates new tensions, mistrust and open conflict that need to be overcome!<br>					Experience the brilliant climax of the legendary X-Trilogy , and take your place in the history of the X Universe.<br>					<ul class="bb_ul"><li>Largest X Universe ever.<br>					</li><li>New faction: the Terrans – inhabitants of the Earth.<br>					</li><li>More jobs and non-linear missions than ever before.<br>					</li><li>More than 100 new spaceships, new ship classes and weapon systems.<br>					</li><li>Re-designed user interface for comfortable control by mouse, keyboard and joystick.<br>					</li><li>New group management tool.<br>					</li><li>Large battleships can be boarded by an outside team.</li></ul>','It is the year 2938. The long wished-for encounter of the X Universe and the Earth holds both joy and sorrow for the people. Despite flourishing trade, the clash of the diverse races, cultures and life forms creates new tensions, mistrust and open conflict that need to be overcome!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2840,'The Human Race had advanced to the point where we could travel among the stars, we developed giant automated machines to help us colonise other worlds, but there was a fault in their programming and they turned and attacked. Forcing us to lay a trap to protect Earth and exiling the Human race to stay on Earth once again.<br>					500 Years later Kyle Brennan starts his journey by piloting an experimental ship equipped with a new piece of technology allowing it to cross vast distances on its own. However it malfunctions and traps him in a group of sectors inhabited by Aliens, hunted and with no way home, this is his story of survival... Beyond the Frontier...<br>					<br>X: Beyond The Frontier is the first part in the X-Universe series of games developed by Egosoft.<br><br>					It tells the story of mankind''s rise and fall in the universe, and the attempt by Kyle Brennan to help repopulate the stars using a new ship called the Experimental Shuttle, and how he became trapped in a closed group of sectors linked by a series of jumpgates, owing credits to an alien for helping to save him, and hunted by several people. Unknowingly, a group of secret service people are after him, a group who have tried to hide their races secret, that they are the descendants of a group of Humans who saved earth from the Terraformer fleet they created to help colonise the universe.<br>					Now with the Truth coming out, X: Beyond the Frontier allows the player to play as Kyle Brennan on his hunt to find a way home, whilst helping a group of people find the truth about their ancestry, and continue to help save earth from the Terraformers who are now known as the Xenon.<br>					<h2 class="bb_tag">Features</h2>					<ul class="bb_ul"><li><strong>Trade</strong> - Trade in over 50 sectors, with over 50 different goods, upgrade you ships with dozens of upgrades available to you by 5 different races.<br>						 </li><li><strong>Fight</strong> - Find the location of the hostile pirates and survive against attacks by the Xenon.<br>						 </li><li><strong>Build</strong> - Construct stations to build your own production empire.<br>						 </li><li><strong>Think</strong> - Adapt your trading empire to suit the needs of each sectors local economy.<br>					</li></ul>','The Human Race had advanced to the point where we could travel among the stars, we developed giant automated machines to help us colonise other worlds, but there was a fault in their programming and they turned and attacked. Forcing us to lay a trap to protect Earth and exiling the Human race to stay on Earth once again.<br>					500 Years later Kyle Brennan starts his journey by piloting an experimental ship equipped with a new piece of technology allowing it to cross vast distances on its own. However it malfunctions and traps him in a group of sectors inhabited by Aliens, hunted and with no way home, this is his story of survival... Beyond the Frontier...<br>					<br>X: Beyond The Frontier is the first part in the X-Universe series of games developed by Egosoft.<br><br>					It tells the story of mankind''s rise and fall in the universe, and the attempt by Kyle Brennan to help repopulate the stars using a new ship called the Experimental Shuttle, and how he became trapped in a closed group of sectors linked by a series of jumpgates, owing credits to an alien for helping to save him, and hunted by several people. Unknowingly, a group of secret service people are after him, a group who have tried to hide their races secret, that they are the descendants of a group of Humans who saved earth from the Terraformer fleet they created to help colonise the universe.<br>					Now with the Truth coming out, X: Beyond the Frontier allows the player to play as Kyle Brennan on his hunt to find a way home, whilst helping a group of people find the truth about their ancestry, and continue to help save earth from the Terraformers who are now known as the Xenon.<br>					<h2 class="bb_tag">Features</h2>					<ul class="bb_ul"><li><strong>Trade</strong> - Trade in over 50 sectors, with over 50 different goods, upgrade you ships with dozens of upgrades available to you by 5 different races.<br>						 </li><li><strong>Fight</strong> - Find the location of the hostile pirates and survive against attacks by the Xenon.<br>						 </li><li><strong>Build</strong> - Construct stations to build your own production empire.<br>						 </li><li><strong>Think</strong> - Adapt your trading empire to suit the needs of each sectors local economy.<br>					</li></ul>','The Human Race had advanced to the point where we could travel among the stars, we developed giant automated machines to help us colonise other worlds, but there was a fault in their programming and they turned and attacked. Forcing us to lay a trap to protect Earth and exiling the Human race to stay on Earth once again.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2850,'X-Tension is the eagerly awaited expansion pack to X: Beyond the Frontier. The expansion is not limited by a linear plot line but makes use of new ways to expand your empire. You can now take part in missions that are offered to you throughout the game.<br>					<h2 class="bb_tag">Features</h2>					<ul class="bb_ul"><li><strong>More Ships</strong> - You are no longer limited to one ship, but can now buy and pilot all fighters and small transports in the game. As well as capturing new Pirate ships.<br>						 </li><li><strong>Expanded Universe</strong> - The universe has also been expanded with over 40 new sectors to visit, trade and fight inside, allowing you to find new locations to build new stations and trade in new goods.<br>						 </li><li><strong>The Version 2 Update</strong> - The release of the 2.0 upgrade expanded the game even further allowing you to pilot the larger TL class freighter.<br>					</li></ul>Continue your quest to explore the universe, trade in over 90 sectors, with over 50 goods, upgrade your ship with dozens of wares available to you by 5 unique alien races and protect yourself from the hostile Xenon.','X-Tension is the eagerly awaited expansion pack to X: Beyond the Frontier. The expansion is not limited by a linear plot line but makes use of new ways to expand your empire. You can now take part in missions that are offered to you throughout the game.<br>					<h2 class="bb_tag">Features</h2>					<ul class="bb_ul"><li><strong>More Ships</strong> - You are no longer limited to one ship, but can now buy and pilot all fighters and small transports in the game. As well as capturing new Pirate ships.<br>						 </li><li><strong>Expanded Universe</strong> - The universe has also been expanded with over 40 new sectors to visit, trade and fight inside, allowing you to find new locations to build new stations and trade in new goods.<br>						 </li><li><strong>The Version 2 Update</strong> - The release of the 2.0 upgrade expanded the game even further allowing you to pilot the larger TL class freighter.<br>					</li></ul>Continue your quest to explore the universe, trade in over 90 sectors, with over 50 goods, upgrade your ship with dozens of wares available to you by 5 unique alien races and protect yourself from the hostile Xenon.','X-Tension is the eagerly awaited expansion pack to X: Beyond the Frontier. The expansion is not limited by a linear plot line but makes use of new ways to expand your empire. You can now take part in missions that are offered to you throughout the game.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2870,'<h1>Collector''s Edition</h1><p>This Collector''s Edition of <strong>X Rebirth</strong> includes the following items:<br><ul class="bb_ul"><li>DLC: The Teladi Outpost<br></li><li>DLC: Home of Light <strong>(new!)</strong><br></li><li>Soundtrack Volume 1 (MP3)<br></li><li>Exclusive: Soundtrack Volume 2 (MP3)<br></li><li>Optional download: X - The Space Opera - Per Musica ad Albion (Video)<br></li><li>Bonus download with artworks and X encyclopedia</li></ul><br>The bonus content will be placed in your X Rebirth installation folder:<br>...Steam\SteamApps\common\X Rebirth\Bonus Content</p><br><h1>About the Game</h1>In the distant future, the X universe faces a period of profound and irrevocable change. While the universe stumbles towards an uncertain future, countless adventures await as new enemies rise in search of power. Enter a young adventurer and his unlikely female ally traveling in an old, battered ship with a glorious past - two people alone against the galaxy, playing a key part in the events to come. The fate of the universe rests in the hands of the player...<br><br><strong>X Rebirth</strong> represents a spectacular new beginning for the X series, offering loyal fans and newcomers alike a vast, vivid and extremely detailed universe to explore throughout the game. Varied gameplay elements such as action-packed space combat, detailed trading mechanics and high-speed space exploration with fast travel allow players to experience a truly unique space saga that will keep them hooked for dozens of hours. <strong>X Rebirth</strong> features a whole new user experience - it is easier than ever to start with, and remains as deep as fans expect it.<h2 class="bb_tag">FEATURES</h2><br><strong>TRADE!</strong> A fully simulated economy that means your actions really do matter. Travel the space highways to ﬁnd proﬁt in gigantic space cities, swarming with ships and drones.<br><br>++ Every ship you see has a task. Stop a freighter from reaching its destination and its cargo will be stopped too, causing prices to rise. ++<br><br><strong>FIGHT!</strong> From small scale skirmishes to epic ﬂeet encounters, battles in the X Universe know no limits. Choose to ﬁght for the military, work for the police or be a lawless pirate, or if you prefer just ﬁght when you need to defend yourself - it''s up to you.<br><br>++ Take the action right into massive structures. Target turrets and shield generators to weaken your enemy, damage engines and jump drives to prevent their ships from escaping, or stop their factories producing to cripple their economy. ++<br><br><strong>BUILD!</strong> Create your own empire! From trading stations to large factories, farms to hightech military complexes, everything can belong to you. Build for trade and proﬁt or to strengthen your military presence and dominate your enemies.<br><br>++ Extend and upgrade your stations to make them operate more efﬁciently, with every element visible in glorious animated detail. Harvest your own resources to keep your empire running smoothly. ++<br><br><strong>THINK!</strong> A rich, detailed history and a deep complex plot await you, but you are free to decide when and where to take part. Explore the universe at your own pace - choose your own path and create your own destiny.<br><br>++ Get up-close and personal with aliens and humans alike. Land on stations, meet people, then accept missions from them or hire them as crew members for your ships. ++ <br><br><strong>TRADE, FIGHT, BUILD, THINK...</strong> in the X Universe - the biggest sandbox this side of the galaxy.','In the distant future, the X universe faces a period of profound and irrevocable change. While the universe stumbles towards an uncertain future, countless adventures await as new enemies rise in search of power. Enter a young adventurer and his unlikely female ally traveling in an old, battered ship with a glorious past - two people alone against the galaxy, playing a key part in the events to come. The fate of the universe rests in the hands of the player...<br><br><strong>X Rebirth</strong> represents a spectacular new beginning for the X series, offering loyal fans and newcomers alike a vast, vivid and extremely detailed universe to explore throughout the game. Varied gameplay elements such as action-packed space combat, detailed trading mechanics and high-speed space exploration with fast travel allow players to experience a truly unique space saga that will keep them hooked for dozens of hours. <strong>X Rebirth</strong> features a whole new user experience - it is easier than ever to start with, and remains as deep as fans expect it.<h2 class="bb_tag">FEATURES</h2><br><strong>TRADE!</strong> A fully simulated economy that means your actions really do matter. Travel the space highways to ﬁnd proﬁt in gigantic space cities, swarming with ships and drones.<br><br>++ Every ship you see has a task. Stop a freighter from reaching its destination and its cargo will be stopped too, causing prices to rise. ++<br><br><strong>FIGHT!</strong> From small scale skirmishes to epic ﬂeet encounters, battles in the X Universe know no limits. Choose to ﬁght for the military, work for the police or be a lawless pirate, or if you prefer just ﬁght when you need to defend yourself - it''s up to you.<br><br>++ Take the action right into massive structures. Target turrets and shield generators to weaken your enemy, damage engines and jump drives to prevent their ships from escaping, or stop their factories producing to cripple their economy. ++<br><br><strong>BUILD!</strong> Create your own empire! From trading stations to large factories, farms to hightech military complexes, everything can belong to you. Build for trade and proﬁt or to strengthen your military presence and dominate your enemies.<br><br>++ Extend and upgrade your stations to make them operate more efﬁciently, with every element visible in glorious animated detail. Harvest your own resources to keep your empire running smoothly. ++<br><br><strong>THINK!</strong> A rich, detailed history and a deep complex plot await you, but you are free to decide when and where to take part. Explore the universe at your own pace - choose your own path and create your own destiny.<br><br>++ Get up-close and personal with aliens and humans alike. Land on stations, meet people, then accept missions from them or hire them as crew members for your ships. ++ <br><br><strong>TRADE, FIGHT, BUILD, THINK...</strong> in the X Universe - the biggest sandbox this side of the galaxy.','In the distant future, the X universe faces a period of profound and irrevocable change. While the universe stumbles towards an uncertain future, countless adventures await as new enemies rise in search of power.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2900,'688(I) Hunter/Killer, the most realistic submarine simulation ever developed for PC. Master the sonar and weapons control systems, learn to develop real target situations and outfit your boat with the latest advanced weaponry. Then use your skills to complete the tour of duty and earn your dolphins to become a true submariner.<br>					<ul class="bb_ul"><li>A truly authentic simulation: Developed by Sonalysts, a defense contractor who designs submarine simulators for the US Navy<br>					</li><li>Over 12 detailed operating stations: Control all aspects of submarine warfare, including the sonar suite, fire control, helm and target motion analysis<br>					</li><li>Real-World Terrain: Ocean depth and water density for the entire globe are based on actual satellite topographical data<br>					</li><li>Real-life situations: Conduct detailed training and single missions, plus a full campaign based on political analysis from real world situations<br>					</li><li>Multiplayer Warfare: Seek and Destroy up to 8 players over the internet or LAN<br>					</li><li>Full 3D Technology: Full 3D technology allows for multiple camera views and accurate 3D models of over 20 different naval weapons platforms<br>					</li><li>Complete Control: Manage all of the resources of your submarine, including crewmen training and weapons load-outs</li></ul>','688(I) Hunter/Killer, the most realistic submarine simulation ever developed for PC. Master the sonar and weapons control systems, learn to develop real target situations and outfit your boat with the latest advanced weaponry. Then use your skills to complete the tour of duty and earn your dolphins to become a true submariner.<br>					<ul class="bb_ul"><li>A truly authentic simulation: Developed by Sonalysts, a defense contractor who designs submarine simulators for the US Navy<br>					</li><li>Over 12 detailed operating stations: Control all aspects of submarine warfare, including the sonar suite, fire control, helm and target motion analysis<br>					</li><li>Real-World Terrain: Ocean depth and water density for the entire globe are based on actual satellite topographical data<br>					</li><li>Real-life situations: Conduct detailed training and single missions, plus a full campaign based on political analysis from real world situations<br>					</li><li>Multiplayer Warfare: Seek and Destroy up to 8 players over the internet or LAN<br>					</li><li>Full 3D Technology: Full 3D technology allows for multiple camera views and accurate 3D models of over 20 different naval weapons platforms<br>					</li><li>Complete Control: Manage all of the resources of your submarine, including crewmen training and weapons load-outs</li></ul>','688(I) Hunter/Killer, the most realistic submarine simulation ever developed for PC. Master the sonar and weapons control systems, learn to develop real target situations and outfit your boat with the latest advanced weaponry. Then use your skills to complete the tour of duty and earn your dolphins to become a true submariner.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2910,'International waterways become theaters of war when the world''s most formidable maritime powers exchange their fatal blows. With entire fleets at your command, you must strategically deploy vessels from every class - frigate to aircraft to nuclear submarine - to maintain the precarious balance of naval power and gain position for the deadly endgame.<br>					<ul class="bb_ul"><li>Campaigns and mission scenarios straight from current headlines<br>					</li><li>Exclusive real-time strategy with cuttingedge, real-world weapons<br>					</li><li>Intuitive point and click game play<br>					</li><li>No need to memorize symbols or complex commands<br>					</li><li>Player designed task forces<br>					</li><li>Complete 3D environment rotates and zooms for intense combat action<br>					</li><li>Effects modeled in stunning detail- time of day, clouds, rain, differing sea states, ship''s wake and pyrotechnics</li></ul>','International waterways become theaters of war when the world''s most formidable maritime powers exchange their fatal blows. With entire fleets at your command, you must strategically deploy vessels from every class - frigate to aircraft to nuclear submarine - to maintain the precarious balance of naval power and gain position for the deadly endgame.<br>					<ul class="bb_ul"><li>Campaigns and mission scenarios straight from current headlines<br>					</li><li>Exclusive real-time strategy with cuttingedge, real-world weapons<br>					</li><li>Intuitive point and click game play<br>					</li><li>No need to memorize symbols or complex commands<br>					</li><li>Player designed task forces<br>					</li><li>Complete 3D environment rotates and zooms for intense combat action<br>					</li><li>Effects modeled in stunning detail- time of day, clouds, rain, differing sea states, ship''s wake and pyrotechnics</li></ul>','International waterways become theaters of war when the world''s most formidable maritime powers exchange their fatal blows. With entire fleets at your command, you must strategically deploy vessels from every class - frigate to aircraft to nuclear submarine - to maintain the precarious balance of naval power and gain position for the...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2920,'<p>Take charge of the most deadly modern-day submarines in the world - three distinct submarines across two unique and challenging campaigns. Utilize cutting-edge sensor and weapon technology to locate, track and destroy the enemy - even deliver Tomahawk missiles to inland targets. Whether transiting, diving, or surfacing you control the smartest, stealthiest and most feared subs on the water today!</p>
					<ul>
					<li>Three submarines to command - Seawolf, 688(I) and Akula. Each contains authentic naval systems including Sonar, Radar and Target Motion Analysis.</li>
					<li>Test your skills while firing Tomahawk missiles, rescuing crippled subs, rising through the polar ice cap to communicate information and much more.</li>
					<li>Easy to use game interface - With straightforward controls and automated crewmen, controlling a submarine has never been easier.</li>
					<li>Enhanced sound and 3D graphics engine - 3D Objects (over 250), from Russian trawlers to France''s Mirage fighters - plus exacting sound modes pull you in like never before. You won''t just hear the torpedos, you will feel them.</li></ul>','<p>Take charge of the most deadly modern-day submarines in the world - three distinct submarines across two unique and challenging campaigns. Utilize cutting-edge sensor and weapon technology to locate, track and destroy the enemy - even deliver Tomahawk missiles to inland targets. Whether transiting, diving, or surfacing you control the smartest, stealthiest and most feared subs on the water today!</p>
					<ul>
					<li>Three submarines to command - Seawolf, 688(I) and Akula. Each contains authentic naval systems including Sonar, Radar and Target Motion Analysis.</li>
					<li>Test your skills while firing Tomahawk missiles, rescuing crippled subs, rising through the polar ice cap to communicate information and much more.</li>
					<li>Easy to use game interface - With straightforward controls and automated crewmen, controlling a submarine has never been easier.</li>
					<li>Enhanced sound and 3D graphics engine - 3D Objects (over 250), from Russian trawlers to France''s Mirage fighters - plus exacting sound modes pull you in like never before. You won''t just hear the torpedos, you will feel them.</li></ul>','Take charge of the most deadly modern-day submarines in the world - three distinct submarines across two unique and challenging campaigns. Utilize cutting-edge sensor and weapon technology to locate, track and destroy the enemy - even deliver Tomahawk missiles to inland targets.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (2990,'<strong>DRIVING THIS RECKLESS IS NO ACCIDENT!</strong><br>					But you might want to cause a few.  In these high-speed races, the more damage you inflict, the better. The ultimate in turbo-charged cars and the craziest competitor drivers are waiting to test your best destructive streak. Responsible drivers need not apply.<br>					<ul class="bb_ul"><li>Thousands and thousands of objects to annihilate.<br>					</li><li>Mini games gone wild - hurl the driver in these 12 crazy challenges.<br>					</li><li>Wreck your way across parched deserts, massive storm drains and narrow city streets.<br>					</li><li>Ram your opponents'' car and watch them fly through the air - you''re here to win!</li></ul>FlatOut 2 © 2006 Empire Interactive Europe Ltd. Game concept and development by Bugbear Entertainment Ltd. Empire, FlatOut and &quot;E&quot; are either trademarks or registered trademarks of Empire Interactive Europe Ltd. in the UK/Europe and/or other countries. All rights reserved. NVIDIA, the NVIDIA Logo, GeForce and &quot;The Way It''s Meant to be Played&quot; Logo are registered trademarks and/or trademarks of NVIDIA Corporation in the United States and other countries. GameSpy and the &quot;Powered by GameSpy&quot; design are trademarks of GameSpy Industries, Inc. All rights reserved. a product of the e.u.','<strong>DRIVING THIS RECKLESS IS NO ACCIDENT!</strong><br>					But you might want to cause a few.  In these high-speed races, the more damage you inflict, the better. The ultimate in turbo-charged cars and the craziest competitor drivers are waiting to test your best destructive streak. Responsible drivers need not apply.<br>					<ul class="bb_ul"><li>Thousands and thousands of objects to annihilate.<br>					</li><li>Mini games gone wild - hurl the driver in these 12 crazy challenges.<br>					</li><li>Wreck your way across parched deserts, massive storm drains and narrow city streets.<br>					</li><li>Ram your opponents'' car and watch them fly through the air - you''re here to win!</li></ul>FlatOut 2 © 2006 Empire Interactive Europe Ltd. Game concept and development by Bugbear Entertainment Ltd. Empire, FlatOut and &quot;E&quot; are either trademarks or registered trademarks of Empire Interactive Europe Ltd. in the UK/Europe and/or other countries. All rights reserved. NVIDIA, the NVIDIA Logo, GeForce and &quot;The Way It''s Meant to be Played&quot; Logo are registered trademarks and/or trademarks of NVIDIA Corporation in the United States and other countries. GameSpy and the &quot;Powered by GameSpy&quot; design are trademarks of GameSpy Industries, Inc. All rights reserved. a product of the e.u.','DRIVING THIS RECKLESS IS NO ACCIDENT! But you might want to cause a few. In these high-speed races, the more damage you inflict, the better. The ultimate in turbo-charged cars and the craziest competitor drivers are waiting to test your best destructive streak. Responsible drivers need not apply.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3010,'Xpand Rally is a breathtaking game that gives you the true to life experience of driving powerful rally cars amidst photorealistic sceneries. Realistic weather effects, rolling hills, and animated scenery all add to game''s visual perfection. Xpand Rally also features highly detailed models of modern rally cars and handling physics developed with the help of rally sport professionals which further enhance the realism of driving experience.<br />
<br />
Xpand Rally combines the best elements of Rally and Rally Cross racing in one unique gaming experience.<br />
<br />
The game offers a career mode based on time trials during both individual races and World Championship Series which will satisfy traditional Rally fans. The Rally Cross fans won''t be disappointed either - they can challenge several opponents in head to head racing during competitions based on real and fictitious race events.<br />
<br />
Xpand Rally, as the only title on the market, brings the economy factor into a rally game. The player starts with a junk car and competes in races to earn money and acquire upgrades, repair damage, tweak performance and pay the race entry fees.<br />
<br />
Along with the tuning-up, the car''s condition affects its handling. Due to accurate damage system, it is highly dependent on the player''s driving skills. The physical handling model is also influenced by car parts configuration and provides both authentic feel and joy of driving.<br />
<br />
The interactive race track surroundings with enhanced game physics and the innovative approach to changing daytime and weather conditions, both influencing the car handling, are other hallmarks of Xpand Rally that distinguish it from other racing games.<br />
<br />
For the first time among rally games Xpand Rally includes a complete set of easy-to-use editing tools enabling to create new tracks, cars or even game mods.','Xpand Rally is a breathtaking game that gives you the true to life experience of driving powerful rally cars amidst photorealistic sceneries. Realistic weather effects, rolling hills, and animated scenery all add to game''s visual perfection. Xpand Rally also features highly detailed models of modern rally cars and handling physics developed with the help of rally sport professionals which further enhance the realism of driving experience.<br />
<br />
Xpand Rally combines the best elements of Rally and Rally Cross racing in one unique gaming experience.<br />
<br />
The game offers a career mode based on time trials during both individual races and World Championship Series which will satisfy traditional Rally fans. The Rally Cross fans won''t be disappointed either - they can challenge several opponents in head to head racing during competitions based on real and fictitious race events.<br />
<br />
Xpand Rally, as the only title on the market, brings the economy factor into a rally game. The player starts with a junk car and competes in races to earn money and acquire upgrades, repair damage, tweak performance and pay the race entry fees.<br />
<br />
Along with the tuning-up, the car''s condition affects its handling. Due to accurate damage system, it is highly dependent on the player''s driving skills. The physical handling model is also influenced by car parts configuration and provides both authentic feel and joy of driving.<br />
<br />
The interactive race track surroundings with enhanced game physics and the innovative approach to changing daytime and weather conditions, both influencing the car handling, are other hallmarks of Xpand Rally that distinguish it from other racing games.<br />
<br />
For the first time among rally games Xpand Rally includes a complete set of easy-to-use editing tools enabling to create new tracks, cars or even game mods.','Xpand Rally is a breathtaking game that gives you the true to life experience of driving powerful rally cars amidst photorealistic sceneries. Realistic weather effects, rolling hills, and animated scenery all add to game''s visual perfection.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3020,'Call of Juarez is an epic adventure western themed FPS game. The player alternately assumes the roles of two distinct, antagonistic characters: a sneaking fugitive Billy and his hunter the reverend Ray. Apart from the highly interesting, emotional and psychological aspect of the link between the two characters, the player will experience a variety of gameplay with many differences whilst playing a particular character. <br><br>The game features fast paced revolver duels using historically accurate firearms, horseback riding, mounted combat and stealth actions in memorable locations set after Western movies. Emergent gameplay based on accurate simulation of not only rigid bodies and rag-dolls but also liquids, gases, fire and smoke makes the gameplay innovative and non-linear.<br><br><ul class="bb_ul"><li>Very serious approach to the Wild West theme and detailed reconstruction of the character and visuals of that times<br></li><li>The use of physics and innovative simulation of fire, liquids, dust, smokes and gases to construct emergent gameplay<br></li><li>State of the art graphics making use of the top technology graphics cards features on todays cards<br></li><li>Playing 2 distinct characters with different abilities and different gameplay<br></li><li>Horseback riding and saddle shooting, gunfighter duels<br></li><li>Using the whip to fight, move objects and move the player''s character <br></li><li>Legendary weapons form the Gold Fever era and full akimbo mode for the hands on approach<br></li><li>Exhilarating storyline with full of twists and turns in this exciting Western Genre.</li></ul>','Call of Juarez is an epic adventure western themed FPS game. The player alternately assumes the roles of two distinct, antagonistic characters: a sneaking fugitive Billy and his hunter the reverend Ray. Apart from the highly interesting, emotional and psychological aspect of the link between the two characters, the player will experience a variety of gameplay with many differences whilst playing a particular character. <br><br>The game features fast paced revolver duels using historically accurate firearms, horseback riding, mounted combat and stealth actions in memorable locations set after Western movies. Emergent gameplay based on accurate simulation of not only rigid bodies and rag-dolls but also liquids, gases, fire and smoke makes the gameplay innovative and non-linear.<br><br><ul class="bb_ul"><li>Very serious approach to the Wild West theme and detailed reconstruction of the character and visuals of that times<br></li><li>The use of physics and innovative simulation of fire, liquids, dust, smokes and gases to construct emergent gameplay<br></li><li>State of the art graphics making use of the top technology graphics cards features on todays cards<br></li><li>Playing 2 distinct characters with different abilities and different gameplay<br></li><li>Horseback riding and saddle shooting, gunfighter duels<br></li><li>Using the whip to fight, move objects and move the player''s character <br></li><li>Legendary weapons form the Gold Fever era and full akimbo mode for the hands on approach<br></li><li>Exhilarating storyline with full of twists and turns in this exciting Western Genre.</li></ul>','Call of Juarez is an epic adventure western themed FPS game. The player alternately assumes the roles of two distinct, antagonistic characters: a sneaking fugitive Billy and his hunter the reverend Ray. Apart from the highly interesting, emotional and psychological aspect of the link between the two characters, the player will experience...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3050,'Xpand Rally Xtreme shows the true climate and conditions of rally racing. Dangerous, technical tracks, based on the world''s hardest special stages full of moguls,jumps,grooves and tight hairpins.                                        <br>					                    By winning races amass funds for faster cars and repairs. The player also has the ability to mechanically tune their cars by increasing parameters such as turbocharger efficiency,fitting sports breaks and suspension kits and more.                                        <br>					<strong>Features:</strong>                    <br>					<ul class="bb_ul"><li>Extreme driving in the toughest possible conditions: Innumerable moguls, bumps, ditches, potholes, grooves and jumps-the ultimate                    test of the driver''s skills and his car''s suspension.                    <br>					</li><li>Learn to respect a real rally car: Extreme realism of driving a rally car, thanks to the highly-detailed driving physics                    simulation.                    <br>					</li><li>Go head-to-head with AI opponents in two exciting new racing modes:Off-Road Series featuring 4x4 xtreme cars and Touring Challenge with 1000BHP GT and DTM supercars                    <br>					</li><li>Optical and mechanical car tuning and individual parts preference settings.                    <br>					</li><li>Single race, online play and championship modes                    </li></ul>','Xpand Rally Xtreme shows the true climate and conditions of rally racing. Dangerous, technical tracks, based on the world''s hardest special stages full of moguls,jumps,grooves and tight hairpins.                                        <br>					                    By winning races amass funds for faster cars and repairs. The player also has the ability to mechanically tune their cars by increasing parameters such as turbocharger efficiency,fitting sports breaks and suspension kits and more.                                        <br>					<strong>Features:</strong>                    <br>					<ul class="bb_ul"><li>Extreme driving in the toughest possible conditions: Innumerable moguls, bumps, ditches, potholes, grooves and jumps-the ultimate                    test of the driver''s skills and his car''s suspension.                    <br>					</li><li>Learn to respect a real rally car: Extreme realism of driving a rally car, thanks to the highly-detailed driving physics                    simulation.                    <br>					</li><li>Go head-to-head with AI opponents in two exciting new racing modes:Off-Road Series featuring 4x4 xtreme cars and Touring Challenge with 1000BHP GT and DTM supercars                    <br>					</li><li>Optical and mechanical car tuning and individual parts preference settings.                    <br>					</li><li>Single race, online play and championship modes                    </li></ul>','Xpand Rally Xtreme shows the true climate and conditions of rally racing. Dangerous, technical tracks, based on the world''s hardest special stages full of moguls,jumps,grooves and tight hairpins. By winning races amass funds for faster cars and repairs.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3130,'Men of War: Red Tide is a sequel to the critically acclaimed RTS Men of War. Red Tide introduces a new story driven campaign based on the writings of Soviet scribe Alexander Zorich, it also includes dozens of new or upgraded units and weapons.<br>					Men of War: Red Tide is a stunning mixture of RTS and a third-person action that introduces a new fighting force known for its brutal efficiency during the height of World War II. Played out across more than 20 missions, Men of War: Red Tide allows to take command of the feared &quot;Black Coats,&quot; the nickname given to Soviet Marines, an elite combat group specializing in engagements near the shoreline.<br>					The player has direct control of new game units including the Black Coats, tanks, self-propelled guns, armored trains, landing craft, artillery and new enemy emplaced weapons to capture and use. New air support options include fighters, bombers, hydroplanes; cruisers, destroyers and gun boats which provide naval fire support.<br>					Fighting during the Black Sea Campaigns of WWII, history buffs and WWII aficionados will recognize theaters of battle such as Odessa, Sevastopol, Theodosia, Eltingen, Nikolaev and Constanta.<br><br>					<ul class="bb_ul"><li>23 missions - Soviet, German, Romanian and Italian forces<br>					</li><li>Six intense historical battles and landing operations during 1941-1945<br>					</li><li>Over 100 different military units: tanks, artillery, armored cars, planes (fighters, bombers, transporters), war ships and boats (cruisers, torpedo boats, gunboats)<br>					</li></ul>','Men of War: Red Tide is a sequel to the critically acclaimed RTS Men of War. Red Tide introduces a new story driven campaign based on the writings of Soviet scribe Alexander Zorich, it also includes dozens of new or upgraded units and weapons.<br>					Men of War: Red Tide is a stunning mixture of RTS and a third-person action that introduces a new fighting force known for its brutal efficiency during the height of World War II. Played out across more than 20 missions, Men of War: Red Tide allows to take command of the feared &quot;Black Coats,&quot; the nickname given to Soviet Marines, an elite combat group specializing in engagements near the shoreline.<br>					The player has direct control of new game units including the Black Coats, tanks, self-propelled guns, armored trains, landing craft, artillery and new enemy emplaced weapons to capture and use. New air support options include fighters, bombers, hydroplanes; cruisers, destroyers and gun boats which provide naval fire support.<br>					Fighting during the Black Sea Campaigns of WWII, history buffs and WWII aficionados will recognize theaters of battle such as Odessa, Sevastopol, Theodosia, Eltingen, Nikolaev and Constanta.<br><br>					<ul class="bb_ul"><li>23 missions - Soviet, German, Romanian and Italian forces<br>					</li><li>Six intense historical battles and landing operations during 1941-1945<br>					</li><li>Over 100 different military units: tanks, artillery, armored cars, planes (fighters, bombers, transporters), war ships and boats (cruisers, torpedo boats, gunboats)<br>					</li></ul>','Men of War: Red Tide is a sequel to the critically acclaimed RTS Men of War. Red Tide introduces a new story driven campaign based on the writings of Soviet scribe Alexander Zorich, it also includes dozens of new or upgraded units and weapons.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3170,'<strong>King''s Bounty: Armored Princess</strong> is a sequel to the critically acclaimed King’s Bounty: The Legend. Players will take on the role of Princess Amelie who travels around the world of Teana and searches for the renowned knight, and her mentor, Bill Gilbert. This new world of King’s Bounty: Armored Princess is full of mysteries and dangers. The new character, the Princess, will encounter horrible creatures, huge monstrous bosses and a new race, the bloodthirsty Lizards. As in the multi-award winning game on which this sequel is based, the player has many options to resist these new enemies. Various new skills and characteristics of Amelie as well as her chance to fly will help her overcome the hordes attacking the kingdom.<br><br>The Princess is accompanied by a Pet Dragon, at the very beginning small and amusing, but its abilities develop steadily until it becomes an incredible ally. He will do his best to protect the Princess during the battles, starting with easy blows and treasure hunting and finishing with battle rage and volcano summoning.<br><br><ul class="bb_ul"><li>New fascinating story-line and a whole new continent to explore<br></li><li>A new female character to play – Princess Amelie<br></li><li>Medals giving bonuses can be received for special achievements<br></li><li>Pet Dragon which becomes more powerful as the player does<br></li><li>New Lizard race<br></li><li>Possibility to turn your horse into a Pegasus which can fly<br></li><li>Fast travel between opened continents<br></li><li>Hire companions<br></li><li>Resurrection of the classic system of contracts and headhunting<br></li><li>Improved role playing system including more abilities and the chance to achieve level 50 and higher<br></li><li>Brand new spells and new Adventure Magic spell for game map<br></li><li>New unique bosses: Driller, Gremlion, Archdemon Baal and many others<br></li><li>New engine supporting the latest graphic effects<br></li><li>Beautiful, hand drawn environments<br></li><li>Mac version is available in English, Russian, German, French, Spanish and Italian languages</li></ul>','<strong>King''s Bounty: Armored Princess</strong> is a sequel to the critically acclaimed King’s Bounty: The Legend. Players will take on the role of Princess Amelie who travels around the world of Teana and searches for the renowned knight, and her mentor, Bill Gilbert. This new world of King’s Bounty: Armored Princess is full of mysteries and dangers. The new character, the Princess, will encounter horrible creatures, huge monstrous bosses and a new race, the bloodthirsty Lizards. As in the multi-award winning game on which this sequel is based, the player has many options to resist these new enemies. Various new skills and characteristics of Amelie as well as her chance to fly will help her overcome the hordes attacking the kingdom.<br><br>The Princess is accompanied by a Pet Dragon, at the very beginning small and amusing, but its abilities develop steadily until it becomes an incredible ally. He will do his best to protect the Princess during the battles, starting with easy blows and treasure hunting and finishing with battle rage and volcano summoning.<br><br><ul class="bb_ul"><li>New fascinating story-line and a whole new continent to explore<br></li><li>A new female character to play – Princess Amelie<br></li><li>Medals giving bonuses can be received for special achievements<br></li><li>Pet Dragon which becomes more powerful as the player does<br></li><li>New Lizard race<br></li><li>Possibility to turn your horse into a Pegasus which can fly<br></li><li>Fast travel between opened continents<br></li><li>Hire companions<br></li><li>Resurrection of the classic system of contracts and headhunting<br></li><li>Improved role playing system including more abilities and the chance to achieve level 50 and higher<br></li><li>Brand new spells and new Adventure Magic spell for game map<br></li><li>New unique bosses: Driller, Gremlion, Archdemon Baal and many others<br></li><li>New engine supporting the latest graphic effects<br></li><li>Beautiful, hand drawn environments<br></li><li>Mac version is available in English, Russian, German, French, Spanish and Italian languages</li></ul>','King''s Bounty: Armored Princess is a sequel to the critically acclaimed King’s Bounty: The Legend.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3230,'Three thousand years in the future, mankind has carved a bloody path towards domination of the known universe. Self-proclaimed as a divine race and beyond reproach as a species, they view all alien races as inferior. With fleets of organic starships genetically engineered for war, humanity sets out to conquer the last remaining independent galaxy - The Universal Heart. <br>					As Captain Iconah, you are commissioned to uncover the location and purpose of the Heart. Take command of a living fleet, altering your starship''s DNA in real-time as you grant them new and powerful abilities. The Universal Crusade has just begun!<br>					<ul class="bb_ul"><li><strong>Unique space real-time strategy gameplay</strong> that immerses you in an epic crusade with a rich back story.<br>					</li><li><strong>Non linear single player campaign</strong> comprised of over 30 branching missions.<br>					</li><li><strong>Scalable RTS gameplay</strong>: Resource gathering, technology upgrades and combat are scalable for even the most novice RTS players.<br>					</li><li><strong>Co-op mode </strong> allows two players to work together and control one fleet!<br>					</li><li><strong>Customize all 20+ gene based organic ships</strong> with over 50 different weapons and abilities, giving you thousands of possible combinations to choose from when constructing a fleet.<br>					</li><li><strong>Ship models morph in real time</strong> as genes are inserted, reflecting the choices that you make!<br>					</li><li><strong>Make alliances</strong> with the many other non-player character alien races to secure their support and technology--or purge their resources!<br>					</li><li><strong>Expand your genetic capabilities</strong> by invading enemy vessels, stealing unsuspecting technologies, and maximizing your gene bank''s diversity.<br>					</li><li><strong>Gamespy Multiplayer</strong> featuring 12-player support and many multiplayer maps on which to flex your dominance!</li></ul>','Three thousand years in the future, mankind has carved a bloody path towards domination of the known universe. Self-proclaimed as a divine race and beyond reproach as a species, they view all alien races as inferior. With fleets of organic starships genetically engineered for war, humanity sets out to conquer the last remaining independent galaxy - The Universal Heart. <br>					As Captain Iconah, you are commissioned to uncover the location and purpose of the Heart. Take command of a living fleet, altering your starship''s DNA in real-time as you grant them new and powerful abilities. The Universal Crusade has just begun!<br>					<ul class="bb_ul"><li><strong>Unique space real-time strategy gameplay</strong> that immerses you in an epic crusade with a rich back story.<br>					</li><li><strong>Non linear single player campaign</strong> comprised of over 30 branching missions.<br>					</li><li><strong>Scalable RTS gameplay</strong>: Resource gathering, technology upgrades and combat are scalable for even the most novice RTS players.<br>					</li><li><strong>Co-op mode </strong> allows two players to work together and control one fleet!<br>					</li><li><strong>Customize all 20+ gene based organic ships</strong> with over 50 different weapons and abilities, giving you thousands of possible combinations to choose from when constructing a fleet.<br>					</li><li><strong>Ship models morph in real time</strong> as genes are inserted, reflecting the choices that you make!<br>					</li><li><strong>Make alliances</strong> with the many other non-player character alien races to secure their support and technology--or purge their resources!<br>					</li><li><strong>Expand your genetic capabilities</strong> by invading enemy vessels, stealing unsuspecting technologies, and maximizing your gene bank''s diversity.<br>					</li><li><strong>Gamespy Multiplayer</strong> featuring 12-player support and many multiplayer maps on which to flex your dominance!</li></ul>','Three thousand years in the future, mankind has carved a bloody path towards domination of the known universe. Self-proclaimed as a divine race and beyond reproach as a species, they view all alien races as inferior.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3260,'As an expert safecracker, you are hired by the wealthy family of a recently deceased to search his mansion for his last will and testament. Duncan W. Adams was an avid safe collector and an ''eccentric,'' to say the least. Adams has hidden the deed to his vast fortunes in one of 35 safes. You must crack them all using hints scattered throughout his extravagant mansion. The stakes are high. Use your expertise, wits, and puzzle solving skills to earn your paycheck!<br>					<ul class="bb_ul"><li>A challenging puzzle adventure game with 35 unique safes to crack.<br>					</li><li>Many creative, clever, and truly unique puzzles.<br>					</li><li>Decipher unexpected clues inside each safe that will help you open the others, ultimately leading you to the master safe.<br>					</li><li>Multiple difficulty levels to challenge all types of puzzle enthusiasts.<br>					</li><li>Explore a magnificent mansion with 30 lavish, intriguing, and precisely-detailed rooms.</li></ul>','As an expert safecracker, you are hired by the wealthy family of a recently deceased to search his mansion for his last will and testament. Duncan W. Adams was an avid safe collector and an ''eccentric,'' to say the least. Adams has hidden the deed to his vast fortunes in one of 35 safes. You must crack them all using hints scattered throughout his extravagant mansion. The stakes are high. Use your expertise, wits, and puzzle solving skills to earn your paycheck!<br>					<ul class="bb_ul"><li>A challenging puzzle adventure game with 35 unique safes to crack.<br>					</li><li>Many creative, clever, and truly unique puzzles.<br>					</li><li>Decipher unexpected clues inside each safe that will help you open the others, ultimately leading you to the master safe.<br>					</li><li>Multiple difficulty levels to challenge all types of puzzle enthusiasts.<br>					</li><li>Explore a magnificent mansion with 30 lavish, intriguing, and precisely-detailed rooms.</li></ul>','As an expert safecracker, you are hired by the wealthy family of a recently deceased to search his mansion for his last will and testament. Duncan W. Adams was an avid safe collector and an ''eccentric,'' to say the least. Adams has hidden the deed to his vast fortunes in one of 35 safes.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3270,'The critically-acclaimed and award-winning FPS franchise is back! Packed with tons of fast-paced, adrenaline-fueled single player and multiplayer action, Painkiller Overdose brings with it 6 innovative new demonic weapons, mind-bending physics, lightning-player maps, over 40 demented and sickly-twisted monsters from Hell and gigantic end bosses that will blow your mind!<br>					<ul class="bb_ul"><li>A prequel to the eventual sequel that bridges the storyline and ties up wandering ends.<br>					</li><li>Overdose introduces a new character and storyline that examines the repercussions of Daniel defeating Lucifer in the original Painkiller!<br>					</li><li>16 NEW levels of fast-paced pain-killing action!<br>					</li><li>Six NEW demonic weapons grant the powers of a demi-god to souls awaiting damnation everywhere!<br>					</li><li>Crafted and designed completely by Mindware Studios; long-time advocates and fans of the game.<br>					</li><li>A reshuffled Tarot deck infuses Belial with new powers and devastating combinations.<br>					</li><li>Over 40 demented and sickly-twisted monsters from Hell.<br>					</li><li>New End Bosses of colossal statures standing guard over Hell''s crumbling domain and the entrances to the other realms!<br>					</li><li>A revitalized commitment to multiplayer introduces a series of stats tracking features and game server options intended to revamp the multiplayer experience.<br>					</li><li>Multiplayer compatibility with original Painkiller multiplayer maps and game modes!</li></ul>','The critically-acclaimed and award-winning FPS franchise is back! Packed with tons of fast-paced, adrenaline-fueled single player and multiplayer action, Painkiller Overdose brings with it 6 innovative new demonic weapons, mind-bending physics, lightning-player maps, over 40 demented and sickly-twisted monsters from Hell and gigantic end bosses that will blow your mind!<br>					<ul class="bb_ul"><li>A prequel to the eventual sequel that bridges the storyline and ties up wandering ends.<br>					</li><li>Overdose introduces a new character and storyline that examines the repercussions of Daniel defeating Lucifer in the original Painkiller!<br>					</li><li>16 NEW levels of fast-paced pain-killing action!<br>					</li><li>Six NEW demonic weapons grant the powers of a demi-god to souls awaiting damnation everywhere!<br>					</li><li>Crafted and designed completely by Mindware Studios; long-time advocates and fans of the game.<br>					</li><li>A reshuffled Tarot deck infuses Belial with new powers and devastating combinations.<br>					</li><li>Over 40 demented and sickly-twisted monsters from Hell.<br>					</li><li>New End Bosses of colossal statures standing guard over Hell''s crumbling domain and the entrances to the other realms!<br>					</li><li>A revitalized commitment to multiplayer introduces a series of stats tracking features and game server options intended to revamp the multiplayer experience.<br>					</li><li>Multiplayer compatibility with original Painkiller multiplayer maps and game modes!</li></ul>','The critically-acclaimed and award-winning FPS franchise is back! Packed with tons of fast-paced, adrenaline-fueled single player and multiplayer action, Painkiller Overdose brings with it 6 innovative new demonic weapons, mind-bending physics, lightning-player maps, over 40 demented and sickly-twisted monsters from Hell and gigantic end...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3330,'Survive the ancient temples of Zuma, the critically acclaimed action-puzzler from PopCap! Deep in the jungle lie hidden temples bursting with traps and trickery, and it''s up to you to uncover their treasures. Fire magical balls from your stone frog idol to make matches of three or more and clear the deadly chain before it reaches the golden skull.<br>					<br><br><br>					Explore all the temples — if you''re good, you’ll rack up huge combos and special bonuses that''ll help you on your way. But think fast and aim smart, or you''ll be history in this action-packed puzzle challenge!<br>					<br><br><strong>Key Features</strong><br>					<ul class="bb_ul"><li>3D accelerated graphics and effects.<br>					</li><li>Stunning sounds and tribal tunes.<br>					</li><li>Explore the Adventure mode and test your skills in Gauntlet mode.<br>					</li><li>Over 20 temples to explore!<br>					<ul class="bb_ul"></ul></li></ul>','Survive the ancient temples of Zuma, the critically acclaimed action-puzzler from PopCap! Deep in the jungle lie hidden temples bursting with traps and trickery, and it''s up to you to uncover their treasures. Fire magical balls from your stone frog idol to make matches of three or more and clear the deadly chain before it reaches the golden skull.<br>					<br><br><br>					Explore all the temples — if you''re good, you’ll rack up huge combos and special bonuses that''ll help you on your way. But think fast and aim smart, or you''ll be history in this action-packed puzzle challenge!<br>					<br><br><strong>Key Features</strong><br>					<ul class="bb_ul"><li>3D accelerated graphics and effects.<br>					</li><li>Stunning sounds and tribal tunes.<br>					</li><li>Explore the Adventure mode and test your skills in Gauntlet mode.<br>					</li><li>Over 20 temples to explore!<br>					<ul class="bb_ul"></ul></li></ul>','Survive the ancient temples of Zuma, the critically acclaimed action-puzzler from PopCap! Deep in the jungle lie hidden temples bursting with traps and trickery, and it''s up to you to uncover their treasures.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3410,'<p>It''s shoot-''em-up arcade action at its best! Use an incredible assortment of heavy artillery to blast away enemy tanks and planes, and fight your way to victory. What are you waiting for? Pull yourself up by your bootstraps and get into the action!</p>
                    <ul>
                    <li>Blast your way through 19 missions packed with peril.</li>
                    <li>Two action-packed game modes: Mission and Survival.</li>
                    <li>Enhanced sound effects and an original soundtrack!</li>
                    </ul>','<p>It''s shoot-''em-up arcade action at its best! Use an incredible assortment of heavy artillery to blast away enemy tanks and planes, and fight your way to victory. What are you waiting for? Pull yourself up by your bootstraps and get into the action!</p>
                    <ul>
                    <li>Blast your way through 19 missions packed with peril.</li>
                    <li>Two action-packed game modes: Mission and Survival.</li>
                    <li>Enhanced sound effects and an original soundtrack!</li>
                    </ul>','It''s shoot-''em-up arcade action at its best! Use an incredible assortment of heavy artillery to blast away enemy tanks and planes, and fight your way to victory. What are you waiting for? Pull yourself up by your bootstraps and get into the action! Blast your way through 19 missions packed with peril.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3480,'<p>Take your best shot with energizing arcade fun! Aim, shoot, clear the orange pegs, then sit back and cheer as 10 whimsical teachers guide you to Peggle greatness. Conquer 55 fanciful levels with 10 mystical Magic Powers, racking up bonus points and shots you''ll smile about for weeks. Face off against your friends in Duel Mode, or tackle 75 extra-tricky challenges. It''s luck and skill and joyous thrills, and amidst all this fevered action only one question remains: Can you become a Peggle Master?</p>
					<ul>
					<li>Wield 10 miraculous Magic Powers!</li>
					<li>Master 55 levels of bouncy delight!</li>
					<li>Conquer 75 Master challenges!</li>
					<li>Play friends or the computer in Duel Mode!</li>
					<li>Revel in breathtaking artwork and music!</li>
					<li>Replay and save your best shots!</li>
					</ul>','<p>Take your best shot with energizing arcade fun! Aim, shoot, clear the orange pegs, then sit back and cheer as 10 whimsical teachers guide you to Peggle greatness. Conquer 55 fanciful levels with 10 mystical Magic Powers, racking up bonus points and shots you''ll smile about for weeks. Face off against your friends in Duel Mode, or tackle 75 extra-tricky challenges. It''s luck and skill and joyous thrills, and amidst all this fevered action only one question remains: Can you become a Peggle Master?</p>
					<ul>
					<li>Wield 10 miraculous Magic Powers!</li>
					<li>Master 55 levels of bouncy delight!</li>
					<li>Conquer 75 Master challenges!</li>
					<li>Play friends or the computer in Duel Mode!</li>
					<li>Revel in breathtaking artwork and music!</li>
					<li>Replay and save your best shots!</li>
					</ul>','Take your best shot with energizing arcade fun! Aim, shoot, clear the orange pegs, then sit back and cheer as 10 whimsical teachers guide you to Peggle greatness. Conquer 55 fanciful levels with 10 mystical Magic Powers, racking up bonus points and shots you''ll smile about for weeks.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3483,'<p><i>Mayday!</i> The Peggle Institute has been invaded by a host of other-worldly creatures. It''s up to you, Peggle Master, to report to duty and shoot and bounce the critters to oblivion. Take your best shot with energizing arcade fun, now exclusively themed with art and sounds from <a href="http://storefront.steampowered.com/v/index.php?area=package&SubId=469">The Orange Box</a>!</p> 
					<p>Peggle Extreme delivers fast-paced puzzle action that combines elements of pinball and pachinko to create a truly unique game experience. As with the original Peggle, Peggle Extreme requires players to fire a metallic silver ball from the top of the screen, relying on gravity to propel the ball downwards while ricocheting off orange and blue "pegs". The goal is to clear all the orange pegs from the screen before running out of balls. A moving "bucket" at the bottom of the screen offers free balls, while green power-up and purple "bonus multiplier" pegs provide additional twists. Peggle Extreme features one power-up in the form of Bjorn the Unicorn, whose special takes the form of a "super-guide" sighting capability which enables players to see where there next shot will go beyond one or two initial bounces.</p>
					<ul>
					<li>Master 10 levels of "Extreme" challenges</li>
					<li>Conquer 5 Master challenges</li>
					<li>Play against a friend or the computer in Duel Mode</li>
					<li>Revel in breathtaking artwork and sounds from Half-Life: Episode 2, Portal, and Team Fortress 2</li>
					<li>Replay and save your best shots</li></ul>','<p><i>Mayday!</i> The Peggle Institute has been invaded by a host of other-worldly creatures. It''s up to you, Peggle Master, to report to duty and shoot and bounce the critters to oblivion. Take your best shot with energizing arcade fun, now exclusively themed with art and sounds from <a href="http://storefront.steampowered.com/v/index.php?area=package&SubId=469">The Orange Box</a>!</p> 
					<p>Peggle Extreme delivers fast-paced puzzle action that combines elements of pinball and pachinko to create a truly unique game experience. As with the original Peggle, Peggle Extreme requires players to fire a metallic silver ball from the top of the screen, relying on gravity to propel the ball downwards while ricocheting off orange and blue "pegs". The goal is to clear all the orange pegs from the screen before running out of balls. A moving "bucket" at the bottom of the screen offers free balls, while green power-up and purple "bonus multiplier" pegs provide additional twists. Peggle Extreme features one power-up in the form of Bjorn the Unicorn, whose special takes the form of a "super-guide" sighting capability which enables players to see where there next shot will go beyond one or two initial bounces.</p>
					<ul>
					<li>Master 10 levels of "Extreme" challenges</li>
					<li>Conquer 5 Master challenges</li>
					<li>Play against a friend or the computer in Duel Mode</li>
					<li>Revel in breathtaking artwork and sounds from Half-Life: Episode 2, Portal, and Team Fortress 2</li>
					<li>Replay and save your best shots</li></ul>','Mayday! The Peggle Institute has been invaded by a host of other-worldly creatures. It''s up to you, Peggle Master, to report to duty and shoot and bounce the critters to oblivion. Take your best shot with energizing arcade fun, now exclusively themed with art and sounds from The Orange Box!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3490,'<p>Venice is sinking and only you can save it! From the floating fortress of your golden gondola, you''ll restore the city by returning its lost treasures. Sling costly coins, launch lovely lyres and ricochet ruby rings into the corresponding spaces overhead. Use your arsenal of special shots to create cascading combos and earn bonus points along the way. But beware &#151; shelves, chutes, swirlies and other traps will make things tricky, so you''ll need power-ups like Wild Shot and Wings to help you sail through the levels. So grab your gondola and get ready &#151; with a majestic soundtrack, gloriously ornate artwork and four enduring game modes, Venice is a classic test of wits, will and skill!</p>
<ul>
<li>Dive into 4 game modes: Journey, Flood, Survival and Trick Shots</li>
<li>Save 72 buildings over 8 neighborhoods</li>
<li>Wield astonishing power-ups like Wild Shot and Wings</li>
<li>Overcome obstacles like tricky chutes, sinister swirlies and more</li>
<li>Revel in ornate art, mellifluous music and spectacular effects</li>
<li>Earn bonus points and power-ups with terrific tumbles and cascading combos</li>
<li>Save your high scores for pride and posterity!</li>
</ul>','<p>Venice is sinking and only you can save it! From the floating fortress of your golden gondola, you''ll restore the city by returning its lost treasures. Sling costly coins, launch lovely lyres and ricochet ruby rings into the corresponding spaces overhead. Use your arsenal of special shots to create cascading combos and earn bonus points along the way. But beware &#151; shelves, chutes, swirlies and other traps will make things tricky, so you''ll need power-ups like Wild Shot and Wings to help you sail through the levels. So grab your gondola and get ready &#151; with a majestic soundtrack, gloriously ornate artwork and four enduring game modes, Venice is a classic test of wits, will and skill!</p>
<ul>
<li>Dive into 4 game modes: Journey, Flood, Survival and Trick Shots</li>
<li>Save 72 buildings over 8 neighborhoods</li>
<li>Wield astonishing power-ups like Wild Shot and Wings</li>
<li>Overcome obstacles like tricky chutes, sinister swirlies and more</li>
<li>Revel in ornate art, mellifluous music and spectacular effects</li>
<li>Earn bonus points and power-ups with terrific tumbles and cascading combos</li>
<li>Save your high scores for pride and posterity!</li>
</ul>','Venice is sinking and only you can save it! From the floating fortress of your golden gondola, you''ll restore the city by returning its lost treasures. Sling costly coins, launch lovely lyres and ricochet ruby rings into the corresponding spaces overhead.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3500,'<p>You are the world-famous Mystery P.I. and you''ve been hired by Grandma Rose to find her $488 million dollar winning lottery ticket that has gone missing! Retrace Grandma''s steps to collect clues by finding hidden objects and solving puzzles. Search the city for the clues and piece them together to solve the case. Grandma Rose has agreed to pay you $20 million if you find the ticket before the deadline. Hurry, you only have 12 hours to find the ticket!</p>
					<p>Investigate 20 unique locations to find over 2100 cleverly hidden objects! As your investigation skills improve your P.I. rank increases -- strive for a "Perfect Investigation" to get big bonus points!</p>
					<p>Two fun ways to play: In Find the Ticket mode you must locate the missing ticket before the deadline. Unlock Unlimited Seek &amp; Find game mode to search for all the hidden objects with no time limits -- every scene, every item! Collect all 20 KEYS while finding the Ticket to unlock a fun bonus location hidden in the city.</p>','<p>You are the world-famous Mystery P.I. and you''ve been hired by Grandma Rose to find her $488 million dollar winning lottery ticket that has gone missing! Retrace Grandma''s steps to collect clues by finding hidden objects and solving puzzles. Search the city for the clues and piece them together to solve the case. Grandma Rose has agreed to pay you $20 million if you find the ticket before the deadline. Hurry, you only have 12 hours to find the ticket!</p>
					<p>Investigate 20 unique locations to find over 2100 cleverly hidden objects! As your investigation skills improve your P.I. rank increases -- strive for a "Perfect Investigation" to get big bonus points!</p>
					<p>Two fun ways to play: In Find the Ticket mode you must locate the missing ticket before the deadline. Unlock Unlimited Seek &amp; Find game mode to search for all the hidden objects with no time limits -- every scene, every item! Collect all 20 KEYS while finding the Ticket to unlock a fun bonus location hidden in the city.</p>','You are the world-famous Mystery P.I. and you''ve been hired by Grandma Rose to find her $488 million dollar winning lottery ticket that has gone missing! Retrace Grandma''s steps to collect clues by finding hidden objects and solving puzzles. Search the city for the clues and piece them together to solve the case.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3510,'<p>You are an adventure seeker who travels the world in search of forgotten & lost treasures. Search for hidden objects and circumvent unique puzzle traps to recover the most sought after treasures the world has ever known.</p>
					<p>A newly-discovered fragment of an ancient map is believed to reveal the location of the Lost Tomb of Egypt. Under the direction of the Museum, you must immediately begin your adventure to locate the Lost Tomb and the treasures locked within! Complete over 100 levels by finding hidden objects and circumventing unique puzzle traps. Good luck on your adventure!</p>
					<ul>
					<li>Find over 2000 hidden objects in over 100 levels.</li>
					<li>Explore 22 unique Egyptian locations.</li>
					<li>Circumvent 7 unique mini-game puzzle traps to continue your missions.</li>
					<li>Two game modes: "Find the Lost Tomb" and "Secret Game" mode.</li>
					<li>Find the hidden Scarabs to unlock Secret Game mode and a bonus Egyptian location.</li>
					<li>Strive for the Perfect Search Bonus by not using the ''Hint'' button.</li>
					<li>Play against the clock or in Relaxed Mode with no time limits.</li>
					<li>Unlock interesting facts about Egypt in your journal.</li></ul>','<p>You are an adventure seeker who travels the world in search of forgotten & lost treasures. Search for hidden objects and circumvent unique puzzle traps to recover the most sought after treasures the world has ever known.</p>
					<p>A newly-discovered fragment of an ancient map is believed to reveal the location of the Lost Tomb of Egypt. Under the direction of the Museum, you must immediately begin your adventure to locate the Lost Tomb and the treasures locked within! Complete over 100 levels by finding hidden objects and circumventing unique puzzle traps. Good luck on your adventure!</p>
					<ul>
					<li>Find over 2000 hidden objects in over 100 levels.</li>
					<li>Explore 22 unique Egyptian locations.</li>
					<li>Circumvent 7 unique mini-game puzzle traps to continue your missions.</li>
					<li>Two game modes: "Find the Lost Tomb" and "Secret Game" mode.</li>
					<li>Find the hidden Scarabs to unlock Secret Game mode and a bonus Egyptian location.</li>
					<li>Strive for the Perfect Search Bonus by not using the ''Hint'' button.</li>
					<li>Play against the clock or in Relaxed Mode with no time limits.</li>
					<li>Unlock interesting facts about Egypt in your journal.</li></ul>','You are an adventure seeker who travels the world in search of forgotten & lost treasures. Search for hidden objects and circumvent unique puzzle traps to recover the most sought after treasures the world has ever known. A newly-discovered fragment of an ancient map is believed to reveal the location of the Lost Tomb of Egypt.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3520,'<p>The heist of the century has just happened!  You''ve been hired by the casino to find & return the stolen money before its grand opening in 16 hours. Search for over 2300 cleverly hidden objects in 25 intriguing locations to solve the Vegas Heist.</p>
					<p>Two addictive ways to play: Vegas Heist mode and Unlimited Seek &amp; Find mode. Collect all the hidden Keys and Poker Chips to unlock the bonus mode.  Find the clues, solve the Vegas Heist!</p>
					<ul>
					<li>Find over 2300 cleverly hidden objects</li>
					<li>Investigate 25 intriguing Vegas locations to locate the stolen money</li>
					<li>Two fun game modes: ''Solve the Vegas Heist'' and ''Unlimited Seek &amp; Find''</li>
					<li>Play 5 unique mini-games: Word Search, Tile Rotation, Tile Swap, Jigsaw and a unique crime solving puzzle</li></ul>','<p>The heist of the century has just happened!  You''ve been hired by the casino to find & return the stolen money before its grand opening in 16 hours. Search for over 2300 cleverly hidden objects in 25 intriguing locations to solve the Vegas Heist.</p>
					<p>Two addictive ways to play: Vegas Heist mode and Unlimited Seek &amp; Find mode. Collect all the hidden Keys and Poker Chips to unlock the bonus mode.  Find the clues, solve the Vegas Heist!</p>
					<ul>
					<li>Find over 2300 cleverly hidden objects</li>
					<li>Investigate 25 intriguing Vegas locations to locate the stolen money</li>
					<li>Two fun game modes: ''Solve the Vegas Heist'' and ''Unlimited Seek &amp; Find''</li>
					<li>Play 5 unique mini-games: Word Search, Tile Rotation, Tile Swap, Jigsaw and a unique crime solving puzzle</li></ul>','The heist of the century has just happened! You''ve been hired by the casino to find & return the stolen money before its grand opening in 16 hours. Search for over 2300 cleverly hidden objects in 25 intriguing locations to solve the Vegas Heist. Two addictive ways to play: Vegas Heist mode and Unlimited Seek &amp; Find mode.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3530,'<p>Pieces of an ancient stone tablet have started turning up around the globe and the Museum needs your help to locate the pieces and find the most expensive gem ever known...the &#147;World Diamond&#148;.  Under the direction of the Museum, you must immediately begin your global seek & find adventure.  Complete over 100 levels by finding hidden objects and circumventing unique puzzle traps.</p>
                    <p>Travel to 25 unique &amp; exotic locations around the world finding over 2100 hidden objects in 3 different game modes: Find the World Diamond story mode, plus two Unlimited Play game modes which are unlocked after you have found the World Diamond or have found all of the hidden Gems in each location.  Take on 8 different types of mini-game puzzles including place-the-differences and spot-the-differences.  Good luck on your around the world adventure!</p>
                    <ul>
                    <li>Find over 2100 Hidden Objects in over 100 levels.</li>
                    <li>Explore 25 exotic &amp; worldly locations.</li>
                    <li>Play 8 unique mini-game puzzle traps including Spot-the-Differences, Place-the-differences, and many more.</li>
                    <li>Three game modes: Find the World Diamond, Unlimited Seek & Find, and Unlimited Spot the Differences.</li>
                    <li>Find the hidden Gems to unlock the Unlimited game modes.</li>
                    <li>Strive for a Perfect Search bonus by not using Hint.</li>
                    <li>Play against the clock or in Relaxed Mode with no time limits.</li>
                    <li>Unlock interesting facts in your journal as you travel the globe.</li>
                    </ul>','<p>Pieces of an ancient stone tablet have started turning up around the globe and the Museum needs your help to locate the pieces and find the most expensive gem ever known...the &#147;World Diamond&#148;.  Under the direction of the Museum, you must immediately begin your global seek & find adventure.  Complete over 100 levels by finding hidden objects and circumventing unique puzzle traps.</p>
                    <p>Travel to 25 unique &amp; exotic locations around the world finding over 2100 hidden objects in 3 different game modes: Find the World Diamond story mode, plus two Unlimited Play game modes which are unlocked after you have found the World Diamond or have found all of the hidden Gems in each location.  Take on 8 different types of mini-game puzzles including place-the-differences and spot-the-differences.  Good luck on your around the world adventure!</p>
                    <ul>
                    <li>Find over 2100 Hidden Objects in over 100 levels.</li>
                    <li>Explore 25 exotic &amp; worldly locations.</li>
                    <li>Play 8 unique mini-game puzzle traps including Spot-the-Differences, Place-the-differences, and many more.</li>
                    <li>Three game modes: Find the World Diamond, Unlimited Seek & Find, and Unlimited Spot the Differences.</li>
                    <li>Find the hidden Gems to unlock the Unlimited game modes.</li>
                    <li>Strive for a Perfect Search bonus by not using Hint.</li>
                    <li>Play against the clock or in Relaxed Mode with no time limits.</li>
                    <li>Unlock interesting facts in your journal as you travel the globe.</li>
                    </ul>','Pieces of an ancient stone tablet have started turning up around the globe and the Museum needs your help to locate the pieces and find the most expensive gem ever known...the &#147;World Diamond&#148;. Under the direction of the Museum, you must immediately begin your global seek & find adventure.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3540,'<p>The sun has set at the Peggle Institute, but the bouncy delight has just begun! Join the Peggle Masters on a dreamtime adventure of alter egos and peg-tastic action. Stay up late to aim, shoot and clear orange pegs, and bask in Extreme Fever glory under the silver moon. Then, put your Peggle skills to the ultimate test in Challenge mode. If you can master all that fevered action, play to your heart''s content with Duel mode and Quick Play. Plus, you can stock your Trophy Room and revel in clickable replays for even more rebounding joy!</p>                    
					<ul>                    
					<li>Explore all 60 levels in Adventure mode</li>                    
					<li>Meet a new Peggle Master and learn a new Magic Power</li>                    
					<li>Test your skills in 60 challenges</li>                    
					<li>Unlock Duel mode to compete against friends and the computer</li>                    
					<li>Celebrate your Peggle prowess with clickable replays and a Trophy Room!</li>                    </ul>','<p>The sun has set at the Peggle Institute, but the bouncy delight has just begun! Join the Peggle Masters on a dreamtime adventure of alter egos and peg-tastic action. Stay up late to aim, shoot and clear orange pegs, and bask in Extreme Fever glory under the silver moon. Then, put your Peggle skills to the ultimate test in Challenge mode. If you can master all that fevered action, play to your heart''s content with Duel mode and Quick Play. Plus, you can stock your Trophy Room and revel in clickable replays for even more rebounding joy!</p>                    
					<ul>                    
					<li>Explore all 60 levels in Adventure mode</li>                    
					<li>Meet a new Peggle Master and learn a new Magic Power</li>                    
					<li>Test your skills in 60 challenges</li>                    
					<li>Unlock Duel mode to compete against friends and the computer</li>                    
					<li>Celebrate your Peggle prowess with clickable replays and a Trophy Room!</li>                    </ul>','The sun has set at the Peggle Institute, but the bouncy delight has just begun! Join the Peggle Masters on a dreamtime adventure of alter egos and peg-tastic action. Stay up late to aim, shoot and clear orange pegs, and bask in Extreme Fever glory under the silver moon. Then, put your Peggle skills to the ultimate test in Challenge mode.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3560,'<p>Spin, match, explode... WOW! It''s a brilliant new way to play Bejeweled! Get set for a vivid sensory rush as you spin and match explosive gems for shockwaves of fun. Rotate jewels freely to set up electrifying combos, outwit surprising obstacles like Locks and Bombs, and create high-voltage Flame and Lightning gems. When you need to dial up the intensity or fine-tune your skills, turn to Challenge mode or five-minute Blitz. And if relaxing is more your style, kick up your feet with stress-free Zen. No matter the mode, you''ll discover new strategies, improve your moves, and find endless ways to win!</p>                    
					<ul>                    
					<li>Use the revolutionary Gem Rotator to move gems around and make matches anywhere on the board</li>                     
					<li>Relax, rev up, refocus or recharge in four game modes &#151; Classic, Zen, Challenge and Blitz</li>                    
					<li>Clear away Locks and Bombs for magnificent bonuses</li>                    
					<li>Create Flame and Lightning power gems, then blast them to smithereens just because you can</li>                    
					<li>Relive your best moves with Instant Replay and see where you rank on the high-score list</li>                    
					<li>Start playing quickly and easily with in-game tips</li>                    
					<li>Enjoy eye-popping graphics and special effects... you''ve never seen Bejeweled like this before!</li>                    </ul>','<p>Spin, match, explode... WOW! It''s a brilliant new way to play Bejeweled! Get set for a vivid sensory rush as you spin and match explosive gems for shockwaves of fun. Rotate jewels freely to set up electrifying combos, outwit surprising obstacles like Locks and Bombs, and create high-voltage Flame and Lightning gems. When you need to dial up the intensity or fine-tune your skills, turn to Challenge mode or five-minute Blitz. And if relaxing is more your style, kick up your feet with stress-free Zen. No matter the mode, you''ll discover new strategies, improve your moves, and find endless ways to win!</p>                    
					<ul>                    
					<li>Use the revolutionary Gem Rotator to move gems around and make matches anywhere on the board</li>                     
					<li>Relax, rev up, refocus or recharge in four game modes &#151; Classic, Zen, Challenge and Blitz</li>                    
					<li>Clear away Locks and Bombs for magnificent bonuses</li>                    
					<li>Create Flame and Lightning power gems, then blast them to smithereens just because you can</li>                    
					<li>Relive your best moves with Instant Replay and see where you rank on the high-score list</li>                    
					<li>Start playing quickly and easily with in-game tips</li>                    
					<li>Enjoy eye-popping graphics and special effects... you''ve never seen Bejeweled like this before!</li>                    </ul>','Spin, match, explode... WOW! It''s a brilliant new way to play Bejeweled! Get set for a vivid sensory rush as you spin and match explosive gems for shockwaves of fun. Rotate jewels freely to set up electrifying combos, outwit surprising obstacles like Locks and Bombs, and create high-voltage Flame and Lightning gems.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3570,'<p>A fun loving & eccentric New York billionaire has hidden the will to his vast fortune somewhere in New York City!  His family only has 17 hours to locate the will or their Grandpa''s entire estate will be given to his cat & dog.</p>                    
					<p>You are the world famous Mystery P.I. and the family has hired you to track down the clues hidden all over NYC.  Seek & Find over 2100 hidden objects in 25 amazing NY locations like Times Square, Central Park, Coney Island, the Brooklyn Bridge and many more. If you succeed you will be awarded $25 Million dollars.</p>                    
					<p>Three addictive ways to play: In NY Fortune mode you must find the clues to locate the will.  Collect all the Keys & Apples to unlock two Unlimited game modes: Unlock Unlimited Seek & Find and Spot the Differences to find every hidden item in every scene.</p>                    
					<ul>                    
					<li>Find over 2100 cleverly hidden objects.</li>                    
					<li>Investigate 25 amazing New York locations to find the clues.</li>                    
					<li>Three fun game modes: ''Find the NY Fortune'' and two Unlimited game modes</li>                    
					<li>Play 5 unique mini-games: Match-3, Word Search, Circle Rotation, Tile Swap, Jigsaw plus a unique final puzzle.</li>                    
					<li>Locate the secret Keys and Apples to unlock two Unlimited game modes.</li>                    
					<li>Go for a Perfect Investigation & speed bonuses to become a Master PI.</li>                    </ul>','<p>A fun loving & eccentric New York billionaire has hidden the will to his vast fortune somewhere in New York City!  His family only has 17 hours to locate the will or their Grandpa''s entire estate will be given to his cat & dog.</p>                    
					<p>You are the world famous Mystery P.I. and the family has hired you to track down the clues hidden all over NYC.  Seek & Find over 2100 hidden objects in 25 amazing NY locations like Times Square, Central Park, Coney Island, the Brooklyn Bridge and many more. If you succeed you will be awarded $25 Million dollars.</p>                    
					<p>Three addictive ways to play: In NY Fortune mode you must find the clues to locate the will.  Collect all the Keys & Apples to unlock two Unlimited game modes: Unlock Unlimited Seek & Find and Spot the Differences to find every hidden item in every scene.</p>                    
					<ul>                    
					<li>Find over 2100 cleverly hidden objects.</li>                    
					<li>Investigate 25 amazing New York locations to find the clues.</li>                    
					<li>Three fun game modes: ''Find the NY Fortune'' and two Unlimited game modes</li>                    
					<li>Play 5 unique mini-games: Match-3, Word Search, Circle Rotation, Tile Swap, Jigsaw plus a unique final puzzle.</li>                    
					<li>Locate the secret Keys and Apples to unlock two Unlimited game modes.</li>                    
					<li>Go for a Perfect Investigation & speed bonuses to become a Master PI.</li>                    </ul>','A fun loving & eccentric New York billionaire has hidden the will to his vast fortune somewhere in New York City! His family only has 17 hours to locate the will or their Grandpa''s entire estate will be given to his cat & dog. You are the world famous Mystery P.I. and the family has hired you to track down the clues hidden all over NYC.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3580,'<p>The Wizard has vanished, and only you can find him in this spellbinding hidden-object adventure! The clues to the Wizard''s whereabouts are in his workbook, but all the pages are blank. You''ll need his magic pen to uncover and guess the image on each page. The better your guesses, the better your score &mdash; and every image you uncover brings you closer to finding the Wizard. Plus, you can play mystical mini-games, unlock special challenges, score bonus points and earn potent potions. It''s a unique new twist on the seek-and-find genre that you''ve gotta try!</p>                    
					<ul>                    
					<li>Discover over 400 pages of hidden objects</li>                    
					<li>Power up with 10 magic potions</li>                    
					<li>Unlock 16 unique hidden-object mini-games!</li>                    
					<li>Open seven sketchbooks with special challenges</li>                    </ul>','<p>The Wizard has vanished, and only you can find him in this spellbinding hidden-object adventure! The clues to the Wizard''s whereabouts are in his workbook, but all the pages are blank. You''ll need his magic pen to uncover and guess the image on each page. The better your guesses, the better your score &mdash; and every image you uncover brings you closer to finding the Wizard. Plus, you can play mystical mini-games, unlock special challenges, score bonus points and earn potent potions. It''s a unique new twist on the seek-and-find genre that you''ve gotta try!</p>                    
					<ul>                    
					<li>Discover over 400 pages of hidden objects</li>                    
					<li>Power up with 10 magic potions</li>                    
					<li>Unlock 16 unique hidden-object mini-games!</li>                    
					<li>Open seven sketchbooks with special challenges</li>                    </ul>','The Wizard has vanished, and only you can find him in this spellbinding hidden-object adventure! The clues to the Wizard''s whereabouts are in his workbook, but all the pages are blank. You''ll need his magic pen to uncover and guess the image on each page.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3590,'<img src="https://steamcdn-a.akamaihd.net/steam/apps/3590/extras/PvZ_background.jpg?t=1447351772" ><br><br>Zombies are invading your home, and the only defense is your arsenal of plants! Armed with an alien nursery-worth of zombie-zapping plants like peashooters and cherry bombs, you''ll need to think fast and plant faster to stop dozens of types of zombies dead in their tracks. Obstacles like a setting sun, creeping fog and a swimming pool add to the challenge, and with five game modes to dig into, the fun never dies!<h2 class="bb_tag">Features</h2>                    <ul class="bb_ul"><li>Play five game modes: Adventure, Mini-Games, Puzzle, Survival, plus the stress-free Zen Garden<br>                    </li><li>Conquer all 50 levels of Adventure mode  through day, night, and fog, in a swimming pool and on the rooftop<br>                    </li><li>Battle 26 types of zombies including pole-vaulters, snorkelers and Zomboni drivers<br>                    </li><li>Earn 49 powerful perennials and collect coins to buy a pet snail, power-ups and more!<br>                    </li><li>Open the Almanac to see all the plants and zombies, plus amusing facts and quotes<br>                    </li><li>Browse Crazy Daves shop for special plants and tools to stem any zombie assault<br>                    </li><li>Amazing graphics and soundtrack, plus a bonus music video<br>                    </li><li>Infinite replayability: the game is never the same experience twice!<br>                    </li><li>Unlock all the Steam Achievements<br>                    </li></ul>','<img src="https://steamcdn-a.akamaihd.net/steam/apps/3590/extras/PvZ_background.jpg?t=1447351772" ><br><br>Zombies are invading your home, and the only defense is your arsenal of plants! Armed with an alien nursery-worth of zombie-zapping plants like peashooters and cherry bombs, you''ll need to think fast and plant faster to stop dozens of types of zombies dead in their tracks. Obstacles like a setting sun, creeping fog and a swimming pool add to the challenge, and with five game modes to dig into, the fun never dies!<h2 class="bb_tag">Features</h2>                    <ul class="bb_ul"><li>Play five game modes: Adventure, Mini-Games, Puzzle, Survival, plus the stress-free Zen Garden<br>                    </li><li>Conquer all 50 levels of Adventure mode  through day, night, and fog, in a swimming pool and on the rooftop<br>                    </li><li>Battle 26 types of zombies including pole-vaulters, snorkelers and Zomboni drivers<br>                    </li><li>Earn 49 powerful perennials and collect coins to buy a pet snail, power-ups and more!<br>                    </li><li>Open the Almanac to see all the plants and zombies, plus amusing facts and quotes<br>                    </li><li>Browse Crazy Daves shop for special plants and tools to stem any zombie assault<br>                    </li><li>Amazing graphics and soundtrack, plus a bonus music video<br>                    </li><li>Infinite replayability: the game is never the same experience twice!<br>                    </li><li>Unlock all the Steam Achievements<br>                    </li></ul>','Zombies are invading your home, and the only defense is your arsenal of plants! Armed with an alien nursery-worth of zombie-zapping plants like peashooters and cherry bombs, you''ll need to think fast and plant faster to stop dozens of types of zombies dead in their tracks.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3600,'<p>An unexpected storm has left you shipwrecked on a mysterious and remote private island. Seek & find cleverly hidden objects and solve puzzles to find a way off the island!  Find over 2100 hidden objects in 25 intriguing and mysterious locations to find items that will help you escape!</p>
                    <p>Play 5 different types of mini-game puzzles to collect inventory items from each location that will be needed to help you escape the remote Rosecliff Island.  Play 3 different game modes: Escape the Island, Unlimited Seek & Find, and a Mystery Bonus Game.</p>
                    <ul>
                    <li>Find over 2100 cleverly hidden objects.</li>
                    <li>Explore 25 mysterious island locations to find a way off.</li>
                    <li>Three fun game modes: Escape Mode, Unlimited Seek & Find, & a Mystery Bonus Game.</li>
                    <li>Play 5 unique mini-games: Match 3, Word Search, Puzzle Rotation, Memory Match, Jigsaw plus a unique final puzzle.</li>
                    <li>Locate all the hidden locks to reveal two bonus games.</li>
                    <li>Go for a Perfect Search & back-to-back speed bonuses to beat your high score.</li>
                    </ul>','<p>An unexpected storm has left you shipwrecked on a mysterious and remote private island. Seek & find cleverly hidden objects and solve puzzles to find a way off the island!  Find over 2100 hidden objects in 25 intriguing and mysterious locations to find items that will help you escape!</p>
                    <p>Play 5 different types of mini-game puzzles to collect inventory items from each location that will be needed to help you escape the remote Rosecliff Island.  Play 3 different game modes: Escape the Island, Unlimited Seek & Find, and a Mystery Bonus Game.</p>
                    <ul>
                    <li>Find over 2100 cleverly hidden objects.</li>
                    <li>Explore 25 mysterious island locations to find a way off.</li>
                    <li>Three fun game modes: Escape Mode, Unlimited Seek & Find, & a Mystery Bonus Game.</li>
                    <li>Play 5 unique mini-games: Match 3, Word Search, Puzzle Rotation, Memory Match, Jigsaw plus a unique final puzzle.</li>
                    <li>Locate all the hidden locks to reveal two bonus games.</li>
                    <li>Go for a Perfect Search & back-to-back speed bonuses to beat your high score.</li>
                    </ul>','An unexpected storm has left you shipwrecked on a mysterious and remote private island. Seek & find cleverly hidden objects and solve puzzles to find a way off the island! Find over 2100 hidden objects in 25 intriguing and mysterious locations to find items that will help you escape!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3610,'<p>Seek & Find the Hollywood Blockbuster! The only copy of this year''s biggest blockbuster movie has gone missing the day before the VIP Hollywood premiere.  You are the world famous Mystery P.I. and have been hired to track down and return the lost movie.</p>
					<p>Seek & Find over 2100 hidden objects in 25 stunning L.A. locations like Malibu Beach, Rodeo Drive, Movie Sets, Hollywood hot spots and many more.  Hurry you only have 17 hours to locate the movie or the Hollywood Studio will be ruined.  If you succeed you will be awarded $15 Million dollars.</p>
					<p>Three addictive ways to play: Solve the L.A. Mystery to track down the lost blockbuster movie.  Collect all the special Keys & Film Reels to unlock two Unlimited game modes: Unlimited Seek & Find and a Match 3 Puzzle Game.</p>
					<ul>
					<li>Find over 2100 cleverly hidden objects.</li>
					<li>Investigate 25 amazing L.A. locations to find the clues.</li>
					<li>Three fun game modes: ''Solve the L.A. Mystery'' and 2 Unlimited Bonus modes.</li>
					<li>Play 8 different mini-games: Match-3, Word Search, Circle Rotation, Memory Match, Tile Swap, Jigsaw and more.</li>
					<li>Locate the hidden Keys and Film Reels to unlock the Unlimited bonus games.</li>
					<li>Go for a Perfect Investigation & speed bonuses to become a Master PI.</li>
					</ul>','<p>Seek & Find the Hollywood Blockbuster! The only copy of this year''s biggest blockbuster movie has gone missing the day before the VIP Hollywood premiere.  You are the world famous Mystery P.I. and have been hired to track down and return the lost movie.</p>
					<p>Seek & Find over 2100 hidden objects in 25 stunning L.A. locations like Malibu Beach, Rodeo Drive, Movie Sets, Hollywood hot spots and many more.  Hurry you only have 17 hours to locate the movie or the Hollywood Studio will be ruined.  If you succeed you will be awarded $15 Million dollars.</p>
					<p>Three addictive ways to play: Solve the L.A. Mystery to track down the lost blockbuster movie.  Collect all the special Keys & Film Reels to unlock two Unlimited game modes: Unlimited Seek & Find and a Match 3 Puzzle Game.</p>
					<ul>
					<li>Find over 2100 cleverly hidden objects.</li>
					<li>Investigate 25 amazing L.A. locations to find the clues.</li>
					<li>Three fun game modes: ''Solve the L.A. Mystery'' and 2 Unlimited Bonus modes.</li>
					<li>Play 8 different mini-games: Match-3, Word Search, Circle Rotation, Memory Match, Tile Swap, Jigsaw and more.</li>
					<li>Locate the hidden Keys and Film Reels to unlock the Unlimited bonus games.</li>
					<li>Go for a Perfect Investigation & speed bonuses to become a Master PI.</li>
					</ul>','Seek & Find the Hollywood Blockbuster! The only copy of this year''s biggest blockbuster movie has gone missing the day before the VIP Hollywood premiere. You are the world famous Mystery P.I. and have been hired to track down and return the lost movie. Seek & Find over 2100 hidden objects in 25 stunning L.A.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3620,'An irresistible force has taken our fearless frog to an island where the ribbeting puzzle-action of Zuma has evolved in amazing ways… but evil spirits and tenacious tiki bosses rule the land!
					<p>Survive the ire of the island by firing stone spheres to destroy the deadly stream of balls. Conquer over 60 levels by staying sharp and avoiding hidden traps. Slide and hop for smarter shots; hit targets for exotic bonuses; detonate new power-up balls; battle six imposing tiki bosses and guide your agile amphibian to victory in four all new game modes! Will you succumb to the perilous pitfalls, or can you tame the jungle in this PopCap ball-blasting challenge?</p>
					<ul>
					<li>Conquer over 60 levels and defeat six mini-game Boss Battles 
					<li>Score explosive power-ups including three new shots
					<li>Explore new gameplay like lily-pad hopping, slide-aiming, and more
					<li>Take a shot at 70 all-new Challenges in the Jungle of Mystery, Quiet Village, Lost City and Mosquito Coast. 
					<li>Run the Iron Frog gauntlet — beat 10 levels in a row!
					<li>Turn up the heat in Heroic Frog mode
					<li>Enjoy amazing graphics and effects that bring Zuma into the modern world of gaming
					</ul>','An irresistible force has taken our fearless frog to an island where the ribbeting puzzle-action of Zuma has evolved in amazing ways… but evil spirits and tenacious tiki bosses rule the land!
					<p>Survive the ire of the island by firing stone spheres to destroy the deadly stream of balls. Conquer over 60 levels by staying sharp and avoiding hidden traps. Slide and hop for smarter shots; hit targets for exotic bonuses; detonate new power-up balls; battle six imposing tiki bosses and guide your agile amphibian to victory in four all new game modes! Will you succumb to the perilous pitfalls, or can you tame the jungle in this PopCap ball-blasting challenge?</p>
					<ul>
					<li>Conquer over 60 levels and defeat six mini-game Boss Battles 
					<li>Score explosive power-ups including three new shots
					<li>Explore new gameplay like lily-pad hopping, slide-aiming, and more
					<li>Take a shot at 70 all-new Challenges in the Jungle of Mystery, Quiet Village, Lost City and Mosquito Coast. 
					<li>Run the Iron Frog gauntlet — beat 10 levels in a row!
					<li>Turn up the heat in Heroic Frog mode
					<li>Enjoy amazing graphics and effects that bring Zuma into the modern world of gaming
					</ul>','New low price!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3700,'As World War II draws to a close, the first covert battles of the Cold War begin. Caught in the life and death struggle between Soviets and Germans in war-torn Berlin, you control the fate of a lone American OSS Sniper. Disguised as a German and working deep behind enemy lines you must stop Stalin''s forces from gaining control of Germany''s nuclear secrets. Prepare to alter the course of history.<br><br><br>Authentic World War II sniper simulation featuring realistic weapons, bullet ballistics and sniping skills<br><br><ul class="bb_ul"><li>Massive single player game with 28 heart-pounding missions<br></li><li>Intense 8-player LAN sniper battles including Deathmatch, Team Deathmatch and Assassination game modes<br></li><li>3rd person view for close quarter action and movement - 1st view person for sniping<br></li><li>Options to take account of gravity, wind, posture, heart-rate and breathing to execute the perfect shot<br></li><li>Multi-angle ''Bullet Cam'' for kill confirmation<br></li><li>Non linear game play provides unique action each time a mission is played</li></ul>','As World War II draws to a close, the first covert battles of the Cold War begin. Caught in the life and death struggle between Soviets and Germans in war-torn Berlin, you control the fate of a lone American OSS Sniper. Disguised as a German and working deep behind enemy lines you must stop Stalin''s forces from gaining control of Germany''s nuclear secrets. Prepare to alter the course of history.<br><br><br>Authentic World War II sniper simulation featuring realistic weapons, bullet ballistics and sniping skills<br><br><ul class="bb_ul"><li>Massive single player game with 28 heart-pounding missions<br></li><li>Intense 8-player LAN sniper battles including Deathmatch, Team Deathmatch and Assassination game modes<br></li><li>3rd person view for close quarter action and movement - 1st view person for sniping<br></li><li>Options to take account of gravity, wind, posture, heart-rate and breathing to execute the perfect shot<br></li><li>Multi-angle ''Bullet Cam'' for kill confirmation<br></li><li>Non linear game play provides unique action each time a mission is played</li></ul>','As World War II draws to a close, the first covert battles of the Cold War begin. Caught in the life and death struggle between Soviets and Germans in war-torn Berlin, you control the fate of a lone American OSS Sniper.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3710,'Welcome to Mega-City One, a city of over 400 million people - every one of them a potential criminal. It is the third decade of the 22nd Century, unemployment is widespread, boredom is universal and only the Judges can prevent total anarchy. Empowered to dispense instant justice, they are Judge, Jury and Executioner all in one. The most feared and respected of all the Judges is you, Judge Dredd.<br>Patrol the streets and mete out instant justice wherever it is needed. The Psi-Judges are predicting a terrible plague  is this the sudden outbreak of Vampires on the city, and are they the work of the malevolent Dark Judges?<br><ul class="bb_ul"><li>JUDGE, JURY and EXECUTIONER it''s your choice to shoot to kill, or disarm and arrest<br></li><li>Two-player co-operative LAN play throughout the entirety of the immersive storyline<br></li><li>Intense LAN action for up to 32 players<br></li><li>Customizable multiplayer games with enemy bots<br></li><li>Choose from over 60 characters for insane mayhem!</li></ul>','Welcome to Mega-City One, a city of over 400 million people - every one of them a potential criminal. It is the third decade of the 22nd Century, unemployment is widespread, boredom is universal and only the Judges can prevent total anarchy. Empowered to dispense instant justice, they are Judge, Jury and Executioner all in one. The most feared and respected of all the Judges is you, Judge Dredd.<br>Patrol the streets and mete out instant justice wherever it is needed. The Psi-Judges are predicting a terrible plague  is this the sudden outbreak of Vampires on the city, and are they the work of the malevolent Dark Judges?<br><ul class="bb_ul"><li>JUDGE, JURY and EXECUTIONER it''s your choice to shoot to kill, or disarm and arrest<br></li><li>Two-player co-operative LAN play throughout the entirety of the immersive storyline<br></li><li>Intense LAN action for up to 32 players<br></li><li>Customizable multiplayer games with enemy bots<br></li><li>Choose from over 60 characters for insane mayhem!</li></ul>','Welcome to Mega-City One, a city of over 400 million people - every one of them a potential criminal. It is the third decade of the 22nd Century, unemployment is widespread, boredom is universal and only the Judges can prevent total anarchy. Empowered to dispense instant justice, they are Judge, Jury and Executioner all in one.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3720,'<p>Everybody wants to rule the world! Achieve global power with EVIL GENIUS, the one and only complete world domination simulator. All the everyday tasks of the deliciously wicked mastermind are available to experience and master from building your ultra-secret base to developing spectacular super-weapons to carry out your nefarious master plan. How evil are you?</p>
			<ul>
			<li>Choose from 3 notorious Evil Genius characters to serve as your icon and represent you in your quest for power.</li>
			<li>Create the ultimate doomsday device and use it to achieve total global domination.</li>
			<li>Create your lair with over 300 items including kung fu academies, rocket caverns, and laboratories.</li>
			<li>Use ingenious traps and wicked ''interrogation'' devices to toy with and dispatch obnoxious overdressed government agents.</li>
			<li>Manage your minions as you train them in treacherous trades such as experimental research programs, heavy weapons usage, and international sabotage.</li>
			<li>Recruit dastardly henchmen to patrol your base, take out your enemies, and undertake outrageous missions to increase your power and notoriety.</li>
			</ul>','<p>Everybody wants to rule the world! Achieve global power with EVIL GENIUS, the one and only complete world domination simulator. All the everyday tasks of the deliciously wicked mastermind are available to experience and master from building your ultra-secret base to developing spectacular super-weapons to carry out your nefarious master plan. How evil are you?</p>
			<ul>
			<li>Choose from 3 notorious Evil Genius characters to serve as your icon and represent you in your quest for power.</li>
			<li>Create the ultimate doomsday device and use it to achieve total global domination.</li>
			<li>Create your lair with over 300 items including kung fu academies, rocket caverns, and laboratories.</li>
			<li>Use ingenious traps and wicked ''interrogation'' devices to toy with and dispatch obnoxious overdressed government agents.</li>
			<li>Manage your minions as you train them in treacherous trades such as experimental research programs, heavy weapons usage, and international sabotage.</li>
			<li>Recruit dastardly henchmen to patrol your base, take out your enemies, and undertake outrageous missions to increase your power and notoriety.</li>
			</ul>','Everybody wants to rule the world! Achieve global power with EVIL GENIUS, the one and only complete world domination simulator. All the everyday tasks of the deliciously wicked mastermind are available to experience and master from building your ultra-secret base to developing spectacular super-weapons to carry out your nefarious master...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3730,'Aliens Versus Predator Classic 2000 features the Colonial Marine, Alien and Predator Campaigns and the frenetic single-player Skirmish mode from the original title: Alien Versus Predator Gold Edition, which was released to massive acclaim in 2000.<br>					Alien Versus Predator Classic 2000 has been updated to run on modern PCs and laptops using DirectX 9.0c and includes support for Xbox 360 Controller for Windows.<br>					The three most ferocious species in the universe in a bloodthirsty battle for the ultimate prize: survival. Take your pick: be a Colonial Marine, a Predator or an Alien. Fight through suspense-filled environments: from starships and space stations to colonial bases and eerie planetscapes. One wrong move turns you from hunter to prey.<br>					<ul class="bb_ul"><li>Three campaigns: Colonial Marine, Alien and Predator<br>					</li><li>Includes all the levels from the original AvP Gold Edition plus the Millennium Expansion Pack<br>					</li><li>Skirmish mode against infinite Alien hordes<br>					</li><li>Bonus Episodes<br>					</li><li>Unique abilities, weapons and equipment for each species<br>					</li><li>Scale walls and elevator shafts as an ALIEN with frightening speed as you attack and devour your victims<br>					</li><li>Stalk your prey as the deadly PREDATOR using wrist blades, shoulder cannons and stealth mode<br>					</li><li>Lock and load as a COLONIAL MARINE using motion trackers, grenade launchers and flame-throwers to exterminate your foes<br>					</li><li>Supports Xbox 360 Controller for Windows<br>					</li><li>Music from the original soundtrack CD<br>					</li></ul><h2 class="bb_tag">Multiplayer Features</h2>					<ul class="bb_ul"><li>Integrated with Steam Overlay<br>					</li><li>Uses Steam name<br>					</li><li>Host/Join games via bare-bones in-game lobby browser<br>					</li><li>Can invite and join friends and others via the Steam overlay<br>					</li><li>Game attempts host migration<br>					</li><li>Dedicated servers are not supported or planned<br>					</li></ul>','Aliens Versus Predator Classic 2000 features the Colonial Marine, Alien and Predator Campaigns and the frenetic single-player Skirmish mode from the original title: Alien Versus Predator Gold Edition, which was released to massive acclaim in 2000.<br>					Alien Versus Predator Classic 2000 has been updated to run on modern PCs and laptops using DirectX 9.0c and includes support for Xbox 360 Controller for Windows.<br>					The three most ferocious species in the universe in a bloodthirsty battle for the ultimate prize: survival. Take your pick: be a Colonial Marine, a Predator or an Alien. Fight through suspense-filled environments: from starships and space stations to colonial bases and eerie planetscapes. One wrong move turns you from hunter to prey.<br>					<ul class="bb_ul"><li>Three campaigns: Colonial Marine, Alien and Predator<br>					</li><li>Includes all the levels from the original AvP Gold Edition plus the Millennium Expansion Pack<br>					</li><li>Skirmish mode against infinite Alien hordes<br>					</li><li>Bonus Episodes<br>					</li><li>Unique abilities, weapons and equipment for each species<br>					</li><li>Scale walls and elevator shafts as an ALIEN with frightening speed as you attack and devour your victims<br>					</li><li>Stalk your prey as the deadly PREDATOR using wrist blades, shoulder cannons and stealth mode<br>					</li><li>Lock and load as a COLONIAL MARINE using motion trackers, grenade launchers and flame-throwers to exterminate your foes<br>					</li><li>Supports Xbox 360 Controller for Windows<br>					</li><li>Music from the original soundtrack CD<br>					</li></ul><h2 class="bb_tag">Multiplayer Features</h2>					<ul class="bb_ul"><li>Integrated with Steam Overlay<br>					</li><li>Uses Steam name<br>					</li><li>Host/Join games via bare-bones in-game lobby browser<br>					</li><li>Can invite and join friends and others via the Steam overlay<br>					</li><li>Game attempts host migration<br>					</li><li>Dedicated servers are not supported or planned<br>					</li></ul>','Aliens Versus Predator Classic 2000 features the Colonial Marine, Alien and Predator Campaigns and the frenetic single-player Skirmish mode from the original title: Alien Versus Predator Gold Edition, which was released to massive acclaim in 2000.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3800,'A common legend pervades the galaxy-that of a powerful, highly intelligent ancient race that will one day deliver the universe.  They are known as Humans.<br />
					Some claim they are the messiah. Others believe they exist only in the imaginations of the young. The Seekers, however, know Humans exist and believe they are an enemy that must be destroyed. Under the guise of benevolent explorers, Seekers comb the universe and eradicate any Human colonies they find. Until now.<br />
					Working with award-winning science fiction author Orson Scott Card, GlyphX Games has created a gripping storyline that will thrust gamers into an incredible intergalactic saga.<br />
					The Advent of Humanity Begins...','A common legend pervades the galaxy-that of a powerful, highly intelligent ancient race that will one day deliver the universe.  They are known as Humans.<br />
					Some claim they are the messiah. Others believe they exist only in the imaginations of the young. The Seekers, however, know Humans exist and believe they are an enemy that must be destroyed. Under the guise of benevolent explorers, Seekers comb the universe and eradicate any Human colonies they find. Until now.<br />
					Working with award-winning science fiction author Orson Scott Card, GlyphX Games has created a gripping storyline that will thrust gamers into an incredible intergalactic saga.<br />
					The Advent of Humanity Begins...','A common legend pervades the galaxy-that of a powerful, highly intelligent ancient race that will one day deliver the universe. They are known as Humans. The Advent of Humanity Begins...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3810,'In the years between the World Wars, Agent BloodRayne works as a killing machine for The Brimstone Society--a top secret fraternity that hunts down and destroys supernatural threats. Two missions, five years apart, turn out to be connected by one man.  For years, this man has been searching the world for powerful occult relics to bring Germany into a new age of domination. Rayne must face his elite Nazi army and prevent them from releasing horrific creatures in their quest for the artifacts.  Starring the super-sexy, super-lethal, supernatural heroine BloodRayne, this original action horror game unleashed the red headed dhampir on the world.','In the years between the World Wars, Agent BloodRayne works as a killing machine for The Brimstone Society--a top secret fraternity that hunts down and destroys supernatural threats. Two missions, five years apart, turn out to be connected by one man.  For years, this man has been searching the world for powerful occult relics to bring Germany into a new age of domination. Rayne must face his elite Nazi army and prevent them from releasing horrific creatures in their quest for the artifacts.  Starring the super-sexy, super-lethal, supernatural heroine BloodRayne, this original action horror game unleashed the red headed dhampir on the world.','In the years between the World Wars, Agent BloodRayne works as a killing machine for The Brimstone Society--a top secret fraternity that hunts down and destroys supernatural threats. Starring heroine Rayne, this original action horror game unleashed the red headed dhampir on the world.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3820,'BloodRayne is a dhampir, born from the unnatural union of vampire and human. Blessed with the powers of a vampire but cursed with the thirst for blood and a weakness to sunlight, Rayne is challenged with her most personal battle yet as she hunts down her siblings. They have banded together and pledged to carry on their father''s legacy of creating a new era of vampire supremacy where humans are mere cattle. Rayne''s siblings have created ''The Shroud,'' a mysterious substance that will render the sun''s lethal rays harmless to vampires. Now only BloodRayne stands between an unsuspecting humanity and a horrifying vampire dawn.','BloodRayne is a dhampir, born from the unnatural union of vampire and human. Blessed with the powers of a vampire but cursed with the thirst for blood and a weakness to sunlight, Rayne is challenged with her most personal battle yet as she hunts down her siblings. They have banded together and pledged to carry on their father''s legacy of creating a new era of vampire supremacy where humans are mere cattle. Rayne''s siblings have created ''The Shroud,'' a mysterious substance that will render the sun''s lethal rays harmless to vampires. Now only BloodRayne stands between an unsuspecting humanity and a horrifying vampire dawn.','BloodRayne is a dhampir, born from the unnatural union of vampire and human. Blessed with the powers of a vampire but cursed with the thirst for blood and a weakness to sunlight, Rayne is challenged with her most personal battle yet as she hunts down her siblings.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3830,'A Psychic Odyssey Through the Minds of Misfits, Monsters, and Madmen.<br />
<br />
This classic action/adventure platformer from acclaimed developers Double Fine Productions follows the story of a young psychic named Razputin. In his quest to join the Psychonauts--an elite group of international psychic secret agents--he breaks into their secret training facility: Whispering Rock Psychic Summer Camp. But this is no average psychic summer camp! A mysterious villain has kidnapped Raz’s fellow campers and stolen their brains. Now he must use his psychic powers of Telekinesis, Levitation, and most of all his ability to project himself into the minds of others--to find the loose noodles and keep them from falling into the wrong hands. Fight mental demons! Uncover hidden memories! Sort emotional baggage! Explore the fantastic realm of the inner mind! Join the Psychonauts!','A Psychic Odyssey Through the Minds of Misfits, Monsters, and Madmen.<br />
<br />
This classic action/adventure platformer from acclaimed developers Double Fine Productions follows the story of a young psychic named Razputin. In his quest to join the Psychonauts--an elite group of international psychic secret agents--he breaks into their secret training facility: Whispering Rock Psychic Summer Camp. But this is no average psychic summer camp! A mysterious villain has kidnapped Raz’s fellow campers and stolen their brains. Now he must use his psychic powers of Telekinesis, Levitation, and most of all his ability to project himself into the minds of others--to find the loose noodles and keep them from falling into the wrong hands. Fight mental demons! Uncover hidden memories! Sort emotional baggage! Explore the fantastic realm of the inner mind! Join the Psychonauts!','A Psychic Odyssey Through the Minds of Misfits, Monsters, and Madmen. This classic action/adventure platformer from acclaimed developers Double Fine Productions follows the story of a young psychic named Razputin.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3900,'With over 6 million units sold and unprecedented critical acclaim from fans and press around the world, Sid Meier''s Civilization is recognized as one of the greatest PC game franchises of all-time. Now, Sid Meier and Firaxis Games will take this incredibly fun and addictive game to new heights by adding new ways to play and win, new tools to manage and expand your civilization, all-new easy to use mod capabilities and intense multiplayer modes and options*. Civilization IV will come to life like never before in a beautifully detailed, living 3D world that will elevate the gameplay experience to a whole new level. Civilization IV has already been heralded as one of the top ten games of 2005, and a must-have for gamers around the globe!<br><br><strong>*Mac version''s Online Multiplayer is no longer supported.</strong>','With over 6 million units sold and unprecedented critical acclaim from fans and press around the world, Sid Meier''s Civilization is recognized as one of the greatest PC game franchises of all-time. Now, Sid Meier and Firaxis Games will take this incredibly fun and addictive game to new heights by adding new ways to play and win, new tools to manage and expand your civilization, all-new easy to use mod capabilities and intense multiplayer modes and options*. Civilization IV will come to life like never before in a beautifully detailed, living 3D world that will elevate the gameplay experience to a whole new level. Civilization IV has already been heralded as one of the top ten games of 2005, and a must-have for gamers around the globe!<br><br><strong>*Mac version''s Online Multiplayer is no longer supported.</strong>','With over 6 million units sold and unprecedented critical acclaim from fans and press around the world, Sid Meier''s Civilization is recognized as one of the greatest PC game franchises of all-time. Now, Sid Meier and Firaxis Games will take this incredibly fun and addictive game to new heights by adding new ways to play and win, new...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3910,'Sid Meier''s Civilization III: Complete, the latest offering in the Sid Meier''s Civilization III franchise, provides gaming fans with Sid Meier''s Civilization III, the highly-addictive journey of discovery, combined with the updated and enhanced multiplayer expansion pack Sid Meier''s Civilization III: Play the World*, as well as all of the great new civilizations, scenarios, and features from Sid Meier''s Civilization III: Conquests! Sid Meier''s Civilization III: Complete provides more ways to explore, more strategies to employ, more modes of play, and more ways to win, all in one box!<br />
<br />
*Online Multiplayer to be suspended as of May 31st 2014, LAN mode still supported','Sid Meier''s Civilization III: Complete, the latest offering in the Sid Meier''s Civilization III franchise, provides gaming fans with Sid Meier''s Civilization III, the highly-addictive journey of discovery, combined with the updated and enhanced multiplayer expansion pack Sid Meier''s Civilization III: Play the World*, as well as all of the great new civilizations, scenarios, and features from Sid Meier''s Civilization III: Conquests! Sid Meier''s Civilization III: Complete provides more ways to explore, more strategies to employ, more modes of play, and more ways to win, all in one box!<br />
<br />
*Online Multiplayer to be suspended as of May 31st 2014, LAN mode still supported','Sid Meier''s Civilization III: Complete, the latest offering in the Sid Meier''s Civilization III franchise, provides gaming fans with Sid Meier''s Civilization III, the highly-addictive journey of discovery.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3920,'Sail the Caribbean, marauding all on the high seas or ally your ship and crew as a privateer in search of riches - the life you choose is up to you. Face dogged enemies, raid unsuspecting villages, woo fair maidens, avoid capture or dig for buried treasure. Discover what it takes to become one of the most famous pirates in history!','Sail the Caribbean, marauding all on the high seas or ally your ship and crew as a privateer in search of riches - the life you choose is up to you. Face dogged enemies, raid unsuspecting villages, woo fair maidens, avoid capture or dig for buried treasure. Discover what it takes to become one of the most famous pirates in history!','Sail the Caribbean, marauding all on the high seas or ally your ship and crew as a privateer in search of riches - the life you choose is up to you. Face dogged enemies, raid unsuspecting villages, woo fair maidens, avoid capture or dig for buried treasure. Discover what it takes to become one of the most famous pirates in history!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3960,'Following a great increase in terrorism, internal strife and ultimately, the nuclear destruction of Washington, D.C., the United States shatters into a half-dozen nation-states that descend into war. Take the helm of one of these newfound sovereignties (or the ''peacekeeping'' European Expeditionary Force) and struggle to reunify America... by any means necessary!<br>					<ul class="bb_ul"><li>Modern 3D tactical war game viewed from a &quot;bird''s-eye&quot; overhead camera.<br>					</li><li>Non-linear mission progression with changes based on player-made decisions.<br>					</li><li>Real-time resolution of turned-based moves. Take your time while you decide your move, but once you have selected your action, see the results all play out in full animation models, exploding vehicles, and burning cities and forests!<br>					</li><li>Fully destructible terrain/environment. As the battle proceeds, everything from explosions and destroyed buildings permanently mark the terrain. Moving tanks will leave tread marks that stay for the duration of the mission. At the end, very little will look the same.<br>					</li><li>Fight your way across the United States! Had enough of the windy city? Then go ahead and bomb Chicago! Invade across the Rockies into California, capture the tank factories in Ohio, and lay siege to New York City! You decide - the fate of the nation is in your hands!<br>					</li><li>Call up National Guard forces equipped with M1 Abrams battle tanks, Apache helicopters and stealth bombers. Or make a deal with the Russians and equip your boys with MiG fighters and T-95 Heavy Tanks.</li></ul>','Following a great increase in terrorism, internal strife and ultimately, the nuclear destruction of Washington, D.C., the United States shatters into a half-dozen nation-states that descend into war. Take the helm of one of these newfound sovereignties (or the ''peacekeeping'' European Expeditionary Force) and struggle to reunify America... by any means necessary!<br>					<ul class="bb_ul"><li>Modern 3D tactical war game viewed from a &quot;bird''s-eye&quot; overhead camera.<br>					</li><li>Non-linear mission progression with changes based on player-made decisions.<br>					</li><li>Real-time resolution of turned-based moves. Take your time while you decide your move, but once you have selected your action, see the results all play out in full animation models, exploding vehicles, and burning cities and forests!<br>					</li><li>Fully destructible terrain/environment. As the battle proceeds, everything from explosions and destroyed buildings permanently mark the terrain. Moving tanks will leave tread marks that stay for the duration of the mission. At the end, very little will look the same.<br>					</li><li>Fight your way across the United States! Had enough of the windy city? Then go ahead and bomb Chicago! Invade across the Rockies into California, capture the tank factories in Ohio, and lay siege to New York City! You decide - the fate of the nation is in your hands!<br>					</li><li>Call up National Guard forces equipped with M1 Abrams battle tanks, Apache helicopters and stealth bombers. Or make a deal with the Russians and equip your boys with MiG fighters and T-95 Heavy Tanks.</li></ul>','Following a great increase in terrorism, internal strife and ultimately, the nuclear destruction of Washington, D.C., the United States shatters into a half-dozen nation-states that descend into war. Take the helm of one of these newfound sovereignties (or the ''peacekeeping'' European Expeditionary Force) and struggle to reunify America...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3980,'CivCity: Rome, an innovative city builder inspired by the world of Sid Meiers Civilization, and created by a collaboration between Firefly Studios and Firaxis Games, invites players to shift focus from building a multi-city empire and zoom-in on the great cities of the Roman Empire, culminating in Rome itself! Through dozens of missions, each offering an array of interesting decisions, players will be charged with building, nurturing and managing one of these great cities as they endeavour to lead the Roman Empire from its humble beginnings to its mighty apogee. Features players have enjoyed in the Civilization series, like research, city happiness, production and culture, can now be managed actively in the wonderfully immersive world of CivCity: Rome.<br>					<ul class="bb_ul"><li>Look inside the buildings - For the first time in a city builder you can look inside the Villas, the forums, and even the Roman baths! Discover, in much greater detail, how Romans went about their daily lives. <br>					</li><li>Civilize your city - More than 70 technologies can be developed over time to give your city a strategic advantage. Use the rich research tree to improve many aspects of your city and its relation to the wider empire.<br>					</li><li>Follow the life of a Roman family - Do they thrive and prosper from humble hut to noble palace as they move through the generations or not? Well, thats your call! <br>					</li><li>Ease of play - Driven purely by building placement and strong visual feedback, the game lets you create your own living community simply by choosing and placing the wide variety of buildings. <br>					</li><li>Real Romans - An intriguing array of characters will interact with you</li></ul>','CivCity: Rome, an innovative city builder inspired by the world of Sid Meiers Civilization, and created by a collaboration between Firefly Studios and Firaxis Games, invites players to shift focus from building a multi-city empire and zoom-in on the great cities of the Roman Empire, culminating in Rome itself! Through dozens of missions, each offering an array of interesting decisions, players will be charged with building, nurturing and managing one of these great cities as they endeavour to lead the Roman Empire from its humble beginnings to its mighty apogee. Features players have enjoyed in the Civilization series, like research, city happiness, production and culture, can now be managed actively in the wonderfully immersive world of CivCity: Rome.<br>					<ul class="bb_ul"><li>Look inside the buildings - For the first time in a city builder you can look inside the Villas, the forums, and even the Roman baths! Discover, in much greater detail, how Romans went about their daily lives. <br>					</li><li>Civilize your city - More than 70 technologies can be developed over time to give your city a strategic advantage. Use the rich research tree to improve many aspects of your city and its relation to the wider empire.<br>					</li><li>Follow the life of a Roman family - Do they thrive and prosper from humble hut to noble palace as they move through the generations or not? Well, thats your call! <br>					</li><li>Ease of play - Driven purely by building placement and strong visual feedback, the game lets you create your own living community simply by choosing and placing the wide variety of buildings. <br>					</li><li>Real Romans - An intriguing array of characters will interact with you</li></ul>','CivCity: Rome, an innovative city builder inspired by the world of Sid Meiers Civilization, and created by a collaboration between Firefly Studios and Firaxis Games, invites players to shift focus from building a multi-city empire and zoom-in on the great cities of the Roman Empire, culminating in Rome itself!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (3990,'Sid Meier''s Civilization IV: Warlords is the first expansion pack for the award-winning game that has become an instant world-wide hit. Paying homage to some of history''s greatest military leaders, the expansion delivers six unique and interesting scenarios, giving players the chance to change the course of history with the help of their new powerful &quot;warlord&quot; unit. Civ IV: Warlords includes new civilizations, leaders, units, and wonders that offer even more fun and exciting ways for players to expand their civilization''s military power as they strive for world domination.<br>					<ul class="bb_ul"><li>Warlords: a new great person type called the Warlord.<br>					</li><li>Vassal states: conquer an enemy and subjugate them to your rule.<br>					</li><li>Game scenarios: the expansion delivers eight scenarios.<br>					</li><li>New civilizations: the pack provides six new civilizations and associated unique units.<br>					</li><li>Civilization leaders: 10 new leaders, including leaders for the new civilizations as well as additional leaders for existing civilizations.<br>					</li><li>Leader traits: two new leader traits.<br>					</li><li>New wonders: three new wonders.<br>					</li><li>Unique buildings: each civilization has a new unique building as well as their unique unit.<br>					</li><li>New units, resources, and improvements: many new items are presented throughout the scenarios.<br>					</li><li>Core game tweaks and additions: expanded features and gameplay tweaks made to the core game.<br>					</li><li>Post-release patches and game upgrades: the pack contains all of the patches and game additions (pit boss, etc.) yet released for Sid Meier''s Civilization IV.</li></ul>','Sid Meier''s Civilization IV: Warlords is the first expansion pack for the award-winning game that has become an instant world-wide hit. Paying homage to some of history''s greatest military leaders, the expansion delivers six unique and interesting scenarios, giving players the chance to change the course of history with the help of their new powerful &quot;warlord&quot; unit. Civ IV: Warlords includes new civilizations, leaders, units, and wonders that offer even more fun and exciting ways for players to expand their civilization''s military power as they strive for world domination.<br>					<ul class="bb_ul"><li>Warlords: a new great person type called the Warlord.<br>					</li><li>Vassal states: conquer an enemy and subjugate them to your rule.<br>					</li><li>Game scenarios: the expansion delivers eight scenarios.<br>					</li><li>New civilizations: the pack provides six new civilizations and associated unique units.<br>					</li><li>Civilization leaders: 10 new leaders, including leaders for the new civilizations as well as additional leaders for existing civilizations.<br>					</li><li>Leader traits: two new leader traits.<br>					</li><li>New wonders: three new wonders.<br>					</li><li>Unique buildings: each civilization has a new unique building as well as their unique unit.<br>					</li><li>New units, resources, and improvements: many new items are presented throughout the scenarios.<br>					</li><li>Core game tweaks and additions: expanded features and gameplay tweaks made to the core game.<br>					</li><li>Post-release patches and game upgrades: the pack contains all of the patches and game additions (pit boss, etc.) yet released for Sid Meier''s Civilization IV.</li></ul>','Sid Meier''s Civilization IV: Warlords is the first expansion pack for the award-winning game that has become an instant world-wide hit. Paying homage to some of history''s greatest military leaders, the expansion delivers six unique and interesting scenarios, giving players the chance to change the course of history with the help of their...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4000,'Garry''s Mod is a physics sandbox. There aren''t any predefined aims or goals. We give you the tools and leave you to play.<br><br>You spawn objects and weld them together to create your own contraptions - whether that''s a car, a rocket, a catapult or something that doesn''t have a name yet - that''s up to you. You can do it offline, or join the thousands of players who play online each day. <br><br>If you''re not too great at construction - don''t worry! You can place a variety of characters in silly positions. But if you want to do more, we have the means.<h2 class="bb_tag">Beyond the Sandbox</h2><br>The Garry''s Mod community is a tremendous source of content and has added hundreds of unique modes to the game. In Trouble In Terrorist Town, you can be a detective solving an online murder as criminals attempt to cover up their homicides. Be a ball, a plant, a chair, or anything else in Prop Hunt''s elaborate, shape-shifting game of Hide &amp; Seek. Elevator: Source is gaming''s first elevator thrill ride, delivering players to airlocks and kitten dance parties. <br><br>We have one of the most vibrant Steam Community Workshops, with over 300''000 models, maps, and contraptions to download. It has everything from new tools to improve your builds, to guns that fire rainbow-tinged nuclear blasts from space. Take as much or as little as you need: it’s all free. <br><br><strong>Please note: Some multiplayer servers and game-modes might require you to own other games - such as Counter-Strike: Source and Team Fortress 2.</strong>','Garry''s Mod is a physics sandbox. There aren''t any predefined aims or goals. We give you the tools and leave you to play.<br><br>You spawn objects and weld them together to create your own contraptions - whether that''s a car, a rocket, a catapult or something that doesn''t have a name yet - that''s up to you. You can do it offline, or join the thousands of players who play online each day. <br><br>If you''re not too great at construction - don''t worry! You can place a variety of characters in silly positions. But if you want to do more, we have the means.<h2 class="bb_tag">Beyond the Sandbox</h2><br>The Garry''s Mod community is a tremendous source of content and has added hundreds of unique modes to the game. In Trouble In Terrorist Town, you can be a detective solving an online murder as criminals attempt to cover up their homicides. Be a ball, a plant, a chair, or anything else in Prop Hunt''s elaborate, shape-shifting game of Hide &amp; Seek. Elevator: Source is gaming''s first elevator thrill ride, delivering players to airlocks and kitten dance parties. <br><br>We have one of the most vibrant Steam Community Workshops, with over 300''000 models, maps, and contraptions to download. It has everything from new tools to improve your builds, to guns that fire rainbow-tinged nuclear blasts from space. Take as much or as little as you need: it’s all free. <br><br><strong>Please note: Some multiplayer servers and game-modes might require you to own other games - such as Counter-Strike: Source and Team Fortress 2.</strong>','Garry''s Mod is a physics sandbox. There aren''t any predefined aims or goals. We give you the tools and leave you to play.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4100,'<p>You''ve been invited back for Season 2! Poker Superstars II raises the stakes with more superstars, a bigger tournament and a brand new poker AI. Import your own photo into the game and become a Poker Superstar. Then get ready to battle through an exciting new tournament structure against 15 of poker''s top players powered by a ''first of its kind'' artificial intelligence system that has learned to win by playing millions of simulated tournaments! The Superstars are ready to win, are you?</p><span class="copyHead">It contains these great features:</span>
					<ul>
					<li><span class="copyHead">Tougher Challenge!</span> First of its kind artificial intelligence system that has taught itself how to play, and how to win.</li>
					<li><span class="copyHead">Bigger Tournament!</span> You get to play the dynamic and competitive tournament right from the TV show.</li>
					<li><span class="copyHead">More Superstars!</span> This time, you are one of 16 Poker Superstars.</li>
					<li><span class="copyHead">Import Your Photo!</span> Be the Poker Superstar you know you are and see yourself right in the game!</li>
					<li><span class="copyHead">Interactive Opponent Pictures!</span> Now you get to see the Superstars smile devilishly when they beat you, as well as scowl when you beat them!</li>
					<li><span class="copyHead">Learn or Master!</span> Game Tips will introduce you to the game while the Game Tip button can help you hone your game.</li>
					<li><span class="copyHead">Amateur or Superstars!</span> Two different levels of challenge let you tune the game to the play level you want.</li>
					<li><span class="copyHead">Player Cards!</span> The game will track all your winnings, flops seen %, pots won % and best hands.  So you''ll be able to see what kind of player you are.</li>
					<li><span class="copyHead">3 Exciting Game Modes!</span> Round lets you play a quick round. Season challenges you to win the full tournament. Limit lets you play the set bet amount game found frequently in casinos and online.</li>
					<li><span class="copyHead">Top Ten Lists!</span> Track your top winnings, top pots and top hands.</li></ul>','<p>You''ve been invited back for Season 2! Poker Superstars II raises the stakes with more superstars, a bigger tournament and a brand new poker AI. Import your own photo into the game and become a Poker Superstar. Then get ready to battle through an exciting new tournament structure against 15 of poker''s top players powered by a ''first of its kind'' artificial intelligence system that has learned to win by playing millions of simulated tournaments! The Superstars are ready to win, are you?</p><span class="copyHead">It contains these great features:</span>
					<ul>
					<li><span class="copyHead">Tougher Challenge!</span> First of its kind artificial intelligence system that has taught itself how to play, and how to win.</li>
					<li><span class="copyHead">Bigger Tournament!</span> You get to play the dynamic and competitive tournament right from the TV show.</li>
					<li><span class="copyHead">More Superstars!</span> This time, you are one of 16 Poker Superstars.</li>
					<li><span class="copyHead">Import Your Photo!</span> Be the Poker Superstar you know you are and see yourself right in the game!</li>
					<li><span class="copyHead">Interactive Opponent Pictures!</span> Now you get to see the Superstars smile devilishly when they beat you, as well as scowl when you beat them!</li>
					<li><span class="copyHead">Learn or Master!</span> Game Tips will introduce you to the game while the Game Tip button can help you hone your game.</li>
					<li><span class="copyHead">Amateur or Superstars!</span> Two different levels of challenge let you tune the game to the play level you want.</li>
					<li><span class="copyHead">Player Cards!</span> The game will track all your winnings, flops seen %, pots won % and best hands.  So you''ll be able to see what kind of player you are.</li>
					<li><span class="copyHead">3 Exciting Game Modes!</span> Round lets you play a quick round. Season challenges you to win the full tournament. Limit lets you play the set bet amount game found frequently in casinos and online.</li>
					<li><span class="copyHead">Top Ten Lists!</span> Track your top winnings, top pots and top hands.</li></ul>','You''ve been invited back for Season 2! Poker Superstars II raises the stakes with more superstars, a bigger tournament and a brand new poker AI. Import your own photo into the game and become a Poker Superstar.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4230,'<strong>The Official WTCC Game |</strong> RACE is the first ever game to be focused on the hard hitting, intense action of the exciting WTCC championship which is exploding in popularity all over the world. Based on WTCC, one of only three official FIA world championships next to Formula 1 and WRC, RACE features the complete WTCC championship season of 2006, all the cars, drivers and locations, including several official tracks and cars brand new to the racing game genre.<br>					The game recreates the championship as close to real life as possible and simulates the cars and the driving style in a ultra realistic fashion.<br>					 RACE features various difficulty levels to attract everyone, from hardcore simulation gamers to beginners level still featuring the same elements and a highly realistic driving experience.','<strong>The Official WTCC Game |</strong> RACE is the first ever game to be focused on the hard hitting, intense action of the exciting WTCC championship which is exploding in popularity all over the world. Based on WTCC, one of only three official FIA world championships next to Formula 1 and WRC, RACE features the complete WTCC championship season of 2006, all the cars, drivers and locations, including several official tracks and cars brand new to the racing game genre.<br>					The game recreates the championship as close to real life as possible and simulates the cars and the driving style in a ultra realistic fashion.<br>					 RACE features various difficulty levels to attract everyone, from hardcore simulation gamers to beginners level still featuring the same elements and a highly realistic driving experience.','The Official WTCC Game | RACE is the first ever game to be focused on the hard hitting, intense action of the exciting WTCC championship which is exploding in popularity all over the world. Based on WTCC, one of only three official FIA world championships next to Formula 1 and WRC, RACE features the complete WTCC championship season of...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4290,'Celebrating the 50-year anniversary of Caterham Cars Ltd, RACE fans can now expand the WTCC Experience with this exceptional series of classic sportscars. RACE: CATERHAM introduces a total of 60 individual new cars/car skins based on some of the most exciting models in the Caterham sports car range, including the Caterham CSR 200, CSR 260 and the CSR 320 Concept, a concept version with a grueling 320hp.<br />
Racers can run the cars on two exciting new tracks: the legendary Imola circuit and the former GP track Estoril.<br />
RACE: CATERHAM includes new features that improve the original RACE game experience: improved performance scalability, a performance monitor to help the player find the best possible graphical settings, and a new controller interface with more options for joy-pad or keyboard/mouse controls.','Celebrating the 50-year anniversary of Caterham Cars Ltd, RACE fans can now expand the WTCC Experience with this exceptional series of classic sportscars. RACE: CATERHAM introduces a total of 60 individual new cars/car skins based on some of the most exciting models in the Caterham sports car range, including the Caterham CSR 200, CSR 260 and the CSR 320 Concept, a concept version with a grueling 320hp.<br />
Racers can run the cars on two exciting new tracks: the legendary Imola circuit and the former GP track Estoril.<br />
RACE: CATERHAM includes new features that improve the original RACE game experience: improved performance scalability, a performance monitor to help the player find the best possible graphical settings, and a new controller interface with more options for joy-pad or keyboard/mouse controls.','Celebrating the 50-year anniversary of Caterham Cars Ltd, RACE fans can now expand the WTCC Experience with this exceptional series of classic sportscars. RACE: CATERHAM introduces a total of 60 individual new cars/car skins based on some of the most exciting models in the Caterham sports car range, including the Caterham CSR 200, CSR...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4300,'<p>RoboBlitz&trade; is a humorous, physics-based action game full of inventive gizmos, weapons, characters, and environments. Players take on the role of Blitz, a multi-talented robot who must activate an aging Space Cannon to save his world from a band of maladjusted space pirates.</p>
					<ul>
					<li>19 levels of puzzle-solving and high-intensity action, set in 7 unique environments</li>
					<li>Humorous characters and unique weapons</li>
					<li>Gameplay entirely driven by physics</li>
					<li>Advanced robot simulation and control theory</li>
					<li>Powered by Unreal&reg; Engine 3</li></ul>','<p>RoboBlitz&trade; is a humorous, physics-based action game full of inventive gizmos, weapons, characters, and environments. Players take on the role of Blitz, a multi-talented robot who must activate an aging Space Cannon to save his world from a band of maladjusted space pirates.</p>
					<ul>
					<li>19 levels of puzzle-solving and high-intensity action, set in 7 unique environments</li>
					<li>Humorous characters and unique weapons</li>
					<li>Gameplay entirely driven by physics</li>
					<li>Advanced robot simulation and control theory</li>
					<li>Powered by Unreal&reg; Engine 3</li></ul>','RoboBlitz&trade; is a humorous, physics-based action game full of inventive gizmos, weapons, characters, and environments. Players take on the role of Blitz, a multi-talented robot who must activate an aging Space Cannon to save his world from a band of maladjusted space pirates.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4420,'Silverfall, a once glorious city, lies in the fantastical Kingdom of       Nelwë, where the forces of Technology and Nature are strongly opposed. Symptoms of this terrible conflict have begun to manifest physically as melded cyberbiologic organics and living steam-driven automatons.<br>					Drag your hero from the pits of this world and craft him into a mighty champion that can oppose the planet-choking Order of Nothingness. Freedom to evolve in either the technological or spiritual paths is in your hands and you must choose your comrades wisely to provide a balance and benefit to your efforts - but be cautious, any bias in your choices will either corrupt or upgrade the growing world around you.<br>					<ul class="bb_ul"><li>Create &amp; customize your hero (face, sex, skin, hair...) from the 4 Nelwë races (human, elf, goblin &amp; troll).<br>					</li><li>Your hero advances without class limits and with more than 130 skills &amp; magic spells at his disposal.<br>					</li><li>Freely explore a stunning and immense fantasy world! <br>					</li><li>From the floating city of Cloudworks, to the volcanic scenery of the city of Blazis.<br>					</li><li>Revolutionary light and shadow effects combine with a realistic physics engine which gives never seen before detail to the environment &amp; special effects.<br>					</li><li>Playable with up to 8 players in multiplayer mode through either a LAN connection or on the Internet, with cooperative play or PvP.</li></ul>','Silverfall, a once glorious city, lies in the fantastical Kingdom of       Nelwë, where the forces of Technology and Nature are strongly opposed. Symptoms of this terrible conflict have begun to manifest physically as melded cyberbiologic organics and living steam-driven automatons.<br>					Drag your hero from the pits of this world and craft him into a mighty champion that can oppose the planet-choking Order of Nothingness. Freedom to evolve in either the technological or spiritual paths is in your hands and you must choose your comrades wisely to provide a balance and benefit to your efforts - but be cautious, any bias in your choices will either corrupt or upgrade the growing world around you.<br>					<ul class="bb_ul"><li>Create &amp; customize your hero (face, sex, skin, hair...) from the 4 Nelwë races (human, elf, goblin &amp; troll).<br>					</li><li>Your hero advances without class limits and with more than 130 skills &amp; magic spells at his disposal.<br>					</li><li>Freely explore a stunning and immense fantasy world! <br>					</li><li>From the floating city of Cloudworks, to the volcanic scenery of the city of Blazis.<br>					</li><li>Revolutionary light and shadow effects combine with a realistic physics engine which gives never seen before detail to the environment &amp; special effects.<br>					</li><li>Playable with up to 8 players in multiplayer mode through either a LAN connection or on the Internet, with cooperative play or PvP.</li></ul>','Silverfall, a once glorious city, lies in the fantastical Kingdom of Nelwë, where the forces of Technology and Nature are strongly opposed. Symptoms of this terrible conflict have begun to manifest physically as melded cyberbiologic organics and living steam-driven automatons.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4460,'Construct the city of the 21st Century with City Life!<br>					City Life 2008 Edition is a next-generation City Builder. Its 3D game engine provides a level of detail and animation unprecedented in the City Builder genre, with total freedom of construction. From superb villas in residential neighbourhoods to imposing skyscrapers in the financial district, design, construct and develop the city of your dreams. Provide comfort and satisfaction for your citizens by offering them work, health care, entertainment facilities, and much more, and ensure that your city’s coffers are brimming. It’s up to you to manage your city efficiently, balancing booming development with the problems of pollution and traffic that this brings. Build a sense of community between the six unique subcultures, or pay the price if their relationships deteriorate into conflict or riots. You are the architect, mayor and business mogul!<br>2008 Edition<br>					City Life 2008 Edition contains all the content of the previous versions, adding a further 23 new maps and over 60 new buildings, including landmarks such as London’s Royal Opera House and St. Paul’s Cathedral. Over 360 buildings are at your disposal in this latest version. You now have the possibility to import satellite maps, heightmaps, and other user-generated terrain into the game. Use your imagination to create ever more spectacular towns, or recreate the exceptional cities of the real world!<br>Features<br>					<ul class="bb_ul"><li>Gigantic city building simulation with high performance 3D engine.<br>					</li><li>Explore 50 maps in five different environments.<br>					</li><li>360° camera rotation and zooming allows you to dive into the heart of your city and observe its inhabitants.<br>					</li><li>Six unique subcultures with specific expectations and needs.<br>					</li><li>Play in Scenario or Free Mode.<br>					</li><li>New import tool for satellite maps and heightmaps.<br>					</li><li>A powerful building creation tool based on a modular system. No technical skills required, only your imagination.</li></ul>','Construct the city of the 21st Century with City Life!<br>					City Life 2008 Edition is a next-generation City Builder. Its 3D game engine provides a level of detail and animation unprecedented in the City Builder genre, with total freedom of construction. From superb villas in residential neighbourhoods to imposing skyscrapers in the financial district, design, construct and develop the city of your dreams. Provide comfort and satisfaction for your citizens by offering them work, health care, entertainment facilities, and much more, and ensure that your city’s coffers are brimming. It’s up to you to manage your city efficiently, balancing booming development with the problems of pollution and traffic that this brings. Build a sense of community between the six unique subcultures, or pay the price if their relationships deteriorate into conflict or riots. You are the architect, mayor and business mogul!<br>2008 Edition<br>					City Life 2008 Edition contains all the content of the previous versions, adding a further 23 new maps and over 60 new buildings, including landmarks such as London’s Royal Opera House and St. Paul’s Cathedral. Over 360 buildings are at your disposal in this latest version. You now have the possibility to import satellite maps, heightmaps, and other user-generated terrain into the game. Use your imagination to create ever more spectacular towns, or recreate the exceptional cities of the real world!<br>Features<br>					<ul class="bb_ul"><li>Gigantic city building simulation with high performance 3D engine.<br>					</li><li>Explore 50 maps in five different environments.<br>					</li><li>360° camera rotation and zooming allows you to dive into the heart of your city and observe its inhabitants.<br>					</li><li>Six unique subcultures with specific expectations and needs.<br>					</li><li>Play in Scenario or Free Mode.<br>					</li><li>New import tool for satellite maps and heightmaps.<br>					</li><li>A powerful building creation tool based on a modular system. No technical skills required, only your imagination.</li></ul>','Construct the city of the 21st Century with City Life! City Life 2008 Edition is a next-generation City Builder. Its 3D game engine provides a level of detail and animation unprecedented in the City Builder genre, with total freedom of construction.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4470,'<p>Silverfall Earth Awakening is an action RPG with unique graphical feel offering a fantastic quest to explore the new territories of Nelwë. In this heroic fantasy world where nature and technology collide you will have to make important choices which will lead you to side with one or the other. Play any one of the available six races, of which 2 are new: the stocky and lucky ''Dwarves'' and the agile and treacherous ''Lizardmen'', and prepare yourself to confront an impressive array of creatures and formidable bosses to save the realm of Nelwë.</p>
					<ul>
					<li>Alongside the Elves, Goblins, Trolls and Humans, discover 2 new playable races with 5 specific skills each : The dwarves and the Lizardmen, and then customize your hero ( skin, gender , hair, etc .)</li>
					<li>Master over 156 skills and magic spells, including 8 new exclusive ''Ultimate'' skills and 12 unique ''High Level'' skills for an even more devastating result.</li>
					<li>Use different object crafting skills and make thousands of new and unique weapons, armour and spells. </li>
					<li>Discover a new, fully adaptable game interface with improved ergonomics in which you can now control your hero with the mouse or keyboard.</li>
					<li>Import your hero from Silverfall to Earth Awakening and keep your level, equipment and skills...or start the adventure from the beginning with a level 45 hero.</li>
					<li>Playable with up to 8 players in multiplayer mode via LAN and in cooperative or PVP mode via the Internet.</li></ul>','<p>Silverfall Earth Awakening is an action RPG with unique graphical feel offering a fantastic quest to explore the new territories of Nelwë. In this heroic fantasy world where nature and technology collide you will have to make important choices which will lead you to side with one or the other. Play any one of the available six races, of which 2 are new: the stocky and lucky ''Dwarves'' and the agile and treacherous ''Lizardmen'', and prepare yourself to confront an impressive array of creatures and formidable bosses to save the realm of Nelwë.</p>
					<ul>
					<li>Alongside the Elves, Goblins, Trolls and Humans, discover 2 new playable races with 5 specific skills each : The dwarves and the Lizardmen, and then customize your hero ( skin, gender , hair, etc .)</li>
					<li>Master over 156 skills and magic spells, including 8 new exclusive ''Ultimate'' skills and 12 unique ''High Level'' skills for an even more devastating result.</li>
					<li>Use different object crafting skills and make thousands of new and unique weapons, armour and spells. </li>
					<li>Discover a new, fully adaptable game interface with improved ergonomics in which you can now control your hero with the mouse or keyboard.</li>
					<li>Import your hero from Silverfall to Earth Awakening and keep your level, equipment and skills...or start the adventure from the beginning with a level 45 hero.</li>
					<li>Playable with up to 8 players in multiplayer mode via LAN and in cooperative or PVP mode via the Internet.</li></ul>','Silverfall Earth Awakening is an action RPG with unique graphical feel offering a fantastic quest to explore the new territories of Nelwë. In this heroic fantasy world where nature and technology collide you will have to make important choices which will lead you to side with one or the other.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4500,'In 1986, the world''s worst nuclear disaster occurred at the Chernobyl Nuclear Power Plant. Soviet authorities established an ''Exclusion Zone'' around, but a second explosion hit the reactor in 2006, creating The Zone as we know it – dangerous place, filled with mutated creatures, deadly radiation, and a strange, anomalous energy. The Zone was cordoned off by the military, who would shoot on sight anyone foolish enough to get inside.<br> <br>Year 2012. The Zone is still a dangerous place and a threat to all mankind. Mercenaries, bounty hunters and explorers ventured further and further into the heart of the Zone driven by reports of strange ''artifacts'' imbued with anomalous energy. To sell them on the black market or trying to find the ''truth'' behind the Zone. Whatever their motivation, over time these individuals - Scavengers, Trespassers, Adventurers, Loners, Killers, Explorers and Robbers - have become known as S.T.A.L.K.E.R.s.<br> <br>You will have to find your own way to survive in the Zone!<br> <br><ul class="bb_ul"><li>An immersive storyline, seamlessly blended with a living, breathing, non-linear open-world environment.<br></li><li>An accurately modeled real-world buildings and locations from deep inside of the Chernobyl Exclusion Zone.<br></li><li>Unique ''Survival FPS'' gameplay, which combines action, stealth, survival and RPG elements - to create an incomparable experience in the Zone.<br></li><li>Enemy Threat Evaluation AI system - NPC characters react to changes in environments and situations.<br></li><li>Realistic combat mechanics with accurate ballistic properties.<br></li><li>Dynamic day-night cycle and weather system, that directly impacts gameplay.<br></li><li>Advanced physics and dynamic lighting effects powered by the ''X-Ray Engine''.<br></li><li>Intense multiplayer action, supporting up to 32 players.</li></ul>','In 1986, the world''s worst nuclear disaster occurred at the Chernobyl Nuclear Power Plant. Soviet authorities established an ''Exclusion Zone'' around, but a second explosion hit the reactor in 2006, creating The Zone as we know it – dangerous place, filled with mutated creatures, deadly radiation, and a strange, anomalous energy. The Zone was cordoned off by the military, who would shoot on sight anyone foolish enough to get inside.<br> <br>Year 2012. The Zone is still a dangerous place and a threat to all mankind. Mercenaries, bounty hunters and explorers ventured further and further into the heart of the Zone driven by reports of strange ''artifacts'' imbued with anomalous energy. To sell them on the black market or trying to find the ''truth'' behind the Zone. Whatever their motivation, over time these individuals - Scavengers, Trespassers, Adventurers, Loners, Killers, Explorers and Robbers - have become known as S.T.A.L.K.E.R.s.<br> <br>You will have to find your own way to survive in the Zone!<br> <br><ul class="bb_ul"><li>An immersive storyline, seamlessly blended with a living, breathing, non-linear open-world environment.<br></li><li>An accurately modeled real-world buildings and locations from deep inside of the Chernobyl Exclusion Zone.<br></li><li>Unique ''Survival FPS'' gameplay, which combines action, stealth, survival and RPG elements - to create an incomparable experience in the Zone.<br></li><li>Enemy Threat Evaluation AI system - NPC characters react to changes in environments and situations.<br></li><li>Realistic combat mechanics with accurate ballistic properties.<br></li><li>Dynamic day-night cycle and weather system, that directly impacts gameplay.<br></li><li>Advanced physics and dynamic lighting effects powered by the ''X-Ray Engine''.<br></li><li>Intense multiplayer action, supporting up to 32 players.</li></ul>','S.T.A.L.K.E.R.: Shadow of Chernobyl tells a story about survival in the Zone – a very dangerous place, where you fear not only the radiation, anomalies and deadly creatures, but other S.T.A.L.K.E.R.s, who have their own goals and wishes.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4520,'The U.S. Army is the most powerful ground force in the entire world. The backbone of a ground invasion is the U.S. Army Infantry, and in the midst of combat, their skills, courage, and teamwork are put to the test.<br><br>					While readiness continues to be the U.S. Army''s top priority, how it goes about its business is changing. Full Spectrum Warrior began as a training aid for the U.S. Army to reinforce Army doctrine and team effort within the troops. It is the most realistic portrayal of Infantry-level urban warfare via unique tactical action gameplay. Players become the Squad Leader, commanding Alpha and Bravo squads. There is potential for danger down every alley, behind every window. Watch those angles folks, we''ve got a job to do here. Hooah!<br><br>					<ul class="bb_ul"><li>Unique combination of tactical and action gameplay.<br>					</li><li>Authentic implementation of U.S. Army Infantry doctrine.<br>					</li><li>Simple control scheme lets you command eight soldiers in real time.<br>					</li><li>Squad equipment reflects real weaponry and equipment currently in use by the U.S. Army.<br>					</li><li>Immersive urban environments with danger around every corner.<br>					</li><li>2-player co-op, each player controls one fire team.<br>					</li><li>Includes 2 exclusive bonus levels not available on Xbox.</li></ul>','The U.S. Army is the most powerful ground force in the entire world. The backbone of a ground invasion is the U.S. Army Infantry, and in the midst of combat, their skills, courage, and teamwork are put to the test.<br><br>					While readiness continues to be the U.S. Army''s top priority, how it goes about its business is changing. Full Spectrum Warrior began as a training aid for the U.S. Army to reinforce Army doctrine and team effort within the troops. It is the most realistic portrayal of Infantry-level urban warfare via unique tactical action gameplay. Players become the Squad Leader, commanding Alpha and Bravo squads. There is potential for danger down every alley, behind every window. Watch those angles folks, we''ve got a job to do here. Hooah!<br><br>					<ul class="bb_ul"><li>Unique combination of tactical and action gameplay.<br>					</li><li>Authentic implementation of U.S. Army Infantry doctrine.<br>					</li><li>Simple control scheme lets you command eight soldiers in real time.<br>					</li><li>Squad equipment reflects real weaponry and equipment currently in use by the U.S. Army.<br>					</li><li>Immersive urban environments with danger around every corner.<br>					</li><li>2-player co-op, each player controls one fire team.<br>					</li><li>Includes 2 exclusive bonus levels not available on Xbox.</li></ul>','The U.S. Army is the most powerful ground force in the entire world. The backbone of a ground invasion is the U.S. Army Infantry, and in the midst of combat, their skills, courage, and teamwork are put to the test. While readiness continues to be the U.S. Army''s top priority, how it goes about its business is changing.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4530,'Sequel to the critically acclaimed, squad-based/real-time tactical combat game, Full Spectrum Warrior: Ten Hammers delivers the most authentic and realistic infantry combat experience ever. As Squad Leader, coordinate the actions of multiple infantry squads, leading them through over 12 levels of intense action. Utilize authentic combat tactics to command your squad as you battle enemies with an explosive arsenal of weapons, high-tech military equipment and new controllable mechanized units. New advanced squad controls give you more in-depth tactical command over your squad as you lead them through a variety of realistic combat missions. With all new multiplayer modes, go online and team up with a friend in two player co-op or go head-to-head with up to eight players through a variety of new adversarial and team-based objective missions.<br><br>					<ul class="bb_ul"><li><strong>Innovative gaming experience </strong>- Combines intense squad based combat and real-time tactical action, delivering the most authentic and realistic infantry combat experience ever.<br>					</li><li><strong>New Squad Controls </strong>- Independently controllable scout &amp; buddy teams, ability to give orders to one team while controlling another, and ability to enter buildings and position sniper teams.<br>					</li><li><strong>Advanced reactive enemy AI</strong> that reacts realistically to combat situations.<br>					</li><li><strong>Expansive, non-linear level design </strong> with multiple pathways to accomplish objectives.<br>					</li><li><strong>New Multiplayer Experience </strong>- Full Spectrum Warrior style gameplay with both Co-op and Adversarial (Coalition vs. Opfor) online multiplayer modes.</li></ul>','Sequel to the critically acclaimed, squad-based/real-time tactical combat game, Full Spectrum Warrior: Ten Hammers delivers the most authentic and realistic infantry combat experience ever. As Squad Leader, coordinate the actions of multiple infantry squads, leading them through over 12 levels of intense action. Utilize authentic combat tactics to command your squad as you battle enemies with an explosive arsenal of weapons, high-tech military equipment and new controllable mechanized units. New advanced squad controls give you more in-depth tactical command over your squad as you lead them through a variety of realistic combat missions. With all new multiplayer modes, go online and team up with a friend in two player co-op or go head-to-head with up to eight players through a variety of new adversarial and team-based objective missions.<br><br>					<ul class="bb_ul"><li><strong>Innovative gaming experience </strong>- Combines intense squad based combat and real-time tactical action, delivering the most authentic and realistic infantry combat experience ever.<br>					</li><li><strong>New Squad Controls </strong>- Independently controllable scout &amp; buddy teams, ability to give orders to one team while controlling another, and ability to enter buildings and position sniper teams.<br>					</li><li><strong>Advanced reactive enemy AI</strong> that reacts realistically to combat situations.<br>					</li><li><strong>Expansive, non-linear level design </strong> with multiple pathways to accomplish objectives.<br>					</li><li><strong>New Multiplayer Experience </strong>- Full Spectrum Warrior style gameplay with both Co-op and Adversarial (Coalition vs. Opfor) online multiplayer modes.</li></ul>','Sequel to the critically acclaimed, squad-based/real-time tactical combat game, Full Spectrum Warrior: Ten Hammers delivers the most authentic and realistic infantry combat experience ever. As Squad Leader, coordinate the actions of multiple infantry squads, leading them through over 12 levels of intense action.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4560,'<h2 class="bb_tag">DISCLAIMER</h2><i>This legacy version of COH1 will also give you access to <a href="http://store.steampowered.com/app/228200/Company_of_Heroes" target="_blank" rel="noreferrer"  ><u>the latest updated version of COH1</u></a> - simply called &quot;Company of Heroes&quot; in your Steam library. <strong>PLEASE USE THE LATTER TO PLAY ONLINE</strong>, and visit the associated pages to join the COH1 Steam Community &amp; Modding scene:<br><strong><ul class="bb_ul"><li><a href="http://steamcommunity.com/app/228200" target="_blank" rel="noreferrer"  ><u>COH1 Community Hub</u></a><br></li><li><a href="http://steamcommunity.com/app/228200/workshop/" target="_blank" rel="noreferrer"  ><u>COH1 Steam Workshop</u></a></li></ul></strong></i><h2 class="bb_tag">DESCRIPTION</h2>Delivering a visceral WWII gaming experience, Company of Heroes redefines real time strategy gaming by bringing the sacrifice of heroic soldiers, war-ravaged environments, and dynamic battlefields to life. Beginning with the D-Day Invasion of Normandy, players lead squads of Allied soldiers into battle against the German war machine through some of the most pivotal battles of WWII. Through a rich single player campaign, players experience the cinematic intensity and bravery of ordinary soldiers thrust into extraordinary events.<br><br>					<ul class="bb_ul"><li><strong>A Cinematic Single Player Experience</strong> that captures the turmoil of WWII as never before.<br>					</li><li><strong>Advanced squad AI</strong> brings your soldiers to life as they interact with the changing environment, take cover, and execute advanced squad tactics to eliminate all enemy opposition. <br>					</li><li><strong>Stunning Visuals </strong> - Relic''s next generation cutting-edge engine provides graphic quality and a physics driven world that is unprecedented in an RTS.<br>					</li><li><strong>Environmental Strategy</strong> - Real-time physics and a completely destructible environment guarantee no two battles ever play out in the same way. Destroy anything and re-shape the battlefield! Use buildings and terrain to your advantage, or deny them to the enemy.<br>					</li><li><strong>2-8 Player Multiplayer Competition via LAN or Internet</strong> - Go online with friends and join the ultimate battle of Axis versus Allies.</li></ul>','<h2 class="bb_tag">DISCLAIMER</h2><i>This legacy version of COH1 will also give you access to <a href="http://store.steampowered.com/app/228200/Company_of_Heroes" target="_blank" rel="noreferrer"  ><u>the latest updated version of COH1</u></a> - simply called &quot;Company of Heroes&quot; in your Steam library. <strong>PLEASE USE THE LATTER TO PLAY ONLINE</strong>, and visit the associated pages to join the COH1 Steam Community &amp; Modding scene:<br><strong><ul class="bb_ul"><li><a href="http://steamcommunity.com/app/228200" target="_blank" rel="noreferrer"  ><u>COH1 Community Hub</u></a><br></li><li><a href="http://steamcommunity.com/app/228200/workshop/" target="_blank" rel="noreferrer"  ><u>COH1 Steam Workshop</u></a></li></ul></strong></i><h2 class="bb_tag">DESCRIPTION</h2>Delivering a visceral WWII gaming experience, Company of Heroes redefines real time strategy gaming by bringing the sacrifice of heroic soldiers, war-ravaged environments, and dynamic battlefields to life. Beginning with the D-Day Invasion of Normandy, players lead squads of Allied soldiers into battle against the German war machine through some of the most pivotal battles of WWII. Through a rich single player campaign, players experience the cinematic intensity and bravery of ordinary soldiers thrust into extraordinary events.<br><br>					<ul class="bb_ul"><li><strong>A Cinematic Single Player Experience</strong> that captures the turmoil of WWII as never before.<br>					</li><li><strong>Advanced squad AI</strong> brings your soldiers to life as they interact with the changing environment, take cover, and execute advanced squad tactics to eliminate all enemy opposition. <br>					</li><li><strong>Stunning Visuals </strong> - Relic''s next generation cutting-edge engine provides graphic quality and a physics driven world that is unprecedented in an RTS.<br>					</li><li><strong>Environmental Strategy</strong> - Real-time physics and a completely destructible environment guarantee no two battles ever play out in the same way. Destroy anything and re-shape the battlefield! Use buildings and terrain to your advantage, or deny them to the enemy.<br>					</li><li><strong>2-8 Player Multiplayer Competition via LAN or Internet</strong> - Go online with friends and join the ultimate battle of Axis versus Allies.</li></ul>','Delivering a visceral WWII gaming experience, Company of Heroes redefines RTS by bringing the sacrifice of heroic soldiers, war-ravaged environments, and dynamic battlefields to life. This legacy version also grants access to the latest version of COH, just called &quot;Company of Heroes&quot;.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4570,'<h1>Reviews</h1><p><a href="http://store.steampowered.com/sub/30560/" target="_blank" rel="noreferrer"  ><img src="https://steamcdn-a.akamaihd.net/steam/apps/4570/extras/DOW_STEAM_BANNER_616x616.jpg?t=1528131594" ></a></p><br><h1>About the Game</h1>Prepare yourself for the grim, dark future of the 41st millennium, where alien races battle mankind for galactic domination in a universe of unending war.<br>Personalize your armies with a revolutionary unit customization tool that gives you the ability to choose your armies insignias, banners, squad colors and names.<br><br><br><ul class="bb_ul"><li><strong>Engaging story driven single player campaign.</strong><br>Command the elite chapter of the Blood Ravens in an original epic tale of treason and conspiracy as you serve the Emperor and protect humanity from the scourges of Warhammer 40,000 universe.<br></li><li><strong>Master four unique races.</strong><br>Command your Space Marines, Orks, Chaos and Eldar in epic battles and master their distinct abilities, weapons, and tech trees to eradicate the enemy and rule the known universe.<br></li><li><strong>Unprecedented realism.</strong><br>Appropriately scaled terrain, vehicle physics and dynamic lightning contribute to a level of realism never before displayed in a real-time strategy game.<br></li><li><strong>Visceral cinematic melee and ranged combat.</strong><br>Realistic unit animations immerse you in intense brutal combat .<br></li><li><strong>Pioneering tactical gameplay.</strong><br>Innovations such as cover, squad-based combat, and morale add new strategic depth to real-time warfare.<br></li><li><strong>Dynamic multiplayer.</strong><br>Test your true combat abilities in two-to-eight player battles providing endless re-playability</li></ul>','Prepare yourself for the grim, dark future of the 41st millennium, where alien races battle mankind for galactic domination in a universe of unending war.<br>Personalize your armies with a revolutionary unit customization tool that gives you the ability to choose your armies insignias, banners, squad colors and names.<br><br><br><ul class="bb_ul"><li><strong>Engaging story driven single player campaign.</strong><br>Command the elite chapter of the Blood Ravens in an original epic tale of treason and conspiracy as you serve the Emperor and protect humanity from the scourges of Warhammer 40,000 universe.<br></li><li><strong>Master four unique races.</strong><br>Command your Space Marines, Orks, Chaos and Eldar in epic battles and master their distinct abilities, weapons, and tech trees to eradicate the enemy and rule the known universe.<br></li><li><strong>Unprecedented realism.</strong><br>Appropriately scaled terrain, vehicle physics and dynamic lightning contribute to a level of realism never before displayed in a real-time strategy game.<br></li><li><strong>Visceral cinematic melee and ranged combat.</strong><br>Realistic unit animations immerse you in intense brutal combat .<br></li><li><strong>Pioneering tactical gameplay.</strong><br>Innovations such as cover, squad-based combat, and morale add new strategic depth to real-time warfare.<br></li><li><strong>Dynamic multiplayer.</strong><br>Test your true combat abilities in two-to-eight player battles providing endless re-playability</li></ul>','Prepare yourself for the grim, dark future of the 41st millennium, where alien races battle mankind for galactic domination in a universe of unending war. Personalize your armies with a revolutionary unit customization tool that gives you the ability to choose your armies insignias, banners, squad colors and names.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4580,'Deep under the central desert of Kronus, a vast honeycomb of skull-lined tunnels and funeral chambers house the awakening Necron menace. Eons ago, these were the boulevards and squares of a great necropolis built to house the bones of the races who had fallen to the Necrons, and ultimately were where the Necrons themselves retire to spend eternity. Over millions of years, sand and rock had covered it all until ill-fated excavations awoke the deathless. <br>Play any of seven races, striving for control over Kronus. Take other races'' strongholds by winning challenging battles on various maps individually associated with the respective strongholds. <br><br><ul class="bb_ul"><li><strong>New Races</strong><br>Take command of two new playable races: Tau and Necron to unleash massive carnage across the frontlines of battle.<br><br></li><li><strong>Expanded multiplayer</strong><br>Dominate opponents online across 12 new multiplayer maps - with up to 8 players battling it out for supremacy.<br><br></li><li><strong>Deep single player campaign</strong><br>Conquer the planet of Kronus any way you choose - leading any one of seven races on an epic crusade through an all-new, non-linear single player campaign where you can experience unique storylines from each race''s perspective.<br><br></li><li><strong>Customization</strong><br>Customize your hero''s weapons, items and abilities as he grows in power and influence. Personalize your army with a variety of insignias, squad colors, banners and names.</li></ul>','Deep under the central desert of Kronus, a vast honeycomb of skull-lined tunnels and funeral chambers house the awakening Necron menace. Eons ago, these were the boulevards and squares of a great necropolis built to house the bones of the races who had fallen to the Necrons, and ultimately were where the Necrons themselves retire to spend eternity. Over millions of years, sand and rock had covered it all until ill-fated excavations awoke the deathless. <br>Play any of seven races, striving for control over Kronus. Take other races'' strongholds by winning challenging battles on various maps individually associated with the respective strongholds. <br><br><ul class="bb_ul"><li><strong>New Races</strong><br>Take command of two new playable races: Tau and Necron to unleash massive carnage across the frontlines of battle.<br><br></li><li><strong>Expanded multiplayer</strong><br>Dominate opponents online across 12 new multiplayer maps - with up to 8 players battling it out for supremacy.<br><br></li><li><strong>Deep single player campaign</strong><br>Conquer the planet of Kronus any way you choose - leading any one of seven races on an epic crusade through an all-new, non-linear single player campaign where you can experience unique storylines from each race''s perspective.<br><br></li><li><strong>Customization</strong><br>Customize your hero''s weapons, items and abilities as he grows in power and influence. Personalize your army with a variety of insignias, squad colors, banners and names.</li></ul>','Deep under the central desert of Kronus, a vast honeycomb of skull-lined tunnels and funeral chambers house the awakening Necron menace. Eons ago, these were the boulevards and squares of a great necropolis built to house the bones of the races who had fallen to the Necrons, and ultimately were where the Necrons themselves retire to...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4700,'<img src="https://steamcdn-a.akamaihd.net/steam/apps/4700/extras/MED2_FIRST.gif?t=1548693689" ><br><br>Complete your Total War collection with this Definitive Edition of Total War: MEDIEVAL II, which includes all DLC and feature updates since the game’s release: <br><br>Kingdoms is the most content-rich expansion ever produced for a Total War game, with four new entire campaigns centred on expanded maps of the British Isles, Teutonic Northern Europe, the Middle East, and the Americas.<br><br>Total War: MEDIEVAL II Definitive Edition offers hundreds and hundreds of hours of absorbing gameplay and every bit of content made for the game. See below for full details. <br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4700/extras/MED2_SECOND.GIF?t=1548693689" ><br><br><strong>About Total War: MEDIEVAL II</strong><br><br>Take command of your army and expand your reign in Total War: MEDIEVAL II - the fourth instalment of the award-winning Total War series of strategy games. Direct massive battles featuring up to 10,000 bloodthirsty troops on epic 3D battlefields, while presiding over some of the greatest Medieval nations of the Western and Middle Eastern world. <br><br>Spanning the most turbulent era in Western history, your quest for territory and power takes you through Europe, Africa, and the Middle East, and even onto the shores of the New World.<br><br>You''ll manage your empire with an iron fist, handling everything from building and improving cities to recruiting and training armies. Wield diplomacy to manipulate allies and enemies, outsmart the dreaded Inquisition, and influence the Pope. Lead the fight in the Crusades and bring victory to Islam or Christianity in the Holy War. <br>Rewrite history and conquer the world. This is Total War!<br><br>•	Bigger and better real-time battles. Improved combat choreography, larger armies, quicker pace, and spectacular finishing moves make this the most visceral and exciting Total War ever.<br>•	New epic campaign. The ambitious single player campaign will span three continents and let players sail across to the Americas to confront the Aztecs on their home soil.<br>•	Greater accessibility. An enhanced user interface and optional shorter campaigns make the Total War experience faster and easier to enjoy than ever before.<br>•	Over 40 new features. An advanced terrain system, enhanced weather effects, and more will help you divide and conquer.<br>•	Intense Multiplayer Battles. Wage war against other players in 8-way multiplayer games.<br><br><br><strong>About Kingdoms</strong><br><br>Kingdoms presents players with all-new territories to explore, troops to command, and enemies to conquer.<br><br>Kingdoms is the most content-rich expansion ever produced for a Total War game, with four new entire campaigns centred on expanded maps of the British Isles, Teutonic Northern Europe, the Middle East, and the Americas. In Total War: MEDIEVAL II, you were only given a tantalizing glimpse of South America, but in Kingdoms, vast tracts of land in both North and South America have been opened up for you to conquer. All-new factions from the New World are also now fully playable, including the Aztecs, Apaches, and Mayans.<br><br>Along with the new maps in the Britannia, Teutonic, Crusades, and New World Campaigns, there are 13 new factions to play, over 110 units to control, and 50 building types, adding up to 80 hours of new gameplay. Kingdoms also offers new multiplayer maps and hotseat multiplayer, a first for the Total War series, allowing you to play one-versus-one campaign games on the same computer.<br><br>•	Four new campaigns - Britannia, Teutonic, Crusades, and New World<br>•	10 new units<br>•	13 new factions<br>•	9 new agents<br>•	50 new buildings<br>•	60+ new territories across four new maps<br>•	15 new multiplayer maps and scenarios<br>•	All-new 1v1 hotseat multiplayer campaign mode','<img src="https://steamcdn-a.akamaihd.net/steam/apps/4700/extras/MED2_FIRST.gif?t=1548693689" ><br><br>Complete your Total War collection with this Definitive Edition of Total War: MEDIEVAL II, which includes all DLC and feature updates since the game’s release: <br><br>Kingdoms is the most content-rich expansion ever produced for a Total War game, with four new entire campaigns centred on expanded maps of the British Isles, Teutonic Northern Europe, the Middle East, and the Americas.<br><br>Total War: MEDIEVAL II Definitive Edition offers hundreds and hundreds of hours of absorbing gameplay and every bit of content made for the game. See below for full details. <br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4700/extras/MED2_SECOND.GIF?t=1548693689" ><br><br><strong>About Total War: MEDIEVAL II</strong><br><br>Take command of your army and expand your reign in Total War: MEDIEVAL II - the fourth instalment of the award-winning Total War series of strategy games. Direct massive battles featuring up to 10,000 bloodthirsty troops on epic 3D battlefields, while presiding over some of the greatest Medieval nations of the Western and Middle Eastern world. <br><br>Spanning the most turbulent era in Western history, your quest for territory and power takes you through Europe, Africa, and the Middle East, and even onto the shores of the New World.<br><br>You''ll manage your empire with an iron fist, handling everything from building and improving cities to recruiting and training armies. Wield diplomacy to manipulate allies and enemies, outsmart the dreaded Inquisition, and influence the Pope. Lead the fight in the Crusades and bring victory to Islam or Christianity in the Holy War. <br>Rewrite history and conquer the world. This is Total War!<br><br>•	Bigger and better real-time battles. Improved combat choreography, larger armies, quicker pace, and spectacular finishing moves make this the most visceral and exciting Total War ever.<br>•	New epic campaign. The ambitious single player campaign will span three continents and let players sail across to the Americas to confront the Aztecs on their home soil.<br>•	Greater accessibility. An enhanced user interface and optional shorter campaigns make the Total War experience faster and easier to enjoy than ever before.<br>•	Over 40 new features. An advanced terrain system, enhanced weather effects, and more will help you divide and conquer.<br>•	Intense Multiplayer Battles. Wage war against other players in 8-way multiplayer games.<br><br><br><strong>About Kingdoms</strong><br><br>Kingdoms presents players with all-new territories to explore, troops to command, and enemies to conquer.<br><br>Kingdoms is the most content-rich expansion ever produced for a Total War game, with four new entire campaigns centred on expanded maps of the British Isles, Teutonic Northern Europe, the Middle East, and the Americas. In Total War: MEDIEVAL II, you were only given a tantalizing glimpse of South America, but in Kingdoms, vast tracts of land in both North and South America have been opened up for you to conquer. All-new factions from the New World are also now fully playable, including the Aztecs, Apaches, and Mayans.<br><br>Along with the new maps in the Britannia, Teutonic, Crusades, and New World Campaigns, there are 13 new factions to play, over 110 units to control, and 50 building types, adding up to 80 hours of new gameplay. Kingdoms also offers new multiplayer maps and hotseat multiplayer, a first for the Total War series, allowing you to play one-versus-one campaign games on the same computer.<br><br>•	Four new campaigns - Britannia, Teutonic, Crusades, and New World<br>•	10 new units<br>•	13 new factions<br>•	9 new agents<br>•	50 new buildings<br>•	60+ new territories across four new maps<br>•	15 new multiplayer maps and scenarios<br>•	All-new 1v1 hotseat multiplayer campaign mode','Spanning the most turbulent era in Western history, your quest for territory and power takes you through Europe, Africa, the Middle East, and even onto the shores of the New World.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4720,'What twists the mind of an ordinary human into a serial killer?<br />
<br />
Assigned to the Serial Crimes Unit, Agent Ethan Thomas must answer this question, and bring the worst of society to justice. His solve rate is the best in the bureau....perhaps too good.<br />
<br />
While investigating the growing list of serial killers, Agent Thomas concludes that something is twisting the bodies and souls of those that society has left behind. The homeless, addicted and deranged are rising from the city’s underbelly and committing mindless acts of violence. Could there be an unseen connection between the increasing brutality of the latest serial killings and the increasing crime rate? This question is pushed to the forefront after Agent Thomas is framed for the murder of two police officers. Now he must solve the murders to stop the killings, and exonerate himself from the crimes of which he is accused.<br />
<br />
As FBI agent Ethan Thomas, you rely on sharp instincts and sophisticated forensic tools to investigate crime scenes, collect evidence, and find clues that will lead you to the killers. With danger lurking in every shadow, you need whatever weapons you can find to stay alive. If you run out of bullets, you’ll have to fight with a fire axe, shovel, pipe, two-by-four, or whatever you can pry from the environment around you. You’ll need to make sure nothing stops you as you try to uncover exactly who...or what is behind the grisly killings plaguing the city.','What twists the mind of an ordinary human into a serial killer?<br />
<br />
Assigned to the Serial Crimes Unit, Agent Ethan Thomas must answer this question, and bring the worst of society to justice. His solve rate is the best in the bureau....perhaps too good.<br />
<br />
While investigating the growing list of serial killers, Agent Thomas concludes that something is twisting the bodies and souls of those that society has left behind. The homeless, addicted and deranged are rising from the city’s underbelly and committing mindless acts of violence. Could there be an unseen connection between the increasing brutality of the latest serial killings and the increasing crime rate? This question is pushed to the forefront after Agent Thomas is framed for the murder of two police officers. Now he must solve the murders to stop the killings, and exonerate himself from the crimes of which he is accused.<br />
<br />
As FBI agent Ethan Thomas, you rely on sharp instincts and sophisticated forensic tools to investigate crime scenes, collect evidence, and find clues that will lead you to the killers. With danger lurking in every shadow, you need whatever weapons you can find to stay alive. If you run out of bullets, you’ll have to fight with a fire axe, shovel, pipe, two-by-four, or whatever you can pry from the environment around you. You’ll need to make sure nothing stops you as you try to uncover exactly who...or what is behind the grisly killings plaguing the city.','What twists the mind of an ordinary human into a serial killer? Assigned to the Serial Crimes Unit, Agent Ethan Thomas must answer this question, and bring the worst of society to justice. His solve rate is the best in the bureau....perhaps too good.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4760,'Once the Roman Empire is under your command, don''t lay down your sword just yet - the Barbarians are coming. With two award-winning titles from the esteemed Total War series, you''ll have twice as many obstacles and opportunities to control and conquer the greatest empire ever known to man.<br>					The Collection Edition includes:<br>					<strong>Rome: Total War</strong> Guide one of three noble Roman families on a century spanning quest to seize control of the Roman Empire.<br>					<strong>Rome: Total War - Barbarian Invasion</strong><br>					 (official expansion pack to Rome: Total War) Witness the decline of Rome as Barbarian hordes attack, forcing a bitter internal struggle between rival factions.<br>					<ul class="bb_ul"><li>Voted 2004 Best Strategy game by IGN, GameSpy and GameSpot.<br>					</li><li>Fight alongside or against history''s greatest leaders such as Julius Caesar, Spartacus, and Hannibal to expand or destroy the Roman Empire.<br>					</li><li>Lay siege against the Romans as Attila the Hun, fearful Saxons, or other savage factions using signature weapons and abilities.<br>					</li><li>Command warrior-tested legions in cinematic epic battles with thousands of soldiers on-screen at once.<br>					</li><li>A century-spanning campaign charges players with strategically managing the economic, civil, religious and military arms of their empire.</li></ul>','Once the Roman Empire is under your command, don''t lay down your sword just yet - the Barbarians are coming. With two award-winning titles from the esteemed Total War series, you''ll have twice as many obstacles and opportunities to control and conquer the greatest empire ever known to man.<br>					The Collection Edition includes:<br>					<strong>Rome: Total War</strong> Guide one of three noble Roman families on a century spanning quest to seize control of the Roman Empire.<br>					<strong>Rome: Total War - Barbarian Invasion</strong><br>					 (official expansion pack to Rome: Total War) Witness the decline of Rome as Barbarian hordes attack, forcing a bitter internal struggle between rival factions.<br>					<ul class="bb_ul"><li>Voted 2004 Best Strategy game by IGN, GameSpy and GameSpot.<br>					</li><li>Fight alongside or against history''s greatest leaders such as Julius Caesar, Spartacus, and Hannibal to expand or destroy the Roman Empire.<br>					</li><li>Lay siege against the Romans as Attila the Hun, fearful Saxons, or other savage factions using signature weapons and abilities.<br>					</li><li>Command warrior-tested legions in cinematic epic battles with thousands of soldiers on-screen at once.<br>					</li><li>A century-spanning campaign charges players with strategically managing the economic, civil, religious and military arms of their empire.</li></ul>','Control and conquer the greatest empire ever known to man.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4770,'Rome: Total War - Alexander is the second official expansion pack to Rome: Total War.<br>					<ul class="bb_ul"><li>An entirely new campaign map that stretches from Macedonia to Greece and into the heart of the ancient Persian Empire<br>					</li><li>New campaign game that tasks players with matching the exploits of Alexander the Great as he swept across Central Asia and dominated the Persian Empire <br>					</li><li>Four new factions including the Macedonians, Persians and Indians<br>					</li><li>Over 25 new units, including Alexander''s own renowned historical troops <br>					</li><li>Historical Alexander the Great campaign with six new historical battles that unlock sequentially, telling the story of Alexander and providing a historical backdrop to each of the battles<br>					</li><li>All-new movies to support the Alexander campaign, with professional voiceovers by actor Brian Blessed (Alexander, Star Wars Episode I: The Phantom Menace)</li></ul>','Rome: Total War - Alexander is the second official expansion pack to Rome: Total War.<br>					<ul class="bb_ul"><li>An entirely new campaign map that stretches from Macedonia to Greece and into the heart of the ancient Persian Empire<br>					</li><li>New campaign game that tasks players with matching the exploits of Alexander the Great as he swept across Central Asia and dominated the Persian Empire <br>					</li><li>Four new factions including the Macedonians, Persians and Indians<br>					</li><li>Over 25 new units, including Alexander''s own renowned historical troops <br>					</li><li>Historical Alexander the Great campaign with six new historical battles that unlock sequentially, telling the story of Alexander and providing a historical backdrop to each of the battles<br>					</li><li>All-new movies to support the Alexander campaign, with professional voiceovers by actor Brian Blessed (Alexander, Star Wars Episode I: The Phantom Menace)</li></ul>','Rome: Total War - Alexander is the second official expansion pack to Rome: Total War. An entirely new campaign map that stretches from Macedonia to Greece and into the heart of the ancient Persian Empire New campaign game that tasks players with matching the exploits of Alexander the Great as he swept across Central Asia and dominated...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4780,'Medieval II: Total War Kingdoms is the official expansion to last year''s award-winning Medieval II: Total War, presenting players with all-new territories to explore, troops to command, and enemies to conquer.<br>					Kingdoms is the most content-rich expansion ever produced for a Total War game, with four new entire campaigns centered on expanded maps of the British Isles, Teutonic Northern Europe, the Middle East, and the Americas. In Medieval II, you were only given a tantalizing glimpse of South America, but in Kingdoms, vast tracts of land in both North and South America have been opened up for you to conquer. All-new factions from the New World are also now fully playable, including the Aztecs, Apaches, and Mayans.<br>					Along with the new maps in the Britannia, Teutonic, Crusades, and New World Campaigns, there are 13 new factions to play, over 110 units to control, and 50 building types, adding up to 80 hours of new gameplay. Kingdoms also offers new multiplayer maps and hotseat multiplayer, a first for the Total War series, allowing you to play one-versus-one campaign games on the same computer.<br>					<ul class="bb_ul"><li>Four new campaigns - Britannia, Teutonic, Crusades, and New World<br>					</li><li>10 new units<br>					</li><li>13 new factions<br>					</li><li>9 new agents<br>					</li><li>50 new buildings<br>					</li><li>60+ new territories across four new maps<br>					</li><li>15 new multiplayer maps and scenarios<br>					</li><li>All-new 1v1 hotseat multiplayer campaign mode</li></ul>','Medieval II: Total War Kingdoms is the official expansion to last year''s award-winning Medieval II: Total War, presenting players with all-new territories to explore, troops to command, and enemies to conquer.<br>					Kingdoms is the most content-rich expansion ever produced for a Total War game, with four new entire campaigns centered on expanded maps of the British Isles, Teutonic Northern Europe, the Middle East, and the Americas. In Medieval II, you were only given a tantalizing glimpse of South America, but in Kingdoms, vast tracts of land in both North and South America have been opened up for you to conquer. All-new factions from the New World are also now fully playable, including the Aztecs, Apaches, and Mayans.<br>					Along with the new maps in the Britannia, Teutonic, Crusades, and New World Campaigns, there are 13 new factions to play, over 110 units to control, and 50 building types, adding up to 80 hours of new gameplay. Kingdoms also offers new multiplayer maps and hotseat multiplayer, a first for the Total War series, allowing you to play one-versus-one campaign games on the same computer.<br>					<ul class="bb_ul"><li>Four new campaigns - Britannia, Teutonic, Crusades, and New World<br>					</li><li>10 new units<br>					</li><li>13 new factions<br>					</li><li>9 new agents<br>					</li><li>50 new buildings<br>					</li><li>60+ new territories across four new maps<br>					</li><li>15 new multiplayer maps and scenarios<br>					</li><li>All-new 1v1 hotseat multiplayer campaign mode</li></ul>','Medieval II: Total War Kingdoms is the official expansion to last year''s award-winning Medieval II: Total War, presenting players with all-new territories to explore, troops to command, and enemies to conquer.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4800,'Heroes of Annihilated Empires - is a fantasy-based game from GSC Game World in the genre of RTS vs RPG for PC. <br><br>A new proprietary 3D-engine is used to power the game. Episode one is set on Atlans island, the historical homeland of elves. The world of the game is living and huge, full of magic, mythical creatures, heroes and powerful forces involved in a large-scale conflict dating back to the past. The gameplay enables the player, controlling one of the heroes, as to lead thousands-strong armies into battle, so as combat with the hero alone, making use of the entire arsenal of possibilities and powerful magical spells. The possibility to upgrade your hero, improve his abilities, find artifacts and get random quests serves to hugely diversify the gameplay.<br><br><ul class="bb_ul"><li>Innovative opposing of two genres in one game - RTS vs RPG<br></li><li>New 3D engine<br></li><li>Detailed game world, including support of 5 novels from Europe-renowned writer Ilya Novak<br></li><li>Mass-scale battles of thousands-strong armies<br></li><li>Four unique races, individual skills, spells and artifacts<br></li><li>12 heroes, 12 neutral races, 100 units and 150 various buildings<br></li><li>Excellently developed character types and impressive unit animation<br></li><li>Over 150 magic items and over 100 spells<br></li><li>Original and involving story of the campaign<br></li><li>Classic multiplayer over LAN or the Internet, up to 7 players in a game. Mix of two genres in the game: RTS vs RPG with a possibility to blend or choose in between during the play.<br></li><li>Original card system of magic spells, equally interesting to both hardcore gamers and newbies. Over 50 spell cards<br></li><li>Involving process of character level-ups throughout the entire game<br></li><li>Stunning intros and cut-scenes. Comics in-between missions to give a deeper story insight</li></ul>','Heroes of Annihilated Empires - is a fantasy-based game from GSC Game World in the genre of RTS vs RPG for PC. <br><br>A new proprietary 3D-engine is used to power the game. Episode one is set on Atlans island, the historical homeland of elves. The world of the game is living and huge, full of magic, mythical creatures, heroes and powerful forces involved in a large-scale conflict dating back to the past. The gameplay enables the player, controlling one of the heroes, as to lead thousands-strong armies into battle, so as combat with the hero alone, making use of the entire arsenal of possibilities and powerful magical spells. The possibility to upgrade your hero, improve his abilities, find artifacts and get random quests serves to hugely diversify the gameplay.<br><br><ul class="bb_ul"><li>Innovative opposing of two genres in one game - RTS vs RPG<br></li><li>New 3D engine<br></li><li>Detailed game world, including support of 5 novels from Europe-renowned writer Ilya Novak<br></li><li>Mass-scale battles of thousands-strong armies<br></li><li>Four unique races, individual skills, spells and artifacts<br></li><li>12 heroes, 12 neutral races, 100 units and 150 various buildings<br></li><li>Excellently developed character types and impressive unit animation<br></li><li>Over 150 magic items and over 100 spells<br></li><li>Original and involving story of the campaign<br></li><li>Classic multiplayer over LAN or the Internet, up to 7 players in a game. Mix of two genres in the game: RTS vs RPG with a possibility to blend or choose in between during the play.<br></li><li>Original card system of magic spells, equally interesting to both hardcore gamers and newbies. Over 50 spell cards<br></li><li>Involving process of character level-ups throughout the entire game<br></li><li>Stunning intros and cut-scenes. Comics in-between missions to give a deeper story insight</li></ul>','Heroes of Annihilated Empires - is a fantasy-based game from GSC Game World in the genre of RTS vs RPG for PC. 4 unique races awaits for the heroes, who want to fight in an Epic scale battles!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4850,'To stand alone in war is extremely unpleasant. Extremely pleasant, on the other hand, is the stand-alone version Cossacks: Back to War. Containing all of the gameplay features of Cossacks: European Wars and Cossacks: The Art of War, this is a complete care package for all current and future Cossacks fans. This add-on contains 100 captivating missions taking place between the 16th and 18th centuries. In addition, two new nations, Switzerland and Hungary, are included. These countries waged war in the late Middle Ages and essentially influenced the development of European military strategies. This addition causes the second add-on of Cossacks to pass the threshold of allowed gaming fun.<h2 class="bb_tag">Features:</h2><ul class="bb_ul"><li>Thrilling real-time strategy game with historical background.<br>					</li><li>Fascinating 3D landscapes.<br>					</li><li>Play takes place in Europe between the 16th and 18th centuries.<br>					</li><li>Stand-alone game, other Cossacks games not required to play.<br>					</li><li>A total of 20 different European nations to command.<br>					</li><li>100 new single missions.<br>					</li><li>2 new nations: Switzerland and Hungary with a total of 8 new units.<br>					</li><li>Spectacular real-time battles with up to 8,000 units.<br>					</li><li>4 different difficulty levels.<br>					</li><li>1 new camel riding unit for Algeria and Turkey: Bedouin.<br>					</li><li>This version with low system requirements is adapted for comfortable play on any hardware from low-end computers, laptops and netbooks, to high-end PCs (with Windows Vista/7).<br>					</li><li>Ad-Hoc multiplayer play (offline mode).<br>					</li><li>Infinite AI skirmishes on randomly generated maps.<br>					</li></ul>','To stand alone in war is extremely unpleasant. Extremely pleasant, on the other hand, is the stand-alone version Cossacks: Back to War. Containing all of the gameplay features of Cossacks: European Wars and Cossacks: The Art of War, this is a complete care package for all current and future Cossacks fans. This add-on contains 100 captivating missions taking place between the 16th and 18th centuries. In addition, two new nations, Switzerland and Hungary, are included. These countries waged war in the late Middle Ages and essentially influenced the development of European military strategies. This addition causes the second add-on of Cossacks to pass the threshold of allowed gaming fun.<h2 class="bb_tag">Features:</h2><ul class="bb_ul"><li>Thrilling real-time strategy game with historical background.<br>					</li><li>Fascinating 3D landscapes.<br>					</li><li>Play takes place in Europe between the 16th and 18th centuries.<br>					</li><li>Stand-alone game, other Cossacks games not required to play.<br>					</li><li>A total of 20 different European nations to command.<br>					</li><li>100 new single missions.<br>					</li><li>2 new nations: Switzerland and Hungary with a total of 8 new units.<br>					</li><li>Spectacular real-time battles with up to 8,000 units.<br>					</li><li>4 different difficulty levels.<br>					</li><li>1 new camel riding unit for Algeria and Turkey: Bedouin.<br>					</li><li>This version with low system requirements is adapted for comfortable play on any hardware from low-end computers, laptops and netbooks, to high-end PCs (with Windows Vista/7).<br>					</li><li>Ad-Hoc multiplayer play (offline mode).<br>					</li><li>Infinite AI skirmishes on randomly generated maps.<br>					</li></ul>','Cossacks: Back to War contains all of the gameplay features of Cossacks: European Wars and Cossacks: The Art of War, this is a complete care package for all current and future Cossacks fans. This add-on contains two new nations: Switzerland and Hungary.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4870,'<strong>Cossacks: The Art of War</strong> – continues the history of the great battles of XVII–XVIII centuries, and introduces five new campaigns, two nations, some new units and much more.','<strong>Cossacks: The Art of War</strong> – continues the history of the great battles of XVII–XVIII centuries, and introduces five new campaigns, two nations, some new units and much more.','Cossacks: The Art of War continues the history of the great battles of XVII–XVIII centuries');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4880,'Cossacks: European Wars is a historical real-time strategy based on events of the 16th through the 18th centuries in Europe, when nations and states were created and demolished, and wars shed seas of blood. There are 16 nations or regions in Cossacks: Algeria, Austria, England, France, the Netherlands, Piemonte, Poland, Portugal, Prussia, Russia, Saxony, Spain, Sweden, Turkey, Ukraine, and Venice. Each has its own original graphics, economic and technical development peculiarities, military advantages and drawbacks, and unique units and technologies, providing vast choices of tactics and strategy in war against any enemy. Thus, England is the mightiest sea power, Austria has powerful light and heavy cavalry, and Cossacks are the pride of the Ukrainian army.<br />
						<br />
<br />
						Battles of up to 8,000 units may be conducted on single or network game maps. One can carry out lingering city sieges, wage guerilla wars, capture commanding heights and arrange ambushes, deploy landing forces on enemy shores, and conduct sea battles. The game system is arranged to reduce per-unit control and resource micromanagement, and to turn to global goals of powerful economy formation, science development, the capturing of new lands, and defending borders.','Cossacks: European Wars is a historical real-time strategy based on events of the 16th through the 18th centuries in Europe, when nations and states were created and demolished, and wars shed seas of blood. There are 16 nations or regions in Cossacks: Algeria, Austria, England, France, the Netherlands, Piemonte, Poland, Portugal, Prussia, Russia, Saxony, Spain, Sweden, Turkey, Ukraine, and Venice. Each has its own original graphics, economic and technical development peculiarities, military advantages and drawbacks, and unique units and technologies, providing vast choices of tactics and strategy in war against any enemy. Thus, England is the mightiest sea power, Austria has powerful light and heavy cavalry, and Cossacks are the pride of the Ukrainian army.<br />
						<br />
<br />
						Battles of up to 8,000 units may be conducted on single or network game maps. One can carry out lingering city sieges, wage guerilla wars, capture commanding heights and arrange ambushes, deploy landing forces on enemy shores, and conduct sea battles. The game system is arranged to reduce per-unit control and resource micromanagement, and to turn to global goals of powerful economy formation, science development, the capturing of new lands, and defending borders.','This game is devoted to the key events of the XVII–XVIII centuries.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4890,'Let the battle begin! The Cossacks II: Battle for Europe add-on continues the renowned Cossacks II:Napoleonic Wars game. It depicts the rather short historic period of the Napoleonic wars. The Napoleon wars changed Europe forever, leading to the formation of empires and putting an end to almost one thousand years of constant strife between small states. The game provides mass-scale battles between thousands-strong armies of the nations involved in conflicts during this period. The theatres of operation introduce France, Britain, Austria, Russia, Prussia, Egypt, and three nations not represented in the original game – Spain, the Grand Duchy of Warsaw (Poland), and the Confederation of the Rhine.<br>						The Cossacks II: Battle for Europe reconstructs in detail the soldiers'' uniforms weapons and architecture of each nation. Each nation''s army has its unique units and possibilities. The game includes over 180 units 190 buildings and 1200 flora and fauna elements. When developing the combat system the peculiarities of early 19th century warring were taken into account as was the value of formations provisions and troop morale. Tactical tricks utilized by military commanders of the time are fully reflected in the game. An &quot;honest&quot; system of bullet and cannonball ballistics based on physics is an innovative addition to the Cossacks engine. Other engine features include 3-dimensional landscaping which creates realistic-looking scenery and towns and impacts combat tactics. For example the firing range of a subdivision of soldiers or a cannon positioned at the top of a hill is greater than the firing range of a unitstationed on flat terrain. <br>						<h2 class="bb_tag">Key features:</h2>						<ul class="bb_ul"><li>Control the French, Russians, Austrians, Britons, Prussians, or Egyptians -- master new weapons and tactics during a time that redefined the meaning of modern warfare.<br>						</li><li>Fight through historically inspired battles of the 19th century, with massive armies colliding in different types of terrain and weather.<br>						</li><li>Battles on real historical scale with tens of thausands of units on one map.<br>						</li><li>Realistic Troop Morale System - Well-fed troops live longer and grow in experience to become valuable battlefield assets, while fierce and overwhelming opponents, or marching long distances will cause morale to drop<br>						</li><li>Enhanced diplomacy tools help you create treaties that give you the advantages<br>						</li></ul>','Let the battle begin! The Cossacks II: Battle for Europe add-on continues the renowned Cossacks II:Napoleonic Wars game. It depicts the rather short historic period of the Napoleonic wars. The Napoleon wars changed Europe forever, leading to the formation of empires and putting an end to almost one thousand years of constant strife between small states. The game provides mass-scale battles between thousands-strong armies of the nations involved in conflicts during this period. The theatres of operation introduce France, Britain, Austria, Russia, Prussia, Egypt, and three nations not represented in the original game – Spain, the Grand Duchy of Warsaw (Poland), and the Confederation of the Rhine.<br>						The Cossacks II: Battle for Europe reconstructs in detail the soldiers'' uniforms weapons and architecture of each nation. Each nation''s army has its unique units and possibilities. The game includes over 180 units 190 buildings and 1200 flora and fauna elements. When developing the combat system the peculiarities of early 19th century warring were taken into account as was the value of formations provisions and troop morale. Tactical tricks utilized by military commanders of the time are fully reflected in the game. An &quot;honest&quot; system of bullet and cannonball ballistics based on physics is an innovative addition to the Cossacks engine. Other engine features include 3-dimensional landscaping which creates realistic-looking scenery and towns and impacts combat tactics. For example the firing range of a subdivision of soldiers or a cannon positioned at the top of a hill is greater than the firing range of a unitstationed on flat terrain. <br>						<h2 class="bb_tag">Key features:</h2>						<ul class="bb_ul"><li>Control the French, Russians, Austrians, Britons, Prussians, or Egyptians -- master new weapons and tactics during a time that redefined the meaning of modern warfare.<br>						</li><li>Fight through historically inspired battles of the 19th century, with massive armies colliding in different types of terrain and weather.<br>						</li><li>Battles on real historical scale with tens of thausands of units on one map.<br>						</li><li>Realistic Troop Morale System - Well-fed troops live longer and grow in experience to become valuable battlefield assets, while fierce and overwhelming opponents, or marching long distances will cause morale to drop<br>						</li><li>Enhanced diplomacy tools help you create treaties that give you the advantages<br>						</li></ul>','Cossacks II: Battle for Europe is a standalone add-on for &quot;Cossacks II: Napoleonic Wars&quot; presenting new nations with the possibility to wage multiplayer battles.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4900,'From the creators of <a href="http://store.steampowered.com/app/90002/" target="_blank" rel="noreferrer"  >Natural Selection</a> comes Zen of Sudoku, a relaxing, easy to play version of Sudoku for your PC.<br><ul class="bb_ul"><li>Relax with hand-painted Japanese-styled backgrounds, no timer and lush natural soundscapes.<br></li><li>Stimulates your brain to keep it healthy and alert.<br></li><li>Teaches you the basics of Sudoku through advanced strategies like &quot;naked pairs&quot;, &quot;x-wing&quot; and &quot;locked candidates&quot;.<br></li><li>Play unlimited puzzles, print them to finish offline and enter custom puzzles from other sources.<br></li><li>Unlock trophies, backgrounds and more.</li></ul>This product includes portions of the <a href="https://steamcommunity.com/linkfilter/?url=http://developer.popcap.com/" target="_blank" rel="noopener"  >PopCap Games Framework</a>.','From the creators of <a href="http://store.steampowered.com/app/90002/" target="_blank" rel="noreferrer"  >Natural Selection</a> comes Zen of Sudoku, a relaxing, easy to play version of Sudoku for your PC.<br><ul class="bb_ul"><li>Relax with hand-painted Japanese-styled backgrounds, no timer and lush natural soundscapes.<br></li><li>Stimulates your brain to keep it healthy and alert.<br></li><li>Teaches you the basics of Sudoku through advanced strategies like &quot;naked pairs&quot;, &quot;x-wing&quot; and &quot;locked candidates&quot;.<br></li><li>Play unlimited puzzles, print them to finish offline and enter custom puzzles from other sources.<br></li><li>Unlock trophies, backgrounds and more.</li></ul>This product includes portions of the <a href="https://steamcommunity.com/linkfilter/?url=http://developer.popcap.com/" target="_blank" rel="noopener"  >PopCap Games Framework</a>.','From the creators of Natural Selection comes Zen of Sudoku, a relaxing, easy to play version of Sudoku for your PC.Relax with hand-painted Japanese-styled backgrounds, no timer and lush natural soundscapes.Stimulates your brain to keep it healthy and alert.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (4920,'<img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline4_OnosMarine.jpg?t=1556039235" ><br><br>Natural Selection 2 pits alien against human in an action-packed struggle for survival. Wield devastating weaponry as a Frontiersman marine, or become the xenomorph as a deadly Kharaa lifeform. <br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline2_FadeMarine.jpg?t=1556039235" ><h2 class="bb_tag">Strategy Meets Shooter</h2><br>Natural Selection 2 is a First Person Shooter and Real Time Stategy game rolled into one! Each team, alien and human, has a Commander. The Commander looks down on the battlefield and issues orders, places structures, collects resources, researches technology, and deploys abilities. <br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline10_StrategyShooter.jpg?t=1556039235" ><br><br>Here are some gameplay examples: A human Commander could drop health packs and ammunition to a trapped marine squad, and deploy sentry guns to help them defend their position. Or an alien Commander could grow a new Hive to spread infestation throughout newly captured territory, allowing more alien eggs to spawn...<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline11_BattleRoyale.jpg?t=1556039235" ><h2 class="bb_tag">Two Unique Sides</h2><br>Aliens players choose to evolve into one of five lifeforms: The fast, fearsome Skulk can run on walls and deliver massive damage with its jaws. Lerks fly and deploy gasses to support their teammates in battle. Gorges heal other lifeforms and build tunnels, hydra turrets, walls, and other tactical structures. Fades blink in and out of battle, picking off marines with giant scythes. Finally, the giant Onos is so massive and so tough, that even entire marine squads can''t take it down.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline11_Giblets.jpg?t=1556039235" ><br><br>Marines wield rifles, shotguns, grenade launchers, pistols, and other weapons. Cluster grenades can clear ventilation shafts of sneaky Skulks, flamethrowers make short work of alien structures and infestation, and boosts dropped by the Commander increase combat effectiveness. <br><br>When attacking on foot doesn''t cut it, marines can construct hulking Exosuits wielding miniguns and railguns, and equip jetpacks for high speed assaults on alien Hives.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline5_ExoFiring.jpg?t=1556039235" ><h2 class="bb_tag">Long Term Development</h2><br>Natural Selection 2 receives constant updates. This year, 2016, Unknown Worlds continues to develop new features, content, and improvements.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline12_Workshop.jpg?t=1556039235" ><h2 class="bb_tag">Mod Tools Come Standard</h2><br>Natural Selection 2 comes with all the tools we used to make the game. All game code is open source. That means you can create, and play, an endless variety of mods. Publish, share, and download mods from the Steam Workshop, and automatically download mods when you join modded games.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/SpecialArmor_Small.jpg?t=1556039235" ><h2 class="bb_tag">Digital Deluxe Edition</h2><br>Digital Deluxe Edition includes:<br><br><ul class="bb_ul"><li><strong>Official Soundtrack</strong> - 1 hour of tribal, industrial music composed by David John and Simon Chylinski <br></li><li><strong>Digital Art Book</strong> - 40+ pages of art by Cory Strader, including environments, creatures, weapons and more<br></li><li><strong>Exclusive in-game marine model</strong> - Exclusive in-game marine model - A new marine model with custom visor and armor plating<br></li><li><strong>Exclusive Wallpapers and Avatars</strong> - Unique views of the NS2 universe by Amanda Diaz</li></ul>','<img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline4_OnosMarine.jpg?t=1556039235" ><br><br>Natural Selection 2 pits alien against human in an action-packed struggle for survival. Wield devastating weaponry as a Frontiersman marine, or become the xenomorph as a deadly Kharaa lifeform. <br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline2_FadeMarine.jpg?t=1556039235" ><h2 class="bb_tag">Strategy Meets Shooter</h2><br>Natural Selection 2 is a First Person Shooter and Real Time Stategy game rolled into one! Each team, alien and human, has a Commander. The Commander looks down on the battlefield and issues orders, places structures, collects resources, researches technology, and deploys abilities. <br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline10_StrategyShooter.jpg?t=1556039235" ><br><br>Here are some gameplay examples: A human Commander could drop health packs and ammunition to a trapped marine squad, and deploy sentry guns to help them defend their position. Or an alien Commander could grow a new Hive to spread infestation throughout newly captured territory, allowing more alien eggs to spawn...<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline11_BattleRoyale.jpg?t=1556039235" ><h2 class="bb_tag">Two Unique Sides</h2><br>Aliens players choose to evolve into one of five lifeforms: The fast, fearsome Skulk can run on walls and deliver massive damage with its jaws. Lerks fly and deploy gasses to support their teammates in battle. Gorges heal other lifeforms and build tunnels, hydra turrets, walls, and other tactical structures. Fades blink in and out of battle, picking off marines with giant scythes. Finally, the giant Onos is so massive and so tough, that even entire marine squads can''t take it down.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline11_Giblets.jpg?t=1556039235" ><br><br>Marines wield rifles, shotguns, grenade launchers, pistols, and other weapons. Cluster grenades can clear ventilation shafts of sneaky Skulks, flamethrowers make short work of alien structures and infestation, and boosts dropped by the Commander increase combat effectiveness. <br><br>When attacking on foot doesn''t cut it, marines can construct hulking Exosuits wielding miniguns and railguns, and equip jetpacks for high speed assaults on alien Hives.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline5_ExoFiring.jpg?t=1556039235" ><h2 class="bb_tag">Long Term Development</h2><br>Natural Selection 2 receives constant updates. This year, 2016, Unknown Worlds continues to develop new features, content, and improvements.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/Inline12_Workshop.jpg?t=1556039235" ><h2 class="bb_tag">Mod Tools Come Standard</h2><br>Natural Selection 2 comes with all the tools we used to make the game. All game code is open source. That means you can create, and play, an endless variety of mods. Publish, share, and download mods from the Steam Workshop, and automatically download mods when you join modded games.<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/4920/extras/SpecialArmor_Small.jpg?t=1556039235" ><h2 class="bb_tag">Digital Deluxe Edition</h2><br>Digital Deluxe Edition includes:<br><br><ul class="bb_ul"><li><strong>Official Soundtrack</strong> - 1 hour of tribal, industrial music composed by David John and Simon Chylinski <br></li><li><strong>Digital Art Book</strong> - 40+ pages of art by Cory Strader, including environments, creatures, weapons and more<br></li><li><strong>Exclusive in-game marine model</strong> - Exclusive in-game marine model - A new marine model with custom visor and armor plating<br></li><li><strong>Exclusive Wallpapers and Avatars</strong> - Unique views of the NS2 universe by Amanda Diaz</li></ul>','A fast paced multiplayer shooter that pits aliens against humans in a strategic and action-packed struggle for survival!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6000,'Chaos has erupted throughout the galaxy. As leader of an elite squad of Republic Commandos, your mission is to infiltrate, dominate, and ultimately, annihilate the enemy. Your squad will follow your orders and your lead, working together as a team - instinctively, intelligently, instantly. You are their leader. They are your weapon.<br>			<ul class="bb_ul"><li><strong>Innovative Squad Control System</strong> - With intuitive and smart squad commands, the simple touch of one button easily controls your squad to perform complex commands and strategic maneuvers.<br>			</li><li><strong>Multiple Gaming Mode</strong>  - Choose the single-player option and command a squad of four that you can dispatch at will. Or, choose the multiplayer option and play with up to sixteen players online in different multi-player modes.<br>			</li><li><strong>Prelude to Episode III</strong> - Encounter new vehicles, locations and enemies from the upcoming film.<br>			</li></ul>','Chaos has erupted throughout the galaxy. As leader of an elite squad of Republic Commandos, your mission is to infiltrate, dominate, and ultimately, annihilate the enemy. Your squad will follow your orders and your lead, working together as a team - instinctively, intelligently, instantly. You are their leader. They are your weapon.<br>			<ul class="bb_ul"><li><strong>Innovative Squad Control System</strong> - With intuitive and smart squad commands, the simple touch of one button easily controls your squad to perform complex commands and strategic maneuvers.<br>			</li><li><strong>Multiple Gaming Mode</strong>  - Choose the single-player option and command a squad of four that you can dispatch at will. Or, choose the multiplayer option and play with up to sixteen players online in different multi-player modes.<br>			</li><li><strong>Prelude to Episode III</strong> - Encounter new vehicles, locations and enemies from the upcoming film.<br>			</li></ul>','You are the leader of an elite squad of Republic Commandos, your mission is to infiltrate, dominate, and ultimately, annihilate the enemy. Your squad will follow your orders and your lead, working together as a team - instinctively, intelligently, instantly. You are their leader. They are your weapon.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6010,'The Man With The Hat Is Back In His Greatest Adventure Yet!<br>			1939 - The eve of World War II. Nazi agents are about to get their hands on a weapon more dangerous than the atom bomb. Only Indy can stop them before they unleash the deadly secret that sank Atlantis.<br>			<ul class="bb_ul"><li>Point ''n’ click your way through fistfights, puzzles, balloon rides, car chases and Indy one-liners.<br>			</li><li>Explore over 200 spectacular locations.<br>			</li><li>Hear LucasArts'' exclusive iMUSE create a musical score that follows your every move.<br>			</li><li>Play and replay - three unique challenging paths to vanquish the Reich.<br>			</li></ul>','The Man With The Hat Is Back In His Greatest Adventure Yet!<br>			1939 - The eve of World War II. Nazi agents are about to get their hands on a weapon more dangerous than the atom bomb. Only Indy can stop them before they unleash the deadly secret that sank Atlantis.<br>			<ul class="bb_ul"><li>Point ''n’ click your way through fistfights, puzzles, balloon rides, car chases and Indy one-liners.<br>			</li><li>Explore over 200 spectacular locations.<br>			</li><li>Hear LucasArts'' exclusive iMUSE create a musical score that follows your every move.<br>			</li><li>Play and replay - three unique challenging paths to vanquish the Reich.<br>			</li></ul>','The Man With The Hat Is Back In His Greatest Adventure Yet! 1939 - The eve of World War II. Nazi agents are about to get their hands on a weapon more dangerous than the atom bomb. Only Indy can stop them before they unleash the deadly secret that sank Atlantis.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6020,'Forge your weapon and follow the path of the Jedi<br>Jedi Knight: Jedi Academy is the latest installment of the highly acclaimed Jedi Knight series. Take on the role of a new student eager to learn the ways of the Force from Jedi Master Luke Skywalker. Interact with famous Star Wars characters in many classic Star Wars locations as you face the ultimate choice: fight for good and freedom on the light side or follow the path of power and evil to the dark side.<br>			<ul class="bb_ul"><li>Customize your character by defining both look and gender before entering the Academy to learn the power-and dangers- of the Force.<br>			</li><li>Construct your own Lightsaber from handle to blade. As you progress, discover the power of wiedling two Lightsabers or the ultimate double-bladed Lightsaber made famous by Darth Maul.<br>			</li><li>New vehicles, weapons, force powers and Star Wars locations.<br>			</li><li>Unique level selection system allows you to choose your own missions and adventures.<br>			</li><li>Six multiplayer modes including team based siege mode and two-on-one power duel. Fight in 23 multiplayer arenas!<br>			</li></ul>','Forge your weapon and follow the path of the Jedi<br>Jedi Knight: Jedi Academy is the latest installment of the highly acclaimed Jedi Knight series. Take on the role of a new student eager to learn the ways of the Force from Jedi Master Luke Skywalker. Interact with famous Star Wars characters in many classic Star Wars locations as you face the ultimate choice: fight for good and freedom on the light side or follow the path of power and evil to the dark side.<br>			<ul class="bb_ul"><li>Customize your character by defining both look and gender before entering the Academy to learn the power-and dangers- of the Force.<br>			</li><li>Construct your own Lightsaber from handle to blade. As you progress, discover the power of wiedling two Lightsabers or the ultimate double-bladed Lightsaber made famous by Darth Maul.<br>			</li><li>New vehicles, weapons, force powers and Star Wars locations.<br>			</li><li>Unique level selection system allows you to choose your own missions and adventures.<br>			</li><li>Six multiplayer modes including team based siege mode and two-on-one power duel. Fight in 23 multiplayer arenas!<br>			</li></ul>','Forge your weapon and follow the path of the Jedi Jedi Knight: Jedi Academy is the latest installment of the highly acclaimed Jedi Knight series. Take on the role of a new student eager to learn the ways of the Force from Jedi Master Luke Skywalker.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6030,'The Legacy of Star Wars Dark Forces™ and Star Wars® Jedi Knight lives on in the intense first-person action of Jedi Outcast.<br>			<ul class="bb_ul"><li>As Kyle Katarn, agent of the New Republic, use your Lightsaber and the full power of the Force to combat a new evil plaguing the galaxy.<br>			</li><li>Wield over 8 Force abilities including the Jedi Mind Trick, Force Lightning and Force Grip.<br>			</li><li>Choose wisely from an arsenal of 13 weapons including disruptor rifle, thermal detonators, trip mines and Wookiee bowcaster.<br>			</li><li>Play on-line with 2-32 players or against a variety of AI Bots - and gain an additional 7 Force powers.<br>			</li><li>Test your skills in 24 single-player missions and in 6 different types of multiplayer games including Jedi Master, Holocron, Capture the Ysalamiri, Duel, Deathmatch and Capture the Flag.<br>			</li><li>Interact with legendary Star Wars characters such as Luke Skywalker and Lando Calrissian (featuring the voice of Billy Dee Williams as Lando.)<br>			</li><li>Developed by critically acclaimed Raven Studios and powered by the Quake III Arena engine.<br>			</li></ul>','The Legacy of Star Wars Dark Forces™ and Star Wars® Jedi Knight lives on in the intense first-person action of Jedi Outcast.<br>			<ul class="bb_ul"><li>As Kyle Katarn, agent of the New Republic, use your Lightsaber and the full power of the Force to combat a new evil plaguing the galaxy.<br>			</li><li>Wield over 8 Force abilities including the Jedi Mind Trick, Force Lightning and Force Grip.<br>			</li><li>Choose wisely from an arsenal of 13 weapons including disruptor rifle, thermal detonators, trip mines and Wookiee bowcaster.<br>			</li><li>Play on-line with 2-32 players or against a variety of AI Bots - and gain an additional 7 Force powers.<br>			</li><li>Test your skills in 24 single-player missions and in 6 different types of multiplayer games including Jedi Master, Holocron, Capture the Ysalamiri, Duel, Deathmatch and Capture the Flag.<br>			</li><li>Interact with legendary Star Wars characters such as Luke Skywalker and Lando Calrissian (featuring the voice of Billy Dee Williams as Lando.)<br>			</li><li>Developed by critically acclaimed Raven Studios and powered by the Quake III Arena engine.<br>			</li></ul>','The Legacy of Star Wars Dark Forces™ and Star Wars® Jedi Knight lives on in the intense first-person action of Jedi Outcast.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6040,'A DEEP SPACE ADVENTURE BY SEAN CLARK IN COLLABORATION WITH FILMMAKER STEVEN SPIELBERG  <br>				An asteroid the size of a small moon is on a crash course toward Earth, and only NASA veteran Boston Low has the expertise to stop it. Along for the ride are award-winning journalist Maggie Robbins and internationally renowned geologist Ludger Brink.<br>				Once the wayward asteroid is nuked into a safe orbit, the trio conducts a routine examination of the rocky surface.<br>				What they uncover is anything but routine.<br>				Low, Brink and Robbins unwittingly trigger a mechanism that transforms the asteroid into a crystal-like spacecraft. The team is hurtled across the galaxy to a planet so desolate, Brink is moved to name it Cocytus, after the 9th circle of Hell in Dante’s inferno. The bleak landscape was obviously once home to a highly evolved civilization, with remnants of sophisticated architecture, advanced technology and an intricate network of underground tunnels.<br>				But no Cocytans.<br>				Who were the original inhabitants of this once rich empire-turned-wasteland? What are those apparitions that mysteriously appear from time to time? Why have Low, Robbins, and Brink been brought to this place? And how can Low keep his team from unraveling in the face of such uncertainty?  To return to Earth, they must dig for answers, both on the planet’s surface and deep within themselves.<br>				From the combined talents of LucasArts and legendary Steven Spielberg comes an epic adventure that plunges headlong into the very core of the unknown. And takes you with it.<br>				<ul class="bb_ul"><li>Nearly 200 locations and hundreds of puzzles<br>				</li><li>Robert Patrick of T2 as the voice of Boston Low<br>				</li><li>Special effects contributed by Industrial Light &amp; Magic<br>				</li><li>Dialogue contributed by award-winning sci-fi writer Orson Scott Card<br>				</li><li>Alluring Wagnerian musical score sets the epic tone<br>				</li></ul>','A DEEP SPACE ADVENTURE BY SEAN CLARK IN COLLABORATION WITH FILMMAKER STEVEN SPIELBERG  <br>				An asteroid the size of a small moon is on a crash course toward Earth, and only NASA veteran Boston Low has the expertise to stop it. Along for the ride are award-winning journalist Maggie Robbins and internationally renowned geologist Ludger Brink.<br>				Once the wayward asteroid is nuked into a safe orbit, the trio conducts a routine examination of the rocky surface.<br>				What they uncover is anything but routine.<br>				Low, Brink and Robbins unwittingly trigger a mechanism that transforms the asteroid into a crystal-like spacecraft. The team is hurtled across the galaxy to a planet so desolate, Brink is moved to name it Cocytus, after the 9th circle of Hell in Dante’s inferno. The bleak landscape was obviously once home to a highly evolved civilization, with remnants of sophisticated architecture, advanced technology and an intricate network of underground tunnels.<br>				But no Cocytans.<br>				Who were the original inhabitants of this once rich empire-turned-wasteland? What are those apparitions that mysteriously appear from time to time? Why have Low, Robbins, and Brink been brought to this place? And how can Low keep his team from unraveling in the face of such uncertainty?  To return to Earth, they must dig for answers, both on the planet’s surface and deep within themselves.<br>				From the combined talents of LucasArts and legendary Steven Spielberg comes an epic adventure that plunges headlong into the very core of the unknown. And takes you with it.<br>				<ul class="bb_ul"><li>Nearly 200 locations and hundreds of puzzles<br>				</li><li>Robert Patrick of T2 as the voice of Boston Low<br>				</li><li>Special effects contributed by Industrial Light &amp; Magic<br>				</li><li>Dialogue contributed by award-winning sci-fi writer Orson Scott Card<br>				</li><li>Alluring Wagnerian musical score sets the epic tone<br>				</li></ul>','An asteroid the size of a small moon is on a crash course toward Earth. Once the wayward asteroid is nuked into a safe orbit, a trio conducts a routine examination of the rocky surface. What they uncover is anything but routine.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6060,'With brand new space combat, playable Jedi characters, and over 16 all new battlefronts, Star Wars Battlefront II gives you more ways than ever before to play the classic Star Wars battles any way you want. <br>				<ul class="bb_ul"><li><strong>Enhanced Single-Player Experience</strong> - Join the rise of Darth Vader’s elite 501st Legion of Stormtroopers as you fight through an all new story-based saga where every action you take impacts the battlefront and, ultimately, the fate of the Star Wars galaxy.<br>				</li><li><strong>All New Classic Trilogy Locations</strong> - Fight inside the corridors of the second Death Star, in the marshy swamps of Dagobah, and even aboard the Tantive IV, Princess Leia’s Blockade Runner, as seen at the beginning of Star Wars Episode IV: A New Hope.<br>				</li><li><strong>More Classes and Vehicles</strong> - Now choose from six distinct soldier classes, plus bonus hero characters for each of the four factions: Rebels, Imperials, CIS and the Republic. Then jump into more than 30 diverse ground and space vehicles, including the clone BARC speeder, AT-RT and new Jedi Starfighter and ARC 170.<br>				</li><li><strong>PLUS Improved Online Features</strong> - Engage in massive online battles with multiplayer action for up to 64 players. Play five different online game modes including Conquest, Assault, one-and two-flag Capture the Flag, and Hunt.<br>				</li></ul>Now for the first time, Star Wars Battlefront II lets you…<br>				<ul class="bb_ul"><li><strong>Fight as a Jedi</strong> - Earn the ability to wield a lightsaber and use Force powers like Yoda, Darth Vader and many other heroes and villains.<br>				</li><li><strong>Battle in Space</strong> - Dogfight in X-wings, TIE fighters, Jedi starfighters and other classic starcraft, or land your ship on a star destroyer and fight it out on foot aboard enemy ships.<br>				</li><li><strong>Play 16 New Locations</strong> - Battle across Star Wars: Episode III environments such as Utapau, Mustafar and the epic space battle above Coruscant.<br>				</li></ul>','With brand new space combat, playable Jedi characters, and over 16 all new battlefronts, Star Wars Battlefront II gives you more ways than ever before to play the classic Star Wars battles any way you want. <br>				<ul class="bb_ul"><li><strong>Enhanced Single-Player Experience</strong> - Join the rise of Darth Vader’s elite 501st Legion of Stormtroopers as you fight through an all new story-based saga where every action you take impacts the battlefront and, ultimately, the fate of the Star Wars galaxy.<br>				</li><li><strong>All New Classic Trilogy Locations</strong> - Fight inside the corridors of the second Death Star, in the marshy swamps of Dagobah, and even aboard the Tantive IV, Princess Leia’s Blockade Runner, as seen at the beginning of Star Wars Episode IV: A New Hope.<br>				</li><li><strong>More Classes and Vehicles</strong> - Now choose from six distinct soldier classes, plus bonus hero characters for each of the four factions: Rebels, Imperials, CIS and the Republic. Then jump into more than 30 diverse ground and space vehicles, including the clone BARC speeder, AT-RT and new Jedi Starfighter and ARC 170.<br>				</li><li><strong>PLUS Improved Online Features</strong> - Engage in massive online battles with multiplayer action for up to 64 players. Play five different online game modes including Conquest, Assault, one-and two-flag Capture the Flag, and Hunt.<br>				</li></ul>Now for the first time, Star Wars Battlefront II lets you…<br>				<ul class="bb_ul"><li><strong>Fight as a Jedi</strong> - Earn the ability to wield a lightsaber and use Force powers like Yoda, Darth Vader and many other heroes and villains.<br>				</li><li><strong>Battle in Space</strong> - Dogfight in X-wings, TIE fighters, Jedi starfighters and other classic starcraft, or land your ship on a star destroyer and fight it out on foot aboard enemy ships.<br>				</li><li><strong>Play 16 New Locations</strong> - Battle across Star Wars: Episode III environments such as Utapau, Mustafar and the epic space battle above Coruscant.<br>				</li></ul>','Join the rise of Darth Vader’s elite 501st Legion of Stormtroopers as you fight through an all new story-based saga where every action you take impacts the battlefront and, ultimately, the fate of the Star Wars galaxy.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6080,'Thrillville™: Off the Rails lives up to its name with 20 death-defying rides so outrageous, they inspire the same word from every park visitor who sees them:  “WHOA!” Players build these incredible “WHOA Coasters” to leap from one track to another, launch through the air like cannonballs, blast through a burning ring of fire and more.<br>				But the new fun doesn’t stop there. Off the Rails features 34 playable multiplayer minigames, 15 all-new theme areas, over 40 thrill rides, a new story that ties together more than 100 missions, and social interaction with park guests that’s better than ever. The in-depth conversations both advance the plot and suggest better ways to manage the park. But is every guest to be trusted?<br>				<ul class="bb_ul"><li>Experience the visceral fun of interacting with a theme park you create.<br>				</li><li>Build and ride your own creations, talk and joke with all your guests, and play dozens of minigames.<br>				</li><li>Visit 15 themed areas, like Battleville, Winterville, Spaceville and Aeroville, all spread throughout five new parks.<br>				</li><li>Create 20 death-defying WHOA Coasters such as:<br>				<ul class="bb_ul"><li><strong>Hotrod Stunt</strong> - A nitro boost propels a car across a broken track.<br>				</li><li><strong>Pendulizer</strong> - A giant arm grabs the car just before a gap in the track, whips it around in a full circle, then sets it down on the other side.<br>				</li><li><strong>Escape Drop</strong>  - The track holds the car stationary as it lifts itself from level ground to a full 90-degree drop. Then it lets go.<br>				</li></ul>				</li><li>Distinguish your rides even more with enhanced customization options. Attach animatronics, flowers and flaming hoops to all of your coasters and rides.<br>				</li><li>Play 34 minigames – 14 new, 20 returning from the original Thrillville but with new levels.<br>				</li></ul>','Thrillville™: Off the Rails lives up to its name with 20 death-defying rides so outrageous, they inspire the same word from every park visitor who sees them:  “WHOA!” Players build these incredible “WHOA Coasters” to leap from one track to another, launch through the air like cannonballs, blast through a burning ring of fire and more.<br>				But the new fun doesn’t stop there. Off the Rails features 34 playable multiplayer minigames, 15 all-new theme areas, over 40 thrill rides, a new story that ties together more than 100 missions, and social interaction with park guests that’s better than ever. The in-depth conversations both advance the plot and suggest better ways to manage the park. But is every guest to be trusted?<br>				<ul class="bb_ul"><li>Experience the visceral fun of interacting with a theme park you create.<br>				</li><li>Build and ride your own creations, talk and joke with all your guests, and play dozens of minigames.<br>				</li><li>Visit 15 themed areas, like Battleville, Winterville, Spaceville and Aeroville, all spread throughout five new parks.<br>				</li><li>Create 20 death-defying WHOA Coasters such as:<br>				<ul class="bb_ul"><li><strong>Hotrod Stunt</strong> - A nitro boost propels a car across a broken track.<br>				</li><li><strong>Pendulizer</strong> - A giant arm grabs the car just before a gap in the track, whips it around in a full circle, then sets it down on the other side.<br>				</li><li><strong>Escape Drop</strong>  - The track holds the car stationary as it lifts itself from level ground to a full 90-degree drop. Then it lets go.<br>				</li></ul>				</li><li>Distinguish your rides even more with enhanced customization options. Attach animatronics, flowers and flaming hoops to all of your coasters and rides.<br>				</li><li>Play 34 minigames – 14 new, 20 returning from the original Thrillville but with new levels.<br>				</li></ul>','Thrillville™: Off the Rails lives up to its name with 20 death-defying rides! Players can build incredible coasters to leap from one track to another, launch through the air like cannonballs, blast through a burning rings of fire and more!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6090,'Meet the Lionhearts.<br>				A smack-talking rag-tag band of rebels bound on an impossible quest. With an arsenal of outrageous weapons, they''re destined for victory in 12,000 bullets or less. If they can make it through an army of psychotic robots and a wall-smashing Goliaths, they just might save the world... if they don''t burn it down first.<br>				<ul class="bb_ul"><li>Navigate through a richly entertaining story with your smack-talkin'' partners in crime.<br>				</li><li>Take down wicked enemies like half-man, half-animal Grunts, eliminator droids, wall-smashing Goliaths, evil monks and wild twiglets.<br>				</li><li>Brandish over 17 outlandish weapons like the Topsy-Turvy, the Vindaloo Rocket Launcher, or the World''s Smallest Black Hole and the Land Shark Gun.<br>				</li><li>Explore five diverse environments including icy and snowy regions, mountains with breathtaking vistas, deep and foreboding woods, and rain-spattered cliffs.<br>				</li><li>Shoot your way through 21 action-packed missions.<br>				</li></ul>','Meet the Lionhearts.<br>				A smack-talking rag-tag band of rebels bound on an impossible quest. With an arsenal of outrageous weapons, they''re destined for victory in 12,000 bullets or less. If they can make it through an army of psychotic robots and a wall-smashing Goliaths, they just might save the world... if they don''t burn it down first.<br>				<ul class="bb_ul"><li>Navigate through a richly entertaining story with your smack-talkin'' partners in crime.<br>				</li><li>Take down wicked enemies like half-man, half-animal Grunts, eliminator droids, wall-smashing Goliaths, evil monks and wild twiglets.<br>				</li><li>Brandish over 17 outlandish weapons like the Topsy-Turvy, the Vindaloo Rocket Launcher, or the World''s Smallest Black Hole and the Land Shark Gun.<br>				</li><li>Explore five diverse environments including icy and snowy regions, mountains with breathtaking vistas, deep and foreboding woods, and rain-spattered cliffs.<br>				</li><li>Shoot your way through 21 action-packed missions.<br>				</li></ul>','Meet the Lionhearts. A smack-talking rag-tag band of rebels on an impossible quest. If they can make it through an army of psychotic robots and wall-smashing Goliaths, they just might save the world... if they don''t burn it down first.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6120,'Shank is the cult-classic revival of the sidescrolling beat-em-up. Play as Shank in an over-the-top grindhouse game, packed to the rim with enemies, bosses, combos, and more by the award-winning team at Klei Entertainment. The 2D sidescroller beat-em-up is finally on Steamplay, now with improved controls and tuning updates based on popular feedback! Shank will have you shooting and slashing your way through hordes of enemies in a stylized slaughter fest. Embark on a brutal path of blood soaked revenge as Shank battles his way through the criminal underground in his quest for retribution. Boasting fast-paced bloody action, silky smooth controls and a signature pulpy grindhouse art style, Shank is a must-play for action fans.<h2 class="bb_tag">Key Features:</h2><ul class="bb_ul"><li><strong>Violent graphic novel art style:</strong><br><br>Beautiful and fluid graphic novel art and animation styled by veteran director Jeff Agala. <br></li><li><strong>Weapon-based combo system:</strong><br><br>String together endless combos of mayhem and destruction on the fly and pummel your opponents to the ground using an exhaustive arsenal of weapons.<br></li><li><strong>Gorgeous, fully animated story cinematics:</strong><br><br>Watch Shanks brutal story unfold through beautiful fully animated cut scenes.<br></li><li><strong>Brutal Boss Battles:</strong><br><br>Over 8 different massive and unique bloody boss battles.<br></li><li><strong>Two-Player Local Co-Op:</strong><br><br>Murder with a friend. Play in a separate backstory in the two-player co-op mode and face a legion of well-armed enemies in the prequel to the single player experience. </li></ul>','Shank is the cult-classic revival of the sidescrolling beat-em-up. Play as Shank in an over-the-top grindhouse game, packed to the rim with enemies, bosses, combos, and more by the award-winning team at Klei Entertainment. The 2D sidescroller beat-em-up is finally on Steamplay, now with improved controls and tuning updates based on popular feedback! Shank will have you shooting and slashing your way through hordes of enemies in a stylized slaughter fest. Embark on a brutal path of blood soaked revenge as Shank battles his way through the criminal underground in his quest for retribution. Boasting fast-paced bloody action, silky smooth controls and a signature pulpy grindhouse art style, Shank is a must-play for action fans.<h2 class="bb_tag">Key Features:</h2><ul class="bb_ul"><li><strong>Violent graphic novel art style:</strong><br><br>Beautiful and fluid graphic novel art and animation styled by veteran director Jeff Agala. <br></li><li><strong>Weapon-based combo system:</strong><br><br>String together endless combos of mayhem and destruction on the fly and pummel your opponents to the ground using an exhaustive arsenal of weapons.<br></li><li><strong>Gorgeous, fully animated story cinematics:</strong><br><br>Watch Shanks brutal story unfold through beautiful fully animated cut scenes.<br></li><li><strong>Brutal Boss Battles:</strong><br><br>Over 8 different massive and unique bloody boss battles.<br></li><li><strong>Two-Player Local Co-Op:</strong><br><br>Murder with a friend. Play in a separate backstory in the two-player co-op mode and face a legion of well-armed enemies in the prequel to the single player experience. </li></ul>','Shank is the cult-classic revival of the sidescrolling beat-em-up. Play as Shank in an over-the-top grindhouse game, packed to the rim with enemies, bosses, combos, and more by the award-winning team at Klei Entertainment.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6200,'Grim spectres, howling banshees, and sly gremlins are yours to command as you unleash ghastly spirits on the town of Gravenville and scare the wits out of its citizens. In the world of the Ghost Master, spooks do your bidding, as you solve puzzles and unlock mysteries in a challenge that combines the best of strategy, adventure, and resource management games.<br>					<ul class="bb_ul"><li>Up to 15 unique, hair-raising adventures with multi-branching scenarios - all within a coherent plot and complete virtual world.<br>					</li><li>Spook''s-eye view - an innovative 3-D camera lets you view the action from the perspective of humans or ghosts.<br>					</li><li>Revolutionary special effects, incredibly detailed characters, and macabre settings inspired by classic horror films.<br>					</li><li>Groundbreaking artificial intelligence-interact with up to 30 AI-driven characters at every level.<br>					</li><li>Eleven expansive and distinctive locations, including the town''s lunatic asylum, military base, sorority and frat houses, and police station.</li></ul>Ghost Master © 2003 Empire Interactive Europe Ltd. Developed by Sick Puppies, a studio of Empire Interactive. Europe Ltd. Ghost Master, Empire and &quot;E&quot; are trademarks or registered trademarks of Empire Interactive. Europe Ltd. in the UK, Europe and/or other countries. All rights reserved.','Grim spectres, howling banshees, and sly gremlins are yours to command as you unleash ghastly spirits on the town of Gravenville and scare the wits out of its citizens. In the world of the Ghost Master, spooks do your bidding, as you solve puzzles and unlock mysteries in a challenge that combines the best of strategy, adventure, and resource management games.<br>					<ul class="bb_ul"><li>Up to 15 unique, hair-raising adventures with multi-branching scenarios - all within a coherent plot and complete virtual world.<br>					</li><li>Spook''s-eye view - an innovative 3-D camera lets you view the action from the perspective of humans or ghosts.<br>					</li><li>Revolutionary special effects, incredibly detailed characters, and macabre settings inspired by classic horror films.<br>					</li><li>Groundbreaking artificial intelligence-interact with up to 30 AI-driven characters at every level.<br>					</li><li>Eleven expansive and distinctive locations, including the town''s lunatic asylum, military base, sorority and frat houses, and police station.</li></ul>Ghost Master © 2003 Empire Interactive Europe Ltd. Developed by Sick Puppies, a studio of Empire Interactive. Europe Ltd. Ghost Master, Empire and &quot;E&quot; are trademarks or registered trademarks of Empire Interactive. Europe Ltd. in the UK, Europe and/or other countries. All rights reserved.','Grim spectres, howling banshees, and sly gremlins are yours to command as you unleash ghastly spirits on the town of Gravenville and scare the wits out of its citizens. In the world of the Ghost Master, spooks do your bidding, as you solve puzzles and unlock mysteries in a challenge that combines the best of strategy, adventure, and...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (6210,'<p>Develop a state-of-the art Las Vegas resort complex, using all the money and management skill you can. Customers on the living, breathing Las Vegas boulevard are Notoriously hard to satisfy - can you win the hearts and wallets of Vegas?</p>
					<p>Amazing real-time 3D graphics show off your resort to the max. Experience grand panoramic views, or get up close and personal to fine-tune the inside and outside of your perfect Vegas paradise.</p>
					<ul>
					<li>Fulfill the needs of 5000+ individual guests</li>
					<li>500+ vehicles include cars, taxis, limos and helicopters</li>
					<li>10 resort styles, inspired by amazing cultures and themes</li>
					<li>Relaxed attractions provide a welcome break</li>
					<li>Create a wedding chapel on the spur of the moment</li>
					<li>Breathtaking rides and attractions</li>
					<li>User friendly controls make resort construction simple</li>
					<li>Fully customizable - adjust goals, competition and difficulty</li>
					<li>Develop not just the outside of your resort, but the inside too</li>
					<li>Hire and fire staff, based on true-to-life skills and qualities</li>
					<li>Adjust the stakes in your favor and Make It Big!</li></ul>
