INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31870,'From the creators of the #1 selling-PC adventure games comes a new Nancy Drew story-driven casual series that is Fast Fun for Busy Detectives™.  You, as Nancy Drew, are on the set of a controversial remake of the famous 1930''s film Pharaoh!  The studio original movie released with an alternate ending due to the untimely death of Lois Manson, the film''s star, and became a box office smash.  Now, Nancy Drew is undercover on the set to get to the bottom of suspicious press leaks and uncanny accidents that have the production schedule in jeopardy.  Is someone trying to sabotage the movie or is it a curse of the fallen film star?  Seek the source of sabotage on cursed Hollywood set!<br>                    <ul class="bb_ul"><li>Find hidden objects and use clues to crack the case<br>                    </li><li>Make smoothies, pick locks, and decrypt messages<br>                    </li><li>Catch loose reptiles and a cursed black cat<br>                    </li><li>Unlock the alternate ending by earning bonus points<br>                    </li><li>Replay fun mini-games in Arcade Mode<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Dossier Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps_extras/31870/DossierLogo.jpg" ><br>A hidden-object puzzle mystery that’s Fast Fun for Busy Detectives. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','From the creators of the #1 selling-PC adventure games comes a new Nancy Drew story-driven casual series that is Fast Fun for Busy Detectives™.  You, as Nancy Drew, are on the set of a controversial remake of the famous 1930''s film Pharaoh!  The studio original movie released with an alternate ending due to the untimely death of Lois Manson, the film''s star, and became a box office smash.  Now, Nancy Drew is undercover on the set to get to the bottom of suspicious press leaks and uncanny accidents that have the production schedule in jeopardy.  Is someone trying to sabotage the movie or is it a curse of the fallen film star?  Seek the source of sabotage on cursed Hollywood set!<br>                    <ul class="bb_ul"><li>Find hidden objects and use clues to crack the case<br>                    </li><li>Make smoothies, pick locks, and decrypt messages<br>                    </li><li>Catch loose reptiles and a cursed black cat<br>                    </li><li>Unlock the alternate ending by earning bonus points<br>                    </li><li>Replay fun mini-games in Arcade Mode<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Dossier Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps_extras/31870/DossierLogo.jpg" ><br>A hidden-object puzzle mystery that’s Fast Fun for Busy Detectives. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Seek the source of sabotage on a Hollywood set!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31880,'Nancy Drew®: Secret of the Old Clock is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>					The year is 1930.  A fiery explosion at the Lilac Inn leaves its owner, Emily Crandall, teetering on the edge of sanity and propels you, as Nancy Drew, headlong into adventure.  A will left behind by an eccentric millionaire could solve Emily’s problems, and fortunately, you’ve got a car and can drive anywhere you want.  But watch out!  When you’re on the trail of a desperate villain, the road can get very bumpy!  Dare to Play.™<br>					<ul class="bb_ul"><li>Drive Nancy’s blue roadster<br>					</li><li>Go back in time to 1930<br>					</li><li>Play miniature golf<br>					</li><li>Based on the first Nancy Drew book<br>					</li></ul> <br>					<h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>					<img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Nancy Drew®: Secret of the Old Clock is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>					The year is 1930.  A fiery explosion at the Lilac Inn leaves its owner, Emily Crandall, teetering on the edge of sanity and propels you, as Nancy Drew, headlong into adventure.  A will left behind by an eccentric millionaire could solve Emily’s problems, and fortunately, you’ve got a car and can drive anywhere you want.  But watch out!  When you’re on the trail of a desperate villain, the road can get very bumpy!  Dare to Play.™<br>					<ul class="bb_ul"><li>Drive Nancy’s blue roadster<br>					</li><li>Go back in time to 1930<br>					</li><li>Play miniature golf<br>					</li><li>Based on the first Nancy Drew book<br>					</li></ul> <br>					<h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>					<img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Venture into the Past and Outwit a Criminal Before Time Runs Out!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31890,'Nancy Drew®: Secret of Scarlet Hand is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>					Between cases, Nancy Drew has taken an internship as Deputy Curator at the Beech Hill Museum in Washington, D.C. Nancy soon discovers she will be doing more than learning about ancient Maya artifacts–there have been a series of thefts and the only clue left behind in a mysterious scarlet handprint! Will Nancy be able to put the pieces of this ancient puzzle together? Or will the mystery remain entombed forever?  Dare to Play™<br>					<ul class="bb_ul"><li>Learn about the Mayan civilization and its culture<br>					</li><li>Take on the role of a deputy curator for a prestigious museum.<br>					</li><li>Ride the subway and visit sites around Washington D.C.<br>					</li><li>Choose from Junior or Senior Detective difficulty levels.<br>					</li></ul> <br>					<h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>					<img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Nancy Drew®: Secret of Scarlet Hand is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>					Between cases, Nancy Drew has taken an internship as Deputy Curator at the Beech Hill Museum in Washington, D.C. Nancy soon discovers she will be doing more than learning about ancient Maya artifacts–there have been a series of thefts and the only clue left behind in a mysterious scarlet handprint! Will Nancy be able to put the pieces of this ancient puzzle together? Or will the mystery remain entombed forever?  Dare to Play™<br>					<ul class="bb_ul"><li>Learn about the Mayan civilization and its culture<br>					</li><li>Take on the role of a deputy curator for a prestigious museum.<br>					</li><li>Ride the subway and visit sites around Washington D.C.<br>					</li><li>Choose from Junior or Senior Detective difficulty levels.<br>					</li></ul> <br>					<h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>					<img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Expose Buried Secrets and Catch a Thief Red-handed!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31900,'Nancy Drew®: The Creature of Kapu Cave is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    Say Aloha to Trouble in Paradise!  Working as a research assistant in Hawaii sounds like fun in the sun, but ther''s big trouble brewing on the Big Island.  Someone or something destroyed the environmental experiments in the forest around the Hilihili Research compound.  Is it the mythical Kane Okala or unfriendly rivals?  It''s up to you, as Nancy Drew, with the help of the Hardy Boys®, to uncover hidden secrets among the strange whispers that haunt the mountains and forests! Dare to Play!<br>                    <ul class="bb_ul"><li>Play as Nancy Drew or Frank and Joe Hardy<br>                    </li><li>Design shell necklaces to trade for Big Island Bucks<br>                    </li><li>Program your GPS to navigate from beaches and forests to volcanoes<br>                    </li><li>Snorkel for shells and hooked on fishing<br>                    </li><li>Play Junior or Senior detective level<br>                    </li><li>Erase mistakes without starting over<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Nancy Drew®: The Creature of Kapu Cave is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    Say Aloha to Trouble in Paradise!  Working as a research assistant in Hawaii sounds like fun in the sun, but ther''s big trouble brewing on the Big Island.  Someone or something destroyed the environmental experiments in the forest around the Hilihili Research compound.  Is it the mythical Kane Okala or unfriendly rivals?  It''s up to you, as Nancy Drew, with the help of the Hardy Boys®, to uncover hidden secrets among the strange whispers that haunt the mountains and forests! Dare to Play!<br>                    <ul class="bb_ul"><li>Play as Nancy Drew or Frank and Joe Hardy<br>                    </li><li>Design shell necklaces to trade for Big Island Bucks<br>                    </li><li>Program your GPS to navigate from beaches and forests to volcanoes<br>                    </li><li>Snorkel for shells and hooked on fishing<br>                    </li><li>Play Junior or Senior detective level<br>                    </li><li>Erase mistakes without starting over<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Team up with the Hardy Boys® and Track an Ancient Legend Through Hawaii!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31910,'Touted as the most romantic event to grace the ruined halls of Ireland''s Castle Malloy, the Simmons-Mallory wedding was supposed to be a fairytale beginning, but now the groom is missing! Did a banshee crash the wedding or is this a case of cold feet? Can you, as Nancy Drew, unravel the knot of scattered clues and scary superstitions? You''ll to catch more than a bridal bouquet to make this is a happily ever after! Dare to Play<br>                    <ul class="bb_ul"><li>Immerse yourself in Irish culture<br>                    </li><li>Help make bouquets and seating charts for the wedding<br>                    </li><li>Join a band and play the Irish drum<br>                    </li><li>Play arcade games at the Screaming Banshee Inn<br>                    </li><li>Make smoothies for tips<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Touted as the most romantic event to grace the ruined halls of Ireland''s Castle Malloy, the Simmons-Mallory wedding was supposed to be a fairytale beginning, but now the groom is missing! Did a banshee crash the wedding or is this a case of cold feet? Can you, as Nancy Drew, unravel the knot of scattered clues and scary superstitions? You''ll to catch more than a bridal bouquet to make this is a happily ever after! Dare to Play<br>                    <ul class="bb_ul"><li>Immerse yourself in Irish culture<br>                    </li><li>Help make bouquets and seating charts for the wedding<br>                    </li><li>Join a band and play the Irish drum<br>                    </li><li>Play arcade games at the Screaming Banshee Inn<br>                    </li><li>Make smoothies for tips<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Unveil a Ghostly Legend and Find a Vanished Groom!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31920,'Nancy Drew®: The Phantom of Venice is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    The stakes have never been higher as Nancy Drew joins an international undercover investigation to track down a phantom thief in Venice. The police have few leads and you might be the only one who can stop the thefts of historic artifacts. Can you spy on suspects and collect clues before the crime syndicate catches up to you? Dare to Play<br>                    <ul class="bb_ul"><li>Master Italian as you dig for clues<br>                    </li><li>Create a fashion statement or a new disguise<br>                    </li><li>Deal out the fun in the Italian card game Scopa<br>                    </li><li>Cover the costs with creative ways to earn Euros<br>                    </li><li>Travel the canals and listen to singing gondoliers<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Nancy Drew®: The Phantom of Venice is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    The stakes have never been higher as Nancy Drew joins an international undercover investigation to track down a phantom thief in Venice. The police have few leads and you might be the only one who can stop the thefts of historic artifacts. Can you spy on suspects and collect clues before the crime syndicate catches up to you? Dare to Play<br>                    <ul class="bb_ul"><li>Master Italian as you dig for clues<br>                    </li><li>Create a fashion statement or a new disguise<br>                    </li><li>Deal out the fun in the Italian card game Scopa<br>                    </li><li>Cover the costs with creative ways to earn Euros<br>                    </li><li>Travel the canals and listen to singing gondoliers<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Infiltrate a Carnevale of Criminals in Italy!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31930,'Nancy Drew®: The White Wolf of Icicle Creek is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    Mournful howls and thunderous explosions roll across the frozen Canadian mountains surrounding the Icicle Creek Lodge.  Former guests say that the resort is jinxed, but the staff blames a mysterious wolf.  Is the wild animal connected to a lurking saboteur, or is the wolf warning the residents of bigger danger?  It’s up to you, as Nancy Drew, to uncover the secrets before someone leaves you out in the cold!  Follow a trail to hidden secrets and sabotage! Dare to Play!<br>                    <ul class="bb_ul"><li>Play as Nancy Drew and do double duty as a housekeeper and detective<br>                    </li><li>Cook up savory meals<br>                    </li><li>Ride across the snow in a snowmobile<br>                    </li><li>Take aim in snowball fights and explore in snowshoes<br>                    </li><li>Play Junior or Senior detective level and erase mistakes without starting over<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Nancy Drew®: The White Wolf of Icicle Creek is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    Mournful howls and thunderous explosions roll across the frozen Canadian mountains surrounding the Icicle Creek Lodge.  Former guests say that the resort is jinxed, but the staff blames a mysterious wolf.  Is the wild animal connected to a lurking saboteur, or is the wolf warning the residents of bigger danger?  It’s up to you, as Nancy Drew, to uncover the secrets before someone leaves you out in the cold!  Follow a trail to hidden secrets and sabotage! Dare to Play!<br>                    <ul class="bb_ul"><li>Play as Nancy Drew and do double duty as a housekeeper and detective<br>                    </li><li>Cook up savory meals<br>                    </li><li>Ride across the snow in a snowmobile<br>                    </li><li>Take aim in snowball fights and explore in snowshoes<br>                    </li><li>Play Junior or Senior detective level and erase mistakes without starting over<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Follow a Trail to Hidden Secrets and Sabotage!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (31980,'Your friend Bess Marvin is kidnapped and the only chance you have to save her is by solving a 300-year-old Bahamian mystery! Dangerous waters keep treasure hunters from exploring the reefs around Dread Isle, but this remote island might hide the riches of El Toro’s lost fleet! Can you, as Nancy Drew, track down the treasure before time runs out? Dare to Play.<br>                    Nancy Drew®: Ransom of the Seven Ships is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    <ul class="bb_ul"><li>Play as Nancy Drew and George Fayne<br>                    </li><li>See Bess and George for the first time<br>                    </li><li>Dive, sail, and interact with wildlife<br>                    </li><li>Play mini-games with the monkeys<br>                    </li><li>Quest for a lost treasure<br>                    </li><li>Choose from Junior or Senior Detective difficulty levels<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Your friend Bess Marvin is kidnapped and the only chance you have to save her is by solving a 300-year-old Bahamian mystery! Dangerous waters keep treasure hunters from exploring the reefs around Dread Isle, but this remote island might hide the riches of El Toro’s lost fleet! Can you, as Nancy Drew, track down the treasure before time runs out? Dare to Play.<br>                    Nancy Drew®: Ransom of the Seven Ships is a first-person perspective, point-and-click adventure game.  The player is Nancy Drew and has to solve a mystery. Explore rich environments for clues, interrogate suspects, and solve puzzles and mini-games.<br>                    <ul class="bb_ul"><li>Play as Nancy Drew and George Fayne<br>                    </li><li>See Bess and George for the first time<br>                    </li><li>Dive, sail, and interact with wildlife<br>                    </li><li>Play mini-games with the monkeys<br>                    </li><li>Quest for a lost treasure<br>                    </li><li>Choose from Junior or Senior Detective difficulty levels<br>                    </li></ul> <br>                    <h2 class="bb_tag">About The Nancy Drew Adventure Series</h2>                    <img src="https://steamcdn-a.akamaihd.net/steam/apps/31930/extras/ND_logo.jpg" ><br>The original #1 selling PC adventure series. <br>See a <a href="http://storefront.steampowered.com/v/gfx/apps_extras/NancyDrewCompare/english.htm" target="_blank" rel="noreferrer"  >comparison</a> of the Dossier and Adventure Series','Dive into Danger to Rescue Bess from Kidnappers!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32000,'<p>Raycatcher is an innovative new game that syncs gameplay to your favorite mp3s. Load in your entire music library and watch as the game morphs itself to match. The gameplay itself is easy to pick up, yet compelling. Rotate a cluster of colorful shapes to catch matching rays of light cast onto your screen. As you match light to shape, your cluster will expand and evolve.</p>
                    <p>Raycatcher also comes with a selection of great music from the brilliant new artist Noobie Noobinson.</p>
                    <ul>
                    <li><strong>Load in your own music:</strong> Raycatcher will accept .mp3 and .wav formats</li>
                    <li><strong>Beat detection technology:</strong> Changes gameplay to match your music in pleasant and creative ways</li>
                    <li><strong>Make playlists of any length:</strong> Raycatcher is flexible and allows you to play for how ever long you want, and still feel like you''ve made progress</li>
                    <li><strong>Original music by artist Noobie Noobinson:</strong> Music by a new up and coming band, some of which was created specifically for Raycatcher</li>
                    <li><strong>30 evolutionary stages:</strong> Complete with funny and enlightening descriptions. Raycatcher illustrates a cute and informative view of the kosmos</li>
                    <li><strong>Range of difficulty:</strong> Easy to pick up, with 3 difficulty levels that range from easy-yet-challenging to insanely difficult</li>
                    </ul>','<p>Raycatcher is an innovative new game that syncs gameplay to your favorite mp3s. Load in your entire music library and watch as the game morphs itself to match. The gameplay itself is easy to pick up, yet compelling. Rotate a cluster of colorful shapes to catch matching rays of light cast onto your screen. As you match light to shape, your cluster will expand and evolve.</p>
                    <p>Raycatcher also comes with a selection of great music from the brilliant new artist Noobie Noobinson.</p>
                    <ul>
                    <li><strong>Load in your own music:</strong> Raycatcher will accept .mp3 and .wav formats</li>
                    <li><strong>Beat detection technology:</strong> Changes gameplay to match your music in pleasant and creative ways</li>
                    <li><strong>Make playlists of any length:</strong> Raycatcher is flexible and allows you to play for how ever long you want, and still feel like you''ve made progress</li>
                    <li><strong>Original music by artist Noobie Noobinson:</strong> Music by a new up and coming band, some of which was created specifically for Raycatcher</li>
                    <li><strong>30 evolutionary stages:</strong> Complete with funny and enlightening descriptions. Raycatcher illustrates a cute and informative view of the kosmos</li>
                    <li><strong>Range of difficulty:</strong> Easy to pick up, with 3 difficulty levels that range from easy-yet-challenging to insanely difficult</li>
                    </ul>','Raycatcher is an innovative new game that syncs gameplay to your favorite mp3s. Load in your entire music library and watch as the game morphs itself to match. The gameplay itself is easy to pick up, yet compelling. Rotate a cluster of colorful shapes to catch matching rays of light cast onto your screen.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32110,'<p>Embark on an epic quest to recover the stolen treasures of Ancient Egypt in LUXOR: Mah Jong. The fun and challenge is unending with 200 unique layouts available in 3 awesome play modes; Adventure, Single and Traditional. Three difficulty settings ensure that any player will find a challenge, and 3 exotic tile sets make LUXOR: Mah Jong a truly custom experience. Can you work your way up from a lowly farm hand to become the Pharaoh of all Egypt?</p>
							<ul>
							<li>200 Unique Mah Jong Layouts
							<li>3 Exotic Tile Sets
							<li>5 Magical Power-Ups
							<li>3 Difficulty Settings
							<li>3 Modes of Play - Adventure, Single, Traditional
							<li>Unique Player Ranking system
							<li>All New Adventures in the Land of Egypt
							</ul>','<p>Embark on an epic quest to recover the stolen treasures of Ancient Egypt in LUXOR: Mah Jong. The fun and challenge is unending with 200 unique layouts available in 3 awesome play modes; Adventure, Single and Traditional. Three difficulty settings ensure that any player will find a challenge, and 3 exotic tile sets make LUXOR: Mah Jong a truly custom experience. Can you work your way up from a lowly farm hand to become the Pharaoh of all Egypt?</p>
							<ul>
							<li>200 Unique Mah Jong Layouts
							<li>3 Exotic Tile Sets
							<li>5 Magical Power-Ups
							<li>3 Difficulty Settings
							<li>3 Modes of Play - Adventure, Single, Traditional
							<li>Unique Player Ranking system
							<li>All New Adventures in the Land of Egypt
							</ul>','Embark on an epic quest to recover the stolen treasures of Ancient Egypt in LUXOR: Mah Jong. The fun and challenge is unending with 200 unique layouts available in 3 awesome play modes; Adventure, Single and Traditional.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32120,'<p>It’s link-matching madness with Chainz 2: Relinked. Rotate the colored links to make matches of three or more in Classic Mode. Pit your link-matching skills against the clock in Arcade Mode. Ponder every precious move in Strategy Mode. Twist your brain and clear all the links in Puzzle Mode. Add in awesome sound effects, a zippy new music score, and sensationally updated visuals, and Chainz 2: Relinked is sure to keep you chained to your seat!</p>
							<ul>
							<li>4 Awesome Gameplay Modes 
							<li>200 Challenging Levels 
							<li>Exciting New Power-Ups 
							<li>Individualized Personal Profiles
							</ul>','<p>It’s link-matching madness with Chainz 2: Relinked. Rotate the colored links to make matches of three or more in Classic Mode. Pit your link-matching skills against the clock in Arcade Mode. Ponder every precious move in Strategy Mode. Twist your brain and clear all the links in Puzzle Mode. Add in awesome sound effects, a zippy new music score, and sensationally updated visuals, and Chainz 2: Relinked is sure to keep you chained to your seat!</p>
							<ul>
							<li>4 Awesome Gameplay Modes 
							<li>200 Challenging Levels 
							<li>Exciting New Power-Ups 
							<li>Individualized Personal Profiles
							</ul>','It’s link-matching madness with Chainz 2: Relinked. Rotate the colored links to make matches of three or more in Classic Mode. Pit your link-matching skills against the clock in Arcade Mode. Ponder every precious move in Strategy Mode. Twist your brain and clear all the links in Puzzle Mode.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32140,'The master of macabre, Edgar Allan Poe, leads you on a shadowy journey to finally solve the mystery of his death. As a famed mystery writer, you’re looking for your next cold case to crack when an unexpected visitor hands you the perfect case to get your career moving again.  <br><br>When Edgar leads you through some of his most famous works, The Raven, The Gold Bug, The Mystery of Marie Roget and The Purloined Letter, you’ll collect clues, interview witnesses and piece together the conspiracy behind the death of one of America’s greatest writers. <br><br>Who killed Edgar? And, why were such measures taken so that no one would ever know the truth? You have 24 hours and ghosts of the past to guide you through Midnight Mysteries: The Edgar Allan Poe Conspiracy!  <br><br>							<ul class="bb_ul"><li>Celebrate 200 years of Poe in this seek and find murder mystery<br>							</li><li>Hidden object adventure lets you crack a 160-year-old case<br>							</li><li>Guided by Poe himself, you''ll collect items and clues through his most famous works<br>							</li><li>Solve intriguing puzzles to figure out exactly whodunit!<br>							</li></ul>','The master of macabre, Edgar Allan Poe, leads you on a shadowy journey to finally solve the mystery of his death. As a famed mystery writer, you’re looking for your next cold case to crack when an unexpected visitor hands you the perfect case to get your career moving again.  <br><br>When Edgar leads you through some of his most famous works, The Raven, The Gold Bug, The Mystery of Marie Roget and The Purloined Letter, you’ll collect clues, interview witnesses and piece together the conspiracy behind the death of one of America’s greatest writers. <br><br>Who killed Edgar? And, why were such measures taken so that no one would ever know the truth? You have 24 hours and ghosts of the past to guide you through Midnight Mysteries: The Edgar Allan Poe Conspiracy!  <br><br>							<ul class="bb_ul"><li>Celebrate 200 years of Poe in this seek and find murder mystery<br>							</li><li>Hidden object adventure lets you crack a 160-year-old case<br>							</li><li>Guided by Poe himself, you''ll collect items and clues through his most famous works<br>							</li><li>Solve intriguing puzzles to figure out exactly whodunit!<br>							</li></ul>','The master of macabre, Edgar Allan Poe, leads you on a shadowy journey to finally solve the mystery of his death. As a famed mystery writer, you’re looking for your next cold case to crack when an unexpected visitor hands you the perfect case to get your career moving again.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32150,'The next generation of puzzle games is here!  Combining simple arithmetic with colorful cages and logical problem solving, this new puzzle game makes sure you never have to guess—and you don’t have to be a math wiz! <br>						Everyday Genius: SquareLogic can calculate and display possible solutions automatically—allowing you to spend more time playing and less time tediously jotting down possibilities. With puzzles ranging from first-grade easy to astrophysicist hard, you’ll progress along the path to enlightenment as you build your problem-solving brain power with Everyday Genius: SquareLogic.<br>						<ul class="bb_ul"><li>New types of puzzles never before seen in any game!<br>						</li><li>More than 20,000 puzzles, with over 18 different varieties and 6 different sizes<br>						</li><li>Removes the tedium of first-generation puzzle games by automatically handling notation and possibilities for you<br>						</li><li>No need to be a math wiz; solution possibilities are provided, letting you focus on puzzle-solving logic rather than arithmetic<br>						</li><li>Dazzling array of puzzles, with enough variety to tempt even the most sophisticated puzzle palate—hidden cages, double boards, comparisons, sequences, and more<br>						</li><li>Guide teaches you new ways to look at the problem and arrive at the correct solution<br>						</li><li>Thousands of puzzles at each level to challenge players of all ages and abilities<br>						</li><li>Excellent tutorial<br>						</li></ul>','The next generation of puzzle games is here!  Combining simple arithmetic with colorful cages and logical problem solving, this new puzzle game makes sure you never have to guess—and you don’t have to be a math wiz! <br>						Everyday Genius: SquareLogic can calculate and display possible solutions automatically—allowing you to spend more time playing and less time tediously jotting down possibilities. With puzzles ranging from first-grade easy to astrophysicist hard, you’ll progress along the path to enlightenment as you build your problem-solving brain power with Everyday Genius: SquareLogic.<br>						<ul class="bb_ul"><li>New types of puzzles never before seen in any game!<br>						</li><li>More than 20,000 puzzles, with over 18 different varieties and 6 different sizes<br>						</li><li>Removes the tedium of first-generation puzzle games by automatically handling notation and possibilities for you<br>						</li><li>No need to be a math wiz; solution possibilities are provided, letting you focus on puzzle-solving logic rather than arithmetic<br>						</li><li>Dazzling array of puzzles, with enough variety to tempt even the most sophisticated puzzle palate—hidden cages, double boards, comparisons, sequences, and more<br>						</li><li>Guide teaches you new ways to look at the problem and arrive at the correct solution<br>						</li><li>Thousands of puzzles at each level to challenge players of all ages and abilities<br>						</li><li>Excellent tutorial<br>						</li></ul>','The next generation of puzzle games is here! Combining simple arithmetic with colorful cages and logical problem solving, this new puzzle game makes sure you never have to guess—and you don’t have to be a math wiz!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32160,'<p>Bowl or Beware!</p>
						<p>From the depths of the graveyard…a gruesome gang in search of brains!  When Zombies show up at the town’s lanes, it’s up to you to put ‘em back in the ground!</p>
						<p>The Zombies have taken over your favorite lanes, and it’s up to you to send ‘em back to the graveyard where they belong! Select a colorful character to take on the attacking Zombies with your favorite ball and a few tricks and treats. Give a whole new meaning to Zombie strike when you set ‘em up and take ‘em down with cool power ups and tricky obstacles. </p>
						<ul>
						<li>Six screamy lanes to battle your way through to the big Showdown!
						<li>10 terrifying balls and 1 Zombie head to choose from
						<li>Crafty  tricks to throw those Zombies for a loop: Werewolves, MiniCorpses, Buzz Saw and Dance Fever
						<li>Delectable treats to help you knock ‘em dead: ZombieNator, Meatball, ZomBees and Brain Balls
						<li>Zombies advance if you miss them the first time, so get your aim on!
						</ul>','<p>Bowl or Beware!</p>
						<p>From the depths of the graveyard…a gruesome gang in search of brains!  When Zombies show up at the town’s lanes, it’s up to you to put ‘em back in the ground!</p>
						<p>The Zombies have taken over your favorite lanes, and it’s up to you to send ‘em back to the graveyard where they belong! Select a colorful character to take on the attacking Zombies with your favorite ball and a few tricks and treats. Give a whole new meaning to Zombie strike when you set ‘em up and take ‘em down with cool power ups and tricky obstacles. </p>
						<ul>
						<li>Six screamy lanes to battle your way through to the big Showdown!
						<li>10 terrifying balls and 1 Zombie head to choose from
						<li>Crafty  tricks to throw those Zombies for a loop: Werewolves, MiniCorpses, Buzz Saw and Dance Fever
						<li>Delectable treats to help you knock ‘em dead: ZombieNator, Meatball, ZomBees and Brain Balls
						<li>Zombies advance if you miss them the first time, so get your aim on!
						</ul>','Bowl or Beware! From the depths of the graveyard…a gruesome gang in search of brains! When Zombies show up at the town’s lanes, it’s up to you to put ‘em back in the ground! The Zombies have taken over your favorite lanes, and it’s up to you to send ‘em back to the graveyard where they belong!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32200,'<p>Metal Drift is a vehicular sport combat game set in a distant future. As the player, you command an agile, high powered hover tank in a futuristic sports arena. Core game play centers on intense tank-on-tank multiplayer team combat seen through an immersive, first person cockpit.  Layered on this is a goal-oriented game type that allows for high level strategy and team dynamics. Players can level up to unlock new ranks, weapons, and upgrades.</p><br><p>Each weapon and upgrade is specifically designed and balanced to allow different styles of play.  Pair up the Stealth upgrade and the Shock Cannon to uncloak behind an enemy player and unload a devastating blow before disappearing again.  Or choose the Sensor upgrade to see where all the nearby players are, and the Temporal Cannon to shoot them through walls!  There are 56 possible combinations – choose whichever suits your strategy.</p>
					<ul>
					<li>Multiplayer team-based vehicular combat</li>
					<li>5 Different arenas featuring multiple levels and boost tunnels</li>
					<li>Persistent leveling system – level-up to unlock new weapons and upgrades</li>
					<li>Stats and Leaderboards</li>
					<li>56 Different tank configurations</li>
					<li>18 Steam Achievements, with more coming soon!</li>
					<li>Unique energy management system – accumulate energy and then distribute it to weapons or use it to gain a speed boost!</li>
					</ul>','<p>Metal Drift is a vehicular sport combat game set in a distant future. As the player, you command an agile, high powered hover tank in a futuristic sports arena. Core game play centers on intense tank-on-tank multiplayer team combat seen through an immersive, first person cockpit.  Layered on this is a goal-oriented game type that allows for high level strategy and team dynamics. Players can level up to unlock new ranks, weapons, and upgrades.</p><br><p>Each weapon and upgrade is specifically designed and balanced to allow different styles of play.  Pair up the Stealth upgrade and the Shock Cannon to uncloak behind an enemy player and unload a devastating blow before disappearing again.  Or choose the Sensor upgrade to see where all the nearby players are, and the Temporal Cannon to shoot them through walls!  There are 56 possible combinations – choose whichever suits your strategy.</p>
					<ul>
					<li>Multiplayer team-based vehicular combat</li>
					<li>5 Different arenas featuring multiple levels and boost tunnels</li>
					<li>Persistent leveling system – level-up to unlock new weapons and upgrades</li>
					<li>Stats and Leaderboards</li>
					<li>56 Different tank configurations</li>
					<li>18 Steam Achievements, with more coming soon!</li>
					<li>Unique energy management system – accumulate energy and then distribute it to weapons or use it to gain a speed boost!</li>
					</ul>','Metal Drift is a vehicular sport combat game set in a distant future. As the player, you command an agile, high powered hover tank in a futuristic sports arena. Core game play centers on intense tank-on-tank multiplayer team combat seen through an immersive, first person cockpit.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32310,'Europe, 1938: The lost Ark was just a warm-up! Now Adolf Hitler is after the most powerful talisman of all - the Holy Grail. A few brave men stand in his way. Fortunately, one of them is Indiana Jones, and this time he has his dad with him.<br>			The bad guys are in your face all the way – mercenaries, traitors and spies. Not to mention everything the Luftwaffe can throw at you.... Can you handle the heat?<br>			If you can, you just might earn a higher I.Q. (Indy Quotient) than the man with the whip and the hat.<br>			<ul class="bb_ul"><li>Visit dozens of locations you never saw in the movie!<br>			</li><li>No typing to slow you down…. Just point ''n''click!<br>			</li><li>Outstanding high resolution 3d graphics.<br>			</li><li>Over 100 sound effects…. Plus movie theme music.<br>			</li></ul>','Europe, 1938: The lost Ark was just a warm-up! Now Adolf Hitler is after the most powerful talisman of all - the Holy Grail. A few brave men stand in his way. Fortunately, one of them is Indiana Jones, and this time he has his dad with him.<br>			The bad guys are in your face all the way – mercenaries, traitors and spies. Not to mention everything the Luftwaffe can throw at you.... Can you handle the heat?<br>			If you can, you just might earn a higher I.Q. (Indy Quotient) than the man with the whip and the hat.<br>			<ul class="bb_ul"><li>Visit dozens of locations you never saw in the movie!<br>			</li><li>No typing to slow you down…. Just point ''n''click!<br>			</li><li>Outstanding high resolution 3d graphics.<br>			</li><li>Over 100 sound effects…. Plus movie theme music.<br>			</li></ul>','Europe, 1938: The lost Ark was just a warm-up! Now Adolf Hitler is after the most powerful talisman of all - the Holy Grail. A few brave men stand in his way. Fortunately, one of them is Indiana Jones, and this time he has his dad with him.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32330,'Build, Battle and Brawl your way out of trouble!<br>			Play through all three classic Indiana Jones™ movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO®.<br>			<ul class="bb_ul"><li><strong>Explore and Discover</strong> - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.<br>			</li><li><strong>More Than 60 Playable Characters</strong> - Take control of Indy, his friends, and even his enemies. Team up with a friend and together search for fortune and glory.<br>			</li><li><strong>Whip Into Action!</strong> - Attack and disarm enemies, swing over perilous pits, and interact with LEGO® objects and puzzles!<br>			</li></ul>','Build, Battle and Brawl your way out of trouble!<br>			Play through all three classic Indiana Jones™ movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO®.<br>			<ul class="bb_ul"><li><strong>Explore and Discover</strong> - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.<br>			</li><li><strong>More Than 60 Playable Characters</strong> - Take control of Indy, his friends, and even his enemies. Team up with a friend and together search for fortune and glory.<br>			</li><li><strong>Whip Into Action!</strong> - Attack and disarm enemies, swing over perilous pits, and interact with LEGO® objects and puzzles!<br>			</li></ul>','Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones™ movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO®. Explore and Discover - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32340,'Long after the passing of the Second Shadow, when dragons ruled the twilight sky and the stars were bright and numerous, came the Age of the Great Guilds.<br>				Blacksmiths. Shepherds. Clerics. Each dedicated to the absolute control of secret knowledge.<br>				Another such Guild was the Weavers. Over the centuries, their craft transcended the limits of physical cloth, until they wove the very fabric of reality itself. Now, a strange power has swept the Weavers into oblivion, leaving behind one Weaver boy to unravel the mystery. Help young Bobbin rescue his Guild...and you just might save the universe from an unspeakable catastrophe.<br>				An Extraordinary adventure with an interface of magic…<br>				<ul class="bb_ul"><li>Stunning, high-resolution, 3D landscapes.<br>				</li><li>Sophisticated score and musical effects.<br>				</li><li>Detailed animation and special effects.<br>				</li><li>Elegant point ''n'' click control of characters, objects and magic spells.<br>				</li><li>No burdensome typing, mapping, or inventory management.<br>				</li><li>An easy and engaging game for beginners and veterans alike.<br>				</li></ul>','Long after the passing of the Second Shadow, when dragons ruled the twilight sky and the stars were bright and numerous, came the Age of the Great Guilds.<br>				Blacksmiths. Shepherds. Clerics. Each dedicated to the absolute control of secret knowledge.<br>				Another such Guild was the Weavers. Over the centuries, their craft transcended the limits of physical cloth, until they wove the very fabric of reality itself. Now, a strange power has swept the Weavers into oblivion, leaving behind one Weaver boy to unravel the mystery. Help young Bobbin rescue his Guild...and you just might save the universe from an unspeakable catastrophe.<br>				An Extraordinary adventure with an interface of magic…<br>				<ul class="bb_ul"><li>Stunning, high-resolution, 3D landscapes.<br>				</li><li>Sophisticated score and musical effects.<br>				</li><li>Detailed animation and special effects.<br>				</li><li>Elegant point ''n'' click control of characters, objects and magic spells.<br>				</li><li>No burdensome typing, mapping, or inventory management.<br>				</li><li>An easy and engaging game for beginners and veterans alike.<br>				</li></ul>','Long after the passing of the Second Shadow, when dragons ruled the twilight sky and the stars were bright and numerous, came the Age of the Great Guilds. Blacksmiths. Shepherds. Clerics. Each dedicated to the absolute control of secret knowledge. Another such Guild was the Weavers.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32350,'Join three heroic starfighter pilots in harrowing deep space and planetary missions to save the planet of Naboo. Rookie Naboo pilot Rhys Dallows, mercenary Vana Sage and alien pirate Nym form an unlikely alliance as they join together against an unexpected assault on the peaceful planet.<br>			<ul class="bb_ul"><li>Pilot three unique starfighters: the sleek Naboo starfighter, nimble Guardian Mantis and lethal Havoc.<br>			</li><li>Engage in over 14 challenging missions to save Naboo: deep space dogfights, attack runs, escort missions, and more.<br>			</li><li>Vast environments take you deep into Star Wars worlds: from enormous open plains of Naboo to the furthest reaches of space to the interior corridors of the Droid Control Ship.<br>			</li></ul>','Join three heroic starfighter pilots in harrowing deep space and planetary missions to save the planet of Naboo. Rookie Naboo pilot Rhys Dallows, mercenary Vana Sage and alien pirate Nym form an unlikely alliance as they join together against an unexpected assault on the peaceful planet.<br>			<ul class="bb_ul"><li>Pilot three unique starfighters: the sleek Naboo starfighter, nimble Guardian Mantis and lethal Havoc.<br>			</li><li>Engage in over 14 challenging missions to save Naboo: deep space dogfights, attack runs, escort missions, and more.<br>			</li><li>Vast environments take you deep into Star Wars worlds: from enormous open plains of Naboo to the furthest reaches of space to the interior corridors of the Droid Control Ship.<br>			</li></ul>','Join three heroic starfighter pilots in harrowing deep space and planetary missions to save the planet of Naboo. Rookie Naboo pilot Rhys Dallows, mercenary Vana Sage and alien pirate Nym form an unlikely alliance as they join together against an unexpected assault on the peaceful planet.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32360,'Back by popular demand, The Secret of Monkey Island™: Special Edition faithfully re-imagines the internationally-acclaimed classic game (originally released in 1990) for original and new audiences alike. The development team at LucasArts is bringing the game into the modern era with an all new re-imagined contemporary art style, a re-mastered musical score, full voiceover, and an in-depth hint system to help players through the game’s side-splitting puzzles. Purists will also delight in the ability to seamlessly switch between the updated hand-drawn re-imagining and the original classic version.<br>			The game''s twisty plot leads our naive hero on a hilarious, swash-buckling search for the fabled secret of Monkey Island. Tales of pirate wealth lure him to the port of Mêlée with high hopes, no money, and insatiable curiosity. If clever enough, he will win the confidence of Mêlée''s pirates and find himself blown by the winds of fate toward the terrifying and legendary Monkey Island -- an adventure that would chill the bones of even the most bloodthirsty buccaneer.<br>			<br>Relive the swashbuckling humorous misadventures of the wannabe pirate Guybrush Threepwood<br>			<ul class="bb_ul"><li>Go on a daring adventure in your attempt to become the most infamous pirate in the Caribbean<br>			</li><li>Win the heart of the beautiful governor, Elaine Marley<br>			</li><li>Along the way, confront the evil ghost pirate, LeChuck<br>			</li></ul>Play it again for the first time<br>			<ul class="bb_ul"><li>All new re-imagined contemporary art style, hand-drawn to feature animation quality<br>			</li><li>Re-mastered music score presented in full orchestrated detail<br>			</li><li>Complete voice over using the original Monkey Island™ franchise cast brings the story and characters of the original adventures to life like never before<br>			</li><li>Scene-for-scene hot swap allows for seamless transition between special edition and classic modes anywhere and at any time<br>			</li></ul>Includes all new features<br>			<ul class="bb_ul"><li>All new intuitive game interface and controls provide a more interactive gameplay experience<br>			</li><li>In-game puzzle hint system keeps the puzzles fresh and fun		<br>			</li></ul>','Back by popular demand, The Secret of Monkey Island™: Special Edition faithfully re-imagines the internationally-acclaimed classic game (originally released in 1990) for original and new audiences alike. The development team at LucasArts is bringing the game into the modern era with an all new re-imagined contemporary art style, a re-mastered musical score, full voiceover, and an in-depth hint system to help players through the game’s side-splitting puzzles. Purists will also delight in the ability to seamlessly switch between the updated hand-drawn re-imagining and the original classic version.<br>			The game''s twisty plot leads our naive hero on a hilarious, swash-buckling search for the fabled secret of Monkey Island. Tales of pirate wealth lure him to the port of Mêlée with high hopes, no money, and insatiable curiosity. If clever enough, he will win the confidence of Mêlée''s pirates and find himself blown by the winds of fate toward the terrifying and legendary Monkey Island -- an adventure that would chill the bones of even the most bloodthirsty buccaneer.<br>			<br>Relive the swashbuckling humorous misadventures of the wannabe pirate Guybrush Threepwood<br>			<ul class="bb_ul"><li>Go on a daring adventure in your attempt to become the most infamous pirate in the Caribbean<br>			</li><li>Win the heart of the beautiful governor, Elaine Marley<br>			</li><li>Along the way, confront the evil ghost pirate, LeChuck<br>			</li></ul>Play it again for the first time<br>			<ul class="bb_ul"><li>All new re-imagined contemporary art style, hand-drawn to feature animation quality<br>			</li><li>Re-mastered music score presented in full orchestrated detail<br>			</li><li>Complete voice over using the original Monkey Island™ franchise cast brings the story and characters of the original adventures to life like never before<br>			</li><li>Scene-for-scene hot swap allows for seamless transition between special edition and classic modes anywhere and at any time<br>			</li></ul>Includes all new features<br>			<ul class="bb_ul"><li>All new intuitive game interface and controls provide a more interactive gameplay experience<br>			</li><li>In-game puzzle hint system keeps the puzzles fresh and fun		<br>			</li></ul>','Back by popular demand, The Secret of Monkey Island™: Special Edition faithfully re-imagines the internationally-acclaimed classic game (originally released in 1990) for original and new audiences alike.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32370,'Note: Mac version only supports English language<br><br>Choose Your Path.<br>It is four thousand years before the Galactic Empire and hundreds of Jedi Knights have fallen in battle against the ruthless Sith. You are the last hope of the Jedi Order. Can you master the awesome power of the Force on your quest to save the Republic? Or will you fall to the lure of the dark side? Hero or villain, saviour or conqueror... you alone will determine the destiny of the entire galaxy!<br>			<ul class="bb_ul"><li>A brand new Star Wars role-playing experience with unique characters, creatures, vehicles and planets.<br>			</li><li>Learn to use the Force with over 40 different powers and build your own lightsaber.<br>			</li><li>Adventure through some of the most popular Star Wars locations, including Tatooine and the Wookiee homeworld Kashyyyk.<br>			</li><li>Choose your party from nine customisable characters, including Twi''leks, droids and Wookiees.<br>			</li><li>Travel to eight enormous worlds in your own starship, the Ebon Hawk.<br>			</li></ul>','Note: Mac version only supports English language<br><br>Choose Your Path.<br>It is four thousand years before the Galactic Empire and hundreds of Jedi Knights have fallen in battle against the ruthless Sith. You are the last hope of the Jedi Order. Can you master the awesome power of the Force on your quest to save the Republic? Or will you fall to the lure of the dark side? Hero or villain, saviour or conqueror... you alone will determine the destiny of the entire galaxy!<br>			<ul class="bb_ul"><li>A brand new Star Wars role-playing experience with unique characters, creatures, vehicles and planets.<br>			</li><li>Learn to use the Force with over 40 different powers and build your own lightsaber.<br>			</li><li>Adventure through some of the most popular Star Wars locations, including Tatooine and the Wookiee homeworld Kashyyyk.<br>			</li><li>Choose your party from nine customisable characters, including Twi''leks, droids and Wookiees.<br>			</li><li>Travel to eight enormous worlds in your own starship, the Ebon Hawk.<br>			</li></ul>','It is four thousand years before the Galactic Empire and hundreds of Jedi Knights have fallen in battle against the ruthless Sith. You are the last hope of the Jedi Order. Can you master the awesome power of the Force on your quest to save the Republic? Or will you fall to the lure of the dark side?');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32380,'Dark Forces™ set the industry standard for first person action in the Star Wars® universe. Now Jedi Knight: Dark Forces II picks up where the award-winning game left off...with even more features and firepower in dazzling 3D graphics. As Kyle Katarn, you must acquire the lightsaber and learn the ways of the Force to become a Jedi Knight. Confront old foes... Greedo, Boosk, stormtroopers. And new enemies... seven dark Jedi who plan to harness the power of an ancient burial ground for unsurpassed evil. But take heart, your 10 weapon arsenal and over 12 Force powers make you a force to be reckoned with.<br>			<ul class="bb_ul"><li>Single or multiplayer gameplay over modem, network or Internet. 9 multiplayer levels<br>			</li><li>All new realistic 3D environments with animated 3D characters in 21 heart-stopping levels<br>			</li><li>Encounter seven dark jedi, each possessing unique powers<br>			</li><li>Compatible with many 3D graphics cards<br>			</li><li>Intense Star Wars action in an all-new story fraught with danger and adventure - do you take the quick and easy path as Darth Vader did or do you take the patient route to Jedi Knighthood?<br>			</li></ul>If you choose the light side:<br>			<ul class="bb_ul"><li>Train to become a Jedi Knight - master the elegant Lightsaber and learn four special apprentice abilities<br>			</li><li>Use exclusive light side powers: healing, persuasion (for the weak-minded), blinding and absorption<br>			</li></ul>Or be tempted by the dark side:<br>			<ul class="bb_ul"><li>Use your Jedi Knight training and apprentice abilities to become an agent of evil<br>			</li><li>Use exclusive dark side powers: the grip (used if there''s a disturbing lack of faith), Force throw, energy bolts and destruction<br>			</li></ul>','Dark Forces™ set the industry standard for first person action in the Star Wars® universe. Now Jedi Knight: Dark Forces II picks up where the award-winning game left off...with even more features and firepower in dazzling 3D graphics. As Kyle Katarn, you must acquire the lightsaber and learn the ways of the Force to become a Jedi Knight. Confront old foes... Greedo, Boosk, stormtroopers. And new enemies... seven dark Jedi who plan to harness the power of an ancient burial ground for unsurpassed evil. But take heart, your 10 weapon arsenal and over 12 Force powers make you a force to be reckoned with.<br>			<ul class="bb_ul"><li>Single or multiplayer gameplay over modem, network or Internet. 9 multiplayer levels<br>			</li><li>All new realistic 3D environments with animated 3D characters in 21 heart-stopping levels<br>			</li><li>Encounter seven dark jedi, each possessing unique powers<br>			</li><li>Compatible with many 3D graphics cards<br>			</li><li>Intense Star Wars action in an all-new story fraught with danger and adventure - do you take the quick and easy path as Darth Vader did or do you take the patient route to Jedi Knighthood?<br>			</li></ul>If you choose the light side:<br>			<ul class="bb_ul"><li>Train to become a Jedi Knight - master the elegant Lightsaber and learn four special apprentice abilities<br>			</li><li>Use exclusive light side powers: healing, persuasion (for the weak-minded), blinding and absorption<br>			</li></ul>Or be tempted by the dark side:<br>			<ul class="bb_ul"><li>Use your Jedi Knight training and apprentice abilities to become an agent of evil<br>			</li><li>Use exclusive dark side powers: the grip (used if there''s a disturbing lack of faith), Force throw, energy bolts and destruction<br>			</li></ul>','Jedi Knight: Dark Forces II picks up where the award-winning Dark Forces™ game left off...with even more features and firepower in dazzling 3D graphics. As Kyle Katarn, you must acquire a lightsaber and learn the ways of the Force to become a Jedi Knight.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32390,'&quot;I have chosen my destiny, and it lies here...&quot; - Kyle Katarn<br>			It is five years after Kyle''s victory over the seven dark Jedi. Invading Imperial forces advance upon a quiet Rebel outpost, interrupting Kyle''s training of a brave new Jedi, Mara Jade. First introduced in Timothy Zahn''s award-winning Star Wars novel, Heir to the Empire, Mara Jade blends her past experiences as a one time smuggler and Emperor''s Hand with her apprenticeship as a Jedi Knight. Armed with four new weapons and five new Force powers, Mara must secure supplies desperately needed by the New Republic while Kyle, believing it a part of his destiny, pursues the secret treasures shrouded in an ancient Sith temple.<br>			Can the New Republic''s boldest female Jedi protect the Rebel base, negotiate with Ka''Pa the Hutt, then ward off a phalanx of enemies?<br>			Will the ancient secrets of the Sith unleash new powers?<br>			Are Kyle and Mara strong enough to resist the temptations of the dark side, or will new entanglements seduce them?<br>			<ul class="bb_ul"><li>Bring a Whole new game experience to Jedi Knight. Jam-packed features make Mysteries of the Sith a must-have for Jedi Knight fans<br>			</li><li>New playable character, Mara Jade, introduced first in Timothy Zahn''s award-winning Star Wars novel, Heir to the Empire<br>			</li><li>14 new levels, 13 total locations, including wampa-infested swamps, the foreboding fortress of Ka''Pa the Hutt, and the subterranean catacombs of a temple deep within the planet Drommund Kaas<br>			</li><li>4 new weapons, including a carbonite gun, repeating blaster cannon, and sniper scope<br>			</li><li>5 new Force powers, featuring Force Push, Saber Throw, and Force Projection<br>			</li><li>Over 2 dozen new enemies - gladiator, assassin and torture droids, pirate raiders, creatures of the Sith, and a menacing rancor<br>			</li><li>3 new multiplayer personalities, with distinct characteristics, weapons and inventory<br>			</li></ul>Plus these new game advances:<br>			<ul class="bb_ul"><li>Cameras that let you monitor where you are in the heat of battle<br>			</li><li>Enhanced lighting features, including colored lighting support<br>			</li><li>A new multiplayer game, Kill the Fool with the Ysalamiri<br>			</li></ul>Choose wisely and May the Force Be With You.','&quot;I have chosen my destiny, and it lies here...&quot; - Kyle Katarn<br>			It is five years after Kyle''s victory over the seven dark Jedi. Invading Imperial forces advance upon a quiet Rebel outpost, interrupting Kyle''s training of a brave new Jedi, Mara Jade. First introduced in Timothy Zahn''s award-winning Star Wars novel, Heir to the Empire, Mara Jade blends her past experiences as a one time smuggler and Emperor''s Hand with her apprenticeship as a Jedi Knight. Armed with four new weapons and five new Force powers, Mara must secure supplies desperately needed by the New Republic while Kyle, believing it a part of his destiny, pursues the secret treasures shrouded in an ancient Sith temple.<br>			Can the New Republic''s boldest female Jedi protect the Rebel base, negotiate with Ka''Pa the Hutt, then ward off a phalanx of enemies?<br>			Will the ancient secrets of the Sith unleash new powers?<br>			Are Kyle and Mara strong enough to resist the temptations of the dark side, or will new entanglements seduce them?<br>			<ul class="bb_ul"><li>Bring a Whole new game experience to Jedi Knight. Jam-packed features make Mysteries of the Sith a must-have for Jedi Knight fans<br>			</li><li>New playable character, Mara Jade, introduced first in Timothy Zahn''s award-winning Star Wars novel, Heir to the Empire<br>			</li><li>14 new levels, 13 total locations, including wampa-infested swamps, the foreboding fortress of Ka''Pa the Hutt, and the subterranean catacombs of a temple deep within the planet Drommund Kaas<br>			</li><li>4 new weapons, including a carbonite gun, repeating blaster cannon, and sniper scope<br>			</li><li>5 new Force powers, featuring Force Push, Saber Throw, and Force Projection<br>			</li><li>Over 2 dozen new enemies - gladiator, assassin and torture droids, pirate raiders, creatures of the Sith, and a menacing rancor<br>			</li><li>3 new multiplayer personalities, with distinct characteristics, weapons and inventory<br>			</li></ul>Plus these new game advances:<br>			<ul class="bb_ul"><li>Cameras that let you monitor where you are in the heat of battle<br>			</li><li>Enhanced lighting features, including colored lighting support<br>			</li><li>A new multiplayer game, Kill the Fool with the Ysalamiri<br>			</li></ul>Choose wisely and May the Force Be With You.','It is five years after Kyle''s victory over the seven dark Jedi. Invading Imperial forces advance upon a quiet Rebel outpost, interrupting Kyle''s training of a brave new Jedi, Mara Jade. First introduced in Timothy Zahn''s award-winning Star Wars novel, Heir to the Empire, Mara Jade blends her past experiences as a one time smuggler and...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32400,'Behind a veil of secrecy the evil Empire is creating a doomsday army - one that, if finished, will become the final cog in the Empire''s arsenal of terror and domination.<br>			Your Mission? Join the Rebel Alliance''s covert operations division, infiltrate the Empire, then battle every man and machine the Imperial Forces can muster. Search a vast galaxy for clues, attack enemy bases-all in a desperate attempt to stop the activation of this fearsome new weapon.<br>			<ul class="bb_ul"><li>Fully interactive environments - morphing walls and floors, moving platforms, and conveyors, realistic lighting and atmospheric effects.<br>			</li><li>First-person ground combat. Call on 10 weapons to fight twenty types of enemies.<br>			</li><li>Explore the virtual Star Wars universe up close and personal.<br>			</li><li>Climb catwalks, look and shoot up and down, jump off ledges, wade through garbage.<br>			</li></ul>','Behind a veil of secrecy the evil Empire is creating a doomsday army - one that, if finished, will become the final cog in the Empire''s arsenal of terror and domination.<br>			Your Mission? Join the Rebel Alliance''s covert operations division, infiltrate the Empire, then battle every man and machine the Imperial Forces can muster. Search a vast galaxy for clues, attack enemy bases-all in a desperate attempt to stop the activation of this fearsome new weapon.<br>			<ul class="bb_ul"><li>Fully interactive environments - morphing walls and floors, moving platforms, and conveyors, realistic lighting and atmospheric effects.<br>			</li><li>First-person ground combat. Call on 10 weapons to fight twenty types of enemies.<br>			</li><li>Explore the virtual Star Wars universe up close and personal.<br>			</li><li>Climb catwalks, look and shoot up and down, jump off ledges, wade through garbage.<br>			</li></ul>','Behind a veil of secrecy the evil Empire is creating a doomsday army - one that, if finished, will become the final cog in the Empire''s arsenal of terror and domination. Your Mission? Join the Rebel Alliance''s covert operations division, infiltrate the Empire.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32410,'From the team that re-imagined The Secret of Monkey Island™, comes Lucidity, an addictive puzzle platformer set in the surreal childlike dreamscapes of the little girl Sofi. In this challenging puzzler, it’s your task to keep Sofi safe as she drifts deeper into the strange new world of her dreams. Featuring stunning hand-illustrated visuals, a spell-binding original score and unique puzzle platformer gameplay, Lucidity will challenge your wits, test your reflexes and mesmerize your senses.<br>			Take a trip into the surreal childlike dreamscapes of Sofi, a little girl filled with a persistent desire to explore new worlds and overcome all obstacles in her way. Test your skills in this addictive puzzle platformer where through quick reactions and placement of unique puzzle pieces, you create a path to help Sofi traverse safely through 27 visually stunning, hand-illustrated dreamscapes. <br>			<ul class="bb_ul"><li><strong>A Surreal Fantasy</strong> - Take a fantastic journey with little Sofi as she drifts into a vivid dream world where, beckoned by the kind words of her grandmother, she learns to overcome her fears.<br>			</li><li><strong>Mesmerizing Dreamscapes</strong> - Like a children’s storybook come to life, get lost in mesmerizing dreamscapes detailed with beautiful hand-drawn contemporary art.<br>			</li><li><strong>Spell-binding Original Score</strong> - Featuring a lush original score that will draw you into Sofi’s dream world.<br>			</li><li><strong>Addictive Puzzle-Platformer Gameplay</strong> - Skillfully place unique puzzle pieces designed to propel Sofi to and from suspended platforms, or over and under obstacles, in an effort to maintain her state of perpetual motion.<br>			</li><li><strong>Unlockable Steam Achievements</strong> - Collect fireflies on your adventures to unlock additional bonus levels and achievements to make it to the top of the leaderboards.<br>			<ul class="bb_ul"></ul></li></ul>','From the team that re-imagined The Secret of Monkey Island™, comes Lucidity, an addictive puzzle platformer set in the surreal childlike dreamscapes of the little girl Sofi. In this challenging puzzler, it’s your task to keep Sofi safe as she drifts deeper into the strange new world of her dreams. Featuring stunning hand-illustrated visuals, a spell-binding original score and unique puzzle platformer gameplay, Lucidity will challenge your wits, test your reflexes and mesmerize your senses.<br>			Take a trip into the surreal childlike dreamscapes of Sofi, a little girl filled with a persistent desire to explore new worlds and overcome all obstacles in her way. Test your skills in this addictive puzzle platformer where through quick reactions and placement of unique puzzle pieces, you create a path to help Sofi traverse safely through 27 visually stunning, hand-illustrated dreamscapes. <br>			<ul class="bb_ul"><li><strong>A Surreal Fantasy</strong> - Take a fantastic journey with little Sofi as she drifts into a vivid dream world where, beckoned by the kind words of her grandmother, she learns to overcome her fears.<br>			</li><li><strong>Mesmerizing Dreamscapes</strong> - Like a children’s storybook come to life, get lost in mesmerizing dreamscapes detailed with beautiful hand-drawn contemporary art.<br>			</li><li><strong>Spell-binding Original Score</strong> - Featuring a lush original score that will draw you into Sofi’s dream world.<br>			</li><li><strong>Addictive Puzzle-Platformer Gameplay</strong> - Skillfully place unique puzzle pieces designed to propel Sofi to and from suspended platforms, or over and under obstacles, in an effort to maintain her state of perpetual motion.<br>			</li><li><strong>Unlockable Steam Achievements</strong> - Collect fireflies on your adventures to unlock additional bonus levels and achievements to make it to the top of the leaderboards.<br>			<ul class="bb_ul"></ul></li></ul>','From the team that re-imagined The Secret of Monkey Island™, comes Lucidity, an addictive puzzle platformer set in the surreal childlike dreamscapes of the little girl Sofi. In this challenging puzzler, it’s your task to keep Sofi safe as she drifts deeper into the strange new world of her dreams.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32420,'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and Clone Troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.  A brand-new storyline, which bridges the gap between season one and two, takes the player on a multi-faceted adventure to stop a mysterious techno assassin’s destructive plot.  Built around two-player cooperative action, the accessible controls and family-friendly gameplay bring Star Wars fans across generations together like never before to fight the evil Separatists and restore peace to the galaxy.<br>						<ul class="bb_ul"><li>Play as your favorite Jedi heroes including Anakin Skywalker, Obi-Wan Kenobi, Ahsoka Tano, Mace Windu, and  Kit Fisto<br>						</li><li>Slice and dice your way through Separatist droids with your Lightsaber and Force powers and use your agility to perform amazing leaps and navigate levels filled with interactivity <br>						</li><li>Turn your enemies into weapons as you commandeer droids and use their unique abilities to blast enemies and solve puzzles as a Jedi <br>						</li><li>Compete against a friend with in-level challenges for rewards and points to be spent to upgrade your character and unlock bonus items <br>						</li></ul>','Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and Clone Troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.  A brand-new storyline, which bridges the gap between season one and two, takes the player on a multi-faceted adventure to stop a mysterious techno assassin’s destructive plot.  Built around two-player cooperative action, the accessible controls and family-friendly gameplay bring Star Wars fans across generations together like never before to fight the evil Separatists and restore peace to the galaxy.<br>						<ul class="bb_ul"><li>Play as your favorite Jedi heroes including Anakin Skywalker, Obi-Wan Kenobi, Ahsoka Tano, Mace Windu, and  Kit Fisto<br>						</li><li>Slice and dice your way through Separatist droids with your Lightsaber and Force powers and use your agility to perform amazing leaps and navigate levels filled with interactivity <br>						</li><li>Turn your enemies into weapons as you commandeer droids and use their unique abilities to blast enemies and solve puzzles as a Jedi <br>						</li><li>Compete against a friend with in-level challenges for rewards and points to be spent to upgrade your character and unlock bonus items <br>						</li></ul>','Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and Clone Troopers from the preeminent animated television...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32430,'The story and action of Star Wars®: The Force Unleashed™ expands with the release of Star Wars The Force Unleashed: Ultimate Sith Edition, a special new version of the game that will show gamers the deepest, darkest side of the Force in a story that puts them on a collision course with Luke Skywalker himself.  The Ultimate Sith Edition includes all of the original missions found in Star Wars: The Force Unleashed as well as content previously only available via download and an all-new exclusive bonus level.<br>						Star Wars: The Force Unleashed completely re-imagines the scope and scale of the Force and casts players as Darth Vader’s &quot;Secret Apprentice,&quot; unveiling new revelations about the Star Wars galaxy seen through the eyes of a mysterious new character armed with unprecedented powers. <br>						<ul class="bb_ul"><li>Includes the original Star Wars The Force Unleashed game plus 3 re-imagined Classic Trilogy levels: Tatooine, Jedi Temple and ALL-NEW-Hoth level<br>						</li><li>UNLEASH EPIC FORCE POWERS and devastating combos<br>						</li><li>DISCOVER THE UNTOLD STORY of Darth Vader''s secret apprentice set between Episodes III and IV<br>						</li><li>LIFE-LIKE REACTIONS from characters and environments that are different every time you play<br>						</li></ul>','The story and action of Star Wars®: The Force Unleashed™ expands with the release of Star Wars The Force Unleashed: Ultimate Sith Edition, a special new version of the game that will show gamers the deepest, darkest side of the Force in a story that puts them on a collision course with Luke Skywalker himself.  The Ultimate Sith Edition includes all of the original missions found in Star Wars: The Force Unleashed as well as content previously only available via download and an all-new exclusive bonus level.<br>						Star Wars: The Force Unleashed completely re-imagines the scope and scale of the Force and casts players as Darth Vader’s &quot;Secret Apprentice,&quot; unveiling new revelations about the Star Wars galaxy seen through the eyes of a mysterious new character armed with unprecedented powers. <br>						<ul class="bb_ul"><li>Includes the original Star Wars The Force Unleashed game plus 3 re-imagined Classic Trilogy levels: Tatooine, Jedi Temple and ALL-NEW-Hoth level<br>						</li><li>UNLEASH EPIC FORCE POWERS and devastating combos<br>						</li><li>DISCOVER THE UNTOLD STORY of Darth Vader''s secret apprentice set between Episodes III and IV<br>						</li><li>LIFE-LIKE REACTIONS from characters and environments that are different every time you play<br>						</li></ul>','A game that will show gamers the deepest, darkest side of the Force in a story that puts them on a collision course with Luke Skywalker himself.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32440,'Kick Some Brick in I through VI<br>					Play through all six Star Wars movies in one videogame! Adding new characters, new levels, new features and for the first time ever, the chance to build and battle your way through a fun Star Wars galaxy on your PC!<br>					<ul class="bb_ul"><li><strong>New Gameplay Features</strong> with enhanced Force Powers, new power-ups and new Challenge Modes.<br>					</li><li><strong>Solve Puzzles</strong> through the use of creative thinking, teamwork and unique building situations.<br>					</li><li><strong>Over 120 playable characters,</strong> and new characters like Watto, Zam Wessell, Boss Nass and more!<br>					</li><li><strong>Upgraded Character Customizer</strong> allowing millions of possibilities. With character parts from all 6 movies, create cross-Trilogy mash-up characters like Han Windu and Lando Amidala.<br>					</li><li><strong>Redesigned levels</strong> like the &quot;Mos Espa Podrace&quot; and &quot;Gunship Cavalry&quot; to take advantage of the the open vehicle gameplay of LEGO Star Wars II.<br>					</li><li><strong>Bonus levels and missions</strong> allow you to take 10 additional Bounty Hunter missions from Jabba the Hutt in the prequel trilogy.<br>					</li><li><strong>Two Player Local Co-Op</strong> lets friends and families play together.<br>					</li></ul>','Kick Some Brick in I through VI<br>					Play through all six Star Wars movies in one videogame! Adding new characters, new levels, new features and for the first time ever, the chance to build and battle your way through a fun Star Wars galaxy on your PC!<br>					<ul class="bb_ul"><li><strong>New Gameplay Features</strong> with enhanced Force Powers, new power-ups and new Challenge Modes.<br>					</li><li><strong>Solve Puzzles</strong> through the use of creative thinking, teamwork and unique building situations.<br>					</li><li><strong>Over 120 playable characters,</strong> and new characters like Watto, Zam Wessell, Boss Nass and more!<br>					</li><li><strong>Upgraded Character Customizer</strong> allowing millions of possibilities. With character parts from all 6 movies, create cross-Trilogy mash-up characters like Han Windu and Lando Amidala.<br>					</li><li><strong>Redesigned levels</strong> like the &quot;Mos Espa Podrace&quot; and &quot;Gunship Cavalry&quot; to take advantage of the the open vehicle gameplay of LEGO Star Wars II.<br>					</li><li><strong>Bonus levels and missions</strong> allow you to take 10 additional Bounty Hunter missions from Jabba the Hutt in the prequel trilogy.<br>					</li><li><strong>Two Player Local Co-Op</strong> lets friends and families play together.<br>					</li></ul>','Kick Some Brick in I through VI! Play through all six Star Wars movies in one videogame! Adding new characters, new levels, new features and for the first time ever, the chance to build and battle your way through a fun Star Wars galaxy on your PC!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32450,'LEGO® Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO® fashion, get creative and build your own levels to play with friends!<br>					<ul class="bb_ul"><li>New modes including two-player drop-in, drop-out split-screen gameplay lets you play together with your friends and family like never before<br>					</li><li>For the first time, create your own levels and play them with friends!<br>					</li><li>New vehicles, characters and abilities in the biggest LEGO environments ever!<br>					</li><li>Use a variety of weapons from the environment to fight enemies (e.g., chairs, guns, swords, bottles)<br>					</li><li>Collect artifacts through the game to unlock more than 60 playable characters, including villains and supporting characters (Marion Ravenwood, Mutt Williams, Short Round, Rene Belloq, Willie Scott, Marcus Brody, Dr. Henry Jones Sr. and Irina Spalko)<br>					</li><li>A complete retelling of Indy’s three original adventures from the first game, for a whole new experience! <br>					</li><li>Includes all your favorite moments from The Kingdom of the Crystal Skull <br>					</li></ul>','LEGO® Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO® fashion, get creative and build your own levels to play with friends!<br>					<ul class="bb_ul"><li>New modes including two-player drop-in, drop-out split-screen gameplay lets you play together with your friends and family like never before<br>					</li><li>For the first time, create your own levels and play them with friends!<br>					</li><li>New vehicles, characters and abilities in the biggest LEGO environments ever!<br>					</li><li>Use a variety of weapons from the environment to fight enemies (e.g., chairs, guns, swords, bottles)<br>					</li><li>Collect artifacts through the game to unlock more than 60 playable characters, including villains and supporting characters (Marion Ravenwood, Mutt Williams, Short Round, Rene Belloq, Willie Scott, Marcus Brody, Dr. Henry Jones Sr. and Irina Spalko)<br>					</li><li>A complete retelling of Indy’s three original adventures from the first game, for a whole new experience! <br>					</li><li>Includes all your favorite moments from The Kingdom of the Crystal Skull <br>					</li></ul>','LEGO® Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO® fashion, get creative and build your own levels to play with friends!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32460,'Wannabe pirate Guybrush Threepwood, and the now zombie pirate LeChuck, return in what has long been considered one of the greatest LucasArts adventure games of all time. <strong>Monkey Island™ 2 Special Edition: LeChuck’s Revenge™</strong> faithfully re-imagines the classic Monkey Island™ sequel in signature special edition detail. Expanding on the highly successful <a href="http://store.steampowered.com/app/32360/" target="_blank" rel="noreferrer"  >The Secret of Monkey Island™: Special Edition</a> in just about every way, fans will now experience new unique special edition features and interact with the world of Monkey Island like never before.<br>											Having seemingly defeated the evil ghost pirate LeChuck in his first adventure, Guybrush Threepwood sets his sights on the legendary treasure of Big Whoop. But wait, LeChuck is now back in zombie form and he''s out for revenge. Guybrush will have to use his wits, his humor and his insatiable desire for adventure to defeat his nemesis once and for all and truly prove himself the greatest pirate in the Caribbean. Voodoo dolls, spitting contests and amusement parks are just some of the challenges Guybrush must overcome as he meets old friends, fights new enemies and uses every ounce of his mojo to overcome the wrath of LeChuck’s revenge.										<br>											<strong>Play it again for the first time with signature Special Edition features:</strong><br>											<ul class="bb_ul"><li><strong>High-definition graphics:</strong> All new re-imagined contemporary art style, hand-drawn and presented in high definition.<br>											</li><li><strong>Voice over:</strong> Complete voice over using original Monkey Island franchise cast members brings the story and characters to life like never before, now available for both the Special Edition and Classic modes.<br>											</li><li><strong>Renewed music score:</strong> Re-mastered and re-recorded musical score using live instruments.<br>											</li><li><strong>Special Edition and Classic modes:</strong> Scene-for-scene hot swap lets you seamlessly transition between Special Edition and Classic modes at anytime during gameplay.<br>											</li><li><strong>Enhanced gameplay:</strong> All new intuitive game interface and controls provide a more interactive gameplay experience.<br>											</li><li><strong>Hint system:</strong> In-game puzzle hint system keeps the puzzles fresh and fun.<br>											</li></ul><strong>Includes all new features:</strong><br>											<ul class="bb_ul"><li><strong>Direct control:</strong> Choose how you play -- use the classic point-and-click interface or the all new intuitive direct character control for a more interactive gameplay experience.<br>											</li><li><strong>Object highlighting:</strong> Interactive object highlighting provides quicker clues to finding hidden objects.<br>											</li><li><strong>Behind the scenes art:</strong> An in-game art viewer lets players view fantastic never-before-seen artwork from both the Classic and Special Edition versions of the game.<br>											</li><li><strong>Original developer commentary:</strong> Listen to select scene commentary from Ron Gilbert, Tim Schafer and Dave Grossman as they share funny stories and chronicle the development of the original <strong>Monkey Island™ 2: LeChuck''s Revenge™.</strong><br>											</li><li><strong>SteamWorks Achievements:</strong> Only the mightiest of pirates can collect all three. We kid, there’s a lot more, but you will need to be mighty to get them.<br>											</li></ul>','Wannabe pirate Guybrush Threepwood, and the now zombie pirate LeChuck, return in what has long been considered one of the greatest LucasArts adventure games of all time. <strong>Monkey Island™ 2 Special Edition: LeChuck’s Revenge™</strong> faithfully re-imagines the classic Monkey Island™ sequel in signature special edition detail. Expanding on the highly successful <a href="http://store.steampowered.com/app/32360/" target="_blank" rel="noreferrer"  >The Secret of Monkey Island™: Special Edition</a> in just about every way, fans will now experience new unique special edition features and interact with the world of Monkey Island like never before.<br>											Having seemingly defeated the evil ghost pirate LeChuck in his first adventure, Guybrush Threepwood sets his sights on the legendary treasure of Big Whoop. But wait, LeChuck is now back in zombie form and he''s out for revenge. Guybrush will have to use his wits, his humor and his insatiable desire for adventure to defeat his nemesis once and for all and truly prove himself the greatest pirate in the Caribbean. Voodoo dolls, spitting contests and amusement parks are just some of the challenges Guybrush must overcome as he meets old friends, fights new enemies and uses every ounce of his mojo to overcome the wrath of LeChuck’s revenge.										<br>											<strong>Play it again for the first time with signature Special Edition features:</strong><br>											<ul class="bb_ul"><li><strong>High-definition graphics:</strong> All new re-imagined contemporary art style, hand-drawn and presented in high definition.<br>											</li><li><strong>Voice over:</strong> Complete voice over using original Monkey Island franchise cast members brings the story and characters to life like never before, now available for both the Special Edition and Classic modes.<br>											</li><li><strong>Renewed music score:</strong> Re-mastered and re-recorded musical score using live instruments.<br>											</li><li><strong>Special Edition and Classic modes:</strong> Scene-for-scene hot swap lets you seamlessly transition between Special Edition and Classic modes at anytime during gameplay.<br>											</li><li><strong>Enhanced gameplay:</strong> All new intuitive game interface and controls provide a more interactive gameplay experience.<br>											</li><li><strong>Hint system:</strong> In-game puzzle hint system keeps the puzzles fresh and fun.<br>											</li></ul><strong>Includes all new features:</strong><br>											<ul class="bb_ul"><li><strong>Direct control:</strong> Choose how you play -- use the classic point-and-click interface or the all new intuitive direct character control for a more interactive gameplay experience.<br>											</li><li><strong>Object highlighting:</strong> Interactive object highlighting provides quicker clues to finding hidden objects.<br>											</li><li><strong>Behind the scenes art:</strong> An in-game art viewer lets players view fantastic never-before-seen artwork from both the Classic and Special Edition versions of the game.<br>											</li><li><strong>Original developer commentary:</strong> Listen to select scene commentary from Ron Gilbert, Tim Schafer and Dave Grossman as they share funny stories and chronicle the development of the original <strong>Monkey Island™ 2: LeChuck''s Revenge™.</strong><br>											</li><li><strong>SteamWorks Achievements:</strong> Only the mightiest of pirates can collect all three. We kid, there’s a lot more, but you will need to be mighty to get them.<br>											</li></ul>','Wannabe pirate Guybrush Threepwood, and the now zombie pirate LeChuck, return in what has long been considered one of the greatest LucasArts adventure games of all time.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32470,'Command or corrupt an entire galaxy in the definitive <strong>Star Wars</strong> strategy collection. It is a time of galactic civil war. Will you take up the reins of the Rebellion, assume control of the Empire, or rule the <strong>Star Wars</strong> Underworld?<br>					<strong>Star Wars Empire at War:</strong><br>					From the lives of soldiers to the deaths of planets, you are the supreme galactic commander.  It is a time of galactic civil war.  Take up the reins of the Rebellion or assume control for the Empire.  Whichever you choose, it will be up to YOU to steer your side to ultimate victory.  Command everything from individual troops to starships and even the mighty Death Star as you execute campaigns on the ground, in space and across the galaxy.  Forget tedious resource gathering – just jump straight into the heart of the action.  You can even change <strong>Star Wars</strong> history! Every decision affects your next battle and every battle helps shape the fate of the galaxy.<br><br>					<ul class="bb_ul"><li>Conquer or liberate over 80 ground and space locations including Kashyyyk, Tatooine and Dagobah – each with its own strategic advantage. <br>						</li><li>Command iconic <strong>Star Wars</strong> characters such as Obi-Wan Kenobi, Luke Skywalker, Darth Vader and Boba Fett. <br>						</li><li>Pit X-wings against TIE fighters or command an entire fleet of Star Destroyers in space.  Then send down land forces to secure the planet below. <br>					</li></ul><strong>Star Wars® Empire at War™: Forces of Corruption™:</strong><br>					You’ve played the light side.  You’ve played the dark side.  Now play the corrupt side!  As Tyber Zann you’ll stop at nothing to become the most notorious criminal leader since Jabba the Hutt.  With all new tactics like piracy, kidnapping, racketeering and bribery, you can control the shadowy forces of corruption in your attempt to rule the <strong>Star Wars</strong> underworld.  Don’t just control the galaxy…corrupt it!<br><br>					<ul class="bb_ul"><li><strong>All new units and planets:</strong> Command over 28 new underworld units as well as new Rebel and Imperial forces and heroes on 13 new planets.<br>						</li><li><strong>Expanded Multiplayer:</strong> Experience all out, three-faction battles and now play the same side against itself with mirror play.<br>					</li></ul>','Command or corrupt an entire galaxy in the definitive <strong>Star Wars</strong> strategy collection. It is a time of galactic civil war. Will you take up the reins of the Rebellion, assume control of the Empire, or rule the <strong>Star Wars</strong> Underworld?<br>					<strong>Star Wars Empire at War:</strong><br>					From the lives of soldiers to the deaths of planets, you are the supreme galactic commander.  It is a time of galactic civil war.  Take up the reins of the Rebellion or assume control for the Empire.  Whichever you choose, it will be up to YOU to steer your side to ultimate victory.  Command everything from individual troops to starships and even the mighty Death Star as you execute campaigns on the ground, in space and across the galaxy.  Forget tedious resource gathering – just jump straight into the heart of the action.  You can even change <strong>Star Wars</strong> history! Every decision affects your next battle and every battle helps shape the fate of the galaxy.<br><br>					<ul class="bb_ul"><li>Conquer or liberate over 80 ground and space locations including Kashyyyk, Tatooine and Dagobah – each with its own strategic advantage. <br>						</li><li>Command iconic <strong>Star Wars</strong> characters such as Obi-Wan Kenobi, Luke Skywalker, Darth Vader and Boba Fett. <br>						</li><li>Pit X-wings against TIE fighters or command an entire fleet of Star Destroyers in space.  Then send down land forces to secure the planet below. <br>					</li></ul><strong>Star Wars® Empire at War™: Forces of Corruption™:</strong><br>					You’ve played the light side.  You’ve played the dark side.  Now play the corrupt side!  As Tyber Zann you’ll stop at nothing to become the most notorious criminal leader since Jabba the Hutt.  With all new tactics like piracy, kidnapping, racketeering and bribery, you can control the shadowy forces of corruption in your attempt to rule the <strong>Star Wars</strong> underworld.  Don’t just control the galaxy…corrupt it!<br><br>					<ul class="bb_ul"><li><strong>All new units and planets:</strong> Command over 28 new underworld units as well as new Rebel and Imperial forces and heroes on 13 new planets.<br>						</li><li><strong>Expanded Multiplayer:</strong> Experience all out, three-faction battles and now play the same side against itself with mirror play.<br>					</li></ul>','Command or corrupt an entire galaxy in the definitive Star Wars strategy collection. It is a time of galactic civil war. Will you take up the reins of the Rebellion, assume control of the Empire, or rule the Star Wars Underworld?');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32500,'The Star Wars® Saga continues with Star Wars®: The Force Unleashed™ II, the highly anticipated sequel to the fastest-selling Star Wars game ever created. In Star Wars: The Force Unleashed, the world was introduced to Darth Vader’s now fugitive apprentice, Starkiller—the unlikely hero who would ignite the flames of rebellion in a galaxy so desperately in need of a champion.<br><br>											In the sequel, Starkiller returns with over-the-top Force powers and embarks on a journey to discover his own identity and to reunite with his one true love, Juno Eclipse. In Star Wars: The Force Unleashed II, Starkiller is once again the pawn of Darth Vader—but instead of training his protégé as a ruthless assassin, the dark lord is attempting to clone his former apprentice in an attempt to create the Ultimate Sith warrior. The chase is on – Starkiller is in pursuit of Juno and Darth Vader is hunting for Starkiller.<br>											<br>											With all-new devastating Force powers and the ability to dual-wield lightsabers, Starkiller cuts a swath through deadly new enemies across exciting worlds from the Star Wars films - all in his desperate search for answers to his past.<br>											<br>											<strong>Key features:</strong><br>											<ul class="bb_ul"><li>Continue the galaxy-altering journey of Starkiller, Darth Vader''s fugitive apprentice, that shapes the key events between Star Wars: Episode III and Episode IV.<br>											</li><li>Unleash the Force with more power and precision through improved controls and new powers, such as the deceptive Mind Trick, which turns enemies against their allies.<br>											</li><li>Discover the true power of Starkiller with Force Fury, where his attacks and Force powers are exponentially increased.<br>											</li><li>Improved targeting system enhances precision use of Force powers and greater interaction with puzzles and the environment.<br>											</li><li>Take combat to the next level with the ability to wield dual lightsabers and punish enemies with all-new combo attacks.<br>											</li><li>Experience the most life-like interactions with Pixelux Entertainment''s Digital Molecular Matter (DMM) coupled with euphoria from Natural Motion Ltd and the powerful Havok Physics system.<br>											</li><li>Expanded customization options such as new costumes and power-enhancing lightsaber crystals.<br>											</li><li>Fight through all-new challenge levels designed to test and hone your fighting and Force power skills.<br>											</li><li>Skillfully manage your combat techniques to defeat a variety of brand-new enemies, which will culminate in epic boss battles.<br>											</li><li>Immerse yourself once again in the story that was honored with awards from the Writer''s Guild of America and the Academy of Interactive Arts and Sciences.<br>											</li></ul>','The Star Wars® Saga continues with Star Wars®: The Force Unleashed™ II, the highly anticipated sequel to the fastest-selling Star Wars game ever created. In Star Wars: The Force Unleashed, the world was introduced to Darth Vader’s now fugitive apprentice, Starkiller—the unlikely hero who would ignite the flames of rebellion in a galaxy so desperately in need of a champion.<br><br>											In the sequel, Starkiller returns with over-the-top Force powers and embarks on a journey to discover his own identity and to reunite with his one true love, Juno Eclipse. In Star Wars: The Force Unleashed II, Starkiller is once again the pawn of Darth Vader—but instead of training his protégé as a ruthless assassin, the dark lord is attempting to clone his former apprentice in an attempt to create the Ultimate Sith warrior. The chase is on – Starkiller is in pursuit of Juno and Darth Vader is hunting for Starkiller.<br>											<br>											With all-new devastating Force powers and the ability to dual-wield lightsabers, Starkiller cuts a swath through deadly new enemies across exciting worlds from the Star Wars films - all in his desperate search for answers to his past.<br>											<br>											<strong>Key features:</strong><br>											<ul class="bb_ul"><li>Continue the galaxy-altering journey of Starkiller, Darth Vader''s fugitive apprentice, that shapes the key events between Star Wars: Episode III and Episode IV.<br>											</li><li>Unleash the Force with more power and precision through improved controls and new powers, such as the deceptive Mind Trick, which turns enemies against their allies.<br>											</li><li>Discover the true power of Starkiller with Force Fury, where his attacks and Force powers are exponentially increased.<br>											</li><li>Improved targeting system enhances precision use of Force powers and greater interaction with puzzles and the environment.<br>											</li><li>Take combat to the next level with the ability to wield dual lightsabers and punish enemies with all-new combo attacks.<br>											</li><li>Experience the most life-like interactions with Pixelux Entertainment''s Digital Molecular Matter (DMM) coupled with euphoria from Natural Motion Ltd and the powerful Havok Physics system.<br>											</li><li>Expanded customization options such as new costumes and power-enhancing lightsaber crystals.<br>											</li><li>Fight through all-new challenge levels designed to test and hone your fighting and Force power skills.<br>											</li><li>Skillfully manage your combat techniques to defeat a variety of brand-new enemies, which will culminate in epic boss battles.<br>											</li><li>Immerse yourself once again in the story that was honored with awards from the Writer''s Guild of America and the Academy of Interactive Arts and Sciences.<br>											</li></ul>','The Star Wars® Saga continues with Star Wars®: The Force Unleashed™ II, the highly anticipated sequel to the fastest-selling Star Wars game ever created.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32510,'The beloved and critically acclaimed <strong>LEGO® Star Wars™</strong> franchise is back.  <strong>LEGO Star Wars III:The Clone Wars</strong>, combines the epic stories and iconic characters from the Star Wars universe and hit animated TV series <strong>Star Wars: The Clone Wars™</strong> with all new gameplay features.<br><br>						Players will enjoy brand new game mechanics allowing them to create, control and explore in a galaxy far, far away like never before.  Promising breathtaking visuals as well as new characters and levels, the game also features the signature tongue-in-cheek humor from the LEGO universe.  With over 20 story-based missions and 40 bonus levels spanning the entire Clone Wars era, <strong>LEGO Star Wars III:  The Clone Wars</strong> will allow fans to explore endlessly and laugh their way through the Star Wars galaxy in the most humorous, accessible and action-packed LEGO game to date.<br><br>						<h2 class="bb_tag">Product Information</h2>						<ul class="bb_ul"><li><strong>New Story</strong> – For the first time, players will experience their favorite stories from Star Wars: The Clone Wars, retold in the amazing LEGO world that fans know and love.<br>						</li><li><strong>Massive Ground Battles</strong> – Brand new to the LEGO Star Wars experience, players will take control of battalions of clone troopers against the relentless droid army - building bases, deploying vehicles and calling in reinforcements to defeat opponents.<br>						</li><li><strong>SceneSwap</strong> – Authentic to the Star Wars experience, a new feature allows players to take control of multiple teams in separate locations. Working together to complete various objectives, players will control each team through the press of a button, while playing in single player or in multiplayer co-op modes.<br>						</li><li><strong>All New Boss Battles</strong> – For the first time in the LEGO Star Wars franchise, fans will fight against massive bosses as seen in The Clone Wars animated series, including Gor, the epic Zillo Beast and many other favorites.<br>						</li><li><strong>Multi-Layered Space Battles</strong> – Players will be able to take off in their favorite ships to navigate and fly through multi-layered combat throughout the galaxy.<br>						</li><li><strong>New Combat Abilities</strong> – Characters will have more dynamic moves allowing players greater freedom to battle their opponents.  Characters will also have new lightsaber abilities including Lightsaber Cutting, Lightsaber Throwing, and Lightsaber Climbing.  The game will also feature new grappling abilities allowing players to climb their way through puzzles and defeat enemies.<br>						</li><li><strong>Explore the Galaxy</strong> – Players will be able to explore exotic locations in a variety of ships throughout 16 different star systems.  Fans will play as villainous Separatists, the noble Republic  heroes or even as bounty hunters, tracking down characters across the galaxy.  <br>						</li><li><strong>Expanded Force Abilities</strong> – Using the Force in all new ways to control LEGO objects, players will solve puzzles, access new areas, pick up and throw enemies - even turning them into weapons.    <br>						</li><li><strong>Brand New Clone Weapons, Vehicles and Characters</strong> – New clone weapons including rapid fire guns and rocket launchers, as well as all new massive capital ships to explore, such as Anakin Skywalker’s  flagship the Resolute and Grievous’ devastating warship , the Malevolence.    Players will also navigate through the galaxy in new vehicles such as the Republic gunship, Clone Turbo Tank and even Anakin’s Jedi Intercepter and the Twilight.  Fans will also  discover their favorite classic characters such as Darth Vader, Chewbacca and Luke Skywalker.<br>						</li><li><strong>Puzzle Solving</strong> – The game will feature all new puzzles that reward creative thinking through the use of teamwork and unique building situations only possible in a LEGO galaxy far, far away.  <br>						</li><li><strong>All new lighting and animations</strong> – A brand new engine brings characters to life, giving players a whole new level of control in a vibrant environment, unlike anything ever seen before in a LEGO game.  <br>						</li><li><strong>Split Screen</strong> – Improved dynamic split screen for multi-player co-op with jump in/jump out abilities for friends and families to play together.<br>						</li></ul>','The beloved and critically acclaimed <strong>LEGO® Star Wars™</strong> franchise is back.  <strong>LEGO Star Wars III:The Clone Wars</strong>, combines the epic stories and iconic characters from the Star Wars universe and hit animated TV series <strong>Star Wars: The Clone Wars™</strong> with all new gameplay features.<br><br>						Players will enjoy brand new game mechanics allowing them to create, control and explore in a galaxy far, far away like never before.  Promising breathtaking visuals as well as new characters and levels, the game also features the signature tongue-in-cheek humor from the LEGO universe.  With over 20 story-based missions and 40 bonus levels spanning the entire Clone Wars era, <strong>LEGO Star Wars III:  The Clone Wars</strong> will allow fans to explore endlessly and laugh their way through the Star Wars galaxy in the most humorous, accessible and action-packed LEGO game to date.<br><br>						<h2 class="bb_tag">Product Information</h2>						<ul class="bb_ul"><li><strong>New Story</strong> – For the first time, players will experience their favorite stories from Star Wars: The Clone Wars, retold in the amazing LEGO world that fans know and love.<br>						</li><li><strong>Massive Ground Battles</strong> – Brand new to the LEGO Star Wars experience, players will take control of battalions of clone troopers against the relentless droid army - building bases, deploying vehicles and calling in reinforcements to defeat opponents.<br>						</li><li><strong>SceneSwap</strong> – Authentic to the Star Wars experience, a new feature allows players to take control of multiple teams in separate locations. Working together to complete various objectives, players will control each team through the press of a button, while playing in single player or in multiplayer co-op modes.<br>						</li><li><strong>All New Boss Battles</strong> – For the first time in the LEGO Star Wars franchise, fans will fight against massive bosses as seen in The Clone Wars animated series, including Gor, the epic Zillo Beast and many other favorites.<br>						</li><li><strong>Multi-Layered Space Battles</strong> – Players will be able to take off in their favorite ships to navigate and fly through multi-layered combat throughout the galaxy.<br>						</li><li><strong>New Combat Abilities</strong> – Characters will have more dynamic moves allowing players greater freedom to battle their opponents.  Characters will also have new lightsaber abilities including Lightsaber Cutting, Lightsaber Throwing, and Lightsaber Climbing.  The game will also feature new grappling abilities allowing players to climb their way through puzzles and defeat enemies.<br>						</li><li><strong>Explore the Galaxy</strong> – Players will be able to explore exotic locations in a variety of ships throughout 16 different star systems.  Fans will play as villainous Separatists, the noble Republic  heroes or even as bounty hunters, tracking down characters across the galaxy.  <br>						</li><li><strong>Expanded Force Abilities</strong> – Using the Force in all new ways to control LEGO objects, players will solve puzzles, access new areas, pick up and throw enemies - even turning them into weapons.    <br>						</li><li><strong>Brand New Clone Weapons, Vehicles and Characters</strong> – New clone weapons including rapid fire guns and rocket launchers, as well as all new massive capital ships to explore, such as Anakin Skywalker’s  flagship the Resolute and Grievous’ devastating warship , the Malevolence.    Players will also navigate through the galaxy in new vehicles such as the Republic gunship, Clone Turbo Tank and even Anakin’s Jedi Intercepter and the Twilight.  Fans will also  discover their favorite classic characters such as Darth Vader, Chewbacca and Luke Skywalker.<br>						</li><li><strong>Puzzle Solving</strong> – The game will feature all new puzzles that reward creative thinking through the use of teamwork and unique building situations only possible in a LEGO galaxy far, far away.  <br>						</li><li><strong>All new lighting and animations</strong> – A brand new engine brings characters to life, giving players a whole new level of control in a vibrant environment, unlike anything ever seen before in a LEGO game.  <br>						</li><li><strong>Split Screen</strong> – Improved dynamic split screen for multi-player co-op with jump in/jump out abilities for friends and families to play together.<br>						</li></ul>','LEGO Star Wars III: The Clone Wars will allow fans to explore endlessly and laugh their way through the Star Wars galaxy in the most humorous, accessible and action-packed LEGO game to date.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32610,'Enemies lurk in locations around the globe, waiting for the right opportunity to strike. As part of Delta Force, the U.S. Army''s most secretive and highly trained unit, you have the skills and the firepower to hunt them down and take them out. Get ready to insert yourself into critical situations by air, land and sea, and show you have the courage to take the fight to the enemy and overcome overwhelming odds to achieve victory.<br>					In Delta Force: Xtreme 2, you''ll take control of Delta Force, employing the most dangerous and effective commando tactics and state-of-the-art weaponry at your disposal to defeat the enemy. Track enemies across a variety of expansive landscapes scattered across the globe in 10 single-player scenarios, and take them down with more than 20 real-world weapons. Insert into danger zones using dangerous HALO jumps, and use choppers, tanks and high-speed watercraft to roar into the midst of the action. Create your own exciting custom levels with the Battle Editor tool, and battle players from all over in five challenging online multiplayer game types.<br>					<h2 class="bb_tag">Features </h2>					<ul class="bb_ul"><li>Command the secretive, highly trained Delta Force and use commando tactics and state-of-the-art weapons to take out dangerous enemies <br>					</li><li>Insert yourself into the action by land, air and sea using choppers, tanks and high-speed watercraft <br>					</li><li>Experience realistic, accurate and deadly shooting via enhanced ballistics <br>					</li><li>Employ the powerful and easy-to-use MED level editor to create custom levels or recreate historical fights <br>					</li><li>Customize urban, jungle and mountain environments using 10 new and 20 classic highly detailed terrains <br>					</li><li>Add dynamic weather effects and real-time lighting as well as thousands of objects and buildings to create a realistic environment <br>					</li><li>Up to 64 players may battle online in Deathmatch, Team Deathmatch, Capture the Flag, Team King of the Hill and Flagball multiplayer games <br>					</li><li>Experience a fair fight every time using the game''s anticheat technology, and see how you measure up with persistent stats that track your performance <br>					</li><li>Assemble an impressive squad and manage it via the new NovaWorld Community <br>					</li></ul>','Enemies lurk in locations around the globe, waiting for the right opportunity to strike. As part of Delta Force, the U.S. Army''s most secretive and highly trained unit, you have the skills and the firepower to hunt them down and take them out. Get ready to insert yourself into critical situations by air, land and sea, and show you have the courage to take the fight to the enemy and overcome overwhelming odds to achieve victory.<br>					In Delta Force: Xtreme 2, you''ll take control of Delta Force, employing the most dangerous and effective commando tactics and state-of-the-art weaponry at your disposal to defeat the enemy. Track enemies across a variety of expansive landscapes scattered across the globe in 10 single-player scenarios, and take them down with more than 20 real-world weapons. Insert into danger zones using dangerous HALO jumps, and use choppers, tanks and high-speed watercraft to roar into the midst of the action. Create your own exciting custom levels with the Battle Editor tool, and battle players from all over in five challenging online multiplayer game types.<br>					<h2 class="bb_tag">Features </h2>					<ul class="bb_ul"><li>Command the secretive, highly trained Delta Force and use commando tactics and state-of-the-art weapons to take out dangerous enemies <br>					</li><li>Insert yourself into the action by land, air and sea using choppers, tanks and high-speed watercraft <br>					</li><li>Experience realistic, accurate and deadly shooting via enhanced ballistics <br>					</li><li>Employ the powerful and easy-to-use MED level editor to create custom levels or recreate historical fights <br>					</li><li>Customize urban, jungle and mountain environments using 10 new and 20 classic highly detailed terrains <br>					</li><li>Add dynamic weather effects and real-time lighting as well as thousands of objects and buildings to create a realistic environment <br>					</li><li>Up to 64 players may battle online in Deathmatch, Team Deathmatch, Capture the Flag, Team King of the Hill and Flagball multiplayer games <br>					</li><li>Experience a fair fight every time using the game''s anticheat technology, and see how you measure up with persistent stats that track your performance <br>					</li><li>Assemble an impressive squad and manage it via the new NovaWorld Community <br>					</li></ul>','Enemies lurk in locations around the globe, waiting for the right opportunity to strike. As part of Delta Force, the U.S. Army''s most secretive and highly trained unit, you have the skills and the firepower to hunt them down and take them out.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32620,'As a member of Delta Force — The Army''s Elite, top secret special forces unit — the word ''impossible'' is not in your vocabulary. In Delta Force, you will conduct missions swiftly and silently, in every possible terrain, under every imaginable condition and through unconventional means.<br>					Features<br>					<ul class="bb_ul"><li>Immersive environment consists of real-world effects, such as bridges that creak, insects that buzz, flocks of birds that form and re-form, and fish that bite. <br>					</li><li>Watch your enemy''s every move, listen for their approach then strike with brutal precision over the most heartbreaking pieces of terrain the world has ever seen. <br>					</li><li>Play in either 1st or 3rd person across miles and miles of vast outdoor environments. Engage the enemy over unprecedented distances. <br>					</li><li>Play over 40 gut-wrenching missions across five continents ranging from airfield takedowns in Central Asia to clearing out S. American cartels to stopping Nuclear terrorism in Northern Russia. <br>					</li></ul>','As a member of Delta Force — The Army''s Elite, top secret special forces unit — the word ''impossible'' is not in your vocabulary. In Delta Force, you will conduct missions swiftly and silently, in every possible terrain, under every imaginable condition and through unconventional means.<br>					Features<br>					<ul class="bb_ul"><li>Immersive environment consists of real-world effects, such as bridges that creak, insects that buzz, flocks of birds that form and re-form, and fish that bite. <br>					</li><li>Watch your enemy''s every move, listen for their approach then strike with brutal precision over the most heartbreaking pieces of terrain the world has ever seen. <br>					</li><li>Play in either 1st or 3rd person across miles and miles of vast outdoor environments. Engage the enemy over unprecedented distances. <br>					</li><li>Play over 40 gut-wrenching missions across five continents ranging from airfield takedowns in Central Asia to clearing out S. American cartels to stopping Nuclear terrorism in Northern Russia. <br>					</li></ul>','As a member of Delta Force — The Army''s Elite, top secret special forces unit — the word ''impossible'' is not in your vocabulary. In Delta Force, you will conduct missions swiftly and silently, in every possible terrain, under every imaginable condition and through unconventional means.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32630,'You''re a member of the U.S. Army''s best kept secret: the elite SPECIAL OPERATIONS unit known as Delta Force, formed to BATTLE TERRORISM throughout the world. When the best of the rest can''t handle the op, YOU are called into action. Can you handle THE JOB?<br><br>					<h2 class="bb_tag">Features</h2> 					<ul class="bb_ul"><li><strong>FREE NovaWorld™:</strong> online gaming supporting up to 50 players. <br>					</li><li><strong>APPROACH THE OBJECTIVE</strong> via parachute and use tall grass, water, and rolling terrain to move undetected. <br>					</li><li><strong>TAKE CHARGE</strong> with the new Commander''s Screen, directing your teammates in single and multiplayer action. <br>					</li><li><strong>CREATE YOUR OWN</strong> single or multiplayer battles with the Mission Editor PLUS Over 40 new missions. <br>					</li><li><strong>TERRORIZE THE TERRORISTS</strong> with new weapons, new equipment, and fixed machine gun and grenade-launcher emplacements. <br>					</li></ul>','You''re a member of the U.S. Army''s best kept secret: the elite SPECIAL OPERATIONS unit known as Delta Force, formed to BATTLE TERRORISM throughout the world. When the best of the rest can''t handle the op, YOU are called into action. Can you handle THE JOB?<br><br>					<h2 class="bb_tag">Features</h2> 					<ul class="bb_ul"><li><strong>FREE NovaWorld™:</strong> online gaming supporting up to 50 players. <br>					</li><li><strong>APPROACH THE OBJECTIVE</strong> via parachute and use tall grass, water, and rolling terrain to move undetected. <br>					</li><li><strong>TAKE CHARGE</strong> with the new Commander''s Screen, directing your teammates in single and multiplayer action. <br>					</li><li><strong>CREATE YOUR OWN</strong> single or multiplayer battles with the Mission Editor PLUS Over 40 new missions. <br>					</li><li><strong>TERRORIZE THE TERRORISTS</strong> with new weapons, new equipment, and fixed machine gun and grenade-launcher emplacements. <br>					</li></ul>','You''re a member of the U.S. Army''s best kept secret: the elite SPECIAL OPERATIONS unit known as Delta Force, formed to BATTLE TERRORISM throughout the world. When the best of the rest can''t handle the op, YOU are called into action. Can you handle THE JOB? Features FREE NovaWorld™: online gaming supporting up to 50 players.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32640,'Engage the enemy across vast outdoor environments and expansive indoor environments as you take control of the US Army''s elite anti-terrorist unit. Delta Force Land Warrior™ introduces new weapons and characters for both single player and intense online multiplayer via NovaWorld.<br>					<ul class="bb_ul"><li>Select from a team of diverse characters, each with their own special abilities. (Sniper, Demolitions, Close Quarters Battle, Aquatics and Heavey Gunner)<br>					</li><li>Advanced new rifles, systems, machine guns and grenade launcher <br>					</li><li>Developed from the same engine used to train the US ARMY elite Land Warrior Soldiers <br>					</li><li>Wage war on the massive battlefields of NovaWorld with up to 50 players simultaneously<br>					</li><li>Rank Yourself against your enemies and allies on NovaWorld<br>					</li></ul>','Engage the enemy across vast outdoor environments and expansive indoor environments as you take control of the US Army''s elite anti-terrorist unit. Delta Force Land Warrior™ introduces new weapons and characters for both single player and intense online multiplayer via NovaWorld.<br>					<ul class="bb_ul"><li>Select from a team of diverse characters, each with their own special abilities. (Sniper, Demolitions, Close Quarters Battle, Aquatics and Heavey Gunner)<br>					</li><li>Advanced new rifles, systems, machine guns and grenade launcher <br>					</li><li>Developed from the same engine used to train the US ARMY elite Land Warrior Soldiers <br>					</li><li>Wage war on the massive battlefields of NovaWorld with up to 50 players simultaneously<br>					</li><li>Rank Yourself against your enemies and allies on NovaWorld<br>					</li></ul>','Engage the enemy across vast outdoor environments and expansive indoor environments as you take control of the US Army''s elite anti-terrorist unit. Delta Force Land Warrior™ introduces new weapons and characters for both single player and intense online multiplayer via NovaWorld.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32650,'As the US army''s elite special operations soldiers you are the most potent ''smart weapon'' known to man. You are the ''tip of the spear'' for covert operations around the world — you are the first line of attack. Nothing stands in your way. From the war torn streets of Somalia you have been re-deployed to take out targets in Colombia and Iran. As the US military''s preemptive strike force you must work with your team to get the job done.<br>					<h2 class="bb_tag">Features </h2>					<ul class="bb_ul"><li><strong>BECOME THE BEST</strong> — Play as any one of these Special Forces units: SFOD-Delta, 2/75th RANGER, SEAL Team 6, SFOD-SF Viper Team (Green Berets), CIA Special Operations, UK SAS 22 Regiment, Australian SASR, Canadian JTF-2, Marines Force Recon, and USAF CSAR (Air Force Pararescue) — all the actual Special Forces units deployed in Operation Enduring Freedom.<br>					</li><li><strong>INFILTRATE ACTUAL LOCATIONS</strong> — 25 new Delta Force missions! Take over the Kandahar Airport, raid rebel headquarters in Mazar-e-Sharif, ambush a convoy near the Pakistani border and demolish bunkers in the foothills of Kabul.<br>					</li><li><strong>OVER 30 WEAPONS TO CHOOSE FROM</strong> — Gear up with a huge arsenal of machine guns, assault rifles, sniper rifles, pistols and rocket launchers new to the Delta Force series.<br>					</li><li><strong>SPY ON THE ENEMY</strong> — Plan your attack with the element of surprise using visual intelligence gathered from Unmanned Aerial Vehicles.<br>					</li><li><strong>RAIN DESTRUCTION FROM THE SKIES</strong> — Call in devastating air strikes to take out key SAM and SCUD missile sites.<br>					</li><li><strong>LARGE-SCALE MULTIPLAYER</strong> — Create your own multiplayer games and maps with the mission editor. 10 new multiplayer maps included! *Battle online via NovaWorld.<br>					</li></ul>','As the US army''s elite special operations soldiers you are the most potent ''smart weapon'' known to man. You are the ''tip of the spear'' for covert operations around the world — you are the first line of attack. Nothing stands in your way. From the war torn streets of Somalia you have been re-deployed to take out targets in Colombia and Iran. As the US military''s preemptive strike force you must work with your team to get the job done.<br>					<h2 class="bb_tag">Features </h2>					<ul class="bb_ul"><li><strong>BECOME THE BEST</strong> — Play as any one of these Special Forces units: SFOD-Delta, 2/75th RANGER, SEAL Team 6, SFOD-SF Viper Team (Green Berets), CIA Special Operations, UK SAS 22 Regiment, Australian SASR, Canadian JTF-2, Marines Force Recon, and USAF CSAR (Air Force Pararescue) — all the actual Special Forces units deployed in Operation Enduring Freedom.<br>					</li><li><strong>INFILTRATE ACTUAL LOCATIONS</strong> — 25 new Delta Force missions! Take over the Kandahar Airport, raid rebel headquarters in Mazar-e-Sharif, ambush a convoy near the Pakistani border and demolish bunkers in the foothills of Kabul.<br>					</li><li><strong>OVER 30 WEAPONS TO CHOOSE FROM</strong> — Gear up with a huge arsenal of machine guns, assault rifles, sniper rifles, pistols and rocket launchers new to the Delta Force series.<br>					</li><li><strong>SPY ON THE ENEMY</strong> — Plan your attack with the element of surprise using visual intelligence gathered from Unmanned Aerial Vehicles.<br>					</li><li><strong>RAIN DESTRUCTION FROM THE SKIES</strong> — Call in devastating air strikes to take out key SAM and SCUD missile sites.<br>					</li><li><strong>LARGE-SCALE MULTIPLAYER</strong> — Create your own multiplayer games and maps with the mission editor. 10 new multiplayer maps included! *Battle online via NovaWorld.<br>					</li></ul>','As the US army''s elite special operations soldiers you are the most potent ''smart weapon'' known to man. You are the ''tip of the spear'' for covert operations around the world — you are the first line of attack. Nothing stands in your way.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32660,'Powered by today''s gaming technology, Delta Force®: Xtreme™ brings the classic Delta Force game back to life to face the enemy once more. As a member of the elite Delta Force, prepare yourself to take on over 60 levels of frantic single and multiplayer FPS action, including graphically enhanced missions from the original game, new maps, improved game features, STATS and much more!<br>					<h2 class="bb_tag">Features </h2>					<ul class="bb_ul"><li>Over 60 levels of combat to test your CQB and long range engagement skills as a Delta Force Operator. <br>					</li><li>As a member of the elite Delta Force re-deploy in over 20 graphically enhanced single player missions — the best of the best from the original game. <br>					</li><li>Additional new single player missions created especially for Delta Force®: Xtreme™ add a new challenge for hardened Delta Operators. <br>					</li><li>Take your friends into battle in over 20 co-operative missions. <br>					</li><li>Over 20 multiplayer levels include: Deathmatch, King of the Hill, Team King of the Hill, Team Deathmatch and Capture the Flag game modes. <br>					</li><li>STAT tracking — you can now see how good you are compared to every other Delta Force Operator out there and watch your rankings climb as your skills improve! <br>					</li></ul>','Powered by today''s gaming technology, Delta Force®: Xtreme™ brings the classic Delta Force game back to life to face the enemy once more. As a member of the elite Delta Force, prepare yourself to take on over 60 levels of frantic single and multiplayer FPS action, including graphically enhanced missions from the original game, new maps, improved game features, STATS and much more!<br>					<h2 class="bb_tag">Features </h2>					<ul class="bb_ul"><li>Over 60 levels of combat to test your CQB and long range engagement skills as a Delta Force Operator. <br>					</li><li>As a member of the elite Delta Force re-deploy in over 20 graphically enhanced single player missions — the best of the best from the original game. <br>					</li><li>Additional new single player missions created especially for Delta Force®: Xtreme™ add a new challenge for hardened Delta Operators. <br>					</li><li>Take your friends into battle in over 20 co-operative missions. <br>					</li><li>Over 20 multiplayer levels include: Deathmatch, King of the Hill, Team King of the Hill, Team Deathmatch and Capture the Flag game modes. <br>					</li><li>STAT tracking — you can now see how good you are compared to every other Delta Force Operator out there and watch your rankings climb as your skills improve! <br>					</li></ul>','Powered by today''s gaming technology, Delta Force®: Xtreme™ brings the classic Delta Force game back to life to face the enemy once more. As a member of the elite Delta Force, prepare yourself to take on over 60 levels of frantic single and multiplayer FPS action, including graphically enhanced missions from the original game, new maps,...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32670,'In late 1993, the United States launched dual military operations in Mogadishu Somalia. Delta Force Operatives and Army Rangers were sent in to capture Somali warlords and restore order. Experience the intense combat of Operation Restore Hope in this ground breaking first person shooter. As a Delta Force operative participate in a number of daring and intense raids against the oppressive Somali warlords in and around Mogadishu. <br>					<h2 class="bb_tag">Features</h2> 					<ul class="bb_ul"><li>Engage in Close Quarters Battle in a maze of city streets or snipe across the plain with Delta Force''s signature long-range engagements <br>					</li><li>Open fire from heavy weapons mounted in Black Hawk helicopters or on Military Vehicles <br>					</li><li>Gear up with an arsenal of authentically modeled weapons used in the streets of Mogadishu <br>					</li><li>New AI system drives unprecedented teamwork with your fellow soldiers and enemies that skillfully hunt you down <br>					</li><li>Fight through a variety of compelling missions, each with multiple objectives <br>					</li><li>Nonstop, large-scale multiplayer action over LAN or via NovaWorld <br>					</li><li>Powered by a new game engine optimized to showcase the latest 3D graphics and processor technology <br>					</li><li>Developed with direction from Special Operations Forces advisors on realistic tactics, situations and details <br>					</li></ul>','In late 1993, the United States launched dual military operations in Mogadishu Somalia. Delta Force Operatives and Army Rangers were sent in to capture Somali warlords and restore order. Experience the intense combat of Operation Restore Hope in this ground breaking first person shooter. As a Delta Force operative participate in a number of daring and intense raids against the oppressive Somali warlords in and around Mogadishu. <br>					<h2 class="bb_tag">Features</h2> 					<ul class="bb_ul"><li>Engage in Close Quarters Battle in a maze of city streets or snipe across the plain with Delta Force''s signature long-range engagements <br>					</li><li>Open fire from heavy weapons mounted in Black Hawk helicopters or on Military Vehicles <br>					</li><li>Gear up with an arsenal of authentically modeled weapons used in the streets of Mogadishu <br>					</li><li>New AI system drives unprecedented teamwork with your fellow soldiers and enemies that skillfully hunt you down <br>					</li><li>Fight through a variety of compelling missions, each with multiple objectives <br>					</li><li>Nonstop, large-scale multiplayer action over LAN or via NovaWorld <br>					</li><li>Powered by a new game engine optimized to showcase the latest 3D graphics and processor technology <br>					</li><li>Developed with direction from Special Operations Forces advisors on realistic tactics, situations and details <br>					</li></ul>','In late 1993, the United States launched dual military operations in Mogadishu Somalia. Delta Force Operatives and Army Rangers were sent in to capture Somali warlords and restore order. Experience the intense combat of Operation Restore Hope in this ground breaking first person shooter.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32680,'Delta Force — Black Hawk Down: Team Sabre is the official expansion pack to the #1 best selling PC game in North America. Team Sabre was developed using the Delta Force — Black Hawk Down engine and it requires the mother product to run. <br>					The game is a military-based shooter but the missions are fictitious and not based on any actual real events.  The expansion follows the Team Sabre Squadron as they are deployed to take out targets and carry out mission objectives in two separate single player campaigns (*approximately 5 missions each) that take place in Columbia and Iran.  The multiplayer feature boasts 30 new maps and an enhanced level of mod support for players to build their own unique maps. <br>					The highlight of this expansion pack is that it features lush jungle terrain, never seen before to this extent in a Delta Force game.  This also adds an exciting element to gameplay in both the single and multiplayer game.<br>					<br>					<h2 class="bb_tag">Feature Breakdown</h2>					<ul class="bb_ul"><li>2 all new single player campaigns that take place in treacherous South American jungle terrain and across islands in the Persian Gulf. <br>					</li><li>New Weapons &amp; Vehicles: Select from 24 weapons to achieve your mission objectives, including 3 new to the series, the H&amp;K G3A3, H&amp;K G36E and the H&amp;K PSG1 Sniper Rifle. New modes of transport include the MH-53M PaveLow IV helicopter and the RHIB Rigid Hull Inflatable Boat. <br>					</li><li>Free unrivaled multiplayer mayhem — up to 64 players via NovaWorld and up to 50 players on a LAN (tbd). <br>					</li><li>30 new multiplayer maps. <br>					</li><li>Uses an enhanced version of the Delta Force — Black Hawk Down engine with mod-support features for building unique multiplayer battlefields. <br>					</li><li>A portion of the proceeds will be donated to the Warrior Foundation <br>					</li></ul>','Delta Force — Black Hawk Down: Team Sabre is the official expansion pack to the #1 best selling PC game in North America. Team Sabre was developed using the Delta Force — Black Hawk Down engine and it requires the mother product to run. <br>					The game is a military-based shooter but the missions are fictitious and not based on any actual real events.  The expansion follows the Team Sabre Squadron as they are deployed to take out targets and carry out mission objectives in two separate single player campaigns (*approximately 5 missions each) that take place in Columbia and Iran.  The multiplayer feature boasts 30 new maps and an enhanced level of mod support for players to build their own unique maps. <br>					The highlight of this expansion pack is that it features lush jungle terrain, never seen before to this extent in a Delta Force game.  This also adds an exciting element to gameplay in both the single and multiplayer game.<br>					<br>					<h2 class="bb_tag">Feature Breakdown</h2>					<ul class="bb_ul"><li>2 all new single player campaigns that take place in treacherous South American jungle terrain and across islands in the Persian Gulf. <br>					</li><li>New Weapons &amp; Vehicles: Select from 24 weapons to achieve your mission objectives, including 3 new to the series, the H&amp;K G3A3, H&amp;K G36E and the H&amp;K PSG1 Sniper Rifle. New modes of transport include the MH-53M PaveLow IV helicopter and the RHIB Rigid Hull Inflatable Boat. <br>					</li><li>Free unrivaled multiplayer mayhem — up to 64 players via NovaWorld and up to 50 players on a LAN (tbd). <br>					</li><li>30 new multiplayer maps. <br>					</li><li>Uses an enhanced version of the Delta Force — Black Hawk Down engine with mod-support features for building unique multiplayer battlefields. <br>					</li><li>A portion of the proceeds will be donated to the Warrior Foundation <br>					</li></ul>','Delta Force — Black Hawk Down: Team Sabre is the official expansion pack to the #1 best selling PC game in North America. Team Sabre was developed using the Delta Force — Black Hawk Down engine and it requires the mother product to run.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32710,'Command an entire fleet of M1A2 Abrams tanks in this brutal third installment in the Armored Fist series. Using the latest Abrams technology, the game presents the esteemed tank in its up-to-date form which is designed to survive biological, nuclear, and chemical warfare. You''ll first take control of a four-man tank, eventually tackling four major campaigns. Set over the course of 50 smaller missions, the campaigns will take you to such troubled lands as Somalia, Thailand, Afghanistan, Pakistan, Myanmar, and the Republic of Georgia. The game''s five modes of play include solo and co-op entries.<br>					Features<br>					<ul class="bb_ul"><li>Crush Vehicles and Buildings as the M1A2 rolls over obstacles with impunity, leaving only the track of its tread path behind.<br>					</li><li>Coordinate and deploy strategic enemy strikes using artillery, air support, and ground troops.<br>					</li><li>Authentic M1A2 Crew Station Images allow you to control the Abrams Tank from either commander, gunner or driver positions with actual working switches and controls.<br>					</li><li>Over 50 Gripping Innovative Missions — Destroy a terrorist compound, rescue an allied tank platoon, and defend your base from enemy attack.<br>					</li><li>Devastate hordes of advanced AI infantry with your turret mounted M2 50 Caliber machine-gun or simply run em'' over with your 70 tons of rolling steel.<br>					</li><li>Integrated Voice-Over-Net allows you to quickly coordinate your team''s attacks on the multiplayer battlefields of NovaWorld™. If you''re typing, you''re dying.<br>					</li></ul>','Command an entire fleet of M1A2 Abrams tanks in this brutal third installment in the Armored Fist series. Using the latest Abrams technology, the game presents the esteemed tank in its up-to-date form which is designed to survive biological, nuclear, and chemical warfare. You''ll first take control of a four-man tank, eventually tackling four major campaigns. Set over the course of 50 smaller missions, the campaigns will take you to such troubled lands as Somalia, Thailand, Afghanistan, Pakistan, Myanmar, and the Republic of Georgia. The game''s five modes of play include solo and co-op entries.<br>					Features<br>					<ul class="bb_ul"><li>Crush Vehicles and Buildings as the M1A2 rolls over obstacles with impunity, leaving only the track of its tread path behind.<br>					</li><li>Coordinate and deploy strategic enemy strikes using artillery, air support, and ground troops.<br>					</li><li>Authentic M1A2 Crew Station Images allow you to control the Abrams Tank from either commander, gunner or driver positions with actual working switches and controls.<br>					</li><li>Over 50 Gripping Innovative Missions — Destroy a terrorist compound, rescue an allied tank platoon, and defend your base from enemy attack.<br>					</li><li>Devastate hordes of advanced AI infantry with your turret mounted M2 50 Caliber machine-gun or simply run em'' over with your 70 tons of rolling steel.<br>					</li><li>Integrated Voice-Over-Net allows you to quickly coordinate your team''s attacks on the multiplayer battlefields of NovaWorld™. If you''re typing, you''re dying.<br>					</li></ul>','Command an entire fleet of M1A2 Abrams tanks in this brutal third installment in the Armored Fist series. Using the latest Abrams technology, the game presents the esteemed tank in its up-to-date form which is designed to survive biological, nuclear, and chemical warfare.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32720,'With innovative technologies such as fly-by-wire controls, sophisticated systems for night and all-weather operations and the ability to carry a variety of weapons, the F-16 continually proves to be the workhorse of the USAF. Victorious in all of its air-to-air engagements, the awesome reputation of the F-16 is undisputed.<br>					Features <br>					<ul class="bb_ul"><li>Authentic Lockheed Martin approved flight model and avionics <br>					</li><li>Flight tested by Lockheed Martin F-16 Chief Test Pilot, John Fergione <br>					</li><li>Get airborne and begin combat in minutes <br>					</li><li>Fast 3Dfx™ support, up to 1024 x 768 with Voodoo2™ [Incredible with SLI] <br>					</li><li>Fully interactive 3D virtual cockpit accurately reflects the F-16''s current conditions and can be viewed at any time <br>					</li><li>40 single player missions plus 12 multiplayer missions - 6 deathmatch and 6 A.W. (Air War) cooperative missions <br>					</li><li>Mission design tool to create your own scenarios and share them with friends <br>					</li><li>Use F-16''s LANTIRN for night vision and precision bombings <br>					</li><li>6 degrees of freedom graphics system for unrestricted views of the action <br>					</li><li>FREE Large-scale Internet play via NovaWorld — go head-to-head with over 120 F-16 Multirole Fighters, MiG-29 Fulcrums and F-22 Raptors in one arena <br>					</li></ul>','With innovative technologies such as fly-by-wire controls, sophisticated systems for night and all-weather operations and the ability to carry a variety of weapons, the F-16 continually proves to be the workhorse of the USAF. Victorious in all of its air-to-air engagements, the awesome reputation of the F-16 is undisputed.<br>					Features <br>					<ul class="bb_ul"><li>Authentic Lockheed Martin approved flight model and avionics <br>					</li><li>Flight tested by Lockheed Martin F-16 Chief Test Pilot, John Fergione <br>					</li><li>Get airborne and begin combat in minutes <br>					</li><li>Fast 3Dfx™ support, up to 1024 x 768 with Voodoo2™ [Incredible with SLI] <br>					</li><li>Fully interactive 3D virtual cockpit accurately reflects the F-16''s current conditions and can be viewed at any time <br>					</li><li>40 single player missions plus 12 multiplayer missions - 6 deathmatch and 6 A.W. (Air War) cooperative missions <br>					</li><li>Mission design tool to create your own scenarios and share them with friends <br>					</li><li>Use F-16''s LANTIRN for night vision and precision bombings <br>					</li><li>6 degrees of freedom graphics system for unrestricted views of the action <br>					</li><li>FREE Large-scale Internet play via NovaWorld — go head-to-head with over 120 F-16 Multirole Fighters, MiG-29 Fulcrums and F-22 Raptors in one arena <br>					</li></ul>','With innovative technologies such as fly-by-wire controls, sophisticated systems for night and all-weather operations and the ability to carry a variety of weapons, the F-16 continually proves to be the workhorse of the USAF. Victorious in all of its air-to-air engagements, the awesome reputation of the F-16 is undisputed.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32730,'Mass Destruction! Use tactical nuclear weapons to level entire city regions. The most realistic weather environments ever created. Changing weather effects including: rain, snow, hail, and wind. Extreme temperatures affect flight performance. Fly it yourself or let the world''s most advanced fighter do it for you!<br>					Features <br>					<ul class="bb_ul"><li>Extreme temperatures affect flight performance. <br>					</li><li>Changing weather effects including: rain, snow, hail, and wind. <br>					</li><li>Fly it yourself or use the Auto-Options: Auto-landings, Auto-taxi, Auto-takeoff, Auto-shoot list, Auto-formation, Auto-in-flight refueling. <br>					</li><li>The most realistic weather environments ever created. <br>					</li><li>Mass Destruction! Use tactical nuclear weapons to level entire city regions. <br>					</li><li>Voice-Over-Net technology allows players to talk to each other during Novaworld multiplayer combat. <br>					</li></ul>','Mass Destruction! Use tactical nuclear weapons to level entire city regions. The most realistic weather environments ever created. Changing weather effects including: rain, snow, hail, and wind. Extreme temperatures affect flight performance. Fly it yourself or let the world''s most advanced fighter do it for you!<br>					Features <br>					<ul class="bb_ul"><li>Extreme temperatures affect flight performance. <br>					</li><li>Changing weather effects including: rain, snow, hail, and wind. <br>					</li><li>Fly it yourself or use the Auto-Options: Auto-landings, Auto-taxi, Auto-takeoff, Auto-shoot list, Auto-formation, Auto-in-flight refueling. <br>					</li><li>The most realistic weather environments ever created. <br>					</li><li>Mass Destruction! Use tactical nuclear weapons to level entire city regions. <br>					</li><li>Voice-Over-Net technology allows players to talk to each other during Novaworld multiplayer combat. <br>					</li></ul>','Mass Destruction! Use tactical nuclear weapons to level entire city regions. The most realistic weather environments ever created. Changing weather effects including: rain, snow, hail, and wind. Extreme temperatures affect flight performance. Fly it yourself or let the world''s most advanced fighter do it for you!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32740,'The Mikoyan-Gurevich MiG-29 Fulcrum is one of the world''s most maneuverable and toughest fighter jets and has often been compared to its closest Western counterpart, the F-16. Innovations unique to the aircraft allow MiG pilots to perform remarkable moves like the Tailslide and Cobra maneuvers. Exported to nearly 20 air forces, the MiG-29 continues to be a formidable world presence in the struggle for air-superiority.<br>					Features<br>					<ul class="bb_ul"><li>Authentic MiG-29 flight model developed with the assistance of Yuri Prikhodko, Russian MiG-29 test pilot/cosmonaut <br>					</li><li>Fast and furious combat with high definition graphics [1024 x 768 resolution with Voodoo2™ — incredible with SLI] <br>					</li><li>Highly detailed interactive cockpit <br>					</li><li>40 single player missions plus 12 multiplayer missions — 6 deathmatch and 6 A.W. (Air War) cooperative missions <br>					</li><li>MiG-29 Fulcrum mission design tool to create your own sorties <br>					</li><li>8 different camera views for exceptional situational awareness <br>					</li><li>Stunningly realistic landscapes <br>					</li><li>FREE Large-scale Internet play via NovaWorld — go head-to-head with over 120 F-16 Multirole Fighters, MiG-29 Fulcrums and F-22 Raptors in one arena <br>					</li></ul>','The Mikoyan-Gurevich MiG-29 Fulcrum is one of the world''s most maneuverable and toughest fighter jets and has often been compared to its closest Western counterpart, the F-16. Innovations unique to the aircraft allow MiG pilots to perform remarkable moves like the Tailslide and Cobra maneuvers. Exported to nearly 20 air forces, the MiG-29 continues to be a formidable world presence in the struggle for air-superiority.<br>					Features<br>					<ul class="bb_ul"><li>Authentic MiG-29 flight model developed with the assistance of Yuri Prikhodko, Russian MiG-29 test pilot/cosmonaut <br>					</li><li>Fast and furious combat with high definition graphics [1024 x 768 resolution with Voodoo2™ — incredible with SLI] <br>					</li><li>Highly detailed interactive cockpit <br>					</li><li>40 single player missions plus 12 multiplayer missions — 6 deathmatch and 6 A.W. (Air War) cooperative missions <br>					</li><li>MiG-29 Fulcrum mission design tool to create your own sorties <br>					</li><li>8 different camera views for exceptional situational awareness <br>					</li><li>Stunningly realistic landscapes <br>					</li><li>FREE Large-scale Internet play via NovaWorld — go head-to-head with over 120 F-16 Multirole Fighters, MiG-29 Fulcrums and F-22 Raptors in one arena <br>					</li></ul>','The Mikoyan-Gurevich MiG-29 Fulcrum is one of the world''s most maneuverable and toughest fighter jets and has often been compared to its closest Western counterpart, the F-16. Innovations unique to the aircraft allow MiG pilots to perform remarkable moves like the Tailslide and Cobra maneuvers.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32750,'The best-selling Comanche series returns with this fast-paced action game that places you at the controls of a Comanche RAH-66 helicopter. In 6 single player campaigns and multiplayer, the game combines serious firepower with effortless controls and stunning, interactive terrain.<br>					Features <br>					<ul class="bb_ul"><li><strong>NON-STOP ASSAULT</strong> — Blast away at tanks, jets, aircraft carriers, helicopters, missile-launching troops and more. <br>					</li><li><strong>UNLEASH THE POWER</strong> — Shoot Hellfire and Stinger missiles, rockets and a 20mm cannon. <br>					</li><li><strong>AIRBORNE IN MINUTES</strong> — Quickly master flying and fighting using the keyboard &amp; mouse, or for the sim fan, joystick, throttle &amp; pedal controls. <br>					</li><li><strong>STUNNING INTERACTIVE TERRAIN</strong> — Immerse yourself in detailed environments with rotor wash, shadows, terrain scarring and spectacular explosions. <br>					</li><li><strong>6 EXTREME CAMPAIGNS</strong> — Fly across urban, forest, arctic, desert and sea environments while you protect diplomats, support Delta Force, subdue renegade forces, attack warships and more. <br>					</li></ul>','The best-selling Comanche series returns with this fast-paced action game that places you at the controls of a Comanche RAH-66 helicopter. In 6 single player campaigns and multiplayer, the game combines serious firepower with effortless controls and stunning, interactive terrain.<br>					Features <br>					<ul class="bb_ul"><li><strong>NON-STOP ASSAULT</strong> — Blast away at tanks, jets, aircraft carriers, helicopters, missile-launching troops and more. <br>					</li><li><strong>UNLEASH THE POWER</strong> — Shoot Hellfire and Stinger missiles, rockets and a 20mm cannon. <br>					</li><li><strong>AIRBORNE IN MINUTES</strong> — Quickly master flying and fighting using the keyboard &amp; mouse, or for the sim fan, joystick, throttle &amp; pedal controls. <br>					</li><li><strong>STUNNING INTERACTIVE TERRAIN</strong> — Immerse yourself in detailed environments with rotor wash, shadows, terrain scarring and spectacular explosions. <br>					</li><li><strong>6 EXTREME CAMPAIGNS</strong> — Fly across urban, forest, arctic, desert and sea environments while you protect diplomats, support Delta Force, subdue renegade forces, attack warships and more. <br>					</li></ul>','The best-selling Comanche series returns with this fast-paced action game that places you at the controls of a Comanche RAH-66 helicopter. In 6 single player campaigns and multiplayer, the game combines serious firepower with effortless controls and stunning, interactive terrain.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32760,'Caught in the middle of a violent conflict on the fringe of the galaxy — your ability to survive will depend on your piloting skills and combat savvy as a mercenary space fighter. But, as you explore the vastly detailed world of Tachyon: The Fringe, you will often find that the most powerful weapon on your ship is in your head.<br>					Features <br>					<ul class="bb_ul"><li>Single Player Features — Decide where you want to go and what missions you will fly as you explore the vast and richly inhabited universe. <br>					</li><li>Fight in furious space combat battles around the most massive ships and stations ever created in a space game. <br>					</li><li>Explore a multi-sided in-game story line and make crucial decisions that will change your future. <br>					</li><li>Featuring intense team tactics and BASE WARS. Talk to other star pilots and coordinate attacks with Voice-Over-Net. <br>					</li><li>CHOOSE SIDES — Battle across multiple sectors as you fight to destroy opponent''s base. <br>					</li><li>Featuring Bruce Cambell as the voice of Jake Logan<br>					</li></ul>','Caught in the middle of a violent conflict on the fringe of the galaxy — your ability to survive will depend on your piloting skills and combat savvy as a mercenary space fighter. But, as you explore the vastly detailed world of Tachyon: The Fringe, you will often find that the most powerful weapon on your ship is in your head.<br>					Features <br>					<ul class="bb_ul"><li>Single Player Features — Decide where you want to go and what missions you will fly as you explore the vast and richly inhabited universe. <br>					</li><li>Fight in furious space combat battles around the most massive ships and stations ever created in a space game. <br>					</li><li>Explore a multi-sided in-game story line and make crucial decisions that will change your future. <br>					</li><li>Featuring intense team tactics and BASE WARS. Talk to other star pilots and coordinate attacks with Voice-Over-Net. <br>					</li><li>CHOOSE SIDES — Battle across multiple sectors as you fight to destroy opponent''s base. <br>					</li><li>Featuring Bruce Cambell as the voice of Jake Logan<br>					</li></ul>','Caught in the middle of a violent conflict on the fringe of the galaxy — your ability to survive will depend on your piloting skills and combat savvy as a mercenary space fighter. But, as you explore the vastly detailed world of Tachyon: The Fringe, you will often find that the most powerful weapon on your ship is in your head.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32770,'The most ferocious online conflict of the 21st century is now available in its most definitive form: introducing Joint Operations: Combined Arms Gold, the largest multiplayer FPS collection ever. With the award-winning Joint Operations: Typhoon Rising and the bestselling Joint Operations: Escalation together in one convenient package, it''s easier than ever to join the world record setting large scale modern warfare that critics have called &quot;extremely intense,&quot; and &quot;an absolute blast.&quot;  (PC Gamer) <br><br><br>					<ul class="bb_ul"><li>Play in games of up to 150 players online via the all-new, blazing fast NovaWorld network, or host up to 64 player games on LAN<br>					</li><li>Experience the most premium connections and sophisticated anti-cheat technology available with THREE MONTHS FREE NovaWorld Gold premium service included with purchase<br>					</li><li>Battle over 30 unique, breathtaking and massive multiplayer levels across the diverse environments of Indonesia, from chemical weapons factories to ancient jungle ruins<br>					</li><li>Choose your specially-skilled class of warrior from 7 different authentic fighting forces<br>					</li><li>Crush your enemies with 35 fully drivable war machines, from M-1 battle tanks to LCAC amphibious assault hovercraft and Black Hawk helicopters<br>					</li></ul>','The most ferocious online conflict of the 21st century is now available in its most definitive form: introducing Joint Operations: Combined Arms Gold, the largest multiplayer FPS collection ever. With the award-winning Joint Operations: Typhoon Rising and the bestselling Joint Operations: Escalation together in one convenient package, it''s easier than ever to join the world record setting large scale modern warfare that critics have called &quot;extremely intense,&quot; and &quot;an absolute blast.&quot;  (PC Gamer) <br><br><br>					<ul class="bb_ul"><li>Play in games of up to 150 players online via the all-new, blazing fast NovaWorld network, or host up to 64 player games on LAN<br>					</li><li>Experience the most premium connections and sophisticated anti-cheat technology available with THREE MONTHS FREE NovaWorld Gold premium service included with purchase<br>					</li><li>Battle over 30 unique, breathtaking and massive multiplayer levels across the diverse environments of Indonesia, from chemical weapons factories to ancient jungle ruins<br>					</li><li>Choose your specially-skilled class of warrior from 7 different authentic fighting forces<br>					</li><li>Crush your enemies with 35 fully drivable war machines, from M-1 battle tanks to LCAC amphibious assault hovercraft and Black Hawk helicopters<br>					</li></ul>','The most ferocious online conflict of the 21st century is now available in its most definitive form: introducing Joint Operations: Combined Arms Gold, the largest multiplayer FPS collection ever. With the award-winning Joint Operations: Typhoon Rising and the bestselling Joint Operations: Escalation together in one convenient package,...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (32900,'The sequel to the widely popular Restaurant Empire game takes you further into the depths and delights of the culinary universe than ever before. <br>					Take part in an exciting world where the customers are fickle and the bounty in your cash register changes as quickly as their tastes. With two handfuls of cash and a dream of stamping a legacy, build, cook and hire your way to the very top of the gastronomic biz, where tasty food is king and smart management reels in the cash. And if you''re lucky, you just may go further than any other before you and cement your status as a true legend of cuisine...<br>					Key features:<br>					<ul class="bb_ul"><li>A brand-new 16-mission campaign that gives us a look at the ongoing story of the Leboufs, as they try to tiptoe through the minefield of marriage and the unique circumstances of professional success.<br>					</li><li>A superior graphics engine brings to life the cities, characters and restaurants that populate the world of cuisine using advanced techniques such as real-time reflections to give unprecedented realism. Food has never looked so good.<br>					</li><li>Two new enterprise categories: Coffee Shop and Dessert House that complements the existing Restaurant enterprise; with each category having over 130 unique delicacies, beverages and recipes to choose from.<br>					</li><li>New themed restaurants ranging from the aquatic deep, exotic rainforest and motor racing takes the idea of &quot;themes&quot; to unprecedented heights. You''ve never seen restaurants looking this amazing before.<br>					</li><li>Over 700 new interior objects, bringing the total number to 1400. There is more variety and fun than ever before in setting up, decorating and managing your very own restaurant. <br>					</li><li>Introducing the new German cuisine category of restaurants complimenting the existing foods and architectures of the French, Italians and Americans. Over 600 total recipes.<br>					</li><li>Munich, in addition to the triumvirate of Paris, Los Angeles and Rome is now yours to select as a destination to set up shop and expand your burgeoning business.<br>					</li><li>Hire live performers to perk up your restaurant''s atmosphere, varying from concert soloists to rock bands and indoor circus performers, and set up their scheduled stints to entertain your valued guests at the right time of day. <br>					</li><li>With the new Recipe Research feature you can now actively invest into improving the quality of your food as well as gain invaluable knowledge in the formulation of new delicious recipes.<br>					</li><li>And finally, Armand awaits for you with a secret mini-game inside. <br>					<br>					</li></ul>','The sequel to the widely popular Restaurant Empire game takes you further into the depths and delights of the culinary universe than ever before. <br>					Take part in an exciting world where the customers are fickle and the bounty in your cash register changes as quickly as their tastes. With two handfuls of cash and a dream of stamping a legacy, build, cook and hire your way to the very top of the gastronomic biz, where tasty food is king and smart management reels in the cash. And if you''re lucky, you just may go further than any other before you and cement your status as a true legend of cuisine...<br>					Key features:<br>					<ul class="bb_ul"><li>A brand-new 16-mission campaign that gives us a look at the ongoing story of the Leboufs, as they try to tiptoe through the minefield of marriage and the unique circumstances of professional success.<br>					</li><li>A superior graphics engine brings to life the cities, characters and restaurants that populate the world of cuisine using advanced techniques such as real-time reflections to give unprecedented realism. Food has never looked so good.<br>					</li><li>Two new enterprise categories: Coffee Shop and Dessert House that complements the existing Restaurant enterprise; with each category having over 130 unique delicacies, beverages and recipes to choose from.<br>					</li><li>New themed restaurants ranging from the aquatic deep, exotic rainforest and motor racing takes the idea of &quot;themes&quot; to unprecedented heights. You''ve never seen restaurants looking this amazing before.<br>					</li><li>Over 700 new interior objects, bringing the total number to 1400. There is more variety and fun than ever before in setting up, decorating and managing your very own restaurant. <br>					</li><li>Introducing the new German cuisine category of restaurants complimenting the existing foods and architectures of the French, Italians and Americans. Over 600 total recipes.<br>					</li><li>Munich, in addition to the triumvirate of Paris, Los Angeles and Rome is now yours to select as a destination to set up shop and expand your burgeoning business.<br>					</li><li>Hire live performers to perk up your restaurant''s atmosphere, varying from concert soloists to rock bands and indoor circus performers, and set up their scheduled stints to entertain your valued guests at the right time of day. <br>					</li><li>With the new Recipe Research feature you can now actively invest into improving the quality of your food as well as gain invaluable knowledge in the formulation of new delicious recipes.<br>					</li><li>And finally, Armand awaits for you with a secret mini-game inside. <br>					<br>					</li></ul>','The sequel to the widely popular Restaurant Empire game takes you further into the depths and delights of the culinary universe than ever before. Take part in an exciting world where the customers are fickle and the bounty in your cash register changes as quickly as their tastes.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33100,'The endless darkness and the somber, long passages of a military complex have become the abode of evil, as thousands of blood-thirsty creatures fill its offices, storehouses and mysterious laboratories. <br>                    Your mission is simple: clear the base at all costs. You will be provided with explosives to help you gain access to the teleports from where thousands of pitiless creatures pour. A stationary gun will aid in the defense of the area. You have been granted access to the most advanced weapons technology money can buy. As you earn your pay, you can equip yourself with additional weapons in the arming area and biomechanical implants that will make your fighting abilities super human. <br>                    The alien invasion has begun, we have one chance, and that is to stop them cold in their staging area. Do not allow them escape this facility, you are our last hope. The fate of humanity now depends on you!<br>                    <ul class="bb_ul"><li>About 1,000 monsters on each map, showing up to 100 monsters simultaneously on one playing screen<br>                    </li><li>Many hours of game play with 10 missions and a survival mode<br>                    </li><li>Full-on-action male or female character <br>                    </li><li>Character upgrade facility <br>                    </li><li>9 weapons of mass destruction <br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of enemies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li><li>Useful gadgets - flash lights, medkits, battle drones<br>                    </li></ul>','The endless darkness and the somber, long passages of a military complex have become the abode of evil, as thousands of blood-thirsty creatures fill its offices, storehouses and mysterious laboratories. <br>                    Your mission is simple: clear the base at all costs. You will be provided with explosives to help you gain access to the teleports from where thousands of pitiless creatures pour. A stationary gun will aid in the defense of the area. You have been granted access to the most advanced weapons technology money can buy. As you earn your pay, you can equip yourself with additional weapons in the arming area and biomechanical implants that will make your fighting abilities super human. <br>                    The alien invasion has begun, we have one chance, and that is to stop them cold in their staging area. Do not allow them escape this facility, you are our last hope. The fate of humanity now depends on you!<br>                    <ul class="bb_ul"><li>About 1,000 monsters on each map, showing up to 100 monsters simultaneously on one playing screen<br>                    </li><li>Many hours of game play with 10 missions and a survival mode<br>                    </li><li>Full-on-action male or female character <br>                    </li><li>Character upgrade facility <br>                    </li><li>9 weapons of mass destruction <br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of enemies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li><li>Useful gadgets - flash lights, medkits, battle drones<br>                    </li></ul>','Your mission is simple: clear the base at all costs. You will be provided with explosives to help you gain access to the teleports from where thousands of pitiless creatures pour.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33110,'Crowds of blood-thirsty monsters, crawling from every corner of the secret research base. Gloomy basements and modern labs, darkness changing into blazing bulbs. The only usual thing is: you''re in a bad place alone, and there''s no one to help you!<br>                    An improved version of a cult 2003 game which won hearts of the huge army of players worldwide. Complete game missions, earning more and more cash for weapons and inventory, use stationary weapons in the hottest places, eliminate monster spawning places with dynamite and increase your firepower with implants and drones.<br>                    You''ve saved our poor little planet so many times... but the real hero never stops!<br>                    Go ahead, great deeds are waiting for you!<br>                    <ul class="bb_ul"><li>About 1,000 monsters on each map, showing up to 100 monsters simultaneously on one playing screen<br>                    </li><li>3 game modes: Campaign, Survive and Gun Stand<br>                    </li><li>Full-on-action male or female character <br>                    </li><li>Character upgrade facility <br>                    </li><li>9 weapons of mass destruction <br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of enemies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li><li>Useful gadgets - flash lights, medkits, battle drones<br>                    </li></ul>','Crowds of blood-thirsty monsters, crawling from every corner of the secret research base. Gloomy basements and modern labs, darkness changing into blazing bulbs. The only usual thing is: you''re in a bad place alone, and there''s no one to help you!<br>                    An improved version of a cult 2003 game which won hearts of the huge army of players worldwide. Complete game missions, earning more and more cash for weapons and inventory, use stationary weapons in the hottest places, eliminate monster spawning places with dynamite and increase your firepower with implants and drones.<br>                    You''ve saved our poor little planet so many times... but the real hero never stops!<br>                    Go ahead, great deeds are waiting for you!<br>                    <ul class="bb_ul"><li>About 1,000 monsters on each map, showing up to 100 monsters simultaneously on one playing screen<br>                    </li><li>3 game modes: Campaign, Survive and Gun Stand<br>                    </li><li>Full-on-action male or female character <br>                    </li><li>Character upgrade facility <br>                    </li><li>9 weapons of mass destruction <br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of enemies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li><li>Useful gadgets - flash lights, medkits, battle drones<br>                    </li></ul>','Crowds of blood-thirsty monsters, crawling from every corner of the secret research base. Gloomy basements and modern labs, darkness changing into blazing bulbs. The only usual thing is: you''re in a bad place alone, and there''s no one to help you!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33120,'Alien Shooter 2 -Reloaded is a large-scale sequel to the first part of Alien Shooter. This is the unique alloy of arcade action and RPG elements which combines well-established world of classical games and unmatched dynamics of the first part.<br>                    Alien Shooter 2 - Reloaded is a modified version of the Alien Shooter 2 game. Sigma Team started working on it right after release of AS2, taking into account the players'' wishes:<br>                    <ul class="bb_ul"><li><strong>Size of the full version installation file was reduced to 300 Mb, compared to 1Gb of the original Alien Shooter 2. Large installation file prevented users with slow connection from buying and downloading the game.</strong><br>                    </li><li><strong>Player upgrade parameters simplified. Now you don''t need to develop separate skills for each weapon type, so you''ll be able to complete the game using all the weapon types featured in it.</strong><br>                    </li><li><strong>Two new missions added. Now the game features 17 full levels.</strong><br>                    </li><li><strong> New individual shooting mode added - Gun Stand. You will use powerful military equipment to eliminate advancing enemy troops. As the game goes on, you will upgrade your weapon in different ways, and the right choice will let you win the battle!</strong><br>                    </li></ul><ul class="bb_ul"><li>about 10,000 monsters on each map, showing up to 100 monsters simultaneously on one playing screen<br>                    </li><li>Arcade action combined with sophisticated RPG elements<br>                    </li><li>Many hours of game play with 17 missions<br>                    </li><li>3 game modes: Campaign, Survive and Gun Stand<br>                    </li><li>And, to crown it all, dynamic music and sound effects<br>                    </li><li>Natural phenomena (fog, rain, water)<br>                    </li><li>A variety of playable characters, each featuring unique abilities<br>                    </li><li>Character upgrade facility <br>                    </li><li>More than 50 types of weapons - now you can not just kill but also burn, freeze and even diminish the enemies<br>                    </li><li>More than 20 types of handy gadgets - from flare guns, radar and medkits to battle drones and much more<br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of enemies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li></ul>','Alien Shooter 2 -Reloaded is a large-scale sequel to the first part of Alien Shooter. This is the unique alloy of arcade action and RPG elements which combines well-established world of classical games and unmatched dynamics of the first part.<br>                    Alien Shooter 2 - Reloaded is a modified version of the Alien Shooter 2 game. Sigma Team started working on it right after release of AS2, taking into account the players'' wishes:<br>                    <ul class="bb_ul"><li><strong>Size of the full version installation file was reduced to 300 Mb, compared to 1Gb of the original Alien Shooter 2. Large installation file prevented users with slow connection from buying and downloading the game.</strong><br>                    </li><li><strong>Player upgrade parameters simplified. Now you don''t need to develop separate skills for each weapon type, so you''ll be able to complete the game using all the weapon types featured in it.</strong><br>                    </li><li><strong>Two new missions added. Now the game features 17 full levels.</strong><br>                    </li><li><strong> New individual shooting mode added - Gun Stand. You will use powerful military equipment to eliminate advancing enemy troops. As the game goes on, you will upgrade your weapon in different ways, and the right choice will let you win the battle!</strong><br>                    </li></ul><ul class="bb_ul"><li>about 10,000 monsters on each map, showing up to 100 monsters simultaneously on one playing screen<br>                    </li><li>Arcade action combined with sophisticated RPG elements<br>                    </li><li>Many hours of game play with 17 missions<br>                    </li><li>3 game modes: Campaign, Survive and Gun Stand<br>                    </li><li>And, to crown it all, dynamic music and sound effects<br>                    </li><li>Natural phenomena (fog, rain, water)<br>                    </li><li>A variety of playable characters, each featuring unique abilities<br>                    </li><li>Character upgrade facility <br>                    </li><li>More than 50 types of weapons - now you can not just kill but also burn, freeze and even diminish the enemies<br>                    </li><li>More than 20 types of handy gadgets - from flare guns, radar and medkits to battle drones and much more<br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of enemies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li></ul>','Alien Shooter 2 -Reloaded is a large-scale sequel to the first part of Alien Shooter. This is the unique alloy of arcade action and RPG elements which combines well-established world of classical games and unmatched dynamics of the first part. Alien Shooter 2 - Reloaded is a modified version of the Alien Shooter 2 game.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33130,'Where is the line between life and death? How far can human science go trying to understand this?<br>                    Take part in the great battle to rescue humanity and find out what''s happening! The human race is in danger again. This time scientists could not cope the imminent threat and became monsters themselves. Crowds of zombie people filled the secret research base. The dreadful contagion is about to spread earth wide. Use the last chance to save the humanity from total annihilation!<br>                    Find the answer to the main question - what caused the catastrophe? Who knows, maybe on the final stage you''ll face something terrible?..<br>                    Try your monster fighting skills in two additional game modes - Survive and Gun Stand. Only these modes will really show how good you''ve become.<br>                    <ul class="bb_ul"><li>Fight your way through contaminated hordes<br>                    </li><li>Use 10 types of weapons<br>                    </li><li>Improve the character''s skills<br>                    </li><li>Upgrade available arms with the money earned<br>                    </li><li>About 1,000 zombies on each map, showing up to 100 zombies simultaneously on one playing screen<br>                    </li><li>3 game modes: Campaign, Survive and Gun Stand<br>                    </li><li>Full-on-action male or female character <br>                    </li><li>Character upgrade facility <br>                    </li><li>9 upgradeable weapons of mass destruction <br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of zombies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li><li>Useful gadgets - flash lights, medkits, battle drones and radar.<br>                    </li></ul>','Where is the line between life and death? How far can human science go trying to understand this?<br>                    Take part in the great battle to rescue humanity and find out what''s happening! The human race is in danger again. This time scientists could not cope the imminent threat and became monsters themselves. Crowds of zombie people filled the secret research base. The dreadful contagion is about to spread earth wide. Use the last chance to save the humanity from total annihilation!<br>                    Find the answer to the main question - what caused the catastrophe? Who knows, maybe on the final stage you''ll face something terrible?..<br>                    Try your monster fighting skills in two additional game modes - Survive and Gun Stand. Only these modes will really show how good you''ve become.<br>                    <ul class="bb_ul"><li>Fight your way through contaminated hordes<br>                    </li><li>Use 10 types of weapons<br>                    </li><li>Improve the character''s skills<br>                    </li><li>Upgrade available arms with the money earned<br>                    </li><li>About 1,000 zombies on each map, showing up to 100 zombies simultaneously on one playing screen<br>                    </li><li>3 game modes: Campaign, Survive and Gun Stand<br>                    </li><li>Full-on-action male or female character <br>                    </li><li>Character upgrade facility <br>                    </li><li>9 upgradeable weapons of mass destruction <br>                    </li><li>Red or Green blood selection <br>                    </li><li>Highly imaginative selection of zombies <br>                    </li><li>Reactive music which helps to drive the action<br>                    </li><li>Useful gadgets - flash lights, medkits, battle drones and radar.<br>                    </li></ul>','Where is the line between life and death? How far can human science go trying to understand this? Take part in the great battle to rescue humanity and find out what''s happening! The human race is in danger again. This time scientists could not cope the imminent threat and became monsters themselves.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33180,'Zombie Shooter 2 is a unique blend of two game genres - Action and RPG. Every player can choose a character to the liking, get experience to develop skills, earn money and spend it at weapons, medications and useful devices. All of this will be used against thousands of enemies. The zombies fill the game screen, never letting you rest, even for a minute.<br>					Imagine yourself coming to visit an unknown city and seeing it almost ruined, with all the citizens turned into zombies. What will you do? Call for help, organize a large-scale rescue campaign or... Try to dig your way out of the situation, find out what happened and use your last chance to save the person you love!<br>					<ul class="bb_ul"><li>New project from the maker of the legendary Alien Shooter series.<br>					</li><li>Huge crowds of enemies, more than 100 zombies on one map at a time.<br>					</li><li>Ability to upgrade the main character''s parameters.<br>					</li><li>More than 60 weapon types, including sniper rifles.<br>					</li><li>Lots of auxiliary devices, including radar and battle drones.<br>					</li><li>Several types of vehicles to drive.<br>					</li><li>Three game types: Campaign, Survive, Gun Stand.<br>					</li></ul>','Zombie Shooter 2 is a unique blend of two game genres - Action and RPG. Every player can choose a character to the liking, get experience to develop skills, earn money and spend it at weapons, medications and useful devices. All of this will be used against thousands of enemies. The zombies fill the game screen, never letting you rest, even for a minute.<br>					Imagine yourself coming to visit an unknown city and seeing it almost ruined, with all the citizens turned into zombies. What will you do? Call for help, organize a large-scale rescue campaign or... Try to dig your way out of the situation, find out what happened and use your last chance to save the person you love!<br>					<ul class="bb_ul"><li>New project from the maker of the legendary Alien Shooter series.<br>					</li><li>Huge crowds of enemies, more than 100 zombies on one map at a time.<br>					</li><li>Ability to upgrade the main character''s parameters.<br>					</li><li>More than 60 weapon types, including sniper rifles.<br>					</li><li>Lots of auxiliary devices, including radar and battle drones.<br>					</li><li>Several types of vehicles to drive.<br>					</li><li>Three game types: Campaign, Survive, Gun Stand.<br>					</li></ul>','Zombie Shooter 2 is a unique blend of two game genres - Action and RPG. Every player can choose a character to the liking, get experience to develop skills, earn money and spend it at weapons, medications and useful devices. All of this will be used against thousands of enemies.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33230,'Assassin’s Creed® 2 is the follow-up to the title that became the fastest-selling new IP in video game history. The highly anticipated title features a new hero, Ezio Auditore da Firenze, a young Italian noble, and a new era, the Renaissance.<br>						Assassin’s Creed 2 retains the core gameplay experience that made the first opus a resounding success and features new experiences that will surprise and challenge players.<br>						Assassin’s Creed 2 is an epic story of family, vengeance and conspiracy set in the pristine, yet brutal, backdrop of a Renaissance Italy. Ezio befriends Leonardo da Vinci, takes on Florence’s most powerful families and ventures throughout the canals of Venice where he learns to become a master assassin.<br>						<ul class="bb_ul"><li><strong>EZIO, A NEW ASSASSIN FOR A NEW ERA</strong> Ezio Auditore da Firenze is a young Italian noble who will learn the ways of the assassins after his family was betrayed and he looks to seek vengeance. He is a lady’s man, a free soul with panache yet has a very human side to his personality. Through him, you become a master assassin.<br>						</li><li><strong>RENAISSANCE ITALY</strong> Italy in the 15th century was less a country and more a collection of city-states where families with political and economic strength began to take leadership roles in cities like Florence and Venice. This journey through some of the most beautiful cities in the world takes place in a time in history where culture and art were born alongside some of the most chilling stories of corruption, greed and murder. <br>						</li><li><strong>A NEW-FOUND FREEDOM</strong> You will be able to perform missions when you want and how you want in this open-ended world that brings back free-running and adds elements such as swimming and even flying to the adventure. The variety in gameplay adds another layer for you to truly play through the game any way you choose.<br>						</li><li><strong>DYNAMIC CROWD </strong>Discover a living, breathing world where every character is an opportunity for the player. Blending in with the crowd is easier, working with in-game characters provide ample rewards but can also lead to surprising consequences.<br>						</li><li><strong>BECOME A MASTER ASSASSIN</strong> Perfect your skills to become a master assassin where you brandish new weapons, learn to disarm enemies then use their weapons against them, and assassinate enemies using both hidden blades.</li></ul><br>Please note that as of November 19th, 2018, the online features for this game are no longer supported. The Multiplayer mode / Co-op mode will no longer be accessible.<br>(MAC ONLY)','Assassin’s Creed® 2 is the follow-up to the title that became the fastest-selling new IP in video game history. The highly anticipated title features a new hero, Ezio Auditore da Firenze, a young Italian noble, and a new era, the Renaissance.<br>						Assassin’s Creed 2 retains the core gameplay experience that made the first opus a resounding success and features new experiences that will surprise and challenge players.<br>						Assassin’s Creed 2 is an epic story of family, vengeance and conspiracy set in the pristine, yet brutal, backdrop of a Renaissance Italy. Ezio befriends Leonardo da Vinci, takes on Florence’s most powerful families and ventures throughout the canals of Venice where he learns to become a master assassin.<br>						<ul class="bb_ul"><li><strong>EZIO, A NEW ASSASSIN FOR A NEW ERA</strong> Ezio Auditore da Firenze is a young Italian noble who will learn the ways of the assassins after his family was betrayed and he looks to seek vengeance. He is a lady’s man, a free soul with panache yet has a very human side to his personality. Through him, you become a master assassin.<br>						</li><li><strong>RENAISSANCE ITALY</strong> Italy in the 15th century was less a country and more a collection of city-states where families with political and economic strength began to take leadership roles in cities like Florence and Venice. This journey through some of the most beautiful cities in the world takes place in a time in history where culture and art were born alongside some of the most chilling stories of corruption, greed and murder. <br>						</li><li><strong>A NEW-FOUND FREEDOM</strong> You will be able to perform missions when you want and how you want in this open-ended world that brings back free-running and adds elements such as swimming and even flying to the adventure. The variety in gameplay adds another layer for you to truly play through the game any way you choose.<br>						</li><li><strong>DYNAMIC CROWD </strong>Discover a living, breathing world where every character is an opportunity for the player. Blending in with the crowd is easier, working with in-game characters provide ample rewards but can also lead to surprising consequences.<br>						</li><li><strong>BECOME A MASTER ASSASSIN</strong> Perfect your skills to become a master assassin where you brandish new weapons, learn to disarm enemies then use their weapons against them, and assassinate enemies using both hidden blades.</li></ul><br>Please note that as of November 19th, 2018, the online features for this game are no longer supported. The Multiplayer mode / Co-op mode will no longer be accessible.<br>(MAC ONLY)','An epic story of family, vengeance and conspiracy set in the pristine, yet brutal, backdrop of a Renaissance Italy. New low price!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33320,'Prince of Persia The Forgotten Sands is the next chapter in the fan-favorite Sands of Time universe. Visiting his brother''s kingdom following his adventure in Azad,<br>						the Prince finds the royal palace under siege from a mighty army bent on its destruction. When the decision is made to use the ancient power of the Sand in a desperate gamble to save the kingdom from total annihilation, <br>						the Prince will embark on an epic adventure in which he will learn to bear the mantle of true leadership, and discover that great power often comes with a great cost. Game features include:<br>						<ul class="bb_ul"><li><strong>Classic Gameplay Reinvented:</strong> From huge-scale multi-enemy combat to dizzying feats of acrobatic prowess in gigantic environments enhanced by the Prince''s ability to control nature and time, <br>						Prince of Persia The Forgotten Sands will push the Prince''s prodigious abilities to unseen levels.<br>						</li><li><strong>A Blockbuster Experience:</strong> Prince of Persia The Forgotten Sands will offer players unforgettable set pieces made possible by the advanced technology offered by the award-winning Anvil engine. <br>						With all-out war at the gates of the kingdom, the Prince''s abilities will be challenged like never before through the course of epic wow moments.<br>						</li><li><strong>Mastery Over Nature:</strong> Wielding powers of nature and time, the Prince will have unparalleled mastery over his environment and his enemies. <br>						The Prince will discover that harnessing the forces of nature itself will prove to be a devastating companion to his ability to rewind time.<br>						</li><li><strong>Return of a Fan-Favorite Franchise:</strong> Set between Prince of Persia: The Sands of Time™ and Prince of Persia: Warrior Within™, <br>						Prince of Persia The Forgotten Sands will provide fans a new chapter in the Prince of Persia universe and deepen their understanding of the Sands of Time series.<br>						</li></ul> <br>						<h2 class="bb_tag">Online Requirement</h2>						A PERMANENT HIGH SPEED INTERNET CONNECTION AND CREATION OF A UBISOFT ACCOUNT ARE REQUIRED TO PLAY THIS GAME. YOU MUST BE AT LEAST 13 TO CREATE A UBISOFT ACCOUNT WITHOUT PARENTAL CONSENT. <br>						UBISOFT MAY CANCEL ACCESS TO ONLINE FEATURES UPON A 30-DAY PRIOR NOTICE PUBLISHED AT <a href="https://steamcommunity.com/linkfilter/?url=http://www.princeofpersia.com" target="_blank" rel="noopener"  >http://www.princeofpersia.com</a>','Prince of Persia The Forgotten Sands is the next chapter in the fan-favorite Sands of Time universe. Visiting his brother''s kingdom following his adventure in Azad,<br>						the Prince finds the royal palace under siege from a mighty army bent on its destruction. When the decision is made to use the ancient power of the Sand in a desperate gamble to save the kingdom from total annihilation, <br>						the Prince will embark on an epic adventure in which he will learn to bear the mantle of true leadership, and discover that great power often comes with a great cost. Game features include:<br>						<ul class="bb_ul"><li><strong>Classic Gameplay Reinvented:</strong> From huge-scale multi-enemy combat to dizzying feats of acrobatic prowess in gigantic environments enhanced by the Prince''s ability to control nature and time, <br>						Prince of Persia The Forgotten Sands will push the Prince''s prodigious abilities to unseen levels.<br>						</li><li><strong>A Blockbuster Experience:</strong> Prince of Persia The Forgotten Sands will offer players unforgettable set pieces made possible by the advanced technology offered by the award-winning Anvil engine. <br>						With all-out war at the gates of the kingdom, the Prince''s abilities will be challenged like never before through the course of epic wow moments.<br>						</li><li><strong>Mastery Over Nature:</strong> Wielding powers of nature and time, the Prince will have unparalleled mastery over his environment and his enemies. <br>						The Prince will discover that harnessing the forces of nature itself will prove to be a devastating companion to his ability to rewind time.<br>						</li><li><strong>Return of a Fan-Favorite Franchise:</strong> Set between Prince of Persia: The Sands of Time™ and Prince of Persia: Warrior Within™, <br>						Prince of Persia The Forgotten Sands will provide fans a new chapter in the Prince of Persia universe and deepen their understanding of the Sands of Time series.<br>						</li></ul> <br>						<h2 class="bb_tag">Online Requirement</h2>						A PERMANENT HIGH SPEED INTERNET CONNECTION AND CREATION OF A UBISOFT ACCOUNT ARE REQUIRED TO PLAY THIS GAME. YOU MUST BE AT LEAST 13 TO CREATE A UBISOFT ACCOUNT WITHOUT PARENTAL CONSENT. <br>						UBISOFT MAY CANCEL ACCESS TO ONLINE FEATURES UPON A 30-DAY PRIOR NOTICE PUBLISHED AT <a href="https://steamcommunity.com/linkfilter/?url=http://www.princeofpersia.com" target="_blank" rel="noopener"  >http://www.princeofpersia.com</a>','Prince of Persia The Forgotten Sands is the next chapter in the fan-favorite Sands of Time universe. Visiting his brother''s kingdom following his adventure in Azad, the Prince finds the royal palace under siege from a mighty army bent on its destruction.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33390,'<p>Zeit²&trade; is a traditional side-scrolling, 2D, shoot-’em-up game that brings unprecedented elements to the game experience. Zeit²’s unique time travel feature has yet to be seen in this genre even after decades of great games.</p>
						<p>Intuitive controls allow players to move forward and backward in time making it possible for the player to combine shots and power, and even be assisted by a shadow version of yourself. Blast away swarms of enemies, get the highest score and discover how you can assist yourself in new exciting ways by warping time at will.</p>
						<h2>Key Features</h2>
						<ul>
							  <li><strong>Time Travel:</strong> Assist yourself and perform stunning moves by interacting with your time shadow when travelling back in time. Pace the game and gain extra points by speeding up time. Balance your time travel and life energy to master the game through 70 challenges. 
							  <li><strong>8 Epic Bosses Battles:</strong> Discover the potential of your arsenal of powerful moves while fighting over a dozen different enemies and defeating the eight massive bosses.
							  <li><strong>Weapon Upgrades:</strong> Your main weapon can be upgraded three times and you will feel the striking force of your additional weapon systems including Beam-Shot, Chain-Shot and Shockwave. The bonus system gives you extra score multipliers as long as you don’t miss out on shooting all enemies. 
							  <li><strong>6 Challenging Game Modes:</strong> Go on a journey through 20 chapters of action and variety in the Arcade mode. Challenge others for the highest score in the other modes: Score Attack, Survival, Wave, Time Limit and Tactics. All modes are well integrated with leaderboards and unlockable achievements.  
							  <li><strong>Easily accessible for the casual player and yet challenging for the hardcore gamer.</strong>
						</ul>','<p>Zeit²&trade; is a traditional side-scrolling, 2D, shoot-’em-up game that brings unprecedented elements to the game experience. Zeit²’s unique time travel feature has yet to be seen in this genre even after decades of great games.</p>
						<p>Intuitive controls allow players to move forward and backward in time making it possible for the player to combine shots and power, and even be assisted by a shadow version of yourself. Blast away swarms of enemies, get the highest score and discover how you can assist yourself in new exciting ways by warping time at will.</p>
						<h2>Key Features</h2>
						<ul>
							  <li><strong>Time Travel:</strong> Assist yourself and perform stunning moves by interacting with your time shadow when travelling back in time. Pace the game and gain extra points by speeding up time. Balance your time travel and life energy to master the game through 70 challenges. 
							  <li><strong>8 Epic Bosses Battles:</strong> Discover the potential of your arsenal of powerful moves while fighting over a dozen different enemies and defeating the eight massive bosses.
							  <li><strong>Weapon Upgrades:</strong> Your main weapon can be upgraded three times and you will feel the striking force of your additional weapon systems including Beam-Shot, Chain-Shot and Shockwave. The bonus system gives you extra score multipliers as long as you don’t miss out on shooting all enemies. 
							  <li><strong>6 Challenging Game Modes:</strong> Go on a journey through 20 chapters of action and variety in the Arcade mode. Challenge others for the highest score in the other modes: Score Attack, Survival, Wave, Time Limit and Tactics. All modes are well integrated with leaderboards and unlockable achievements.  
							  <li><strong>Easily accessible for the casual player and yet challenging for the hardcore gamer.</strong>
						</ul>','Zeit² brings a new twist to the traditional side-scrolling, 2D, shoot-’em-up game sporting a unique time travel feature never seen before in this genre.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33460,'<strong>From Dust</strong> is the latest original game concept by Eric Chahi, creator of the cult classic, “Another World / Out of this World”.<br>						Immerse yourself in a world as exotically beautiful as it is dangerous! You control the destiny of a primitive tribe against the backdrop of a world in constant evolution—a universe where mighty Nature reclaims what is hers; and your mastery of the elements is your people’s only chance of survival...<br>						<h2 class="bb_tag">Key Features:</h2><ul class="bb_ul"><li><strong>Ground-Breaking Technology</strong><br><br>						Play in the sandbox of one of the most advanced real-time nature simulations, where everything you see and interact with evolves dynamically, offering a constantly renewed experience.<br>						</li><li><strong>Unique Art Direction</strong><br><br>						Discover a large variety of environments: Tropical islands, volcanic landscapes, deserts and so much more…<br>						</li><li><strong>Rich Story Mode</strong><br><br>						Explore 13 breathtaking territories of emergent gameplay. Master the natural forces at play on a mysterious archipelago and help a primitive tribe to recover the lost powers of their ancestors.<br>						</li><li><strong>Confront Mighty Nature</strong><br><br>						Protect your tribe against Nature’s most devastating attacks. Face down tsunamis, wildfires, earthquakes, volcanoes, torrential rains…<br>						</li><li><strong>Master Godlike Powers </strong><br><br>						Control the forces of nature to sculpt the world in your image.  Hold back lava, stop raging waters, empty lakes, grow forests and raise mountains!<br>						</li><li><strong>Live Up to the Challenge</strong><br><br>						Race against the clock on 30 additional maps in Challenge Mode. Each scenario is a puzzle-like challenge where time is of the essence...<br>						</li><li><strong>Online leaderboards</strong><br><br>						Compare your Challenge Mode scores with the community on worldwide leaderboards.</li></ul>','<strong>From Dust</strong> is the latest original game concept by Eric Chahi, creator of the cult classic, “Another World / Out of this World”.<br>						Immerse yourself in a world as exotically beautiful as it is dangerous! You control the destiny of a primitive tribe against the backdrop of a world in constant evolution—a universe where mighty Nature reclaims what is hers; and your mastery of the elements is your people’s only chance of survival...<br>						<h2 class="bb_tag">Key Features:</h2><ul class="bb_ul"><li><strong>Ground-Breaking Technology</strong><br><br>						Play in the sandbox of one of the most advanced real-time nature simulations, where everything you see and interact with evolves dynamically, offering a constantly renewed experience.<br>						</li><li><strong>Unique Art Direction</strong><br><br>						Discover a large variety of environments: Tropical islands, volcanic landscapes, deserts and so much more…<br>						</li><li><strong>Rich Story Mode</strong><br><br>						Explore 13 breathtaking territories of emergent gameplay. Master the natural forces at play on a mysterious archipelago and help a primitive tribe to recover the lost powers of their ancestors.<br>						</li><li><strong>Confront Mighty Nature</strong><br><br>						Protect your tribe against Nature’s most devastating attacks. Face down tsunamis, wildfires, earthquakes, volcanoes, torrential rains…<br>						</li><li><strong>Master Godlike Powers </strong><br><br>						Control the forces of nature to sculpt the world in your image.  Hold back lava, stop raging waters, empty lakes, grow forests and raise mountains!<br>						</li><li><strong>Live Up to the Challenge</strong><br><br>						Race against the clock on 30 additional maps in Challenge Mode. Each scenario is a puzzle-like challenge where time is of the essence...<br>						</li><li><strong>Online leaderboards</strong><br><br>						Compare your Challenge Mode scores with the community on worldwide leaderboards.</li></ul>','Immerse yourself in a world as exotically beautiful as it is dangerous in this modern God-Game where Nature is the Star!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33520,'TROPICO RELOADED is the ultimate game compilation for hobby-dictators and those dreaming of their own Caribbean island. Tropico combines real-time strategy and simulation elements with a healthy dose of political intrigue and Caribbean flair to create a unique and critically acclaimed game experience.<br>					<br><img src="https://steamcdn-a.akamaihd.net/steam/apps/33520/extras/tropico.jpg" >TROPICO <br>					<br>You are the sole ruler of a remote banana republic. Fight against poverty, corruption and rebels, make your own people happy or enforce your rule through military strength. However, do not forget to set aside a few dollars for your own retirement on a swiss bank account!<br>					<br><br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/33520/extras/tropic_pleasure_island.jpg" >TROPICO — PARADISE ISLAND <br>					<br>The official expansion for the original game not only brings natural disasters like tropical storms but also new tourist attractions to your island. Face the challenges of tons of new scenarios, prove yourself a worthy leader to your own people and make Tropico a paradise for wealthy visitors from overseas.<br>					<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/33520/extras/tropic_pirate_cove.jpg" >TROPICO 2 — PIRATE COVE <br>					<br>As a feared Pirate King, you have to keep both your buccaneers and prisoners under control and send your ships on the prowl for treasury. Apart from an entirely new setting, the official sequel to the original Tropico offers gameplay improvements, new features and scenarios.<br>					<br><br><br>Key features:<br>					<ul class="bb_ul"><li>Includes the original Tropico, the expansion Paradise Island and Tropico 2: Pirate Cove<br>					</li><li>Over 100 scenarios <br>					</li><li>Random map generator for an infinite number of challenges<br>					</li></ul>','TROPICO RELOADED is the ultimate game compilation for hobby-dictators and those dreaming of their own Caribbean island. Tropico combines real-time strategy and simulation elements with a healthy dose of political intrigue and Caribbean flair to create a unique and critically acclaimed game experience.<br>					<br><img src="https://steamcdn-a.akamaihd.net/steam/apps/33520/extras/tropico.jpg" >TROPICO <br>					<br>You are the sole ruler of a remote banana republic. Fight against poverty, corruption and rebels, make your own people happy or enforce your rule through military strength. However, do not forget to set aside a few dollars for your own retirement on a swiss bank account!<br>					<br><br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/33520/extras/tropic_pleasure_island.jpg" >TROPICO — PARADISE ISLAND <br>					<br>The official expansion for the original game not only brings natural disasters like tropical storms but also new tourist attractions to your island. Face the challenges of tons of new scenarios, prove yourself a worthy leader to your own people and make Tropico a paradise for wealthy visitors from overseas.<br>					<br><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/33520/extras/tropic_pirate_cove.jpg" >TROPICO 2 — PIRATE COVE <br>					<br>As a feared Pirate King, you have to keep both your buccaneers and prisoners under control and send your ships on the prowl for treasury. Apart from an entirely new setting, the official sequel to the original Tropico offers gameplay improvements, new features and scenarios.<br>					<br><br><br>Key features:<br>					<ul class="bb_ul"><li>Includes the original Tropico, the expansion Paradise Island and Tropico 2: Pirate Cove<br>					</li><li>Over 100 scenarios <br>					</li><li>Random map generator for an infinite number of challenges<br>					</li></ul>','TROPICO RELOADED is the ultimate game compilation for hobby-dictators and those dreaming of their own Caribbean island. Tropico combines real-time strategy and simulation elements with a healthy dose of political intrigue and Caribbean flair to create a unique and critically acclaimed game experience.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33570,'Patrician III - sequel to the award winning game Patrician II - features advanced in-game AI, which adjusts its difficulty based on experience and ability. In this economic sandbox game you can gain wealth and power in multiple ways - what you will do with it is up to you. Invite up to 8 of your friends for a multiplayer session via LAN or over the Internet.<br />
<br />
Become a fellow of the famous medieval Hanse trading association in the 13th century. Manage the politics, prestige and economic success in your city and the known parts of Europe! Create a medieval trade empire and expand in to encompass the whole Old World. Build warehouses, workshops, brickworks and much more to strengthen your financial position in the Hansa. Gain reputation in your hometown by developing its infrastructure with roads, hospitals, schools and become Lord Mayor thus gaining full control of the city. Be a famous pirate killer or become one yourself!<br />
<br />
Visit the great cities of Hamburg, Stockholm, London, Novgorod, Oslo and more. Explore the Mediterranean as you build your trade empire. Hold galas to celebrate victory in battle and your town''s growth. Run massive trading operations and cope with the consequences of enhanced seasonal weather effects.<br />
<br />
You can raise your standing through town improvement and diplomacy or fill your coffers through piracy and smuggling. Grow your small town into a major trading centre wielding tremendous economic power today!','Patrician III - sequel to the award winning game Patrician II - features advanced in-game AI, which adjusts its difficulty based on experience and ability. In this economic sandbox game you can gain wealth and power in multiple ways - what you will do with it is up to you. Invite up to 8 of your friends for a multiplayer session via LAN or over the Internet.<br />
<br />
Become a fellow of the famous medieval Hanse trading association in the 13th century. Manage the politics, prestige and economic success in your city and the known parts of Europe! Create a medieval trade empire and expand in to encompass the whole Old World. Build warehouses, workshops, brickworks and much more to strengthen your financial position in the Hansa. Gain reputation in your hometown by developing its infrastructure with roads, hospitals, schools and become Lord Mayor thus gaining full control of the city. Be a famous pirate killer or become one yourself!<br />
<br />
Visit the great cities of Hamburg, Stockholm, London, Novgorod, Oslo and more. Explore the Mediterranean as you build your trade empire. Hold galas to celebrate victory in battle and your town''s growth. Run massive trading operations and cope with the consequences of enhanced seasonal weather effects.<br />
<br />
You can raise your standing through town improvement and diplomacy or fill your coffers through piracy and smuggling. Grow your small town into a major trading centre wielding tremendous economic power today!','Patrician III - sequel to the award winning game Patrician II - features advanced in-game AI, which adjusts its difficulty based on experience and ability. In this economic sandbox game you can gain wealth and power in multiple ways - what you will do with it is up to you.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33600,'‘Broken Sword - The Smoking Mirror: Remastered’ is a stunning update to the multi million-selling original. While investigating a ruthless drug gang, journalist Nico Collard unexpectedly comes across an ancient artifact. Little can she know that the ornately carved obsidian stone will lead her, and her adventuring companion George Stobbart, into a mysterious escapade of intrigue and deceit, in which they must overcome powerful forces and antagonists who will stop at nothing to fulfil their evil ambitions. <br><br>Torment and terror, sacrificial rituals, and bloody massacre is unearthed beneath a veil of Mayan mystery. Kidnap, stolen treasure, astronomy, and deadly drug baron are the least of the duo’s worries, as divine forces threaten to annihilate mankind! Nerve, cunning and guile are essential in order to conquer in this compelling adventure, guaranteed to leave you with an aching brain and a beating heart. Are you up to the challenge?<br><br>Along with an exclusive new interactive digital comic, from ‘Watchmen’ co-creator Dave Gibbons, the game boasts fully animated facial expressions, enhanced graphics throughout, high quality music as well as a context-sensitive hint system, and diary.<br><br><strong>Key Features:</strong><br><ul class="bb_ul"><li>Over 60 characters with which to interact<br></li><li>A multitude of highly detailed locations to explore<br></li><li>Hundreds of mind-bending puzzles and clues to collect<br></li><li>Beautiful classically animated sequences<br></li><li>Stunning music from world-famous composer, Barrington Pheloung</li></ul>','‘Broken Sword - The Smoking Mirror: Remastered’ is a stunning update to the multi million-selling original. While investigating a ruthless drug gang, journalist Nico Collard unexpectedly comes across an ancient artifact. Little can she know that the ornately carved obsidian stone will lead her, and her adventuring companion George Stobbart, into a mysterious escapade of intrigue and deceit, in which they must overcome powerful forces and antagonists who will stop at nothing to fulfil their evil ambitions. <br><br>Torment and terror, sacrificial rituals, and bloody massacre is unearthed beneath a veil of Mayan mystery. Kidnap, stolen treasure, astronomy, and deadly drug baron are the least of the duo’s worries, as divine forces threaten to annihilate mankind! Nerve, cunning and guile are essential in order to conquer in this compelling adventure, guaranteed to leave you with an aching brain and a beating heart. Are you up to the challenge?<br><br>Along with an exclusive new interactive digital comic, from ‘Watchmen’ co-creator Dave Gibbons, the game boasts fully animated facial expressions, enhanced graphics throughout, high quality music as well as a context-sensitive hint system, and diary.<br><br><strong>Key Features:</strong><br><ul class="bb_ul"><li>Over 60 characters with which to interact<br></li><li>A multitude of highly detailed locations to explore<br></li><li>Hundreds of mind-bending puzzles and clues to collect<br></li><li>Beautiful classically animated sequences<br></li><li>Stunning music from world-famous composer, Barrington Pheloung</li></ul>','‘Broken Sword - The Smoking Mirror: Remastered’ is a stunning update to the multi million-selling original. While investigating a ruthless drug gang, journalist Nico Collard unexpectedly comes across an ancient artifact.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33610,'An ancient conspiracy. A broken code. An unsolved murder. Welcome to Broken Sword – The Sleeping Dragon, the multi BAFTA-nominated adventure. Once more George and Nico must travel the world, wrestling danger, and piecing together the clues that will unravel the secrets of the Sleeping Dragon.<br><br>Powerful seismic events are shaking the world. Something sinister is emerging. An Ancient Conspiracy, the Secret of the Templars, and a fiendish source of pure Evil are responsible. The death of a back bedroom computer hacker in Paris is just the beginning of another extraordinary adventure for George Stobbart and Nico Collard. Welcome to the world of Broken Sword.<br><br><strong>Key Features:</strong><br><ul class="bb_ul"><li>Includes breathtaking 3D graphics<br></li><li>A powerful and unique interface<br></li><li>Submerge yourself into Broken Sword universe with The Sleeping Dragon’s unique visual style.</li></ul>','An ancient conspiracy. A broken code. An unsolved murder. Welcome to Broken Sword – The Sleeping Dragon, the multi BAFTA-nominated adventure. Once more George and Nico must travel the world, wrestling danger, and piecing together the clues that will unravel the secrets of the Sleeping Dragon.<br><br>Powerful seismic events are shaking the world. Something sinister is emerging. An Ancient Conspiracy, the Secret of the Templars, and a fiendish source of pure Evil are responsible. The death of a back bedroom computer hacker in Paris is just the beginning of another extraordinary adventure for George Stobbart and Nico Collard. Welcome to the world of Broken Sword.<br><br><strong>Key Features:</strong><br><ul class="bb_ul"><li>Includes breathtaking 3D graphics<br></li><li>A powerful and unique interface<br></li><li>Submerge yourself into Broken Sword universe with The Sleeping Dragon’s unique visual style.</li></ul>','An ancient conspiracy. A broken code. An unsolved murder. Welcome to Broken Sword – The Sleeping Dragon, the multi BAFTA-nominated adventure. Once more George and Nico must travel the world, wrestling danger, and piecing together the clues that will unravel the secrets of the Sleeping Dragon.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33620,'Like its predecessors, Crash Time 3, the new installment of the well-known action racing game series, offers varied gameplay in top quality. The German game forge Synetic has once more taken the graphics engine a significant step further. In a gorgeous game world, completely explorable on wheels, the player gets to solve gripping criminal cases and master other diverse assignments.<br>						An overview of essential innovations in Crash Time 3:<br>						<strong>Completely reworked Story Mode:</strong> The previously published parts of the Crash Time series already offered tons of breathtaking action. Crash Time 3 also includes an all-new storyline. Right from the start, the player learns about the destructive power of a terrorist organization that will cross our heroes'' path again and again during the game. In the course of the game, the player''s objective is to discover more and more details and information regarding a series of crimes that seem to have no connection at first, and then solve everything in a grand finale.<br>						<strong>Extended scope of action:</strong> The player is immersed deeper into the game''s storyline, interviewing informants and collecting information. And the player gets to decide how to proceed while completing the missions – simply stop the opponent with a block pass, or employ other means to achieve the given objective?<br>						<strong>Pathfinding – improved navigation:</strong> An intelligent AI allows delinquent opponents to calculate the shortest paths automatically, and adapts the vehicle performance to the road conditions. <br>						<strong>Fantastic driving physics:</strong> A state-of-the-art physics system offers an even more realistic driving experience.<br>						<strong>Score card:</strong> The score card lists the status of missions, the efficiency of the player''s approach, and the game results in great detail.<br>						<ul class="bb_ul"><li>A gripping storyline and more than 70 missions with many different challenges await the player <br>						</li><li>Bad guys try to avoid capture with all kinds of tricks and driving stunts<br>						</li><li>Area of 32 km2with more than 200 km of city streets and autobahn where you get to drive around by day and by night <br>						</li><li>More than 40 vehicles, from police cars and airport fire engines to tricycles<br>						</li><li>The Story mode creates a dense atmosphere<br>						</li><li>The dynamic pathfinder function of vehicles creates variation and increases the replay value<br>						</li><li>Typical ambiance of the series, with extremely fast car chases and explosive crashes<br>						</li></ul>','Like its predecessors, Crash Time 3, the new installment of the well-known action racing game series, offers varied gameplay in top quality. The German game forge Synetic has once more taken the graphics engine a significant step further. In a gorgeous game world, completely explorable on wheels, the player gets to solve gripping criminal cases and master other diverse assignments.<br>						An overview of essential innovations in Crash Time 3:<br>						<strong>Completely reworked Story Mode:</strong> The previously published parts of the Crash Time series already offered tons of breathtaking action. Crash Time 3 also includes an all-new storyline. Right from the start, the player learns about the destructive power of a terrorist organization that will cross our heroes'' path again and again during the game. In the course of the game, the player''s objective is to discover more and more details and information regarding a series of crimes that seem to have no connection at first, and then solve everything in a grand finale.<br>						<strong>Extended scope of action:</strong> The player is immersed deeper into the game''s storyline, interviewing informants and collecting information. And the player gets to decide how to proceed while completing the missions – simply stop the opponent with a block pass, or employ other means to achieve the given objective?<br>						<strong>Pathfinding – improved navigation:</strong> An intelligent AI allows delinquent opponents to calculate the shortest paths automatically, and adapts the vehicle performance to the road conditions. <br>						<strong>Fantastic driving physics:</strong> A state-of-the-art physics system offers an even more realistic driving experience.<br>						<strong>Score card:</strong> The score card lists the status of missions, the efficiency of the player''s approach, and the game results in great detail.<br>						<ul class="bb_ul"><li>A gripping storyline and more than 70 missions with many different challenges await the player <br>						</li><li>Bad guys try to avoid capture with all kinds of tricks and driving stunts<br>						</li><li>Area of 32 km2with more than 200 km of city streets and autobahn where you get to drive around by day and by night <br>						</li><li>More than 40 vehicles, from police cars and airport fire engines to tricycles<br>						</li><li>The Story mode creates a dense atmosphere<br>						</li><li>The dynamic pathfinder function of vehicles creates variation and increases the replay value<br>						</li><li>Typical ambiance of the series, with extremely fast car chases and explosive crashes<br>						</li></ul>','Like its predecessors, Crash Time 3, the new installment of the well-known action racing game series, offers varied gameplay in top quality. The German game forge Synetic has once more taken the graphics engine a significant step further.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33650,'<strong>Puzzler World</strong> brings over 1200 puzzles of 8 popular puzzle types to your PC. Conceptis picture logic puzzle fans will be happy to know that in addition to Crossword, Wordsearch, Fitword, Sudoku, Codeword, Spot the Difference and Silhouette puzzles, Puzzler World also offers 83 Conceptis Link-a-Pix available in sizes of 10x10, 20x20 and 25x25.<br>						<strong>Puzzler World</strong> is split across two game modes: Quickplay, for a fast puzzle fix, and Challenge, for advance gaming where you can prove your puzzling prowess and tackle a wealth of puzzles and unlockable bonus games on offer.<br>						Successful players can win Hint Tokens to spend on tips and solutions as well as unlock exciting Bonus Games from six additional games to discover; Hangman, Chain Letters, Equate, Jigsaw, Picture Quiz and Missing Piece. The game also boasts a Handwriting Recognition feature which allows players to teach the game their own unique alphabet and handwriting style.<br>						<strong>Key Features:</strong><br>						<ul class="bb_ul"><li><strong>Challenge:</strong> Play for Bonus Games and Rewards, or beat your personal best time.<br>							</li><li><strong>Family Favourites:</strong> Including Wordsearch, Crossword, Sudoku, Spot-the-Difference, Silhouette, Codeword, Fitword and Link-a-Pix<br>							</li><li><strong>Quick Play:</strong> An instant way to improve your puzzling skills.<br>							</li><li><strong>Bonus Games:</strong> Unlock additional bonus games in Challenge mode including Hangman, Equate, Jigsaw, Picture Quiz, Chain Letters and Missing Piece.<br>							</li><li><strong>Handwriting Recognition:</strong> You can write in your own handwriting style which the game will learn to recognize.<br>						</li></ul>','<strong>Puzzler World</strong> brings over 1200 puzzles of 8 popular puzzle types to your PC. Conceptis picture logic puzzle fans will be happy to know that in addition to Crossword, Wordsearch, Fitword, Sudoku, Codeword, Spot the Difference and Silhouette puzzles, Puzzler World also offers 83 Conceptis Link-a-Pix available in sizes of 10x10, 20x20 and 25x25.<br>						<strong>Puzzler World</strong> is split across two game modes: Quickplay, for a fast puzzle fix, and Challenge, for advance gaming where you can prove your puzzling prowess and tackle a wealth of puzzles and unlockable bonus games on offer.<br>						Successful players can win Hint Tokens to spend on tips and solutions as well as unlock exciting Bonus Games from six additional games to discover; Hangman, Chain Letters, Equate, Jigsaw, Picture Quiz and Missing Piece. The game also boasts a Handwriting Recognition feature which allows players to teach the game their own unique alphabet and handwriting style.<br>						<strong>Key Features:</strong><br>						<ul class="bb_ul"><li><strong>Challenge:</strong> Play for Bonus Games and Rewards, or beat your personal best time.<br>							</li><li><strong>Family Favourites:</strong> Including Wordsearch, Crossword, Sudoku, Spot-the-Difference, Silhouette, Codeword, Fitword and Link-a-Pix<br>							</li><li><strong>Quick Play:</strong> An instant way to improve your puzzling skills.<br>							</li><li><strong>Bonus Games:</strong> Unlock additional bonus games in Challenge mode including Hangman, Equate, Jigsaw, Picture Quiz, Chain Letters and Missing Piece.<br>							</li><li><strong>Handwriting Recognition:</strong> You can write in your own handwriting style which the game will learn to recognize.<br>						</li></ul>','Puzzler World brings over 1200 puzzles of 8 popular puzzle types to your PC. Conceptis picture logic puzzle fans will be happy to know that in addition to Crossword, Wordsearch, Fitword, Sudoku, Codeword, Spot the Difference and Silhouette puzzles, Puzzler World also offers 83 Conceptis Link-a-Pix available in sizes of 10x10, 20x20 and...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33660,'<p>Once upon a time The Earth was green and beautiful. It was entrusted to humans to use it wisely together with all living things.</p>
						<p>Over time humans developed advanced technology using up the Earth’s natural resources. Humans lost their connection with the Earth. Caring only for their selfish interests, they didn’t notice the injuries that they had inflicted upon the Earth.</p>
						<p>Climate change became the Earth’s scream for help. But nobody heard. Nobody until the cries become so strong that they woke up <strong>Ziro</strong>, the youngest member of the ancient order of Snowmen Earth guardians.</p>
						<p><strong>Ziro</strong> will take you on a journey of puzzle solving. You will be able to learn how you can reconnect and help Mother Earth.</p>
						<p><strong>Ziro</strong> is innovative puzzle game offering incredible game-play in various levels of difficulty. You can relax and enjoy, or try to solve a serious puzzle that will prove to be a true challenge even for the experienced puzzle solver.</p>
						<p>So, Warm Up The Brain and Cool Down The Earth!</p>
						<p><strong>Key features:</strong></p>
						<ul>
							<li>Puzzle game featuring over 300 mind-cracking levels that will take player all around world in noble quest of fighting global warming</li>
							<li>Full 3D graphics powered by Ultra Engine technology that provides stunning graphics and visual effects rarely seen in casual games</li>
							<li>A wide variety of puzzle elements that will heat up even the most prepared brains</li>
							<li>Relax tension of problem solving and boost up your mood with 40 minutes of funky music</li>
							<li>3 different game modes: Quest, Skill and Practice – a challenge for everyone’s taste</li>
							<li>36 Steam Achievements</li>
							<li>Each level Leaderboard, including total Leaderboards for each game mode</li>
							<li>Enjoy the trip around the world through beautiful environments that are unique and characteristic for each part of the globe</li>
							<li>Learn the most important facts about global warming through fun and excitement</li>
						</ul>','<p>Once upon a time The Earth was green and beautiful. It was entrusted to humans to use it wisely together with all living things.</p>
						<p>Over time humans developed advanced technology using up the Earth’s natural resources. Humans lost their connection with the Earth. Caring only for their selfish interests, they didn’t notice the injuries that they had inflicted upon the Earth.</p>
						<p>Climate change became the Earth’s scream for help. But nobody heard. Nobody until the cries become so strong that they woke up <strong>Ziro</strong>, the youngest member of the ancient order of Snowmen Earth guardians.</p>
						<p><strong>Ziro</strong> will take you on a journey of puzzle solving. You will be able to learn how you can reconnect and help Mother Earth.</p>
						<p><strong>Ziro</strong> is innovative puzzle game offering incredible game-play in various levels of difficulty. You can relax and enjoy, or try to solve a serious puzzle that will prove to be a true challenge even for the experienced puzzle solver.</p>
						<p>So, Warm Up The Brain and Cool Down The Earth!</p>
						<p><strong>Key features:</strong></p>
						<ul>
							<li>Puzzle game featuring over 300 mind-cracking levels that will take player all around world in noble quest of fighting global warming</li>
							<li>Full 3D graphics powered by Ultra Engine technology that provides stunning graphics and visual effects rarely seen in casual games</li>
							<li>A wide variety of puzzle elements that will heat up even the most prepared brains</li>
							<li>Relax tension of problem solving and boost up your mood with 40 minutes of funky music</li>
							<li>3 different game modes: Quest, Skill and Practice – a challenge for everyone’s taste</li>
							<li>36 Steam Achievements</li>
							<li>Each level Leaderboard, including total Leaderboards for each game mode</li>
							<li>Enjoy the trip around the world through beautiful environments that are unique and characteristic for each part of the globe</li>
							<li>Learn the most important facts about global warming through fun and excitement</li>
						</ul>','Once upon a time The Earth was green and beautiful. It was entrusted to humans to use it wisely together with all living things. Over time humans developed advanced technology using up the Earth’s natural resources. Humans lost their connection with the Earth.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33670,'<h1>Steam Exclusive Offer</h1><p><p>This Steam Special Edition includes three exclusive maps and Steam Achievements</p>
					<ul>
					<li>Three Steam-Exclusive additional maps for single player and hot seat mode: The Fall of Londeron, Secret Knowledge, Borderlands
					<li>Over 50 Steam Achievements to unlock
					</ul>
					</p><br><h1>About the Game</h1><p><i>Disciples III: Renaissance</i> is the next title in the award-winning Disciples series and represents a leap forward in the evolution of the turn-based strategy RPG genre.  Building on the overwhelming successes of the first two games, <i>Disciples III: Renaissance</i> introduces a host of new features as well as the compelling gameplay that made the previous titles so popular.</p>
					<ul>
					<li><strong>Three playable races</strong> - the Empire, the Legions of the Damned and the Elven Alliance fight for control of the fantasy world of Nevendar. Each race features unique skills and styles.</li>
					<li><strong>Beautiful 3D graphics</strong> – a new gameplay engine offers lush 3D worlds, a rarity in the tactical turn-based strategy genre.</li>
					<li><strong>Become a hero</strong> – create a custom hero and lead a party into battle with a huge variety of creatures. Equip your hero from a selection of more than 450 weapons, spells and artifacts.</li>
					<li><strong>Unique characters and classes</strong> – recruit party members to aid you in battle. Paladins, Mages, Healers and more feature distinct and visually stunning spells and powers.</li>
					<li><strong>A vast world to explore</strong> -19 missions spread across three campaigns take place in a vast fantasy world rendered in stunning detail.</li>
					<li><strong>Extensive single-player gameplay</strong> – over 70 hours of campaign play across 19 missions.</li>
					<li><strong>Local multi-player gameplay</strong>
					</ul>','<p><i>Disciples III: Renaissance</i> is the next title in the award-winning Disciples series and represents a leap forward in the evolution of the turn-based strategy RPG genre.  Building on the overwhelming successes of the first two games, <i>Disciples III: Renaissance</i> introduces a host of new features as well as the compelling gameplay that made the previous titles so popular.</p>
					<ul>
					<li><strong>Three playable races</strong> - the Empire, the Legions of the Damned and the Elven Alliance fight for control of the fantasy world of Nevendar. Each race features unique skills and styles.</li>
					<li><strong>Beautiful 3D graphics</strong> – a new gameplay engine offers lush 3D worlds, a rarity in the tactical turn-based strategy genre.</li>
					<li><strong>Become a hero</strong> – create a custom hero and lead a party into battle with a huge variety of creatures. Equip your hero from a selection of more than 450 weapons, spells and artifacts.</li>
					<li><strong>Unique characters and classes</strong> – recruit party members to aid you in battle. Paladins, Mages, Healers and more feature distinct and visually stunning spells and powers.</li>
					<li><strong>A vast world to explore</strong> -19 missions spread across three campaigns take place in a vast fantasy world rendered in stunning detail.</li>
					<li><strong>Extensive single-player gameplay</strong> – over 70 hours of campaign play across 19 missions.</li>
					<li><strong>Local multi-player gameplay</strong>
					</ul>','This Steam Special Edition includes three exclusive maps and Steam Achievements.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33680,'The Princess of the Flower Kingdom has vanished! She was taken by the Ghulibas of the north, and it is up to brave Zee Tee to rescue her. On his quest, he - and you - will discover the hidden lands behind the peaceful kingdom, and come face to face with secrets that will set you on edge!<br>						This is the high-definition version of indie fan favorite Eversion, now with Steam support! Complete achievements and compete against your friends in Time Attack levels!<br>						<strong>Key features:</strong><br>						<ul class="bb_ul"><li> Retro-style platform gameplay<br>							</li><li>Dimension-shifting gameplay changes the level around you<br>							</li><li>Explore eight carefully crafted unique worlds<br>							</li><li>Hand-drawn pixel art, legitimate indie-style<br>							</li><li>Surprising plot twists<br>							</li><li>Game length ideal for busy videogame fans<br>							</li><li>Three different endings<br>							</li><li>Extra entertainment value when played alone at night<br>							</li><li>An unforgettable experience<br>						</li></ul>','The Princess of the Flower Kingdom has vanished! She was taken by the Ghulibas of the north, and it is up to brave Zee Tee to rescue her. On his quest, he - and you - will discover the hidden lands behind the peaceful kingdom, and come face to face with secrets that will set you on edge!<br>						This is the high-definition version of indie fan favorite Eversion, now with Steam support! Complete achievements and compete against your friends in Time Attack levels!<br>						<strong>Key features:</strong><br>						<ul class="bb_ul"><li> Retro-style platform gameplay<br>							</li><li>Dimension-shifting gameplay changes the level around you<br>							</li><li>Explore eight carefully crafted unique worlds<br>							</li><li>Hand-drawn pixel art, legitimate indie-style<br>							</li><li>Surprising plot twists<br>							</li><li>Game length ideal for busy videogame fans<br>							</li><li>Three different endings<br>							</li><li>Extra entertainment value when played alone at night<br>							</li><li>An unforgettable experience<br>						</li></ul>','The Princess of the Flower Kingdom has vanished! She was taken by the Ghulibas of the north, and it is up to brave Zee Tee to rescue her. On his quest, he - and you - will discover the hidden lands behind the peaceful kingdom, and come face to face with secrets that will set you on edge!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33760,'Follow Amelia Earhart’s life through space and time to learn about her accomplishments and discover what could have really happened to her on her last flight.  Only you can discover the truth of what really happened on that long flight so many years ago!<h2 class="bb_tag">Features:</h2><ul class="bb_ul"><li>Uncover history as you search for actual memorabilia left behind by Amelia.<br></li><li>Locate and assemble the hidden clues to help unfold Amelia’s story and, ultimately, unlock her mystery.<br></li><li>Plot coordinates using the Coordinator Locator to discover the places Amelia visited around the world. <br></li><li>Find the missing clues in this exciting Hidden Object Adventure game!<br></li><li>Solve 5 mind-bending mini-games including spot the difference and plot the coordinates.<br></li><li>Explore 32 scenes in order to find clues and reveal the missing links to Amelia’s disappearance.</li></ul>','Follow Amelia Earhart’s life through space and time to learn about her accomplishments and discover what could have really happened to her on her last flight.  Only you can discover the truth of what really happened on that long flight so many years ago!<h2 class="bb_tag">Features:</h2><ul class="bb_ul"><li>Uncover history as you search for actual memorabilia left behind by Amelia.<br></li><li>Locate and assemble the hidden clues to help unfold Amelia’s story and, ultimately, unlock her mystery.<br></li><li>Plot coordinates using the Coordinator Locator to discover the places Amelia visited around the world. <br></li><li>Find the missing clues in this exciting Hidden Object Adventure game!<br></li><li>Solve 5 mind-bending mini-games including spot the difference and plot the coordinates.<br></li><li>Explore 32 scenes in order to find clues and reveal the missing links to Amelia’s disappearance.</li></ul>','Follow Amelia Earhart’s life through space and time to learn about her accomplishments and discover what could have really happened to her on her last flight. Only you can discover the truth of what really happened on that long flight so many years ago!Features:Uncover history as you search for actual memorabilia left behind by Amelia.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33770,'The prequel to Radon Labs'' award-winning RPG, Drakensang: The River of Time introduces a brand new story within the Drakensang universe. The new story brings many innovations and new game elements for experienced as well for first time players, who will jump right into the fascinating medieval fantasy RPG scenario of Drakensang: The River Of Time.<br />
						Starting in Aventuria’s Middenrealm in the city of Ferdok, the story of the games takes players down the Great River to the city of Nadoret. Many mythical legends entwine around this river and will also flow into the main plot. The story will contain more twists than in Drakensang: With every place the player visits, his view on things will change. Depending on the choice of character, and behavior, new opportunities and series of quests will come up.<br />
						Living on a ship, players will experience a broad variety of RPG quests. There will be two new character archetypes to play, tons of new foes and monsters as well as equipment items.<br />
						Two new classes of heroes: the Geodes (rare Aventurian druids of the dwarfs) and the Gjalskerland inhabitants (tenacious and hard barbarians).<br />
						Advanced expert mode and adjustable levels of difficulty.','The prequel to Radon Labs'' award-winning RPG, Drakensang: The River of Time introduces a brand new story within the Drakensang universe. The new story brings many innovations and new game elements for experienced as well for first time players, who will jump right into the fascinating medieval fantasy RPG scenario of Drakensang: The River Of Time.<br />
						Starting in Aventuria’s Middenrealm in the city of Ferdok, the story of the games takes players down the Great River to the city of Nadoret. Many mythical legends entwine around this river and will also flow into the main plot. The story will contain more twists than in Drakensang: With every place the player visits, his view on things will change. Depending on the choice of character, and behavior, new opportunities and series of quests will come up.<br />
						Living on a ship, players will experience a broad variety of RPG quests. There will be two new character archetypes to play, tons of new foes and monsters as well as equipment items.<br />
						Two new classes of heroes: the Geodes (rare Aventurian druids of the dwarfs) and the Gjalskerland inhabitants (tenacious and hard barbarians).<br />
						Advanced expert mode and adjustable levels of difficulty.','The prequel to Radon Labs'' award-winning RPG, Drakensang: The River of Time introduces a brand new story within the Drakensang universe. The new story brings many innovations and new game elements for experienced as well for first time players, who will jump right into the fascinating medieval fantasy RPG scenario of Drakensang: The...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33790,'<p>Unravel the Medical Mysteries in this Dramatic Puzzle Adventure! Follow Elizabeth through an engaging storyline with her fellow doctors, staff and some interesting sales reps.! Search for clues to diagnose and solve medical problems for a variety of patients in this enjoyable seek & find game.  Study X-rays, blood tests and 4 more medical mini games add to the fun and future health of your patients!</p>
						<h2>Key features:</h2><ul>
						<li>3 new medical cases.
						<li>New characters & storylines – travel to farms, boating piers, vet clinics, etc. to find clues.
						<li>Interactive inventory items – Pull out drawers, move curtains and more to find clues!
						<li>After reviewing the evidence you make the diagnosis.
						<li>6 new mini-games – X-rays, blood tests, heart rate monitors, and more!
						<li>Over 20 unique hidden object scenes.</ul>','<p>Unravel the Medical Mysteries in this Dramatic Puzzle Adventure! Follow Elizabeth through an engaging storyline with her fellow doctors, staff and some interesting sales reps.! Search for clues to diagnose and solve medical problems for a variety of patients in this enjoyable seek & find game.  Study X-rays, blood tests and 4 more medical mini games add to the fun and future health of your patients!</p>
						<h2>Key features:</h2><ul>
						<li>3 new medical cases.
						<li>New characters & storylines – travel to farms, boating piers, vet clinics, etc. to find clues.
						<li>Interactive inventory items – Pull out drawers, move curtains and more to find clues!
						<li>After reviewing the evidence you make the diagnosis.
						<li>6 new mini-games – X-rays, blood tests, heart rate monitors, and more!
						<li>Over 20 unique hidden object scenes.</ul>','Unravel the Medical Mysteries in this Dramatic Puzzle Adventure!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33900,'Building on 10 years of constant engine development, ARMA II boasts the most realistic combat environment in the world. It models real world ballistics &amp; round deflection, materials penetration, features a realtime day/night cycle and dynamic wind, weather and environmental effects. The simulation of a combat environment is so effective, the engine forms the basis for training simulators used by real armies the world over.<br>                    Although ARMA II is set in the fictional ex-soviet state of ''Chernarus'' the gameworld is actually a 225 square kilometer chunk of the real world! ARMA II''s highly detailed landscape is a meticulous facsimile of real terrain, modeled using extensive geographical data. This recreated region is brought to life with spectacular environmental effects and populated with dynamic civilian settlements and wildlife. Wild animals roam the atmospheric forests while the people of Chernarus try to live out their lives among the war-torn streets.<br>                    The 27th U.S. Marine Expeditionary Unit have been deployed to the former soviet country of Chernarus in this third installment in the series of award winning PC war simulators from Bohemia Interactive, creators of Operation Flashpoint*: Cold War Crisis and ARMA: Combat Operations.<br>                    Force Reconnaissance Team Razor are among the first to fight. This elite five-man team are about to fall down the rabbit hole, trapped in a war not only for control of the country, but the hearts and minds of its people. With the might of the USMC offshore and the Russians anxiously watching from the north, the stakes couldn''t be higher. The fate of Chernarus is balanced on a razor''s edge...<br>					<h2 class="bb_tag">Key Features</h2>                    <ul class="bb_ul"><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/PlayerDrivenStory.jpg" ><strong>PLAYER-DRIVEN STORY</strong> - Command your troops through a branching campaign full of twists and surprises.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/ThrillingRealism.jpg" ><strong>THRILLING REALISM</strong> - Explore the 225 square kilometer of highly detailed landscape, modelled using real-world geographical data and master each of 81 weapons and 120+ vehicles.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/AuthenticSimulation.jpg" ><strong>AUTHENTIC SIMULATION</strong> - Game simulates various aspects of combat and evironment effects from bullet ballistics, material penetration, ammunition types and stopping power to weather conditions.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/ExtensiveMultiplayer.jpg" ><strong>EXTENSIVE MULTIPLAYER</strong> - Play the campaign missions in cooperative mode or join duty in the massive multiplayer battles with up to 50 players.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/AdvancedAI.jpg" ><strong>ADVANCED AI</strong> - Compete the ultimate next-gen AI: no scripts, no predefined pathways. All units react on actual game situation.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/MissionEditor.jpg" ><strong>MISSION EDITOR</strong> - Design your own missions by the intuitive, easy-to-use mission editor and become part of one of the biggest and most creative PC gaming community ever.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/CheatProtection.jpg" ><strong>CHEAT PROTECTION</strong> - Optional anti-cheat BattlEye (<a href="https://steamcommunity.com/linkfilter/?url=http://www.battleye.com" target="_blank" rel="noopener"  >http://www.battleye.com</a>) available to help secure dedicated servers. In addition BE adds ''RCON'' (remote control) for game''s dedicated server software.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/DedicatedServer.jpg" ><strong>DEDICATED SERVER</strong> - To support smooth multi-player experience there is ''dedicated server software'' available for Windows (included with game) and Linux (download-able from game''s website).<br></li></ul>','Building on 10 years of constant engine development, ARMA II boasts the most realistic combat environment in the world. It models real world ballistics &amp; round deflection, materials penetration, features a realtime day/night cycle and dynamic wind, weather and environmental effects. The simulation of a combat environment is so effective, the engine forms the basis for training simulators used by real armies the world over.<br>                    Although ARMA II is set in the fictional ex-soviet state of ''Chernarus'' the gameworld is actually a 225 square kilometer chunk of the real world! ARMA II''s highly detailed landscape is a meticulous facsimile of real terrain, modeled using extensive geographical data. This recreated region is brought to life with spectacular environmental effects and populated with dynamic civilian settlements and wildlife. Wild animals roam the atmospheric forests while the people of Chernarus try to live out their lives among the war-torn streets.<br>                    The 27th U.S. Marine Expeditionary Unit have been deployed to the former soviet country of Chernarus in this third installment in the series of award winning PC war simulators from Bohemia Interactive, creators of Operation Flashpoint*: Cold War Crisis and ARMA: Combat Operations.<br>                    Force Reconnaissance Team Razor are among the first to fight. This elite five-man team are about to fall down the rabbit hole, trapped in a war not only for control of the country, but the hearts and minds of its people. With the might of the USMC offshore and the Russians anxiously watching from the north, the stakes couldn''t be higher. The fate of Chernarus is balanced on a razor''s edge...<br>					<h2 class="bb_tag">Key Features</h2>                    <ul class="bb_ul"><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/PlayerDrivenStory.jpg" ><strong>PLAYER-DRIVEN STORY</strong> - Command your troops through a branching campaign full of twists and surprises.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/ThrillingRealism.jpg" ><strong>THRILLING REALISM</strong> - Explore the 225 square kilometer of highly detailed landscape, modelled using real-world geographical data and master each of 81 weapons and 120+ vehicles.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/AuthenticSimulation.jpg" ><strong>AUTHENTIC SIMULATION</strong> - Game simulates various aspects of combat and evironment effects from bullet ballistics, material penetration, ammunition types and stopping power to weather conditions.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/ExtensiveMultiplayer.jpg" ><strong>EXTENSIVE MULTIPLAYER</strong> - Play the campaign missions in cooperative mode or join duty in the massive multiplayer battles with up to 50 players.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/AdvancedAI.jpg" ><strong>ADVANCED AI</strong> - Compete the ultimate next-gen AI: no scripts, no predefined pathways. All units react on actual game situation.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/MissionEditor.jpg" ><strong>MISSION EDITOR</strong> - Design your own missions by the intuitive, easy-to-use mission editor and become part of one of the biggest and most creative PC gaming community ever.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/CheatProtection.jpg" ><strong>CHEAT PROTECTION</strong> - Optional anti-cheat BattlEye (<a href="https://steamcommunity.com/linkfilter/?url=http://www.battleye.com" target="_blank" rel="noopener"  >http://www.battleye.com</a>) available to help secure dedicated servers. In addition BE adds ''RCON'' (remote control) for game''s dedicated server software.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33900/extras/DedicatedServer.jpg" ><strong>DEDICATED SERVER</strong> - To support smooth multi-player experience there is ''dedicated server software'' available for Windows (included with game) and Linux (download-able from game''s website).<br></li></ul>','Building on 10 years of constant engine development, ARMA II boasts the most realistic combat environment in the world. It models real world ballistics &amp; round deflection, materials penetration, features a realtime day/night cycle and dynamic wind, weather and environmental effects.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33930,'Three years after the conflict in Chernarus, portrayed in the original Arma 2, a new flashpoint explodes in the Green Sea Region. Coalition forces led by the US Army are deployed to Takistan to quickly restore peace and prevent further civilian casualties.<br>					You will enlist into various roles within the US Army, from basic infantrymen, through special operatives, to pilots and tank crew in this new installment in the award winning line up of military simulators for PC from Bohemia Interactive.<br>					Building on 10 years of experience and constant engine development, Arma 2: Operation Arrowhead boasts the most realistic combat environment in the world. It models real world ballistics &amp; round deflection, thermal imaging, materials penetration, features a realtime day/night cycle and dynamic wind, weather and environmental effects.<br>					<h2 class="bb_tag">NOTE:</h2>					Arma 2: Operation Arrowhead is a standalone product and does not require the original Arma 2.<h2 class="bb_tag">Key features:</h2>					<ul class="bb_ul"><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/NewPlayableContent.jpg" ><strong>NEW PLAYABLE CONTENT:</strong> New story campaign for both SP and MP gameplay. Wide range of new tutorials, single scenarios and multiplayer modes.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/MassiveGameWorld.jpg" ><strong>MASSIVE GAME WORLD:</strong> Three brand new Central Asia-style large maps including expansive urban, desert and mountainous terrain featuring a fully destructible and interactive environment.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/UltimateWarExperience.jpg" ><strong>ULTIMATE WAR EXPERIENCE:</strong> Fully integrates with the original Arma 2 for unmatched warfare simulation.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/UniqueGameplayElements.jpg" ><strong>UNIQUE GAMEPLAY ELEMENTS:</strong> Detachable backpacks with equipment, advanced weapon optics, material penetration modelling, remote real-time simulation of Unmanned Arial Vehicles (UAV), freedom of decision and repercussive actions.<br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/ExtraUnitsVehicles.jpg" ><strong>EXTRA UNITS AND VEHICLES:</strong> Multiple factions for all sides including US Army, United Nations, Takistani Army and Guerrillas making a collection of 300+ new units, weapons and vehicles.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/MissionEditor.jpg" ><strong>MISSION EDITOR:</strong> Design your own missions by the intuitive, easy-to-use mission editor and become part of one of the biggest and most creative PC gaming community ever.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/GameModification.jpg" ><strong>GAME MODIFICATION:</strong> Create Your own custom game content with complete editing tools suite (freeware SDK kit) and modify the game in ways where the only limitation is Your own imagination.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/ExtensiveMultiplayer.jpg" ><strong>EXTENSIVE MULTIPLAYER:</strong> Play the campaign missions in cooperative mode or join duty in the massive multiplayer battles with up to 50 players.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/CheatProtection.jpg" ><strong>CHEAT PROTECTION:</strong> Optional anti-cheat BattlEye (<a href="https://steamcommunity.com/linkfilter/?url=http://www.battleye.com" target="_blank" rel="noopener"  >http://www.battleye.com</a>) available to help secure dedicated servers. In addition BE adds ''RCON'' (remote control) for game''s dedicated server software.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/DedicatedServer.jpg" ><strong>DEDICATED SERVER:</strong> To support smooth multi-player experience there is ''dedicated server software'' available for Windows (included with game) and Linux (download-able from game''s website).<br></li></ul>','Three years after the conflict in Chernarus, portrayed in the original Arma 2, a new flashpoint explodes in the Green Sea Region. Coalition forces led by the US Army are deployed to Takistan to quickly restore peace and prevent further civilian casualties.<br>					You will enlist into various roles within the US Army, from basic infantrymen, through special operatives, to pilots and tank crew in this new installment in the award winning line up of military simulators for PC from Bohemia Interactive.<br>					Building on 10 years of experience and constant engine development, Arma 2: Operation Arrowhead boasts the most realistic combat environment in the world. It models real world ballistics &amp; round deflection, thermal imaging, materials penetration, features a realtime day/night cycle and dynamic wind, weather and environmental effects.<br>					<h2 class="bb_tag">NOTE:</h2>					Arma 2: Operation Arrowhead is a standalone product and does not require the original Arma 2.<h2 class="bb_tag">Key features:</h2>					<ul class="bb_ul"><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/NewPlayableContent.jpg" ><strong>NEW PLAYABLE CONTENT:</strong> New story campaign for both SP and MP gameplay. Wide range of new tutorials, single scenarios and multiplayer modes.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/MassiveGameWorld.jpg" ><strong>MASSIVE GAME WORLD:</strong> Three brand new Central Asia-style large maps including expansive urban, desert and mountainous terrain featuring a fully destructible and interactive environment.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/UltimateWarExperience.jpg" ><strong>ULTIMATE WAR EXPERIENCE:</strong> Fully integrates with the original Arma 2 for unmatched warfare simulation.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/UniqueGameplayElements.jpg" ><strong>UNIQUE GAMEPLAY ELEMENTS:</strong> Detachable backpacks with equipment, advanced weapon optics, material penetration modelling, remote real-time simulation of Unmanned Arial Vehicles (UAV), freedom of decision and repercussive actions.<br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/ExtraUnitsVehicles.jpg" ><strong>EXTRA UNITS AND VEHICLES:</strong> Multiple factions for all sides including US Army, United Nations, Takistani Army and Guerrillas making a collection of 300+ new units, weapons and vehicles.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/MissionEditor.jpg" ><strong>MISSION EDITOR:</strong> Design your own missions by the intuitive, easy-to-use mission editor and become part of one of the biggest and most creative PC gaming community ever.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/GameModification.jpg" ><strong>GAME MODIFICATION:</strong> Create Your own custom game content with complete editing tools suite (freeware SDK kit) and modify the game in ways where the only limitation is Your own imagination.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/ExtensiveMultiplayer.jpg" ><strong>EXTENSIVE MULTIPLAYER:</strong> Play the campaign missions in cooperative mode or join duty in the massive multiplayer battles with up to 50 players.<br><br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/CheatProtection.jpg" ><strong>CHEAT PROTECTION:</strong> Optional anti-cheat BattlEye (<a href="https://steamcommunity.com/linkfilter/?url=http://www.battleye.com" target="_blank" rel="noopener"  >http://www.battleye.com</a>) available to help secure dedicated servers. In addition BE adds ''RCON'' (remote control) for game''s dedicated server software.<br><br><br></li><li><img src="https://steamcdn-a.akamaihd.net/steam/apps/33930/extras/DedicatedServer.jpg" ><strong>DEDICATED SERVER:</strong> To support smooth multi-player experience there is ''dedicated server software'' available for Windows (included with game) and Linux (download-able from game''s website).<br></li></ul>','Three years after the conflict in Chernarus, portrayed in the original Arma 2, a new flashpoint explodes in the Green Sea Region. Coalition forces led by the US Army are deployed to Takistan to quickly restore peace and prevent further civilian casualties.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33950,'In this underwater puzzle game you control fish secret agents Max Flounder and Tina Guppy.<br>						Seemingly a common case turns into a tough fight with a mysterious enemy and the strings appear to lead pretty high. Fortunately, you are not alone. Cool crab brothers, a retired agentess, lost baby seahorse and peculiar pair of snails - all of them will join you to help you to discover the evil one. You will need all your wits if you want to win!<h2 class="bb_tag">Key features:</h2>						<ul class="bb_ul"><li>Unlimited gameplay<br>						</li><li>100+ mind-boggling levels based on simple, yet interesting mechanics.<br>						</li><li>Funny story told by animated sequences.<br>						</li><li>3,000+ professionally dubbed comments and dialogs.<br>						</li><li>Lots of bonus stuff to be found and unlocked by the player.<br>						</li><li>Three unique playable characters: agents Tina and Max + crab Virgil.<br>						</li><li>Dozens hours of gameplay for whole family!<br>						</li><li>Best solution challenge at <a href="https://steamcommunity.com/linkfilter/?url=http://www.fish-fillets.com" target="_blank" rel="noopener"  >www.fish-fillets.com</a>.<br>						</li><li>Send your score to internet chart and compare to other players.<br>						</li><li>Includes Level Editor - allows fans to create new mission and campaigns that can be used in the game.</li></ul>','In this underwater puzzle game you control fish secret agents Max Flounder and Tina Guppy.<br>						Seemingly a common case turns into a tough fight with a mysterious enemy and the strings appear to lead pretty high. Fortunately, you are not alone. Cool crab brothers, a retired agentess, lost baby seahorse and peculiar pair of snails - all of them will join you to help you to discover the evil one. You will need all your wits if you want to win!<h2 class="bb_tag">Key features:</h2>						<ul class="bb_ul"><li>Unlimited gameplay<br>						</li><li>100+ mind-boggling levels based on simple, yet interesting mechanics.<br>						</li><li>Funny story told by animated sequences.<br>						</li><li>3,000+ professionally dubbed comments and dialogs.<br>						</li><li>Lots of bonus stuff to be found and unlocked by the player.<br>						</li><li>Three unique playable characters: agents Tina and Max + crab Virgil.<br>						</li><li>Dozens hours of gameplay for whole family!<br>						</li><li>Best solution challenge at <a href="https://steamcommunity.com/linkfilter/?url=http://www.fish-fillets.com" target="_blank" rel="noopener"  >www.fish-fillets.com</a>.<br>						</li><li>Send your score to internet chart and compare to other players.<br>						</li><li>Includes Level Editor - allows fans to create new mission and campaigns that can be used in the game.</li></ul>','In this underwater puzzle game you control fish secret agents Max Flounder and Tina Guppy. Seemingly a common case turns into a tough fight with a mysterious enemy and the strings appear to lead pretty high. Fortunately, you are not alone.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33980,'Pound of Ground, story driven crazy shoot ''em up with red car and LOTS of zombies.<br>							The game combines action elements - a wide range of advanced weapons, fights with various bosses and spectacular, endless battles with the crowds of the undead - with a gripping story full of unexpected disclosures and peculiar characters.<h2 class="bb_tag">Key features:</h2><ul class="bb_ul"><li>A well-written story full of turns of events; it''s mainly about putting things right, about love and ultimately about saving the whole city<br>							</li><li>Duels with variously designed bosses, but also with the crowds of undead enemies<br>							</li><li>Scenes from ''behind the shut curtain'' that add flavour and humour to the story<br>							</li><li>A number of different tasks ensures extended and variegated playability<br>							</li><li>Unique gameplay elements</li></ul>','Pound of Ground, story driven crazy shoot ''em up with red car and LOTS of zombies.<br>							The game combines action elements - a wide range of advanced weapons, fights with various bosses and spectacular, endless battles with the crowds of the undead - with a gripping story full of unexpected disclosures and peculiar characters.<h2 class="bb_tag">Key features:</h2><ul class="bb_ul"><li>A well-written story full of turns of events; it''s mainly about putting things right, about love and ultimately about saving the whole city<br>							</li><li>Duels with variously designed bosses, but also with the crowds of undead enemies<br>							</li><li>Scenes from ''behind the shut curtain'' that add flavour and humour to the story<br>							</li><li>A number of different tasks ensures extended and variegated playability<br>							</li><li>Unique gameplay elements</li></ul>','Pound of Ground, story driven crazy shoot ''em up with red car and LOTS of zombies. The game combines action elements - a wide range of advanced weapons, fights with various bosses and spectacular, endless battles with the crowds of the undead - with a gripping story full of unexpected disclosures and peculiar characters.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (33990,'Alternativa is a story that will take you to a world much different to what you''d expect in 2045. To a world destroyed by war and revolutions, a world led by an oppressive and cruel dictatorship.<br>					Classic point&amp;click adventure game based on the original sci-fi/cyber-punk script which is composed of a number of shorter stories that lead us through the lives of individual characters as well as the fictional world of the future.<br>					Murder of one, power of a few, betrayal of all!<h2 class="bb_tag">Key features:</h2><ul class="bb_ul"><li>Classic point&amp;click adventure game<br>					</li><li>More than 120 backgrounds modeled in detail<br>					</li><li>Play as up to 4 different characters in the story<br>					</li><li>Original sci-fi story in an elaborate world<br>					</li><li>Simple and easy controls using just a mouse<br>					</li><li>Rendered video sequences<br>					</li><li>2 levels of difficulty<br>					</li><li>Interactive dialogues with choices<br>					</li><li>Original soundtrack</li></ul>','Alternativa is a story that will take you to a world much different to what you''d expect in 2045. To a world destroyed by war and revolutions, a world led by an oppressive and cruel dictatorship.<br>					Classic point&amp;click adventure game based on the original sci-fi/cyber-punk script which is composed of a number of shorter stories that lead us through the lives of individual characters as well as the fictional world of the future.<br>					Murder of one, power of a few, betrayal of all!<h2 class="bb_tag">Key features:</h2><ul class="bb_ul"><li>Classic point&amp;click adventure game<br>					</li><li>More than 120 backgrounds modeled in detail<br>					</li><li>Play as up to 4 different characters in the story<br>					</li><li>Original sci-fi story in an elaborate world<br>					</li><li>Simple and easy controls using just a mouse<br>					</li><li>Rendered video sequences<br>					</li><li>2 levels of difficulty<br>					</li><li>Interactive dialogues with choices<br>					</li><li>Original soundtrack</li></ul>','Alternativa is a story that will take you to a world much different to what you''d expect in 2045. To a world destroyed by war and revolutions, a world led by an oppressive and cruel dictatorship. Classic point&amp;click adventure game based on the original sci-fi/cyber-punk script which is composed of a number of shorter stories that...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34010,'Loyalty carries a price and no one knows this more than agent Michael Thorton. A talented young agent cast out by his government, Thorton is the only one with the information needed to stop an impending international catastrophe.  To do so means he must cut himself off from the very people he is sworn to protect.  As players determine how to accomplish different objectives, the decisions made and actions taken in each mission will ultimately transform the type of secret agent Michael Thorton will become.  Every choice the player makes as Michael Thorton will carry consequences for his future and the fate of the world.','Loyalty carries a price and no one knows this more than agent Michael Thorton. A talented young agent cast out by his government, Thorton is the only one with the information needed to stop an impending international catastrophe.  To do so means he must cut himself off from the very people he is sworn to protect.  As players determine how to accomplish different objectives, the decisions made and actions taken in each mission will ultimately transform the type of secret agent Michael Thorton will become.  Every choice the player makes as Michael Thorton will carry consequences for his future and the fate of the world.','Loyalty carries a price and no one knows this more than agent Michael Thorton. A talented young agent cast out by his government, Thorton is the only one with the information needed to stop an impending international catastrophe. To do so means he must cut himself off from the very people he is sworn to protect.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34030,'<img src="https://%CDN_HOST_MEDIA_SSL%/steam/apps/34030/extras/NAPOLEON_FIRST.gif?t=1548693685" crossorigin="anonymous"><br><br>Complete your Total War collection with this Definitive Edition of Total War: NAPOLEON, which includes all DLC and feature updates since the game’s release:<br><br>Take on the Peninsular Campaign, based on the intense conflict that raged over the Spanish Peninsula between 1811 and 1814. Choose one of the three nations at war - France, Great Britain or Spain – and lead your campaign across an independent map featuring 32 new controllable regions.<br><br>Turn the tide of war with the Coalition Battle Pack, which introduces the Battle of Friedland, the pivotal moment when Napoleon crushed Russia’s attempt to contain him. <br><br>Build an unstoppable force with Heroes of the Napoleonic Wars and the Imperial Eagle Pack, which together add over 20 legendary and elite new units.<br><br>Total War: NAPOLEON Definitive Edition offers hundreds and hundreds of hours of absorbing gameplay and every bit of content made for the game. See below for full details. <br><br><img src="https://%CDN_HOST_MEDIA_SSL%/steam/apps/34030/extras/NAPOLEON_SECOND.gif?t=1548693685" crossorigin="anonymous"><br><br><br>History is as yet unwritten<br><br>From the early Italian campaign to the battle of Waterloo, Total War: NAPOLEON covers two decades of relentless battles, a backdrop of a world in flames against which the story of an extraordinary military career unfolds. <br><br>Whether you play as the legendary general or against him, the outcome of war can never be guaranteed. The course of history relies on your ability to lead your troops through the most intense battles as never seen before in a Total War game.<h2 class="bb_tag"><strong>About The Peninsular Campaign</strong></h2><br><br>The Peninsular Campaign is an independent campaign based on the conflict in the Spanish Peninsula between 1811 and 1814. It was during this era that the Spanish resistance gave their style of fighting its name: Guerrilla, or the “little war”.<br><br>Play the campaign from three different perspectives, each with a unique feel:<br>•	The French fight to keep resistance at bay while converting regions to their political alignment.<br>•	The British are very limited for regions at the start but receive enough income from Northern Europe and North America that they can afford to liberate regions back to the Spanish in return for Guerrilla aid.<br>•	The Spanish also have a limited starting position but have permanent access to Guerrillas for effective battlefield use against the French. <br><br>Choose one of the three nations involved - France, Great Britain or Spain - and experience one of the most intense conflicts of the Napoleonic era.<h2 class="bb_tag"><strong>Key Features:</strong></h2><br><br>•	A new and independent Iberian Peninsula campaign map featuring 32 controllable regions.<br>•	5 new Guerrilla unit types, recruitable by all nations, adept at battlefield stealth and with the added ability to deploy outside of their faction''s deployment zones: Tiradores (Skirmisher Infantry), Cazadores, Lanceros (Lancer Cavalry), Husares (Light Cavalry), Leader (General). <br>•	28 new units in total, spread across the three playable nations including the British 95th Rifles, the French Vistula Uhlans and the Spanish Coraceros Espanoles. <br>•	Two new agents to enforce political conversion: <br>•	Provocateurs (French and British nations only) have the ability to promote anti-opposition sentiment in regions, incite unrest, decreases turn time for research and passively spy.<br>•	Priests (Spanish and Portuguese nations only) have the ability to promote anti-opposition sentiment in regions and incite unrest.<br>•	A new Guerrillero agent for the Spanish nation: similar to a Spy but with the new ability to Harass enemy armies - lock them in place for a turn and cause them attrition.<br>•	Political Alignment system which sees the French battle to increase pro-French sentiment throughout the peninsula.<h2 class="bb_tag"><strong>About Coalition Battle Pack</strong></h2><br><br>The Coalition Battle Pack features 6 brand new units and contains the Battle of Friedland fought between France and Russia.<br>The Battle of Friedland (14 June, 1807) with Napoleon''s empire at its height, he took a chance and defeated Russia in detail, knocking them out of the war and bringing the Fourth Coalition to an end.<br><br>Unit Descriptions: <br>•	Lifeguard Hussars: This fast light cavalry unit is best used for dealing with skirmishers and artillery who can attack from long range.<br>•	Coldstream Guards: Disciplined, well-trained and respected, these elite foot guards inspire nearby troops in battle. <br>•	Archduke Charles'' Legion: This highly-disciplined line infantry regiment excels at weapons drill and accuracy.<br>•	Luetzow''s Freikorps: Swift light cavalry, the riders of Luetzow’s Freikorps are excellent in melee and on the charge.<br>•	Life Hussars: Sabre-armed light cavalry, the Life Hussars are powerful on the charge and effective in melee combat.<br>•	Semenovski Lifeguard: Immaculately turned out, these elite guards have excellent morale and are superb when used against skirmish troops and artillery.<h2 class="bb_tag"><strong>About Heroes of the Napoleonic Wars</strong></h2><br><br>These exclusive elite units become available on the campaign map once you have made a specific technological advancement or own the relevant territory.<br><br>They will appear in both single and multiplayer game modes.<br>•	7th Lancers (France) <br>•	Brandenburg Uhlans (Prussia) <br>•	1st Hussars (Austria) <br>•	15th Hussars (Great Britain) <br>•	1st East Prussian Grenadier Battalion (Prussia) <br>•	6th Regiment d''Infanterie Légère (France)<br>•	17th Jäger Regiment (Russia)<br>•	1st Regiment Emperor''s Own (Austria)<br>•	18th Regiment d''Infanterie de Ligne &quot;The Brave&quot; (France) <br>•	Moscow Musketeers (Russia)<h2 class="bb_tag"><strong>About Imperial Eagle Pack</strong></h2><br><br>These exclusive elite units become available on the campaign map once you have made a specific technological advancement or own the relevant territory.<br><br>They will appear in both single and multiplayer game modes.<br>•	Grand Battery of the Convention (France) <br>•	HMS Elephant (Great Britain) <br>•	Towarczys (Prussia) <br>•	Royal Scots Greys (Great Britain) <br>•	5e Regiment de Hussards (France) <br>•	Pavlograd Hussars (Russia) <br>•	8th Life Regiment (Prussia) <br>•	47th (Czech) Regiment (Austria) <br>•	88th Foot “Connaught Rangers” <br>•	Archduke Ferdinand Cuirassiers (Austria)<br>•	Lifeguard Cossacks (Russia)','<img src="https://%CDN_HOST_MEDIA_SSL%/steam/apps/34030/extras/NAPOLEON_FIRST.gif?t=1548693685" crossorigin="anonymous"><br><br>Complete your Total War collection with this Definitive Edition of Total War: NAPOLEON, which includes all DLC and feature updates since the game’s release:<br><br>Take on the Peninsular Campaign, based on the intense conflict that raged over the Spanish Peninsula between 1811 and 1814. Choose one of the three nations at war - France, Great Britain or Spain – and lead your campaign across an independent map featuring 32 new controllable regions.<br><br>Turn the tide of war with the Coalition Battle Pack, which introduces the Battle of Friedland, the pivotal moment when Napoleon crushed Russia’s attempt to contain him. <br><br>Build an unstoppable force with Heroes of the Napoleonic Wars and the Imperial Eagle Pack, which together add over 20 legendary and elite new units.<br><br>Total War: NAPOLEON Definitive Edition offers hundreds and hundreds of hours of absorbing gameplay and every bit of content made for the game. See below for full details. <br><br><img src="https://%CDN_HOST_MEDIA_SSL%/steam/apps/34030/extras/NAPOLEON_SECOND.gif?t=1548693685" crossorigin="anonymous"><br><br><br>History is as yet unwritten<br><br>From the early Italian campaign to the battle of Waterloo, Total War: NAPOLEON covers two decades of relentless battles, a backdrop of a world in flames against which the story of an extraordinary military career unfolds. <br><br>Whether you play as the legendary general or against him, the outcome of war can never be guaranteed. The course of history relies on your ability to lead your troops through the most intense battles as never seen before in a Total War game.<h2 class="bb_tag"><strong>About The Peninsular Campaign</strong></h2><br><br>The Peninsular Campaign is an independent campaign based on the conflict in the Spanish Peninsula between 1811 and 1814. It was during this era that the Spanish resistance gave their style of fighting its name: Guerrilla, or the “little war”.<br><br>Play the campaign from three different perspectives, each with a unique feel:<br>•	The French fight to keep resistance at bay while converting regions to their political alignment.<br>•	The British are very limited for regions at the start but receive enough income from Northern Europe and North America that they can afford to liberate regions back to the Spanish in return for Guerrilla aid.<br>•	The Spanish also have a limited starting position but have permanent access to Guerrillas for effective battlefield use against the French. <br><br>Choose one of the three nations involved - France, Great Britain or Spain - and experience one of the most intense conflicts of the Napoleonic era.<h2 class="bb_tag"><strong>Key Features:</strong></h2><br><br>•	A new and independent Iberian Peninsula campaign map featuring 32 controllable regions.<br>•	5 new Guerrilla unit types, recruitable by all nations, adept at battlefield stealth and with the added ability to deploy outside of their faction''s deployment zones: Tiradores (Skirmisher Infantry), Cazadores, Lanceros (Lancer Cavalry), Husares (Light Cavalry), Leader (General). <br>•	28 new units in total, spread across the three playable nations including the British 95th Rifles, the French Vistula Uhlans and the Spanish Coraceros Espanoles. <br>•	Two new agents to enforce political conversion: <br>•	Provocateurs (French and British nations only) have the ability to promote anti-opposition sentiment in regions, incite unrest, decreases turn time for research and passively spy.<br>•	Priests (Spanish and Portuguese nations only) have the ability to promote anti-opposition sentiment in regions and incite unrest.<br>•	A new Guerrillero agent for the Spanish nation: similar to a Spy but with the new ability to Harass enemy armies - lock them in place for a turn and cause them attrition.<br>•	Political Alignment system which sees the French battle to increase pro-French sentiment throughout the peninsula.<h2 class="bb_tag"><strong>About Coalition Battle Pack</strong></h2><br><br>The Coalition Battle Pack features 6 brand new units and contains the Battle of Friedland fought between France and Russia.<br>The Battle of Friedland (14 June, 1807) with Napoleon''s empire at its height, he took a chance and defeated Russia in detail, knocking them out of the war and bringing the Fourth Coalition to an end.<br><br>Unit Descriptions: <br>•	Lifeguard Hussars: This fast light cavalry unit is best used for dealing with skirmishers and artillery who can attack from long range.<br>•	Coldstream Guards: Disciplined, well-trained and respected, these elite foot guards inspire nearby troops in battle. <br>•	Archduke Charles'' Legion: This highly-disciplined line infantry regiment excels at weapons drill and accuracy.<br>•	Luetzow''s Freikorps: Swift light cavalry, the riders of Luetzow’s Freikorps are excellent in melee and on the charge.<br>•	Life Hussars: Sabre-armed light cavalry, the Life Hussars are powerful on the charge and effective in melee combat.<br>•	Semenovski Lifeguard: Immaculately turned out, these elite guards have excellent morale and are superb when used against skirmish troops and artillery.<h2 class="bb_tag"><strong>About Heroes of the Napoleonic Wars</strong></h2><br><br>These exclusive elite units become available on the campaign map once you have made a specific technological advancement or own the relevant territory.<br><br>They will appear in both single and multiplayer game modes.<br>•	7th Lancers (France) <br>•	Brandenburg Uhlans (Prussia) <br>•	1st Hussars (Austria) <br>•	15th Hussars (Great Britain) <br>•	1st East Prussian Grenadier Battalion (Prussia) <br>•	6th Regiment d''Infanterie Légère (France)<br>•	17th Jäger Regiment (Russia)<br>•	1st Regiment Emperor''s Own (Austria)<br>•	18th Regiment d''Infanterie de Ligne &quot;The Brave&quot; (France) <br>•	Moscow Musketeers (Russia)<h2 class="bb_tag"><strong>About Imperial Eagle Pack</strong></h2><br><br>These exclusive elite units become available on the campaign map once you have made a specific technological advancement or own the relevant territory.<br><br>They will appear in both single and multiplayer game modes.<br>•	Grand Battery of the Convention (France) <br>•	HMS Elephant (Great Britain) <br>•	Towarczys (Prussia) <br>•	Royal Scots Greys (Great Britain) <br>•	5e Regiment de Hussards (France) <br>•	Pavlograd Hussars (Russia) <br>•	8th Life Regiment (Prussia) <br>•	47th (Czech) Regiment (Austria) <br>•	88th Foot “Connaught Rangers” <br>•	Archduke Ferdinand Cuirassiers (Austria)<br>•	Lifeguard Cossacks (Russia)','Complete your Total War collection with this Definitive Edition of Total War: NAPOLEON, which includes all DLC and feature updates since the game’s release');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34190,'SONIC AND SEGA ALL-STARS RACE FOR VICTORY IN A HIGH SPEED HIGH SKILL RACETRACK SHOWDOWN!<br>					TAKE TO THE TRACK BY CAR, MONSTER TRUCK, BIKE AND EVEN AEROPLANE IN SONIC &amp; SEGA ALL-STARS RACING.<br>					Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle under lush rain forest canopies and tear through bustling city scapes in a frantic race to the finish line. Jostle against a selection of 20 challengers including Super Monkey Ball’s Ai Ai, Amigo from Samba and the evil Dr. Eggman in your unique character vehicle. Stay ahead of the pack by dodging traps and launching outrageous character moves such as the invincible Super Sonic, Banana Blitz assault of monkey balls or Tails wild Tornado - set to throw any vehicle clean in the air! But if you’ve been battered, beaten and broken, it’s not over yet! Super-charge your vehicle with power-ups to get back in the race and be sure to stay alert for the secret short-cuts that will give you the edge to victory.<br>					<ul class="bb_ul"><li><strong>Party Racing Fun</strong> - Battle it out in single player, challenge your friends in 4 player split-screen for the ultimate track racing showdown!<br>					</li><li><strong>All Your Favorite Racers</strong> - Choose from 20 different characters from the Sonic &amp; SEGA universe including Sonic, Tails, Aiai and Amigo.<br>					</li><li><strong>High Velocity Vehicles</strong> - Every character drives their own unique vehicle including sports cars, bikes, planes and even a giant banana to perform bespoke special man-oeuvres!<br>					</li><li><strong>All-Star Moves</strong> - Need to get by a competitor? Can’t overtake a racer? Then take them out with a pick-up weapon (missiles, mines and other obstacles) or one of the 20 unique character moves that allows the recipient to know who just hit them!<br>					</li><li><strong>Stunning Visuals</strong> - Race over medieval castle ramparts, under lush rain forest canopies and through bustling city scapes as you battle through 27 challenging tracks from the Sonic and SEGA Universe.<br>                    </li></ul>','SONIC AND SEGA ALL-STARS RACE FOR VICTORY IN A HIGH SPEED HIGH SKILL RACETRACK SHOWDOWN!<br>					TAKE TO THE TRACK BY CAR, MONSTER TRUCK, BIKE AND EVEN AEROPLANE IN SONIC &amp; SEGA ALL-STARS RACING.<br>					Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle under lush rain forest canopies and tear through bustling city scapes in a frantic race to the finish line. Jostle against a selection of 20 challengers including Super Monkey Ball’s Ai Ai, Amigo from Samba and the evil Dr. Eggman in your unique character vehicle. Stay ahead of the pack by dodging traps and launching outrageous character moves such as the invincible Super Sonic, Banana Blitz assault of monkey balls or Tails wild Tornado - set to throw any vehicle clean in the air! But if you’ve been battered, beaten and broken, it’s not over yet! Super-charge your vehicle with power-ups to get back in the race and be sure to stay alert for the secret short-cuts that will give you the edge to victory.<br>					<ul class="bb_ul"><li><strong>Party Racing Fun</strong> - Battle it out in single player, challenge your friends in 4 player split-screen for the ultimate track racing showdown!<br>					</li><li><strong>All Your Favorite Racers</strong> - Choose from 20 different characters from the Sonic &amp; SEGA universe including Sonic, Tails, Aiai and Amigo.<br>					</li><li><strong>High Velocity Vehicles</strong> - Every character drives their own unique vehicle including sports cars, bikes, planes and even a giant banana to perform bespoke special man-oeuvres!<br>					</li><li><strong>All-Star Moves</strong> - Need to get by a competitor? Can’t overtake a racer? Then take them out with a pick-up weapon (missiles, mines and other obstacles) or one of the 20 unique character moves that allows the recipient to know who just hit them!<br>					</li><li><strong>Stunning Visuals</strong> - Race over medieval castle ramparts, under lush rain forest canopies and through bustling city scapes as you battle through 27 challenging tracks from the Sonic and SEGA Universe.<br>                    </li></ul>','SONIC AND SEGA ALL-STARS RACE FOR VICTORY IN A HIGH SPEED HIGH SKILL RACETRACK SHOWDOWN! TAKE TO THE TRACK BY CAR, MONSTER TRUCK, BIKE AND EVEN AEROPLANE IN SONIC &amp; SEGA ALL-STARS RACING. Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34410,'The Most Mysterious Secret Service Agency of WWII<br>                    This is a third-person stealth-action game describing the activities of the SMERSH, the most mysterious secret service agency of World War II.<br>                    Moment of Truth is a sequel to the popular stealth action title Death to Spies. The game''s main character is Semion Strogov, a captain in the 4th department of the Soviet counterintelligence service called SMERSH (a Russian acronym meaning &quot;Death to Spies&quot;).<br>                    The hero possesses the skills to accomplish dangerous missions that include gathering information on the location of hostile military and civil units and assassinating enemy agents, including the Wehrmacht''s high-ranking officers. His task is to capture spies and saboteurs and gather information about their actions using unique technologies and devices.<br>                    <ul class="bb_ul"><li>Brand new missions located in Western and Eastern Europe, USA, in the UK and the territory of the former USSR<br>                    </li><li>New vehicles and weapons<br>                    </li><li>Enhanced animation and visuals<br>                    </li><li>New graphic effects: new landscape texturing with higher resolution and bump mapping effects, updated rendering with HDR and dithered shadows<br>                    </li><li>Improved interface<br>                    </li><li>Moment of Truth contains a lot of improvements based on the game community''s requests<br>                    </li></ul>','The Most Mysterious Secret Service Agency of WWII<br>                    This is a third-person stealth-action game describing the activities of the SMERSH, the most mysterious secret service agency of World War II.<br>                    Moment of Truth is a sequel to the popular stealth action title Death to Spies. The game''s main character is Semion Strogov, a captain in the 4th department of the Soviet counterintelligence service called SMERSH (a Russian acronym meaning &quot;Death to Spies&quot;).<br>                    The hero possesses the skills to accomplish dangerous missions that include gathering information on the location of hostile military and civil units and assassinating enemy agents, including the Wehrmacht''s high-ranking officers. His task is to capture spies and saboteurs and gather information about their actions using unique technologies and devices.<br>                    <ul class="bb_ul"><li>Brand new missions located in Western and Eastern Europe, USA, in the UK and the territory of the former USSR<br>                    </li><li>New vehicles and weapons<br>                    </li><li>Enhanced animation and visuals<br>                    </li><li>New graphic effects: new landscape texturing with higher resolution and bump mapping effects, updated rendering with HDR and dithered shadows<br>                    </li><li>Improved interface<br>                    </li><li>Moment of Truth contains a lot of improvements based on the game community''s requests<br>                    </li></ul>','The Most Mysterious Secret Service Agency of WWII This is a third-person stealth-action game describing the activities of the SMERSH, the most mysterious secret service agency of World War II. Moment of Truth is a sequel to the popular stealth action title Death to Spies.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34420,'XIII Century Gold Edition combines the highly successful strategy game XIII Century: Death or Glory with the follow-up sequel, XIII Century: Blood of Europe.<br><br><strong>XIII Century: Death or Glory</strong> is an RTS game which immerses players in the Middle Ages. Among the playable factions are the English, the French, the Mongols, the Germans and Kievan Rus'' (Russians). The game consists of 5 campaigns, which cover the most well known battles of that period. XIII Century: Death or Glory features large-scale battles, with thousands of soldiers located on a battlefield at the same time, and offers players a chance to test their skills as military leaders in medieval Europe.<br><br><strong>XIII Century: Blood of Europe</strong> campaign is set in 1266 AD. Alexander Nevsky, the famous defender of ancient Rus'' western borders, is long gone, and the knights of the Teutonic Order are again marching to Pskov, a gem of the Northern Rus''. They are out for easy prey and loot. Dovmont, Prince of Pskov, is the only hope to push out the invaders. Prepare to join his armed force to defend their territory and win fame worthy of the memory of the Grand Prince Alexander! Enjoy historical battles of the Middle Ages as Dovmont leads his troops against German and Livonian knights.<br><br>					Features<br>					<ul class="bb_ul"><li>Over 40 battles in 5 campaigns. Famous battles that changed the face of medieval Europe<br>					</li><li>Historical reconstruction. Real conditions of renowned battles such as landscape, time of day and weather conditions are taken into account<br>					</li><li>Authentic heraldry of European aristocracy<br>					</li><li>Dozens of unit types<br>					</li><li>Weapons, arms and equipment of knights are made using historical documents and specifications<br>					</li><li>Unique battle system taking into account 80 parameters and characteristics, which allow complete authenticity of medieval battle on the unit level<br>					</li><li>State-of-the-art shader graphics with astonishing level of refinement and veracity<br>					</li><li>LAN and Internet multiplayer<br>					</li></ul>','XIII Century Gold Edition combines the highly successful strategy game XIII Century: Death or Glory with the follow-up sequel, XIII Century: Blood of Europe.<br><br><strong>XIII Century: Death or Glory</strong> is an RTS game which immerses players in the Middle Ages. Among the playable factions are the English, the French, the Mongols, the Germans and Kievan Rus'' (Russians). The game consists of 5 campaigns, which cover the most well known battles of that period. XIII Century: Death or Glory features large-scale battles, with thousands of soldiers located on a battlefield at the same time, and offers players a chance to test their skills as military leaders in medieval Europe.<br><br><strong>XIII Century: Blood of Europe</strong> campaign is set in 1266 AD. Alexander Nevsky, the famous defender of ancient Rus'' western borders, is long gone, and the knights of the Teutonic Order are again marching to Pskov, a gem of the Northern Rus''. They are out for easy prey and loot. Dovmont, Prince of Pskov, is the only hope to push out the invaders. Prepare to join his armed force to defend their territory and win fame worthy of the memory of the Grand Prince Alexander! Enjoy historical battles of the Middle Ages as Dovmont leads his troops against German and Livonian knights.<br><br>					Features<br>					<ul class="bb_ul"><li>Over 40 battles in 5 campaigns. Famous battles that changed the face of medieval Europe<br>					</li><li>Historical reconstruction. Real conditions of renowned battles such as landscape, time of day and weather conditions are taken into account<br>					</li><li>Authentic heraldry of European aristocracy<br>					</li><li>Dozens of unit types<br>					</li><li>Weapons, arms and equipment of knights are made using historical documents and specifications<br>					</li><li>Unique battle system taking into account 80 parameters and characteristics, which allow complete authenticity of medieval battle on the unit level<br>					</li><li>State-of-the-art shader graphics with astonishing level of refinement and veracity<br>					</li><li>LAN and Internet multiplayer<br>					</li></ul>','XIII Century Gold Edition combines the highly successful strategy game XIII Century: Death or Glory with the follow-up sequel, XIII Century: Blood of Europe.XIII Century: Death or Glory is an RTS game which immerses players in the Middle Ages.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34500,'Light of Altair is a sci-fi colony building game with a deep plot. Grow colonies from landing pod to metropolis, while sending off new spaceships to expand your territory to other worlds. You are not alone in space, 8 factions from different parts of the world are all following their own agendas in the solar system; diplomacy and orbital-combat are essential to learn.<br>			Light of Altair is based on a custom built 3D engine that enables easy zooming from galaxies all the way down to individual moons and asteroids covered in the colonies with their glass domes, mines and launch pads. Advanced shader technology is used to add rich details and lighting to surfaces.<br>			<ul class="bb_ul"><li>Build colonies on planets and asteroids throughout a system.<br>			</li><li>Manage industries and colonists to grow from a tiny landing unit into a towering city.<br>			</li><li>Detailed storyline based on a future-history of Earth.<br>			</li><li>Rich single player campaign traced across the galaxy.<br>			</li><li>Play out important plot events from different sides taking on the role of one of 8 different factions.<br>			</li><li>Detailed tech-tree with over 30 weapons, buildings, and ship-mods to discover.<br>			</li><li>Design ships: Pick a ship schematic and equip weapons, armour and mods to hardpoints. Then command shipyards to build a fleet from the design.<br>			</li></ul>','Light of Altair is a sci-fi colony building game with a deep plot. Grow colonies from landing pod to metropolis, while sending off new spaceships to expand your territory to other worlds. You are not alone in space, 8 factions from different parts of the world are all following their own agendas in the solar system; diplomacy and orbital-combat are essential to learn.<br>			Light of Altair is based on a custom built 3D engine that enables easy zooming from galaxies all the way down to individual moons and asteroids covered in the colonies with their glass domes, mines and launch pads. Advanced shader technology is used to add rich details and lighting to surfaces.<br>			<ul class="bb_ul"><li>Build colonies on planets and asteroids throughout a system.<br>			</li><li>Manage industries and colonists to grow from a tiny landing unit into a towering city.<br>			</li><li>Detailed storyline based on a future-history of Earth.<br>			</li><li>Rich single player campaign traced across the galaxy.<br>			</li><li>Play out important plot events from different sides taking on the role of one of 8 different factions.<br>			</li><li>Detailed tech-tree with over 30 weapons, buildings, and ship-mods to discover.<br>			</li><li>Design ships: Pick a ship schematic and equip weapons, armour and mods to hardpoints. Then command shipyards to build a fleet from the design.<br>			</li></ul>','Light of Altair is a sci-fi colony building game with a deep plot. Grow colonies from landing pod to metropolis, while sending off new spaceships to expand your territory to other worlds. You are not alone in space, 8 factions from different parts of the world are all following their own agendas in the solar system; diplomacy and...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34600,'October 22, 2009 - Update <br>					<a href="https://steamcommunity.com/linkfilter/?url=http://Wargaming.net" target="_blank" rel="noopener"  >Wargaming.net</a> has released free Downloadable Content for Order of War. The DLC will download automatically the next time you launch the game. This DLC contains all the formerly exclusive pre-order items which include:<br>					<ul class="bb_ul"><li><strong>Heavy Bomber Squadrons</strong> - Addition of German Arado and Allied B-24 Marauder heavy bomber units to air support <br>					</li><li><strong>Infantry Mortar Launchers</strong> - Addition of infantry mortar units <br>					</li><li><strong>Off-Map Heavy Artillery</strong> - Addition of heavy artillery strikes to the air support menu <br>					</li><li><strong>Survival Mission Mode</strong> - New survival mission mode where you fend off waves of attacking enemies for as long as possible <br>					</li></ul> <br>					<h2 class="bb_tag">About Order of War</h2>					In the summer of 1944, the Second World War entered its end-game when the Allies launched two major operations that would drive back German forces on both the Western and Eastern Fronts at once. <br>				Their names were Overlord and Bagration.  Overlord famously commenced with the D-Day landings in Normandy and ended in the Liberation of Paris, while Bagration - a far less well-known but far larger Russian operation - crushed the invading German forces in the east, leading to their complete withdrawal from Soviet territory.  Had either operation been unsuccessful, history could have been very different. <br>				In the ultimate test of military strategy, Order of War will challenge you not only to lead America''s finest to victory in the west, but also place you in command of the German forces charged with repelling the Red Army''s seemingly unstoppable offensive in the east. Even the keenest military minds will find that it''s one thing to make history, but quite another to change it.  <br><br>			...Do you have what it takes to command? <br><br>			Key features: <br><br>				<ul class="bb_ul"><li>Experience WWII warfare on an epic, cinematic stage; that truly captures the intensity and scale of the battlefield. <br>				</li><li>Take Command of an entire armoured force consisting of up to 1000 soldiers, tank divisions, armoured vehicles, heavy artillery and air force. <br>				</li><li>Players can choose between two different campaign modes offering completely different storyline, missions, objectives and environments. <br>				</li><li>Experience the unique dynamic camera that allows players to command troops over huge geographical scale whilst maintaining movie-like vistas and detail. <br>				</li></ul>','October 22, 2009 - Update <br>					<a href="https://steamcommunity.com/linkfilter/?url=http://Wargaming.net" target="_blank" rel="noopener"  >Wargaming.net</a> has released free Downloadable Content for Order of War. The DLC will download automatically the next time you launch the game. This DLC contains all the formerly exclusive pre-order items which include:<br>					<ul class="bb_ul"><li><strong>Heavy Bomber Squadrons</strong> - Addition of German Arado and Allied B-24 Marauder heavy bomber units to air support <br>					</li><li><strong>Infantry Mortar Launchers</strong> - Addition of infantry mortar units <br>					</li><li><strong>Off-Map Heavy Artillery</strong> - Addition of heavy artillery strikes to the air support menu <br>					</li><li><strong>Survival Mission Mode</strong> - New survival mission mode where you fend off waves of attacking enemies for as long as possible <br>					</li></ul> <br>					<h2 class="bb_tag">About Order of War</h2>					In the summer of 1944, the Second World War entered its end-game when the Allies launched two major operations that would drive back German forces on both the Western and Eastern Fronts at once. <br>				Their names were Overlord and Bagration.  Overlord famously commenced with the D-Day landings in Normandy and ended in the Liberation of Paris, while Bagration - a far less well-known but far larger Russian operation - crushed the invading German forces in the east, leading to their complete withdrawal from Soviet territory.  Had either operation been unsuccessful, history could have been very different. <br>				In the ultimate test of military strategy, Order of War will challenge you not only to lead America''s finest to victory in the west, but also place you in command of the German forces charged with repelling the Red Army''s seemingly unstoppable offensive in the east. Even the keenest military minds will find that it''s one thing to make history, but quite another to change it.  <br><br>			...Do you have what it takes to command? <br><br>			Key features: <br><br>				<ul class="bb_ul"><li>Experience WWII warfare on an epic, cinematic stage; that truly captures the intensity and scale of the battlefield. <br>				</li><li>Take Command of an entire armoured force consisting of up to 1000 soldiers, tank divisions, armoured vehicles, heavy artillery and air force. <br>				</li><li>Players can choose between two different campaign modes offering completely different storyline, missions, objectives and environments. <br>				</li><li>Experience the unique dynamic camera that allows players to command troops over huge geographical scale whilst maintaining movie-like vistas and detail. <br>				</li></ul>','October 22, 2009 - Update Wargaming.net has released free Downloadable Content for Order of War. The DLC will download automatically the next time you launch the game. This DLC contains all the formerly exclusive pre-order items which include: Heavy Bomber Squadrons - Addition of German Arado and Allied B-24 Marauder heavy bomber units...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34630,'Take the command of Free Nations Union forces and defeat the Phantom League on one of six distant planets. The rebels decided to seize the power on Earth by first conquering the space colonies, which provide vital energy resources to AOG. The war for global domination unrolls on continents, at sea, and in the air. With secret allies, you can disclose and provide troops at any moment, surprisingly shifting the power balance in a particular region. Lead your divisions, fleets, and air squadrons against those who dared threaten our freedom and democracy.<br>						<ul class="bb_ul"><li>Original political system based on &quot;Secret Allies&quot; providing endless replayability <br>						</li><li>Smooth and Dynamic Gameplay <br>						</li><li>Full 3D Graphic Engine <br>						</li><li>Huge 3D Landscapes <br>						</li><li>26 Detailed 3D Units <br>						</li><li>Realistic Lighting, Explosions and Effects <br>						</li><li>3D Sound <br>						</li><li>6 Different Worlds (planets)<br>						</li></ul>','Take the command of Free Nations Union forces and defeat the Phantom League on one of six distant planets. The rebels decided to seize the power on Earth by first conquering the space colonies, which provide vital energy resources to AOG. The war for global domination unrolls on continents, at sea, and in the air. With secret allies, you can disclose and provide troops at any moment, surprisingly shifting the power balance in a particular region. Lead your divisions, fleets, and air squadrons against those who dared threaten our freedom and democracy.<br>						<ul class="bb_ul"><li>Original political system based on &quot;Secret Allies&quot; providing endless replayability <br>						</li><li>Smooth and Dynamic Gameplay <br>						</li><li>Full 3D Graphic Engine <br>						</li><li>Huge 3D Landscapes <br>						</li><li>26 Detailed 3D Units <br>						</li><li>Realistic Lighting, Explosions and Effects <br>						</li><li>3D Sound <br>						</li><li>6 Different Worlds (planets)<br>						</li></ul>','Take the command of Free Nations Union forces and defeat the Phantom League on one of six distant planets. The rebels decided to seize the power on Earth by first conquering the space colonies, which provide vital energy resources to AOG. The war for global domination unrolls on continents, at sea, and in the air.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34640,'Massive Assault: Phantom Renaissance is the sequel to highly acclaimed turn-based strategy game Massive Assault. Massive Assault: Phantom Renaissance features a renewed global conflict between the Free Nations Union and Phantom League in distant space colonies. The game is based on the Massive Assault’s original &quot;Secret Allies&quot; concept, acknowledged by the press and the players as innovative and easy to learn and hard to master one and in many respects rejuvenating turn-based genre.<br>						<ul class="bb_ul"><li>6 new planets for World Wars including massive-sized deathmatch maps <br>						</li><li>2 Mega Campaigns <br>						</li><li>20 new single-player scenarios with new mission types and twists <br>						</li><li>All-new Assault game mode<br>						</li><li>New A.I. - with various computer opponent profiles<br>						</li><li>10 new units, unique for each side, leading to different strategies <br>						</li><li>Enhanced 3D engine: remade unit, terrain and effect visualization technology <br>						</li><li>Additional battle music<br>						</li><li>2 new viewing modes: CNN-style fancy camera and historic-atlas-style 2D strategic map mode <br>						</li></ul>','Massive Assault: Phantom Renaissance is the sequel to highly acclaimed turn-based strategy game Massive Assault. Massive Assault: Phantom Renaissance features a renewed global conflict between the Free Nations Union and Phantom League in distant space colonies. The game is based on the Massive Assault’s original &quot;Secret Allies&quot; concept, acknowledged by the press and the players as innovative and easy to learn and hard to master one and in many respects rejuvenating turn-based genre.<br>						<ul class="bb_ul"><li>6 new planets for World Wars including massive-sized deathmatch maps <br>						</li><li>2 Mega Campaigns <br>						</li><li>20 new single-player scenarios with new mission types and twists <br>						</li><li>All-new Assault game mode<br>						</li><li>New A.I. - with various computer opponent profiles<br>						</li><li>10 new units, unique for each side, leading to different strategies <br>						</li><li>Enhanced 3D engine: remade unit, terrain and effect visualization technology <br>						</li><li>Additional battle music<br>						</li><li>2 new viewing modes: CNN-style fancy camera and historic-atlas-style 2D strategic map mode <br>						</li></ul>','Massive Assault: Phantom Renaissance is the sequel to highly acclaimed turn-based strategy game Massive Assault. Massive Assault: Phantom Renaissance features a renewed global conflict between the Free Nations Union and Phantom League in distant space colonies.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34800,'Uncover the darkest secret of humanity!<br>				Young archeologist Sylvie Leroux accidentally stumbles upon an ancient secret. What she doesn''t realize is that her research will put her in deadly peril. Who wants to prevent her from finishing her research? Are mere humans standing in her way, or is it a supernatural power?<br>				<ul class="bb_ul"><li>Dramatic story with many twists and turns  <br>				</li><li>Mystical atmosphere with breathtaking graphics<br>				</li><li>Challenging and intense puzzles<br>				</li></ul>','Uncover the darkest secret of humanity!<br>				Young archeologist Sylvie Leroux accidentally stumbles upon an ancient secret. What she doesn''t realize is that her research will put her in deadly peril. Who wants to prevent her from finishing her research? Are mere humans standing in her way, or is it a supernatural power?<br>				<ul class="bb_ul"><li>Dramatic story with many twists and turns  <br>				</li><li>Mystical atmosphere with breathtaking graphics<br>				</li><li>Challenging and intense puzzles<br>				</li></ul>','Young archeologist Sylvie Leroux accidentally stumbles upon an ancient secret. What she doesn''t realize is that her research will put her in deadly peril.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34810,'Get your dream job with a company called Project Freedom. Become a space pilot and serve for the corporation. You''re going to get all the excitement and adventure you''ve ever wanted.<br>						<br>Perhaps even more...<br>						<ul class="bb_ul"><li>21 missions in the campaign<br>						</li><li>Outstanding 3D graphics and special effects<br>						</li><li>Original storyline with unexpected turns and surprises<br>						</li><li>A variety of space combat missions including escort, strike, and rescue operations<br>						</li><li>Missions in open space, on planets and moons<br>						</li></ul>','Get your dream job with a company called Project Freedom. Become a space pilot and serve for the corporation. You''re going to get all the excitement and adventure you''ve ever wanted.<br>						<br>Perhaps even more...<br>						<ul class="bb_ul"><li>21 missions in the campaign<br>						</li><li>Outstanding 3D graphics and special effects<br>						</li><li>Original storyline with unexpected turns and surprises<br>						</li><li>A variety of space combat missions including escort, strike, and rescue operations<br>						</li><li>Missions in open space, on planets and moons<br>						</li></ul>','Get your dream job with a company called Project Freedom. Become a space pilot and serve for the corporation. You''re going to get all the excitement and adventure you''ve ever wanted. Perhaps even more... 21 missions in the campaign Outstanding 3D graphics and special effects Original storyline with unexpected turns and surprises A...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34820,'Destroy the Luftwaffe!<br>							<br>There’s something new in the air, and it’s more than the hum of hundreds of aero engines... As the Luftwaffe launches its aerial offensive, the outnumbered Royal Air Force is scrambling to bring into combat new planes that will ensure victory over a stronger foe. Will they succeed? It’s up to you, and your Hurricane or Spitfire. If you hold off the enemy long enough, you’ll be the first to fly the Hawker Tornado and Westland Whirlwind into combat, and enable the Empire to strike back before Reichsmarschall Goering finishes his breakfast. You’ll be rewarded with bonus missions, promotions, decorations, and a view of burning Berlin from the tail turret of a Halifax bomber. Join in the new Battle of Britain. Your aircraft is ready and waiting...<br>							<ul class="bb_ul"><li>Enjoy the realism of a detailed damage model, stunning graphics, and outstanding special effects<br>							</li><li>Choose between arcade and flight simulator control modes, and the RAF or the Luftwaffe in multiplayer mode<br>							</li><li>Get on board of one of realistically modeled planes, e.g. Spitfire and Hurricane and dive into the world of ultra realistic air fights<br>						</li></ul>','Destroy the Luftwaffe!<br>							<br>There’s something new in the air, and it’s more than the hum of hundreds of aero engines... As the Luftwaffe launches its aerial offensive, the outnumbered Royal Air Force is scrambling to bring into combat new planes that will ensure victory over a stronger foe. Will they succeed? It’s up to you, and your Hurricane or Spitfire. If you hold off the enemy long enough, you’ll be the first to fly the Hawker Tornado and Westland Whirlwind into combat, and enable the Empire to strike back before Reichsmarschall Goering finishes his breakfast. You’ll be rewarded with bonus missions, promotions, decorations, and a view of burning Berlin from the tail turret of a Halifax bomber. Join in the new Battle of Britain. Your aircraft is ready and waiting...<br>							<ul class="bb_ul"><li>Enjoy the realism of a detailed damage model, stunning graphics, and outstanding special effects<br>							</li><li>Choose between arcade and flight simulator control modes, and the RAF or the Luftwaffe in multiplayer mode<br>							</li><li>Get on board of one of realistically modeled planes, e.g. Spitfire and Hurricane and dive into the world of ultra realistic air fights<br>						</li></ul>','Destroy the Luftwaffe! There’s something new in the air, and it’s more than the hum of hundreds of aero engines... As the Luftwaffe launches its aerial offensive, the outnumbered Royal Air Force is scrambling to bring into combat new planes that will ensure victory over a stronger foe. Will they succeed?');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34830,'When the democratic government of Isla Trueno is overthrown, an aggressive and hostile military command rises to power.  A highly trained special ops unit is sent in to help the rebels accomplish objectives that only a sniper can handle.  In addition to intense sniper missions, players will also take part in a variety of assault scenarios where their prowess with weapons will be a huge help to the undermanned rebels.  Sniper: Ghost Warrior seeks to challenge players in new ways so that the game is both demanding and entertaining.<br>							Developed by City Interactive’s dedicated next-gen games studio, Sniper: Ghost Warrior delivers an impressive visual and technological gaming experience and features a realistic ballistics system that measures bullet trajectory, bullet drop and environmental effects such as wind, fog &amp; rain. Encompassing a wide array of single and multiplayer levels, players will encounter a variety of challenging terrain. Players take on the role of a Ghost Warrior, an elite sniper in a highly trained special ops unit, whose unique skills in the art of stalking, target detection, surveillance and shooting accuracy will determine mission success. Covert missions force players to operate undetected as they attempt to eliminate hostile enemies one head shot at a time. <br>							<h2 class="bb_tag">Key Features:</h2><ul class="bb_ul"><li>The most realistic sniping experience in a video game ever, right down to managing your breathing for increased accuracy of sniper shots.<br>							</li><li>Enjoy a fully realistic ballistic system that accounts for bullet trajectory, including bullet drop and environmental effects such as wind, fog &amp; rain.<br>							</li><li>Pull off the perfect headshot and watch your bullet strike the enemy with pin-point accuracy in Bullet Cam mode.<br>							</li><li>4 types of sniping rifles:  AS50, MSG90, SR25 &amp; SVD Dragunov<br>							</li><li>A variety of mission types ranging from sniper vs. sniper elimination, real-time tactical assault and fixed machine gun combat.<br>							</li><li>Play as two separate characters: the sniper and the spotter.<br>							</li></ul>','When the democratic government of Isla Trueno is overthrown, an aggressive and hostile military command rises to power.  A highly trained special ops unit is sent in to help the rebels accomplish objectives that only a sniper can handle.  In addition to intense sniper missions, players will also take part in a variety of assault scenarios where their prowess with weapons will be a huge help to the undermanned rebels.  Sniper: Ghost Warrior seeks to challenge players in new ways so that the game is both demanding and entertaining.<br>							Developed by City Interactive’s dedicated next-gen games studio, Sniper: Ghost Warrior delivers an impressive visual and technological gaming experience and features a realistic ballistics system that measures bullet trajectory, bullet drop and environmental effects such as wind, fog &amp; rain. Encompassing a wide array of single and multiplayer levels, players will encounter a variety of challenging terrain. Players take on the role of a Ghost Warrior, an elite sniper in a highly trained special ops unit, whose unique skills in the art of stalking, target detection, surveillance and shooting accuracy will determine mission success. Covert missions force players to operate undetected as they attempt to eliminate hostile enemies one head shot at a time. <br>							<h2 class="bb_tag">Key Features:</h2><ul class="bb_ul"><li>The most realistic sniping experience in a video game ever, right down to managing your breathing for increased accuracy of sniper shots.<br>							</li><li>Enjoy a fully realistic ballistic system that accounts for bullet trajectory, including bullet drop and environmental effects such as wind, fog &amp; rain.<br>							</li><li>Pull off the perfect headshot and watch your bullet strike the enemy with pin-point accuracy in Bullet Cam mode.<br>							</li><li>4 types of sniping rifles:  AS50, MSG90, SR25 &amp; SVD Dragunov<br>							</li><li>A variety of mission types ranging from sniper vs. sniper elimination, real-time tactical assault and fixed machine gun combat.<br>							</li><li>Play as two separate characters: the sniper and the spotter.<br>							</li></ul>','As a Ghost Warrior, an elite sniper in a highly trained special ops unit, your unique skills in the art of stalking, target detection, surveillance and shooting accuracy will determine mission success.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34870,'Sniper: Ghost Warrior 2 is the only multi-platform, first-person, modern shooter exclusively designed around the sniper experience. It takes the bulls-eye precision of its predecessor to new and exciting heights, offering more diverse sniper challenges; a rebuilt AI system and the thrilling “one shot, one kill” precision that made the original a huge hit, selling 3 million copies worldwide. Taking advantage of the advanced capabilities of the CryENGINE3, Sniper: Ghost Warrior 2 also delivers striking graphic environments.<h2 class="bb_tag">Key Features</h2><br><ul class="bb_ul"><li>	Motion Sense Trigger System: an innovative first in which the way the player touches the controller influences the on-screen shot. Like in real-world sniping, in-game shooting requires a steady squeeze of the pad’s trigger so that when the round is fired, the rifle is more accurate. Jerk the trigger and the round is thrown off, thus missing the target and alerting a highly motivated enemy to your presence.<br></li><li>	Realistic Ballistics: the hallmark of the Sniper franchise is the realism of its shooting dynamics.  Wind speed, distance, gravity and bullet-drop all play critical roles in the performance of your shot.<br></li><li>	Refined Shooting Mechanics: a proper breathing technique to steady your heart rate is as important as calculating the time on target of your round, and the best snipers control both their heart and their head. From acquisition of target until the slow steady trigger pull, a sniper must pull together everything to achieve the ideal “one shot; one kill.”<br></li><li>	Improved Enemy AI: the Artificial Intelligence (AI) system was completely re-tooled and designed from scratch.  Much of the improvements were made possible from the switch to the CryEngine 3. Expect everything from flanking movements to frontal assaults as the enemy tries to engage you in close quarters where your rifle is less effective.<br></li><li>	New Target-Rich Environments: Sniper Ghost Warrior 2 adds new urban environments like Sarajevo and treacherous mountain terrain to go along with jungles that are as lush and deadly as ever. <br></li><li>	Various Difficulty Levels: To diversify gameplay and make it accessible to the widest group of gamers, CI Games is introducing three difficulty levels that totally change the nature of the game. You decide how to play – either relax and be the ultimate predator or test your skill and experience the game on Expert Mode.<br></li><li>	Bullet-Cam: everyone’s favorite feature returns to reward expert shots and show the battlefield from a totally new viewpoint. See what the transfer of kinetic energy – a bullet’s true stopping power – can do to the enemy from 1000 meters or more!<br></li><li>	Bullet Penetration: concealment doesn’t necessarily mean cover. In Sniper: Ghost Warrior 2, bullets behave as they would in real life and are able to dispatch enemies hiding behind various types of covers. You can also try to line up your enemies and let a single round take out an entire squad. Wait ‘til you see that on Bullet Cam!<br></li><li>	Expanded List of Sniper Rifles: Try out the world’s most advanced sniper rifles, each of them meticulously recreated so that they accurately simulate the modern weaponry found on today’s battlefields.<br></li><li>	New Gear: own the night with the introduction of thermal and night vision optics, plus a pair of powerful binoculars critical for locating the enemy before they spot you.</li></ul>','Sniper: Ghost Warrior 2 is the only multi-platform, first-person, modern shooter exclusively designed around the sniper experience. It takes the bulls-eye precision of its predecessor to new and exciting heights, offering more diverse sniper challenges; a rebuilt AI system and the thrilling “one shot, one kill” precision that made the original a huge hit, selling 3 million copies worldwide. Taking advantage of the advanced capabilities of the CryENGINE3, Sniper: Ghost Warrior 2 also delivers striking graphic environments.<h2 class="bb_tag">Key Features</h2><br><ul class="bb_ul"><li>	Motion Sense Trigger System: an innovative first in which the way the player touches the controller influences the on-screen shot. Like in real-world sniping, in-game shooting requires a steady squeeze of the pad’s trigger so that when the round is fired, the rifle is more accurate. Jerk the trigger and the round is thrown off, thus missing the target and alerting a highly motivated enemy to your presence.<br></li><li>	Realistic Ballistics: the hallmark of the Sniper franchise is the realism of its shooting dynamics.  Wind speed, distance, gravity and bullet-drop all play critical roles in the performance of your shot.<br></li><li>	Refined Shooting Mechanics: a proper breathing technique to steady your heart rate is as important as calculating the time on target of your round, and the best snipers control both their heart and their head. From acquisition of target until the slow steady trigger pull, a sniper must pull together everything to achieve the ideal “one shot; one kill.”<br></li><li>	Improved Enemy AI: the Artificial Intelligence (AI) system was completely re-tooled and designed from scratch.  Much of the improvements were made possible from the switch to the CryEngine 3. Expect everything from flanking movements to frontal assaults as the enemy tries to engage you in close quarters where your rifle is less effective.<br></li><li>	New Target-Rich Environments: Sniper Ghost Warrior 2 adds new urban environments like Sarajevo and treacherous mountain terrain to go along with jungles that are as lush and deadly as ever. <br></li><li>	Various Difficulty Levels: To diversify gameplay and make it accessible to the widest group of gamers, CI Games is introducing three difficulty levels that totally change the nature of the game. You decide how to play – either relax and be the ultimate predator or test your skill and experience the game on Expert Mode.<br></li><li>	Bullet-Cam: everyone’s favorite feature returns to reward expert shots and show the battlefield from a totally new viewpoint. See what the transfer of kinetic energy – a bullet’s true stopping power – can do to the enemy from 1000 meters or more!<br></li><li>	Bullet Penetration: concealment doesn’t necessarily mean cover. In Sniper: Ghost Warrior 2, bullets behave as they would in real life and are able to dispatch enemies hiding behind various types of covers. You can also try to line up your enemies and let a single round take out an entire squad. Wait ‘til you see that on Bullet Cam!<br></li><li>	Expanded List of Sniper Rifles: Try out the world’s most advanced sniper rifles, each of them meticulously recreated so that they accurately simulate the modern weaponry found on today’s battlefields.<br></li><li>	New Gear: own the night with the introduction of thermal and night vision optics, plus a pair of powerful binoculars critical for locating the enemy before they spot you.</li></ul>','Sniper: Ghost Warrior 2 takes the bulls-eye precision of its predecessor to new and exciting heights!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34900,'Bad Rats is a physics puzzle game where rats finally get their bloody revenge on their new prisoners: The cats.<br>                    Come up with creative solutions for each puzzle using physics, functional objects, and your specially trained Rats. Try different ways of solving each puzzle to finish faster or earn higher scores. Revel in your success as the cat meets a violent demise in any number of humorous ways at the hands of Bad Rats.<br>                    <ul class="bb_ul"><li>Comic cartoon violence and cartoon blood<br>                    </li><li>Realistic physics simulation<br>                    </li><li>10 Specialist Rats, anxious for revenge<br>                    </li><li>11 different and bloody deaths for cats<br>                    </li><li>10 other functional objects to help you<br>                    </li><li>44 Maps, from easy to very hard<br>                    </li><li>Internet and local records<br>                    </li><li>Original, cartoon styled characters<br>                    </li><li>Challenge your creativity, intelligence and logic<br>                    </li><li>Unlock all the Steam Achievements<br>                    </li></ul>','Bad Rats is a physics puzzle game where rats finally get their bloody revenge on their new prisoners: The cats.<br>                    Come up with creative solutions for each puzzle using physics, functional objects, and your specially trained Rats. Try different ways of solving each puzzle to finish faster or earn higher scores. Revel in your success as the cat meets a violent demise in any number of humorous ways at the hands of Bad Rats.<br>                    <ul class="bb_ul"><li>Comic cartoon violence and cartoon blood<br>                    </li><li>Realistic physics simulation<br>                    </li><li>10 Specialist Rats, anxious for revenge<br>                    </li><li>11 different and bloody deaths for cats<br>                    </li><li>10 other functional objects to help you<br>                    </li><li>44 Maps, from easy to very hard<br>                    </li><li>Internet and local records<br>                    </li><li>Original, cartoon styled characters<br>                    </li><li>Challenge your creativity, intelligence and logic<br>                    </li><li>Unlock all the Steam Achievements<br>                    </li></ul>','Bad Rats is a physics puzzle game where rats finally get their bloody revenge on their new prisoners: The cats. Come up with creative solutions for each puzzle using physics, functional objects, and your specially trained Rats. Try different ways of solving each puzzle to finish faster or earn higher scores.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (34920,'Razor2: Hidden Skies Razor2: Hidden Skies is a top view shooter. The game has the style of successful classic arcade games, while using the latest technology to create great visuals and effects.  An old-school game with all new technology. Razor2 has easy gameplay, while challenging your skills with hundreds of enemies and bullets threatening you all the time. The soundtrack is another great feature, Razor2 uses classic orchestrated music, composed especially for the game. <br>					Razor2 includes ten achievements and world records. Do your best, and place your name on the best players ranking.  Play hard to win titles such as the Destructor, shooting down 4000 enemies, or the &quot;almost impossible&quot; Ace Pilot, completing the game without using any continues.<br>					<strong>Key features:</strong><br>					<ul class="bb_ul"><li>Shoot them up (shmup)<br>					</li><li>Eight levels<br>					</li><li>Fifty different enemy waves<br>					</li><li>Incredible Boss fights<br>					</li><li>Weapons and equipment upgrades<br>					</li><li>Three difficulty levels<br>					</li><li>World and local Records<br>					</li><li>Ten medals and achievements<br>					</li><li>Great graphics, art and shaders<br>					</li><li>Easy and amazing gameplay<br>					</li><li>Awesome orchestrated music<br>					</li></ul>','Razor2: Hidden Skies Razor2: Hidden Skies is a top view shooter. The game has the style of successful classic arcade games, while using the latest technology to create great visuals and effects.  An old-school game with all new technology. Razor2 has easy gameplay, while challenging your skills with hundreds of enemies and bullets threatening you all the time. The soundtrack is another great feature, Razor2 uses classic orchestrated music, composed especially for the game. <br>					Razor2 includes ten achievements and world records. Do your best, and place your name on the best players ranking.  Play hard to win titles such as the Destructor, shooting down 4000 enemies, or the &quot;almost impossible&quot; Ace Pilot, completing the game without using any continues.<br>					<strong>Key features:</strong><br>					<ul class="bb_ul"><li>Shoot them up (shmup)<br>					</li><li>Eight levels<br>					</li><li>Fifty different enemy waves<br>					</li><li>Incredible Boss fights<br>					</li><li>Weapons and equipment upgrades<br>					</li><li>Three difficulty levels<br>					</li><li>World and local Records<br>					</li><li>Ten medals and achievements<br>					</li><li>Great graphics, art and shaders<br>					</li><li>Easy and amazing gameplay<br>					</li><li>Awesome orchestrated music<br>					</li></ul>','Razor2: Hidden Skies Razor2: Hidden Skies is a top view shooter. The game has the style of successful classic arcade games, while using the latest technology to create great visuals and effects. An old-school game with all new technology.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35000,'Mini Ninjas is a game that combines furious action with stealth and exploration for an experience that appeals to a wide audience across age groups and preferences. It’s an action-adventure with a strong focus on allowing the player freedom to explore the world and has the depth to allow for very varied gameplay and approaches to getting through the game.','Mini Ninjas is a game that combines furious action with stealth and exploration for an experience that appeals to a wide audience across age groups and preferences. It’s an action-adventure with a strong focus on allowing the player freedom to explore the world and has the depth to allow for very varied gameplay and approaches to getting through the game.','Mini Ninjas is a game that combines furious action with stealth and exploration for an experience that appeals to a wide audience across age groups and preferences. It’s an action-adventure with a strong focus on allowing the player freedom to explore the world and has the depth to allow for very varied gameplay and approaches to getting...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35070,'Clementine Valley used to be the place to be! It was world renowned for its fantastic fruit trees lovingly tended to by Old Jim.  Unfortunately Jim has lost the energy to grow enough fruit to keep the locals happy, let alone attract the tourists Clementine Valley used to have.  Luckily for Jim, Flora’s kind gesture showed him that she has the spirit to continue his legacy and he gives her his Magic Gardening gloves...<br>					It’s up to Flora to restore life to Clementine Valley by growing fruit with her magic gardening gloves!<br>					<ul class="bb_ul"><li>Create a blossoming fruit farm empire in this tree growing, time and resource management game. <br>					</li><li>Use your magic gloves to grow 50 different fruit trees in 8 unique environments. <br>					</li><li>Explore tree roots to discover new fruit seeds to grow and flower bulbs to plant.<br>					</li><li>Sell fruit to 7 different types of special characters, all with their own favorite fruits! <br>					</li><li>Keep pesky birds and cheeky gophers at bay in order to maximize profits! <br>					</li><li>Summon a squirrel helper if you fancy a break, or take on one of the 10 challenges in Challenge mode if you’re feeling adventurous!<br>					</li></ul>','Clementine Valley used to be the place to be! It was world renowned for its fantastic fruit trees lovingly tended to by Old Jim.  Unfortunately Jim has lost the energy to grow enough fruit to keep the locals happy, let alone attract the tourists Clementine Valley used to have.  Luckily for Jim, Flora’s kind gesture showed him that she has the spirit to continue his legacy and he gives her his Magic Gardening gloves...<br>					It’s up to Flora to restore life to Clementine Valley by growing fruit with her magic gardening gloves!<br>					<ul class="bb_ul"><li>Create a blossoming fruit farm empire in this tree growing, time and resource management game. <br>					</li><li>Use your magic gloves to grow 50 different fruit trees in 8 unique environments. <br>					</li><li>Explore tree roots to discover new fruit seeds to grow and flower bulbs to plant.<br>					</li><li>Sell fruit to 7 different types of special characters, all with their own favorite fruits! <br>					</li><li>Keep pesky birds and cheeky gophers at bay in order to maximize profits! <br>					</li><li>Summon a squirrel helper if you fancy a break, or take on one of the 10 challenges in Challenge mode if you’re feeling adventurous!<br>					</li></ul>','Clementine Valley used to be the place to be! It was world renowned for its fantastic fruit trees lovingly tended to by Old Jim. Unfortunately Jim has lost the energy to grow enough fruit to keep the locals happy, let alone attract the tourists Clementine Valley used to have.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35130,'Lara Croft and the Guardian of Light is an action/adventure game featuring Lara Croft. This brand extension combines the hallmarks of the Tomb Raider franchise including exploration &amp; discovery, platforming, and puzzle solving combined with character progression, fun fast-paced combat, and elements of human cooperation and competition. <br><br><strong>Key features:</strong><br>						<ul class="bb_ul"><li>First downloadable only title from Crystal Dynamics, and first downloadable only Lara Croft game.<br>							</li><li>A classic formula of puzzles, combat, exploration, and breathtaking visuals put through the lens of an isometric fast-paced gaming experience.<br>							</li><li>A wide range of options for solving puzzles and traversing deadly environmental traps, offering players an unprecedented level of freedom to choose their own solutions and explore various paths through the dense jungles of Central America.<br>							</li><li>Crystal Dynamics'' proprietary engine delivers sprawling environments with no load-times and unbelievable vertical gameplay through tombs reaching deep into the Earth. <br>							</li><li>Face off against a myriad of undead warriors brought to life by the evil Xolotl, including a number of boss battles that are not to be missed!<br>						</li></ul>','Lara Croft and the Guardian of Light is an action/adventure game featuring Lara Croft. This brand extension combines the hallmarks of the Tomb Raider franchise including exploration &amp; discovery, platforming, and puzzle solving combined with character progression, fun fast-paced combat, and elements of human cooperation and competition. <br><br><strong>Key features:</strong><br>						<ul class="bb_ul"><li>First downloadable only title from Crystal Dynamics, and first downloadable only Lara Croft game.<br>							</li><li>A classic formula of puzzles, combat, exploration, and breathtaking visuals put through the lens of an isometric fast-paced gaming experience.<br>							</li><li>A wide range of options for solving puzzles and traversing deadly environmental traps, offering players an unprecedented level of freedom to choose their own solutions and explore various paths through the dense jungles of Central America.<br>							</li><li>Crystal Dynamics'' proprietary engine delivers sprawling environments with no load-times and unbelievable vertical gameplay through tombs reaching deep into the Earth. <br>							</li><li>Face off against a myriad of undead warriors brought to life by the evil Xolotl, including a number of boss battles that are not to be missed!<br>						</li></ul>','Take control of Lara and her new partner Totec, a Mayan tribesman, and uncover the ancient artifact known as the &quot;Mirror of Smoke&quot; in this all new action adventure game.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35140,'Critically acclaimed Batman: Arkham Asylum returns with a remastered Game of the Year Edition, featuring 4 extra Challenge Maps. The additional Challenge Maps are Crime Alley; Scarecrow Nightmare; Totally Insane and Nocturnal Hunter (both from the Insane Night Map Pack).<br>					<ul class="bb_ul"><li>Utilize the unique FreeFlow™ combat system to chain together unlimited combos seamlessly and battle with huge groups of The Joker’s henchmen in brutal melee brawls <br>					</li><li>Investigate as Batman, the WORLD’S GREATEST DETECTIVE, by solving intricate puzzles with the help of cutting edge forensic tools including x-ray scanning, fingerprint scans, ‘Amido Black’ spray and a pheromone tracker<br>					</li><li>Face off against Gotham’s greatest villains including The Joker, HARLEY QUINN, POISON IVY and KILLER CROC <br>					</li><li>Become the Invisible Predator™ with Batman’s fear takedowns and unique vantage point system to move without being seen and hunt enemies  <br>					</li><li>Choose multiple takedown methods, including swooping from the sky and smashing through walls. <br>					</li><li>Explore every inch of Arkham Asylum and roam freely on the infamous island, presented for the first time ever in its gritty and realistic entirety<br>					</li><li>Experience what it’s like to be BATMAN using BATARANGS, explosive gel aerosol, The Batclaw, sonar resonator and the line launcher <br>					</li><li>Unlock more secrets by completing hidden challenges in the world and develop and customize equipment by earning experience points <br>					</li><li>Enjoy complete superhero freedom in the environment with the use of Batman’s grapnel gun to get to any place you can see, jump from any height and glide in any direction <br>					</li></ul>','Critically acclaimed Batman: Arkham Asylum returns with a remastered Game of the Year Edition, featuring 4 extra Challenge Maps. The additional Challenge Maps are Crime Alley; Scarecrow Nightmare; Totally Insane and Nocturnal Hunter (both from the Insane Night Map Pack).<br>					<ul class="bb_ul"><li>Utilize the unique FreeFlow™ combat system to chain together unlimited combos seamlessly and battle with huge groups of The Joker’s henchmen in brutal melee brawls <br>					</li><li>Investigate as Batman, the WORLD’S GREATEST DETECTIVE, by solving intricate puzzles with the help of cutting edge forensic tools including x-ray scanning, fingerprint scans, ‘Amido Black’ spray and a pheromone tracker<br>					</li><li>Face off against Gotham’s greatest villains including The Joker, HARLEY QUINN, POISON IVY and KILLER CROC <br>					</li><li>Become the Invisible Predator™ with Batman’s fear takedowns and unique vantage point system to move without being seen and hunt enemies  <br>					</li><li>Choose multiple takedown methods, including swooping from the sky and smashing through walls. <br>					</li><li>Explore every inch of Arkham Asylum and roam freely on the infamous island, presented for the first time ever in its gritty and realistic entirety<br>					</li><li>Experience what it’s like to be BATMAN using BATARANGS, explosive gel aerosol, The Batclaw, sonar resonator and the line launcher <br>					</li><li>Unlock more secrets by completing hidden challenges in the world and develop and customize equipment by earning experience points <br>					</li><li>Enjoy complete superhero freedom in the environment with the use of Batman’s grapnel gun to get to any place you can see, jump from any height and glide in any direction <br>					</li></ul>','Experience what it’s like to be Batman and face off against Gotham''s greatest villians. Explore every inch of Arkham Asylum and roam freely on the infamous island.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35300,'<p>Saudi Arabia, one of the world''s leading oil suppliers and a key U.S. ally, has been taken over by a highly organized group of radical terrorists. The government is in a state of collapse and turmoil and you have been chosen to lead the United States'' armed forces to restore control.</p>
					<p>Search and destroy using the latest military hardware from the Abrams tank to the Apache helicopter in realistic settings ranging from the open desert to close-quarters infantry combat. Wear down enemy morale by capturing vehicles, weapons and buildings.  You''ll need elite forces to destroy the world''s best-armed fanatics, bent on world-wide economic collapse.  The soldiers who survive will gain experience and move with you from mission to mission. </p>
					<p>Failure is not an option &mdash; This is Warfare.</p>
					<p>Key features:</p>
					<ul>
					<li>Fight with the latest U.S. & Russian Weapons Systems</li>
					<li>Dominate real territories created from satellite images</li>
					<li>Gain experience for your troops by keeping them alive</li>
					<li>Capture Enemy vehicles and weaponry</li>
					<li>Destroy everything in your path with realistic physics</li>
					<li>Shock and Awe your opponents to wear down their morale</li>
					<li>Hone your tactics in various environments from open desert to urban combat</li>
					<li>12 missions for the USA army expeditionary corps</li>
					</ul>','<p>Saudi Arabia, one of the world''s leading oil suppliers and a key U.S. ally, has been taken over by a highly organized group of radical terrorists. The government is in a state of collapse and turmoil and you have been chosen to lead the United States'' armed forces to restore control.</p>
					<p>Search and destroy using the latest military hardware from the Abrams tank to the Apache helicopter in realistic settings ranging from the open desert to close-quarters infantry combat. Wear down enemy morale by capturing vehicles, weapons and buildings.  You''ll need elite forces to destroy the world''s best-armed fanatics, bent on world-wide economic collapse.  The soldiers who survive will gain experience and move with you from mission to mission. </p>
					<p>Failure is not an option &mdash; This is Warfare.</p>
					<p>Key features:</p>
					<ul>
					<li>Fight with the latest U.S. & Russian Weapons Systems</li>
					<li>Dominate real territories created from satellite images</li>
					<li>Gain experience for your troops by keeping them alive</li>
					<li>Capture Enemy vehicles and weaponry</li>
					<li>Destroy everything in your path with realistic physics</li>
					<li>Shock and Awe your opponents to wear down their morale</li>
					<li>Hone your tactics in various environments from open desert to urban combat</li>
					<li>12 missions for the USA army expeditionary corps</li>
					</ul>','Saudi Arabia, one of the world''s leading oil suppliers and a key U.S. ally, has been taken over by a highly organized group of radical terrorists. The government is in a state of collapse and turmoil and you have been chosen to lead the United States'' armed forces to restore control.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35310,'Clutch is a fast-paced arcade racing game which will challenge the resilience of anyone''s nerves. You play as a person who has survived a catastrophe of the Large Hadron Collider (LHC), while everyone else in the city has been transformed into a bloodthirsty zombie. You return to the abandoned city, looking for a way to change the zombies back into humans. The only way to survive is to move on fast armored vehicles. The player will complete different missions: racing, rescue and more to finally learn the truth.<br>					Key features: <br>					<ul class="bb_ul"><li>A multitude of drivable vehicles and upgrades<br>					</li><li>Many ways to destroy zombies<br>					</li><li>The LHC campus is a complete city open for exploration, sandbox style<br>					</li><li>8 game modes of racing and combat<br>					</li><li>Advanced collision and damage physics<br>					</li><li>Diversity of artifacts that affect the player and rivals<br>					</li></ul>','Clutch is a fast-paced arcade racing game which will challenge the resilience of anyone''s nerves. You play as a person who has survived a catastrophe of the Large Hadron Collider (LHC), while everyone else in the city has been transformed into a bloodthirsty zombie. You return to the abandoned city, looking for a way to change the zombies back into humans. The only way to survive is to move on fast armored vehicles. The player will complete different missions: racing, rescue and more to finally learn the truth.<br>					Key features: <br>					<ul class="bb_ul"><li>A multitude of drivable vehicles and upgrades<br>					</li><li>Many ways to destroy zombies<br>					</li><li>The LHC campus is a complete city open for exploration, sandbox style<br>					</li><li>8 game modes of racing and combat<br>					</li><li>Advanced collision and damage physics<br>					</li><li>Diversity of artifacts that affect the player and rivals<br>					</li></ul>','Clutch is a fast-paced arcade racing game which will challenge the resilience of anyone''s nerves. You play as a person who has survived a catastrophe of the Large Hadron Collider (LHC), while everyone else in the city has been transformed into a bloodthirsty zombie.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35320,'<strong>Insane 2</strong> offers a number of innovations in the off-road racing genre. Besides the traditional time trial mode, the game features 9 other game modes, including the popular “Capture the flag”, “Gate hunt” and “Pathfinder”, as well as some new competitions, such as bonus hunting, territory control and helicopter pursuit. All of these modes are also available in multiplayer, with up to eight players participating simultaneously.<br><br>						More than one hundred and fifty races combined into championships and cup competitions take place in Europe, America, Africa and the Antarctic. The game has an enormous variety of long distance tracks: sand and snowy deserts, high-speed roads and impassable cross-country paths, African beaches and deserted Antarctic stations.<br><br>						The game features 18 vehicles of different classes, from buggies to monstrous “Bigfoots”, as well as an additional prototype class. Rating points won in the races can be used to upgrade any of the vehicles, from a selection of 15 running gear, body or engine upgrade alternatives. Each vehicle is furnished with a detailed destruction system. Reaching the end of a course without suffering any losses is an enormous challenge that only a select few are able to accomplish. The opponents, who constantly create extreme situations, aren’t the only danger: players also need to watch out for railway crossings, heavy tanker trucks and even lightning in stormy weather.<br><br>						<h2 class="bb_tag">Key Features:</h2>						<ul class="bb_ul"><li>18 vehicles from six different types: 4x4, SUV, pick-ups, trucks, extreme vehicles and prototypes.<br>						</li><li>20 locations, 170 races, 4 continents (Eurasia, America, Africa and the Antarctic)<br>						</li><li>10 game modes, also available in multiplayer<br>						</li><li>Rating and game achievements system<br>						</li><li>Detailed vehicle destruction and a car tuning system<br>						</li></ul>','<strong>Insane 2</strong> offers a number of innovations in the off-road racing genre. Besides the traditional time trial mode, the game features 9 other game modes, including the popular “Capture the flag”, “Gate hunt” and “Pathfinder”, as well as some new competitions, such as bonus hunting, territory control and helicopter pursuit. All of these modes are also available in multiplayer, with up to eight players participating simultaneously.<br><br>						More than one hundred and fifty races combined into championships and cup competitions take place in Europe, America, Africa and the Antarctic. The game has an enormous variety of long distance tracks: sand and snowy deserts, high-speed roads and impassable cross-country paths, African beaches and deserted Antarctic stations.<br><br>						The game features 18 vehicles of different classes, from buggies to monstrous “Bigfoots”, as well as an additional prototype class. Rating points won in the races can be used to upgrade any of the vehicles, from a selection of 15 running gear, body or engine upgrade alternatives. Each vehicle is furnished with a detailed destruction system. Reaching the end of a course without suffering any losses is an enormous challenge that only a select few are able to accomplish. The opponents, who constantly create extreme situations, aren’t the only danger: players also need to watch out for railway crossings, heavy tanker trucks and even lightning in stormy weather.<br><br>						<h2 class="bb_tag">Key Features:</h2>						<ul class="bb_ul"><li>18 vehicles from six different types: 4x4, SUV, pick-ups, trucks, extreme vehicles and prototypes.<br>						</li><li>20 locations, 170 races, 4 continents (Eurasia, America, Africa and the Antarctic)<br>						</li><li>10 game modes, also available in multiplayer<br>						</li><li>Rating and game achievements system<br>						</li><li>Detailed vehicle destruction and a car tuning system<br>						</li></ul>','Features traditional time trial mode and 9 other game modes, including the popular “Capture the flag”, “Gate hunt” and “Pathfinder”.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35450,'<h1>D-Day Anniversary 2016 Update for Heroes of the West</h1><p>To commemorate the 72nd anniversary of the D-Day landings in Normandy, we have introduced 2 new maps, a new vehicles and a whole bunch of detail changes and updates for the Heroes of the West mod! The new maps are:<br><ul class="bb_ul"><li>Caen Outskirts: a combined arms map featuring the British in a gruelling fight to break out from the Normandy beachhead in summer 1944. The map also introduces the British Bren Carrier troop transport.<br></li><li>Hill 400: this map recreates the bitter fighting in the winter of 1944 with the 2d Ranger Battalion struggling against Axis forces in the Hurtgen Forest.</li></ul><br>If you own RO2/RS the mod is completely free to you. To get your copy, simply head for the store page: <a href="http://store.steampowered.com/app/440090/" target="_blank" rel="noreferrer"  >HERE</a></p><br><h1>Heroes of the West mod added</h1><p><h2 class="bb_tag">Free user-created mod</h2><br>Now released - the user-generated mod, Heroes of the West. Produced by the RO2/RS community, with a little help and some assets from Tripwire and Antimatter Games. Bringing RO2 warfare to the Western Front, the mod adds 4 new maps, 5 new character sets and 10 new weapons - with lots more to come!<br><br>If you already own RO2/RS, you can simply install the mod here: <br><a href="http://store.steampowered.com/app/440090/" target="_blank" rel="noreferrer"  id="dynamiclink_0" >http://store.steampowered.com/app/440090/</a></p><br><h1>Barrikady</h1><p><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/RO2-Beta_Banner.png?t=1552425243" ><br><strong>October 2015</strong>: For the next update to RO2 and Rising Storm, we have a new Beta map - Barrikady - plus a bunch of other fixes. The new map can be pre-loaded as part of the <a href="http://store.steampowered.com/app/324850/" target="_blank" rel="noreferrer"  >Beta Community Map Pack</a>, or will simply be downloaded as needed when it appears in a server rotation.</p><br><h1>RO2 Contains ALL Rising Storm Content</h1><p>Any purchase of RO2 through this Steam Store page, from 23 Sep 2014, will contain ALL Rising Storm multiplayer content as well as the RO2 content.<br><br>All those who bought older RO2 packages (through Steam or elsewhere, at the old, lower, single-game, price) will have RIFLE-ONLY access to Rising Storm, NOT the whole game. To upgrade to get full access to all the Rising Storm content, you will need to buy Rising Storm now as well:<br><br><a href="http://store.steampowered.com/app/234510/" target="_blank" rel="noreferrer"  id="dynamiclink_1" >http://store.steampowered.com/app/234510/</a></p><br><h1>Game of the Year Edition</h1><p><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/RS-RO2_Banner.png?t=1552425243" ><br><strong>May 2014</strong>: To celebrate the award of PC Gamer''s &quot;Multiplayer Game of the Year 2013&quot;, we have update Rising Storm to the Game of the Year edition. This already includes all the previous content updates (Island Assault and the Counterattack mapping contest maps) and now adds in the following:<br><br><ul class="bb_ul"><li>2 transport vehicles for the RO2 factions - Universal Carrier for the Russians and SdKfz-251 halftrack for the Germans<br></li><li>3 existing maps updated for the transports (Arad 2, Barashka and Rakowice<br></li><li>New map - Maggot Hill, featuring Merrill''s Marauders at Nhpum Ga, April 1944<br></li><li>New Search &amp; Destroy gameplay mode - a single life game-type in which teams take turns attempting to destroy one of multiple objectives by planting an explosive. A full set of 10 maps configured for this new game mode<br></li><li>3 new community maps now official - Phosphate Plant and Otori Shima featuring US vs Japanese and Myshkova River featuring Russians vs Germans</li></ul><br><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/banner_counterattack_CP2.png?t=1552425243" ><br><strong>December 2013</strong>: Now that the $35,000 Counterattack Mapping Contest for RO2 has concluded and helped us find the best community made maps on Steam Workshop, Tripwire have worked with the original map makers to polish them up and add them into Red Orchestra 2 as Official Custom Maps. These are some of the best - adding some great new gameplay. All are included for free for everyone who owns the game. Don''t forget there are more great community maps and content on <a href="http://steamcommunity.com/workshop/browse?appid=35450" target="_blank" rel="noreferrer"  >Steam Workshop</a>, so head on over there now!<br><br>This is the second Counterattack Map Contest Pack and completes the set, bringing you 3 more maps:<br><ul class="bb_ul"><li><strong>Bridges of Druzhina</strong> - a massive combined arms map, Russians attacking across open ground, a river and right through a small city, supported by armor; the Germans dug in and steadily pushed back. A classic!<br></li><li><strong>Cold Steel</strong> - a Soviet assault against German infantry dug in to a huge factory complex, fighting across open spaces and then inside individual factory buildings.<br></li><li><strong>Gumrak Station</strong> - a re-imagining of a classic Ostfront map, moved to Gumrak Station, to the west of Stalingrad.</li></ul></p><br><h1>Digital Deluxe Edition</h1><p>Steam Digital Deluxe Edition adds the following extras on top of the Standard Edition:<br><br><ul class="bb_ul"><li>Day 1 Unlock of the Elite Assault Weapons (MKb 42(H) and AVT-40) and Semi Auto Sniper Weapons (SVT-40 and G 41(W):<br><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/page_banner_Exclusive_guns.png" ><br></li><li>Team Fortress 2 German and Russian hats (&quot;Genuine&quot; if bought during pre-purchase):<br></li><li>Two new characters for Killing Floor - Russian and German Soldier Re-enactors:<br><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/page_banner_Exclusive_soldiers.png" ><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/page_banner_Exclusive_TF2hats.png" ></li></ul></p><br><h1>New Game Modes</h1><p>This new edition adds a whole set of extra features, available for free to all owners of the game, including two new game modes:<ul class="bb_ul"><li><strong>“Action” mode</strong> – Featuring a crosshair, easier aiming and toned down recoil, reduced damage and open access to a wide range of weaponry Action mode is the perfect first step for players into the world of Red Orchestra.<br></li><li><strong>“Classic” mode</strong> blends the gameplay innovations of the new game with the tactical and edgy gameplay of the original giving the fans of the first game exactly what they want.<br></li><li><strong>Mamayev Kurgan</strong> – complete new map, featuring both close-quarters battles in trenches and bunkers, as well as longer ranged combat across the famous hill in Stalingrad.<br></li><li><strong>Refined and improved gameplay</strong> across the board, vehicle improvements, and way better performance and polish. We listened to the community and based on their feedback refined and tweaked almost every major feature in the game!</li></ul></p><br><h1>About the Game</h1><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIF3.jpg?t=1552425243" ><br>Red Orchestra 2 focuses on the Battle of Stalingrad and the surrounding operations, both German and Russian, from July 1942 to February 1943. <br><br>The game allows the player to experience one of the most brutal battles in all of human history. Delivering unrivalled accuracy and attention to detail, along with gritty, vicious combat in multiplayer modes the game will feature everything from quick, brutal firefights to more intricate and challenging tactical modes.<h2 class="bb_tag">Red Orchestra multiplayer taken to new heights</h2><ul class="bb_ul"><li>The brutal, gritty Red Orchestra gameplay has been enhanced, expanded and made more accessible. <br></li><li>Gameplay modes as instantly recognizable as Firefight (Tripwire''s take on Team Death Match), single-life gaming redefined in Countdown mode - and the Territory mode already beloved by the hundreds of thousands of Red Orchestra players worldwide.</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/TigerTankGif3.jpg?t=1552425243" ><h2 class="bb_tag">Immersive First Person Tank Warfare</h2><ul class="bb_ul"><li>Experience what it was like to fight inside one of these metal beasts in WWII with the most immersive first person tank warfare ever created. <br></li><li>Fully modeled 3d interiors, a full AI crew, and advanced armor and damage systems create a unique tanking experience. </li></ul><h2 class="bb_tag">Persistent Stats Tracking and Player Progression</h2><ul class="bb_ul"><li>Persistence constantly gives the gamer something to strive for and keeps them playing.<br></li><li>Grow in rank, earn achievements, improve your abilities, and become a Hero!</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIFGameplay.jpg?t=1552425243" ><h2 class="bb_tag">First person cover system</h2><ul class="bb_ul"><li>Experience the ultimate firefights that a cover system allows, from the immersion of a first person view.<br></li><li>Peek or blind fire over and around cover and more.</li></ul><h2 class="bb_tag">Unique Focus – the Battle of Stalingrad in depth</h2><ul class="bb_ul"><li>Red Orchestra 2 takes the familiar WWII genre into a unique direction. Far removed from the well-trodden Normandy setting, gameplay is based on fresh scenarios and actions the player has never experienced before.<br></li><li>Follow the German army as they assault the city of Stalingrad, to the banks of the Volga. Follow the Soviet army as it holds the city against all the odds then destroys the Axis forces.</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIFGameplay2.jpg?t=1552425243" ><h2 class="bb_tag">WWII weaponry redefined</h2><ul class="bb_ul"><li>True to life ballistics, bullet penetration, breathing, adjustable sights, free aim, weapon bracing, photo-real graphics and more, create WWII weaponry that has no equal.</li></ul><h2 class="bb_tag">Heroes</h2><ul class="bb_ul"><li>Achieve the ultimate goal and become a Hero online. Players with hero status inspire troops around them and cause fear in their enemies. <br></li><li>Heroes have access to the best and rarest weapons and will stand out visually from the rest of the soldiers.</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIFGameplay3.jpg?t=1552425243" ><h2 class="bb_tag">Morale</h2><ul class="bb_ul"><li>Experience what it is like to be a soldier in one of the bloodiest conflicts in history and the importance of a soldier’s state of mind and how it can turn the tide of battle. <br></li><li>Suppress your enemies and gain the advantage in combat!</li></ul><h2 class="bb_tag">Enhanced Unreal® Engine™ 3</h2><ul class="bb_ul"><li>Built on an enhanced version of Unreal Engine 3 the game features cutting edge visuals and features.</li></ul>','<img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIF3.jpg?t=1552425243" ><br>Red Orchestra 2 focuses on the Battle of Stalingrad and the surrounding operations, both German and Russian, from July 1942 to February 1943. <br><br>The game allows the player to experience one of the most brutal battles in all of human history. Delivering unrivalled accuracy and attention to detail, along with gritty, vicious combat in multiplayer modes the game will feature everything from quick, brutal firefights to more intricate and challenging tactical modes.<h2 class="bb_tag">Red Orchestra multiplayer taken to new heights</h2><ul class="bb_ul"><li>The brutal, gritty Red Orchestra gameplay has been enhanced, expanded and made more accessible. <br></li><li>Gameplay modes as instantly recognizable as Firefight (Tripwire''s take on Team Death Match), single-life gaming redefined in Countdown mode - and the Territory mode already beloved by the hundreds of thousands of Red Orchestra players worldwide.</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/TigerTankGif3.jpg?t=1552425243" ><h2 class="bb_tag">Immersive First Person Tank Warfare</h2><ul class="bb_ul"><li>Experience what it was like to fight inside one of these metal beasts in WWII with the most immersive first person tank warfare ever created. <br></li><li>Fully modeled 3d interiors, a full AI crew, and advanced armor and damage systems create a unique tanking experience. </li></ul><h2 class="bb_tag">Persistent Stats Tracking and Player Progression</h2><ul class="bb_ul"><li>Persistence constantly gives the gamer something to strive for and keeps them playing.<br></li><li>Grow in rank, earn achievements, improve your abilities, and become a Hero!</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIFGameplay.jpg?t=1552425243" ><h2 class="bb_tag">First person cover system</h2><ul class="bb_ul"><li>Experience the ultimate firefights that a cover system allows, from the immersion of a first person view.<br></li><li>Peek or blind fire over and around cover and more.</li></ul><h2 class="bb_tag">Unique Focus – the Battle of Stalingrad in depth</h2><ul class="bb_ul"><li>Red Orchestra 2 takes the familiar WWII genre into a unique direction. Far removed from the well-trodden Normandy setting, gameplay is based on fresh scenarios and actions the player has never experienced before.<br></li><li>Follow the German army as they assault the city of Stalingrad, to the banks of the Volga. Follow the Soviet army as it holds the city against all the odds then destroys the Axis forces.</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIFGameplay2.jpg?t=1552425243" ><h2 class="bb_tag">WWII weaponry redefined</h2><ul class="bb_ul"><li>True to life ballistics, bullet penetration, breathing, adjustable sights, free aim, weapon bracing, photo-real graphics and more, create WWII weaponry that has no equal.</li></ul><h2 class="bb_tag">Heroes</h2><ul class="bb_ul"><li>Achieve the ultimate goal and become a Hero online. Players with hero status inspire troops around them and cause fear in their enemies. <br></li><li>Heroes have access to the best and rarest weapons and will stand out visually from the rest of the soldiers.</li></ul><img src="https://steamcdn-a.akamaihd.net/steam/apps/35450/extras/GIFGameplay3.jpg?t=1552425243" ><h2 class="bb_tag">Morale</h2><ul class="bb_ul"><li>Experience what it is like to be a soldier in one of the bloodiest conflicts in history and the importance of a soldier’s state of mind and how it can turn the tide of battle. <br></li><li>Suppress your enemies and gain the advantage in combat!</li></ul><h2 class="bb_tag">Enhanced Unreal® Engine™ 3</h2><ul class="bb_ul"><li>Built on an enhanced version of Unreal Engine 3 the game features cutting edge visuals and features.</li></ul>','Contains full Rising Storm content as well!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35460,'<h1>New Mini Campaign Released</h1><p><img src="https://steamcdn-a.akamaihd.net/steam/apps/35460/extras/TheBall-JustUpdated.jpg?t=1447352829" ><br>Now we also have a brand-new mini campaign for you - the winners of a map-making contest for The Ball. This new campaign can be played completely standalone, from the Survival Mode menu and will give you an extra 2 hours of content for free!</p><br><h1>Playable Character for Killing Floor</h1><p><a href="http://store.steampowered.com/app/1250" target="_blank" rel="noreferrer"  ><img src="https://steamcdn-a.akamaihd.net/steam/apps/35460/extras/HarchierSpebbington.jpg?t=1447352829" ></a><br>Everyone who buys The Ball will get a free fully-playable version of Harchier Spebbington, the hero from The Ball, in Killing Floor. This is, of course, in addition to the unique version of the character that everyone who pre-ordered The Ball got.<br><br>For more information on Killing Floor - <a href="http://store.steampowered.com/app/1250" target="_blank" rel="noreferrer"  >head over to the store page now</a>!</p><br><h1>About the Game</h1>The Ball is a first person action-adventure game featuring a full single-player experience built on Epic’s Unreal™ Engine 3 technology. As a swashbuckling archaeologist working on the slopes of a dormant volcano somewhere in Mexico, you get stuck in a cavern. It doesn’t take long before you realize this is more than just a cave. You reveal ancient ruins that have been hidden from outsiders for centuries and discover a mysterious artifact, a gold and metal shelled Ball. As you progress towards solving the mystery of this amazing place you must unlock the secrets of the Ball and learn to control this ancient artifact. Venturing deeper into the volcano, you reveal some of mankind’s greatest secrets and you will start to encounter not just puzzles and traps, but also various strange creatures – the guardians of this mystery. These creatures have to be overcome, using only the Ball to defend you.<br>						<h2 class="bb_tag">Key Features</h2>						<ul class="bb_ul"><li>8 hours of single-player adventure<br>							   </li><li>Game mechanics that are very simple to pick up, immersing the user in the physics-based gameplay right from the start<br>							   </li><li>8 huge levels to explore<br>							   </li><li>Includes bonus Survival game mode, with 4 additional levels<br>							   </li><li>Wide range of enemies to overcome, including mummies and an undead gorilla<br>							   </li><li>Unique vehicles – an underground train and the mysterious “Ball Chariot”<br>							   </li><li>35 secrets hidden away to be discovered, as well as multiple achievements for the player to earn<br>							   </li><li>Steamworks™ features including achievements and leaderboards<br>						</li></ul>','The Ball is a first person action-adventure game featuring a full single-player experience built on Epic’s Unreal™ Engine 3 technology. As a swashbuckling archaeologist working on the slopes of a dormant volcano somewhere in Mexico, you get stuck in a cavern. It doesn’t take long before you realize this is more than just a cave. You reveal ancient ruins that have been hidden from outsiders for centuries and discover a mysterious artifact, a gold and metal shelled Ball. As you progress towards solving the mystery of this amazing place you must unlock the secrets of the Ball and learn to control this ancient artifact. Venturing deeper into the volcano, you reveal some of mankind’s greatest secrets and you will start to encounter not just puzzles and traps, but also various strange creatures – the guardians of this mystery. These creatures have to be overcome, using only the Ball to defend you.<br>						<h2 class="bb_tag">Key Features</h2>						<ul class="bb_ul"><li>8 hours of single-player adventure<br>							   </li><li>Game mechanics that are very simple to pick up, immersing the user in the physics-based gameplay right from the start<br>							   </li><li>8 huge levels to explore<br>							   </li><li>Includes bonus Survival game mode, with 4 additional levels<br>							   </li><li>Wide range of enemies to overcome, including mummies and an undead gorilla<br>							   </li><li>Unique vehicles – an underground train and the mysterious “Ball Chariot”<br>							   </li><li>35 secrets hidden away to be discovered, as well as multiple achievements for the player to earn<br>							   </li><li>Steamworks™ features including achievements and leaderboards<br>						</li></ul>','As a swashbuckling archaeologist, unlock the mystery of the ancient ruins that have been hidden for centuries and discover a mysterious artifact, a gold and metal shelled Ball.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35480,'<h1>Special Edition</h1><p>This Edition of Dwarfs!? includes the new Free to Play edition, plus all of the modes that can be purchased separately.</p><br><h1>About the Game</h1><p>''Dwarfs!?'' offers an addictive, fast paced arcade-like experience, with plenty of difficulties and game modes to play around in!</p>
						<p>As the new overseer for your underground Dwarf base, your job is to manage the small colony and make it as rich as possible, before they meet their inevitable doom! To survive as long as possible, you’ll have to steer and guide your greedy little fellows to the richest points in the caves, while avoiding all the dangers – so they don’t end up destroying your Town Hall and its essential supply of beer.</p>
						<p>They explore for you, they mine for you and they fight for you - but if you don''t keep an eye on them, they''ll do what they do best: die for you and take everyone else with them. But, if all else fails when the Spider Queen comes for you – use the Outpost’s Dwarf Cannon and shoot Dwarfs at her!</p>
						<p>There are only 3 certainties in this world: death, taxes and that Dwarfs always dig too deep!</p>
						<h2>Key features</h2>
						<ul>
							  <li>Fun for all ages and skill levels of gamers, with randomly-generated caves so the game is different every time.
							  <li>Madly Addictive Arcade Mode: 4 difficulty levels ranging from casual to crazy hard-core, time limits from 5 minutes to endless, randomly-generated caves and all the gold and monsters you can handle!
							  <li>Base Defense Mode: Tower Defense gameplay, except you don’t have a tower. And your Dwarfs dig the routes. Then you defend against waves of monsters!
							  <li>Rush Mode: Can you handle Dwarfs spawning at insane rates and digging everywhere?
							  <li>Dark Mode: This time, the only light is in the tunnels your Dwarfs dig. Spooky!
							  <li>Campaign Challenges: Tutorials where you can learn all about being a Dwarf Overseer in a few minutes and Challenges where you can put those Overseer abilities to the ultimate test.
							  <li>Leaderboards: Compare the size of your beard (and your scores) with your friends and the rest of the world.
							  <li>Sandbox Mode: Create your own caves!
							  <li>Codex: Alongside the integrated help system is the Codex – the fount of all Dwarf knowledge! Contains everything you need to know, including video tutorials for the budding Overseer.
							  <li>Medals and Achievements: Lots and lots of shiny stuff to collect and show off to your friends!
							  <li>Fully Integrated with Steamworks&trade;
							  <li>And Zombies. Not to mention goblins, skeletons, spiders, dark elves and more. 
						</ul>','<p>''Dwarfs!?'' offers an addictive, fast paced arcade-like experience, with plenty of difficulties and game modes to play around in!</p>
						<p>As the new overseer for your underground Dwarf base, your job is to manage the small colony and make it as rich as possible, before they meet their inevitable doom! To survive as long as possible, you’ll have to steer and guide your greedy little fellows to the richest points in the caves, while avoiding all the dangers – so they don’t end up destroying your Town Hall and its essential supply of beer.</p>
						<p>They explore for you, they mine for you and they fight for you - but if you don''t keep an eye on them, they''ll do what they do best: die for you and take everyone else with them. But, if all else fails when the Spider Queen comes for you – use the Outpost’s Dwarf Cannon and shoot Dwarfs at her!</p>
						<p>There are only 3 certainties in this world: death, taxes and that Dwarfs always dig too deep!</p>
						<h2>Key features</h2>
						<ul>
							  <li>Fun for all ages and skill levels of gamers, with randomly-generated caves so the game is different every time.
							  <li>Madly Addictive Arcade Mode: 4 difficulty levels ranging from casual to crazy hard-core, time limits from 5 minutes to endless, randomly-generated caves and all the gold and monsters you can handle!
							  <li>Base Defense Mode: Tower Defense gameplay, except you don’t have a tower. And your Dwarfs dig the routes. Then you defend against waves of monsters!
							  <li>Rush Mode: Can you handle Dwarfs spawning at insane rates and digging everywhere?
							  <li>Dark Mode: This time, the only light is in the tunnels your Dwarfs dig. Spooky!
							  <li>Campaign Challenges: Tutorials where you can learn all about being a Dwarf Overseer in a few minutes and Challenges where you can put those Overseer abilities to the ultimate test.
							  <li>Leaderboards: Compare the size of your beard (and your scores) with your friends and the rest of the world.
							  <li>Sandbox Mode: Create your own caves!
							  <li>Codex: Alongside the integrated help system is the Codex – the fount of all Dwarf knowledge! Contains everything you need to know, including video tutorials for the budding Overseer.
							  <li>Medals and Achievements: Lots and lots of shiny stuff to collect and show off to your friends!
							  <li>Fully Integrated with Steamworks&trade;
							  <li>And Zombies. Not to mention goblins, skeletons, spiders, dark elves and more. 
						</ul>','Dig! Dig! Dig! Manage the small underground Dwarf base and make it as rich as possible before they meet their inevitable doom. Purchase before May 11th and save!');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35600,'Big Brain Wolf is a hilarious point and click adventure game for puzzle lovers. The player takes upon the role of an asthmatic vegetarian wolf studying to become a genie. In the course of his adventures the player will encounter a large cast of famous funny characters and solve sixty different puzzles. Six neuroscientist designed highly replayable brain training exercises will earn the player precious hints to help solve the more difficult puzzles.<br>							<ul class="bb_ul"><li>60 Different challenging puzzles and enigmas to solve<br>							</li><li>20 Puzzle filled scenes spanning a 5 chapters captivating story<br>							</li><li>A funny new take on universal characters that will appeal to all<br>							</li><li>6 brain training exercises designed and approved by the neuroscientists of Brain Center International<br>							</li><li>10 Original STEAM achievements<br>							</li><li>Great original soundtrack by a jazz quartet<br>							</li></ul>','Big Brain Wolf is a hilarious point and click adventure game for puzzle lovers. The player takes upon the role of an asthmatic vegetarian wolf studying to become a genie. In the course of his adventures the player will encounter a large cast of famous funny characters and solve sixty different puzzles. Six neuroscientist designed highly replayable brain training exercises will earn the player precious hints to help solve the more difficult puzzles.<br>							<ul class="bb_ul"><li>60 Different challenging puzzles and enigmas to solve<br>							</li><li>20 Puzzle filled scenes spanning a 5 chapters captivating story<br>							</li><li>A funny new take on universal characters that will appeal to all<br>							</li><li>6 brain training exercises designed and approved by the neuroscientists of Brain Center International<br>							</li><li>10 Original STEAM achievements<br>							</li><li>Great original soundtrack by a jazz quartet<br>							</li></ul>','Big Brain Wolf is a hilarious point and click adventure game for puzzle lovers. The player takes upon the role of an asthmatic vegetarian wolf studying to become a genie. In the course of his adventures the player will encounter a large cast of famous funny characters and solve sixty different puzzles.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35700,'Trine is a fantasy action game where the player can create and use physics-based objects to beat hazardous puzzles and threatening enemies. Set in a world of great castles and strange machinery, three heroes are bound to a mysterious device called the Trine in a quest to save the kingdom from evil. <br><br>The gameplay is based on fully interactive physics - each character''s different abilities help the player battle an army of undead and defeat hazardous contraptions. The player can at any time freely choose whoever is best suited for the upcoming challenge or puzzle: The Wizard is able to summon objects to help solve puzzles and create new ways to overcome obstacles, the Thief uses her agility and dead-on accuracy to swiftly surprise the monsters, and the Knight unleashes mayhem and physical destruction wherever he goes.<h2 class="bb_tag"><strong>Trine Enchanted Edition</strong> </h2> Trine Enchanted Edition is a remake of the original Trine with dazzling new visual effects and numerous gameplay improvements!<br><br><ul class="bb_ul"><li> Online and local co-op with up to three players<br></li><li>Mid-level saving: Save anywhere to play as long or short sessions as you like<br></li><li>Stunning new graphics based on the Trine 2 engine</li></ul><br>Both Trine Enchanted Edition as well as the original Trine are included in the Enchanted Edition. The different versions are selectable from the game launcher. All Trine purchases have been automatically updated to Trine Enchanted Edition.<br><br><strong>Note:</strong> The original Trine is only included in the Windows and Mac versions.<h2 class="bb_tag"><strong>Key Features</strong> </h2> <br>                    <ul class="bb_ul">                    <li> 3 Heroes – Amadeus the Wizard, Pontius the Knight and Zoya the Thief, each with their own skills:<br>                    <ul class="bb_ul"><li>Wizard is able to cast physically simulated objects and levitate them in the totally interactive game world<br>                    </li><li>Knight is a mayhem-bringer like no other, able to destroy objects and smash skeletons to pieces with his weapons, including the mighty Storm Hammer! <br>                    </li><li>Thief can hit enemies from a distance with her accurate arrows but she also has a grappling hook to easily swing from one platform to another<br>                    </li></ul></li><li>Solve challenges and puzzles in many different ways – combine the characters'' abilities and let your mind come up with creative solutions never seen before<br>                   </li><li> Online and local co-op with up to three players<br>                    </li><li>Characters gain experience points that can be used to upgrade their abilities<br>                    </li><li>Fully interactive game world with life-like physics<br>                    </li><li>15 carefully designed and challenging levels with a distinctly unique atmosphere and graphics, including the Astral Academy, Crystal Caverns, Dragon Graveyard, Forsaken Dungeons, Fangle Forest and the Ruins of the Perished. <br>                    </li><li>Many different items to collect - each affecting the characters'' abilities<br>                    </li><li>Well-hidden secret chests in every level<br>                    </li><li>3 difficulty levels to choose from<br>                    </li><li>Amazing 19-track soundtrack composed by acclaimed Ari Pulkkinen<br>                    </li><li>Fun and challenging Steam Achievements to unlock<br>                    </li></ul><h2 class="bb_tag"><strong>Trine (Original Version)</strong> </h2> <br>Trine Enchanted Edition also includes the original version of Trine for Windows and Mac. The game version can be selected from the game''s launcher.<br><br>The original version also has some additional language subtitle options: Finnish, Turkish, Portuguese, Romanian in addition to those present in Trine Enchanted Edition (English, French, German, Italian, Spanish).','Trine is a fantasy action game where the player can create and use physics-based objects to beat hazardous puzzles and threatening enemies. Set in a world of great castles and strange machinery, three heroes are bound to a mysterious device called the Trine in a quest to save the kingdom from evil. <br><br>The gameplay is based on fully interactive physics - each character''s different abilities help the player battle an army of undead and defeat hazardous contraptions. The player can at any time freely choose whoever is best suited for the upcoming challenge or puzzle: The Wizard is able to summon objects to help solve puzzles and create new ways to overcome obstacles, the Thief uses her agility and dead-on accuracy to swiftly surprise the monsters, and the Knight unleashes mayhem and physical destruction wherever he goes.<h2 class="bb_tag"><strong>Trine Enchanted Edition</strong> </h2> Trine Enchanted Edition is a remake of the original Trine with dazzling new visual effects and numerous gameplay improvements!<br><br><ul class="bb_ul"><li> Online and local co-op with up to three players<br></li><li>Mid-level saving: Save anywhere to play as long or short sessions as you like<br></li><li>Stunning new graphics based on the Trine 2 engine</li></ul><br>Both Trine Enchanted Edition as well as the original Trine are included in the Enchanted Edition. The different versions are selectable from the game launcher. All Trine purchases have been automatically updated to Trine Enchanted Edition.<br><br><strong>Note:</strong> The original Trine is only included in the Windows and Mac versions.<h2 class="bb_tag"><strong>Key Features</strong> </h2> <br>                    <ul class="bb_ul">                    <li> 3 Heroes – Amadeus the Wizard, Pontius the Knight and Zoya the Thief, each with their own skills:<br>                    <ul class="bb_ul"><li>Wizard is able to cast physically simulated objects and levitate them in the totally interactive game world<br>                    </li><li>Knight is a mayhem-bringer like no other, able to destroy objects and smash skeletons to pieces with his weapons, including the mighty Storm Hammer! <br>                    </li><li>Thief can hit enemies from a distance with her accurate arrows but she also has a grappling hook to easily swing from one platform to another<br>                    </li></ul></li><li>Solve challenges and puzzles in many different ways – combine the characters'' abilities and let your mind come up with creative solutions never seen before<br>                   </li><li> Online and local co-op with up to three players<br>                    </li><li>Characters gain experience points that can be used to upgrade their abilities<br>                    </li><li>Fully interactive game world with life-like physics<br>                    </li><li>15 carefully designed and challenging levels with a distinctly unique atmosphere and graphics, including the Astral Academy, Crystal Caverns, Dragon Graveyard, Forsaken Dungeons, Fangle Forest and the Ruins of the Perished. <br>                    </li><li>Many different items to collect - each affecting the characters'' abilities<br>                    </li><li>Well-hidden secret chests in every level<br>                    </li><li>3 difficulty levels to choose from<br>                    </li><li>Amazing 19-track soundtrack composed by acclaimed Ari Pulkkinen<br>                    </li><li>Fun and challenging Steam Achievements to unlock<br>                    </li></ul><h2 class="bb_tag"><strong>Trine (Original Version)</strong> </h2> <br>Trine Enchanted Edition also includes the original version of Trine for Windows and Mac. The game version can be selected from the game''s launcher.<br><br>The original version also has some additional language subtitle options: Finnish, Turkish, Portuguese, Romanian in addition to those present in Trine Enchanted Edition (English, French, German, Italian, Spanish).','Three Heroes make their way through dangers untold in a fairytale world of great castles and strange machinery, featuring physics-based puzzles, beautiful sights and online co-op.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35720,'Trine 2 is a sidescrolling game of action, puzzles and platforming where you play as one of Three Heroes who make their way through dangers untold in a fantastical fairytale world.<br><br>Join Amadeus the Wizard, Pontius the Knight and Zoya the Thief in their adventure full of friendship, magic and betrayal.<br> <br><strong>Trine 2: Complete Story</strong> fully integrates the Goblin Menace expansion campaign and the all-new unlockable Dwarven Caverns level into one mighty fairytale. All owners of Trine 2: Goblin Menace are automatically upgraded to the Complete Story edition.<h2 class="bb_tag">Key Features</h2><ul class="bb_ul"><li> Complete Story edition features the all-new unlockable Dwarven Caverns level that takes our heroes on a journey through deep and dark lava-filled tunnels resonating with ancient legends<br></li><li> 20 levels chock-full of adventure, physics-based puzzles, hazards, enemies and contraptions. <br></li><li> 3 Heroes – Amadeus the Wizard, Pontius the Knight and Zoya the Thief, each with their own skills – and personalities charming and otherwise<br></li><li> Choose new skills to aid the heroes in their quest; fight dragon fire with fire arrows or turn your goblin enemies to ice, fly across chasms with the Kitesail Shield, levitate monsters to great heights and then trap them in a box, or slow down the game world with the time-bending gravity bubble!<br></li><li> Travel through beautiful vistas and environments (sometimes using extremely unreliable methods of transportation), including a castle by the treacherous sea, a burning desert, snowy ice mountains, all the way to the insides of a giant worm<br></li><li> Accessible for both casual and core gamers<br></li><li> Online and local co-op with up to three players<br></li><li> Save anywhere to play as long or short sessions as you like and use the Unlimited Character Mode and Game+ for additional replay value<br></li><li> Superb graphics with next-gen visuals use impressive technical effects, immerse yourself in the fantastical fairytale world full of magic and wonder<br></li><li> Hidden collectibles for extra adventuring<br></li><li> Fun and challenging achievements to unlock<br></li><li> Full language support for English, French, German and Spanish, and optional subtitling for more than 10 languages<br></li><li> Supports NVIDIA 3D Vision </li></ul><h2 class="bb_tag">Trine 2 Soundtrack and Artbook Pack</h2><br>Digital Artbook with commentary by Trine 2 artists highlighting the design of levels, enemies, buildings and many environments. Also features an exclusive look at material not used in the final game.<br><br>Soundtrack by award-winning Ari Pulkkinen, featuring a total of 30 tracks from Trine 2 and Goblin Menace in MP3 format!<br><br>The Digital Artbook will be placed in your Trine 2 folder in the Steam directory:<br>...Steam\steamapps\common\Trine 2\Artbook<br>The Soundtrack will be placed in your Trine 2 folder in the Steam directory:<br>...Steam\steamapps\common\Trine 2\Soundtrack','Trine 2 is a sidescrolling game of action, puzzles and platforming where you play as one of Three Heroes who make their way through dangers untold in a fantastical fairytale world.<br><br>Join Amadeus the Wizard, Pontius the Knight and Zoya the Thief in their adventure full of friendship, magic and betrayal.<br> <br><strong>Trine 2: Complete Story</strong> fully integrates the Goblin Menace expansion campaign and the all-new unlockable Dwarven Caverns level into one mighty fairytale. All owners of Trine 2: Goblin Menace are automatically upgraded to the Complete Story edition.<h2 class="bb_tag">Key Features</h2><ul class="bb_ul"><li> Complete Story edition features the all-new unlockable Dwarven Caverns level that takes our heroes on a journey through deep and dark lava-filled tunnels resonating with ancient legends<br></li><li> 20 levels chock-full of adventure, physics-based puzzles, hazards, enemies and contraptions. <br></li><li> 3 Heroes – Amadeus the Wizard, Pontius the Knight and Zoya the Thief, each with their own skills – and personalities charming and otherwise<br></li><li> Choose new skills to aid the heroes in their quest; fight dragon fire with fire arrows or turn your goblin enemies to ice, fly across chasms with the Kitesail Shield, levitate monsters to great heights and then trap them in a box, or slow down the game world with the time-bending gravity bubble!<br></li><li> Travel through beautiful vistas and environments (sometimes using extremely unreliable methods of transportation), including a castle by the treacherous sea, a burning desert, snowy ice mountains, all the way to the insides of a giant worm<br></li><li> Accessible for both casual and core gamers<br></li><li> Online and local co-op with up to three players<br></li><li> Save anywhere to play as long or short sessions as you like and use the Unlimited Character Mode and Game+ for additional replay value<br></li><li> Superb graphics with next-gen visuals use impressive technical effects, immerse yourself in the fantastical fairytale world full of magic and wonder<br></li><li> Hidden collectibles for extra adventuring<br></li><li> Fun and challenging achievements to unlock<br></li><li> Full language support for English, French, German and Spanish, and optional subtitling for more than 10 languages<br></li><li> Supports NVIDIA 3D Vision </li></ul><h2 class="bb_tag">Trine 2 Soundtrack and Artbook Pack</h2><br>Digital Artbook with commentary by Trine 2 artists highlighting the design of levels, enemies, buildings and many environments. Also features an exclusive look at material not used in the final game.<br><br>Soundtrack by award-winning Ari Pulkkinen, featuring a total of 30 tracks from Trine 2 and Goblin Menace in MP3 format!<br><br>The Digital Artbook will be placed in your Trine 2 folder in the Steam directory:<br>...Steam\steamapps\common\Trine 2\Artbook<br>The Soundtrack will be placed in your Trine 2 folder in the Steam directory:<br>...Steam\steamapps\common\Trine 2\Soundtrack','Three Heroes make their way through dangers untold in a fairytale world, featuring physics-based puzzles, beautiful sights and online co-op.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (35800,'<i>A game of lysergic excellence.</i><br>- Jim Rossignol, Rock, Paper, Shotgun<br><br><i>Like traveling through the Matrix on acid.</i><br>- Joseph Vanburen, <a href="https://steamcommunity.com/linkfilter/?url=http://HarryBalls.com" target="_blank" rel="noopener"  >HarryBalls.com</a><br><br><i>Like having sex with Yog Sothoth</i><br>- the99th, Play This Thing!<br><br>Brainpipe: A Plunge to Unhumanity is an easy-to-pick-up first person game of real-time spatial navigation and quick reflexes. Supported by hypnotic graphics, ear tickling sound effects and immersive dreamscape music, the game''s free floating, forward moving intensity gradually increases from serene to frenetic as you play. Effortless to learn, Brainpipe''s simple and intuitive interface will have you playing in seconds. Immersive and dreamlike, Brainpipe will always beckon you back for more.<br><br>			<ul class="bb_ul"><li>10 twisty tube levels<br>			</li><li>Ramping speed and intensity<br>			</li><li>8 dangerously tempting obstacles to avoid<br>			</li><li>Ten levels of ramping perplexity and oddness.<br>			</li><li>Mind glyphs to collect and score<br>			</li><li>Hypnotic sound and music featuring EelMix<br>			</li><li>Creepy eyeball buttons!<br>			</li><li>Fullscreen or windowed modes<br>			</li><li>Mouse, joystick and gamepad support<br>			</li></ul><br><i>Digital Eel makes deep games about weird stuff, going so far as to name one of their better games Weird Worlds. Then they went ahead and outdid themselves.</i><br>- the99th, Play This Thing!<br><br><i>Completely and utterly original and unbelievably addictive.</i><br>- Tom Lord, TheSixthAxis<br><br><i>The subtle doppler effect on the constant and schizophrenic audio visual assault positions you squarely inside the game in ways that most struggle at.</i><br>- Brandon Boyer, Offworld<br><br>Brainpipe: A Plunge to Unhumanity was the 2009 Independent Games Festival <i>Excellence in Audio</i> award winner.','<i>A game of lysergic excellence.</i><br>- Jim Rossignol, Rock, Paper, Shotgun<br><br><i>Like traveling through the Matrix on acid.</i><br>- Joseph Vanburen, <a href="https://steamcommunity.com/linkfilter/?url=http://HarryBalls.com" target="_blank" rel="noopener"  >HarryBalls.com</a><br><br><i>Like having sex with Yog Sothoth</i><br>- the99th, Play This Thing!<br><br>Brainpipe: A Plunge to Unhumanity is an easy-to-pick-up first person game of real-time spatial navigation and quick reflexes. Supported by hypnotic graphics, ear tickling sound effects and immersive dreamscape music, the game''s free floating, forward moving intensity gradually increases from serene to frenetic as you play. Effortless to learn, Brainpipe''s simple and intuitive interface will have you playing in seconds. Immersive and dreamlike, Brainpipe will always beckon you back for more.<br><br>			<ul class="bb_ul"><li>10 twisty tube levels<br>			</li><li>Ramping speed and intensity<br>			</li><li>8 dangerously tempting obstacles to avoid<br>			</li><li>Ten levels of ramping perplexity and oddness.<br>			</li><li>Mind glyphs to collect and score<br>			</li><li>Hypnotic sound and music featuring EelMix<br>			</li><li>Creepy eyeball buttons!<br>			</li><li>Fullscreen or windowed modes<br>			</li><li>Mouse, joystick and gamepad support<br>			</li></ul><br><i>Digital Eel makes deep games about weird stuff, going so far as to name one of their better games Weird Worlds. Then they went ahead and outdid themselves.</i><br>- the99th, Play This Thing!<br><br><i>Completely and utterly original and unbelievably addictive.</i><br>- Tom Lord, TheSixthAxis<br><br><i>The subtle doppler effect on the constant and schizophrenic audio visual assault positions you squarely inside the game in ways that most struggle at.</i><br>- Brandon Boyer, Offworld<br><br>Brainpipe: A Plunge to Unhumanity was the 2009 Independent Games Festival <i>Excellence in Audio</i> award winner.','Brainpipe is a first person game of spatial navigation and quick reflexes. Supported by hypnotic graphics, ear tickling sound effects and immersive dreamscape music, the game''s free floating, forward moving intensity gradually increases from serene to frenetic as you play.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (36000,'<p><i>Foreign Legion: Buckets of Blood</i> is a cartoon-style third-person shooter. You take the role of a last-standing hard-boiled Legionnaire taking on an entire rebel army.
					<p>A small campaign with various objectives, such as defending civilians, escorting a tourist bus and a mass-chicken-murder map. The game includes a ranking system that allows you to unlock new outfits, accessories and of course new weapons.</p>
					<p>Key features:</p>
					<ul>
					<li><p>18 Various Steam achievements: Try to win Chicken Slaughter (killing all the chickens) and Damage Control (sparing all the civilians) in the same game!</p>
					<li>Fill your buckets with blood by causing suicide bombers to explode prematurely or shoot gory head shots!</li>
					<li>A dynamically evolving soundtrack that reacts to your actions!</li>
					<li>A complete arsenal of weapons, including personal air-raid support to slaughter attacking hordes at once.</li>
					<li>A broad range of difficulty with action-packed fun for both casual and veteran players!</li>
					</ul>','<p><i>Foreign Legion: Buckets of Blood</i> is a cartoon-style third-person shooter. You take the role of a last-standing hard-boiled Legionnaire taking on an entire rebel army.
					<p>A small campaign with various objectives, such as defending civilians, escorting a tourist bus and a mass-chicken-murder map. The game includes a ranking system that allows you to unlock new outfits, accessories and of course new weapons.</p>
					<p>Key features:</p>
					<ul>
					<li><p>18 Various Steam achievements: Try to win Chicken Slaughter (killing all the chickens) and Damage Control (sparing all the civilians) in the same game!</p>
					<li>Fill your buckets with blood by causing suicide bombers to explode prematurely or shoot gory head shots!</li>
					<li>A dynamically evolving soundtrack that reacts to your actions!</li>
					<li>A complete arsenal of weapons, including personal air-raid support to slaughter attacking hordes at once.</li>
					<li>A broad range of difficulty with action-packed fun for both casual and veteran players!</li>
					</ul>','Foreign Legion: Buckets of Blood is a cartoon-style third-person shooter. You take the role of a last-standing hard-boiled Legionnaire taking on an entire rebel army. A small campaign with various objectives, such as defending civilians, escorting a tourist bus and a mass-chicken-murder map.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (36100,'<p>Travel back in time to a world of danger and mystery; a place where the open waters can mean anything but smooth sailing. Get carried away in these three classic installments in the acclaimed Tradewinds® Series.</p>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36100/extras/twl_logo.jpg" align="left">
                    <p>Sail, trade and battle with legendary heroes such as Sinbad in the mythical Far East. Enter a world of danger and intrigue as you complete over 100 unique tasks. Build a flotilla of ships armed with weaponry, both man-made and magic. Sail into the sky to discover new ports and engage in aerial combat with other magical sky ships.</p>
                    <p>Encounter a world of legend, play Tradewinds Legends today!</p>
                    <ul>
                    <li>Over 100 tasks to choose from
                    <li>Play as one of 4 unique characters, or build your own from scratch
                    <li>10 beautiful ports to visit
                    <li>Build your fleet with 7 unique ships, weapons and magical attacks
                    <li>Hundreds of special items to customize your gameplay
                    <li>Interact with a limitless cast of characters on your adventures
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36100/extras/tw2_logo.jpg" align="left">
                    <p>Navigate a fascinating new world and discover uncharted ports teeming with friends and foes alike. The choice is yours; be a master commander, defeating pirates and plundering their vast hordes of booty, or, play it safe by trading exotic island goods, gradually amassing untold wealth, power and influence.</p>
                    <p>Earn enough gold to upgrade your ship and engage in land and sea battles. Two game modes and over sixty hours of adventurous game play await you in Tradewinds® 2.</p>
                    <ul>
                    <li>Buy low and sell high in 20 different ports with 10 different goods
                    <li>Choose one of 5 characters or create and customize your own!
                    <li>Embark on over 100 swashbuckling adventures
                    <li>Over 60 hours of gameplay!
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36100/extras/twc_logo.jpg" align="left">
                    <p>Tradewinds® Classic, set in the 19th century Far East, takes you back to the very beginning where buying and selling exotic goods, or collecting bounties on previously thought-to-be-dead pirates, can lead to untold wealth...or ultimate doom. With enough wisdom, courage and luck you too can become a Tai-Pan!</p>
                    <ul>
                    <li>Buy low, sell high, and build your fortune
                    <li>Choose from 4 unique characters
                    <li>Buy more ships to dominate the seas
                    <li>Collect bounties by defeating villainous pirates
                    </ul>','<p>Travel back in time to a world of danger and mystery; a place where the open waters can mean anything but smooth sailing. Get carried away in these three classic installments in the acclaimed Tradewinds® Series.</p>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36100/extras/twl_logo.jpg" align="left">
                    <p>Sail, trade and battle with legendary heroes such as Sinbad in the mythical Far East. Enter a world of danger and intrigue as you complete over 100 unique tasks. Build a flotilla of ships armed with weaponry, both man-made and magic. Sail into the sky to discover new ports and engage in aerial combat with other magical sky ships.</p>
                    <p>Encounter a world of legend, play Tradewinds Legends today!</p>
                    <ul>
                    <li>Over 100 tasks to choose from
                    <li>Play as one of 4 unique characters, or build your own from scratch
                    <li>10 beautiful ports to visit
                    <li>Build your fleet with 7 unique ships, weapons and magical attacks
                    <li>Hundreds of special items to customize your gameplay
                    <li>Interact with a limitless cast of characters on your adventures
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36100/extras/tw2_logo.jpg" align="left">
                    <p>Navigate a fascinating new world and discover uncharted ports teeming with friends and foes alike. The choice is yours; be a master commander, defeating pirates and plundering their vast hordes of booty, or, play it safe by trading exotic island goods, gradually amassing untold wealth, power and influence.</p>
                    <p>Earn enough gold to upgrade your ship and engage in land and sea battles. Two game modes and over sixty hours of adventurous game play await you in Tradewinds® 2.</p>
                    <ul>
                    <li>Buy low and sell high in 20 different ports with 10 different goods
                    <li>Choose one of 5 characters or create and customize your own!
                    <li>Embark on over 100 swashbuckling adventures
                    <li>Over 60 hours of gameplay!
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36100/extras/twc_logo.jpg" align="left">
                    <p>Tradewinds® Classic, set in the 19th century Far East, takes you back to the very beginning where buying and selling exotic goods, or collecting bounties on previously thought-to-be-dead pirates, can lead to untold wealth...or ultimate doom. With enough wisdom, courage and luck you too can become a Tai-Pan!</p>
                    <ul>
                    <li>Buy low, sell high, and build your fortune
                    <li>Choose from 4 unique characters
                    <li>Buy more ships to dominate the seas
                    <li>Collect bounties by defeating villainous pirates
                    </ul>','Travel back in time to a world of danger and mystery; a place where the open waters can mean anything but smooth sailing. Get carried away in these three classic installments in the acclaimed Tradewinds® Series. &nbsp; Sail, trade and battle with legendary heroes such as Sinbad in the mythical Far East.');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (36130,'<img src="http://storefront.steampowered.com/v/gfx/apps/36130/extras/two_logo.jpg" align="left">
                    <p>Tradewinds Odyssey, the latest installment in the highly-acclaimed Tradewinds series, takes you on an adventurous journey across ancient Greece, where gods, heroes and monsters of legend await. </p>
                    <p>Guide five unique heroes - the Athlete, Cynic, Priestess, Minotaur and Goddess - as you embark on over 50 chapters and quests, encountering characters both strange and familiar. Take part in trading like never before by creating and spreading goods to new lands as you build, strengthen and upgrade your fleet into a powerful force unrivaled in the Aegean! Cast powerful spells bestowed upon you by the gods, or use your unique Hero’s Talent to demolish your opponent in battle.</p>
                    <p>Your adventure begins today… in Tradewinds Odyssey!</p>
                    <ul>
                    <li>Play as 5 unique characters, each with an original storyline
                    <li>Create and customize your own character
                    <li>Spread, create and trade over a dozen exotic goods
                    <li>New ramming feature available in sea battle
                    <li>Achieve great feats and build your rank
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36130/extras/twc_logo.jpg" align="left">
                    <p>Adventure awaits you in Tradewinds Caravans™, the latest installment in the acclaimed Tradewinds Series. As the Middle Ages unfold in the West, cultural centers and merchants across Asia are linked together by an ancient trade route – stretching from the shores of the Mediterranean Sea to China – known as the legendary Silk Road. 
                    Guide six brave heroes as they navigate treacherous terrain swarming with dangerous bandits. Follow their intriguing adventures as they trade exotic goods and engage in real-time battles, all while building the most powerful trading caravan the world has ever seen. Embark on challenging quests, hire fiercely loyal warriors for protection and explore a long-lost world teeming with tantalizing secrets, hidden cities and legends of mythical creatures.
                    Your adventure begins today… in Tradewinds Caravans!</p>
                    <ul>
                    <li>6 unique characters with dozens of individual storylines 
                    <li>Customize your gameplay with special items found during exploration
                    <li>All-new weapons and character-specific powers 
                    <li>Sandlot Games’ signature humor!
                    </ul>','<img src="http://storefront.steampowered.com/v/gfx/apps/36130/extras/two_logo.jpg" align="left">
                    <p>Tradewinds Odyssey, the latest installment in the highly-acclaimed Tradewinds series, takes you on an adventurous journey across ancient Greece, where gods, heroes and monsters of legend await. </p>
                    <p>Guide five unique heroes - the Athlete, Cynic, Priestess, Minotaur and Goddess - as you embark on over 50 chapters and quests, encountering characters both strange and familiar. Take part in trading like never before by creating and spreading goods to new lands as you build, strengthen and upgrade your fleet into a powerful force unrivaled in the Aegean! Cast powerful spells bestowed upon you by the gods, or use your unique Hero’s Talent to demolish your opponent in battle.</p>
                    <p>Your adventure begins today… in Tradewinds Odyssey!</p>
                    <ul>
                    <li>Play as 5 unique characters, each with an original storyline
                    <li>Create and customize your own character
                    <li>Spread, create and trade over a dozen exotic goods
                    <li>New ramming feature available in sea battle
                    <li>Achieve great feats and build your rank
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36130/extras/twc_logo.jpg" align="left">
                    <p>Adventure awaits you in Tradewinds Caravans™, the latest installment in the acclaimed Tradewinds Series. As the Middle Ages unfold in the West, cultural centers and merchants across Asia are linked together by an ancient trade route – stretching from the shores of the Mediterranean Sea to China – known as the legendary Silk Road. 
                    Guide six brave heroes as they navigate treacherous terrain swarming with dangerous bandits. Follow their intriguing adventures as they trade exotic goods and engage in real-time battles, all while building the most powerful trading caravan the world has ever seen. Embark on challenging quests, hire fiercely loyal warriors for protection and explore a long-lost world teeming with tantalizing secrets, hidden cities and legends of mythical creatures.
                    Your adventure begins today… in Tradewinds Caravans!</p>
                    <ul>
                    <li>6 unique characters with dozens of individual storylines 
                    <li>Customize your gameplay with special items found during exploration
                    <li>All-new weapons and character-specific powers 
                    <li>Sandlot Games’ signature humor!
                    </ul>','Tradewinds Odyssey, the latest installment in the highly-acclaimed Tradewinds series, takes you on an adventurous journey across ancient Greece, where gods, heroes and monsters of legend await. Guide five unique heroes - the Athlete, Cynic, Priestess, Minotaur and Goddess - as you embark on over 50 chapters and quests, encountering...');
INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (36180,'<img src="http://storefront.steampowered.com/v/gfx/apps/36180/extras/cm3_logo.jpg" align="left">
                    <p>Over the past few years, we’ve watched Jill Evans grow from a fresh-out-of-baking-school student to a world-class culinary celeb. Now, Jill confronts her greatest challenge yet - planning her dream wedding – in Cake Mania® 3, the highly anticipated follow-up to one of the most popular casual games of all-time!</p>
                    <p>As Jill nervously prepares for her long anticipated wedding day, disaster strikes when a mysterious, long-forgotten time bender crashes to the ground and shatters into pieces. As Jill’s family and friends rush to pick up the scattered shards, they are suddenly sent hurtling through time.  Now, to ensure her wedding goes off without a hitch, Jill herself must travel to remote periods in time - from Ancient Egypt and Revolutionary France, to an unknown future where anything is possible - and work her cake-making magic on a wide variety of locals in order to get herself and her guests back before the ceremony begins!</p>
                    <ul>
                    <li>Access to new bonus levels, customers and outfits with Sandlot Connect
                    <li>Over 350 possible level combinations
                    <li>More than 30 hilarious new customers
                    <li>All-new power-ups, kitchen upgrades and customizable bakeries
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36180/extras/cm2_logo.jpg" align="left">
                    <p>After re-opening the Evans Bakery, and sending her grandparents on an exotic Hawaiian cruise, Jill is back in an all-new, out-of-this-world series of adventures! Help Jill’s college friend Risha in her posh, northwestern, rooftop bakery; rescue her old flame, Jack, in his underwater theme park located on the ocean floor, or wind up in 4 other far-flung bakery locations, each with its own unique layout!</p>
                    <p>What awaits Jill? Fame? Fortune? Love? In Cake Mania® 2, you choose which path Jill pursues, with each decision leading to new baking challenges and dilemmas. With 204 levels of baking and frosting madness, 6 different possible endings and a branching, non-linear storyline, it’s your decision to make in Cake Mania 2!</p>
                    <ul>
                    <li>Customize Jill’s bakeries with 50 unique kitchen upgrades 
                    <li>18 all-new quirky, demanding customers, ranging from Federal Agents to mysterious Aliens, keep Jill on her toes
                    <li>10 deliciously different cake styles with 6 fabulous frostings
                    <li>8 wild cake toppers for earning extra cash
                    <li>See how you measure up in a new Endless Baking mode 
                    </ul>
                    <p>&nbsp;</p>
                    <img src="http://storefront.steampowered.com/v/gfx/apps/36180/extras/cm_logo.jpg" align="left">
                    <p>Welcome to Cake Mania®! Jill, our hero, has returned from culinary school, only to find her beloved grandparents'' bakery closed down. Business has taken a drastic downturn because a new Mega-Mart store opened in the neighborhood.</p>
                    <p>Help Jill save the day by opening a bakery, and earn enough money to re-open her grandparents'' shop in this beautiful, fast-paced adventure. Upgrade your equipment and set up 4 different bakeries in exotic locales. Serve up seasonal confectionary delights to a variety of customers. See if you have what it takes to save the Evans Bakery!</p>
                    <ul>
                    <li>Over 45 fast-paced levels of baking! 
                    <li>Bake in four unique locales 
                    <li>Customize your Kitchen in the Shop Screen  
                    <li>Post your High Scores Online
                    </ul>','<img src="http://storefront.steampowered.com/v/gfx/apps/36180/extras/cm3_logo.jpg" align="left">
                    <p>Over the past few years, we’ve watched Jill Evans grow from a fresh-out-of-baking-school student to a world-class culinary celeb. Now, Jill confronts her greatest challenge yet - planning her dream wedding – in Cake Mania® 3, the highly anticipated follow-up to one of the most popular casual games of all-time!</p>
