INSERT INTO steam_description(steam_appid,detailed_description,about_the_game,short_description) VALUES (36210,'<p>In a distant fairy-tale world, the villagers of Curly Valley are being attacked by legions of quirky and bizarre monsters.  Fortify villages with various towers, upgrades and unusual defensive armaments to repel these mysterious invaders and protect the grateful villagers who cheer your every conquest!  Get ready for the coming onslaught in this addictive, strategic adventure.</p>
                    <ul>
                    <li>Hours of challenging game play
                    <li>20 quirky and bizarre monsters
                    <li>9 Unique Scenes
                    <li>Storybook style art
                    <li>11 Power-ups and level-altering items
                    </ul>','<p>In a distant fairy-tale world, the villagers of Curly Valley are being attacked by legions of quirky and bizarre monsters.  Fortify villages with various towers, upgrades and unusual defensive armaments to repel these mysterious invaders and protect the grateful villagers who cheer your every conquest!  Get ready for the coming onslaught in this addictive, strategic adventure.</p>
                    <ul>
